INSERT INTO opportunities (id,manufacturer_id,reason,action,score_no_distributor,score_confidence,score_brand,created_at) VALUES (1,3,'CORRECTED after finding SEC filing: Immucor was acquired by Werfen in 2023 and is no longer independent. This is the SAME opportunity as the Werfen entry below, not a separate one -- scores lowered accordingly','Do not contact Immucor separately. Any inquiry should go to Werfen''s Dubai regional office and explicitly ask about the Immucor/Capture-Echo-NEO product line for KSA.',2,3,3,'2024-01-01 00:00:00');
INSERT INTO opportunities (id,manufacturer_id,reason,action,score_no_distributor,score_confidence,score_brand,created_at) VALUES (2,2,'Has Dubai regional office but no named KSA distributor','Contact Dubai regional office directly, ask about KSA distribution status',2,2,3,'2024-01-01 00:00:00');
INSERT INTO opportunities (id,manufacturer_id,reason,action,score_no_distributor,score_confidence,score_brand,created_at) VALUES (3,6,'Confirmed distributor only for their airway (LMA) line, not transfusion line','Ask EMEA office (Athlone, Ireland) which entity covers KSA for the transfusion-relevant line',1,2,2,'2024-01-01 00:00:00');
INSERT INTO opportunities (id,manufacturer_id,reason,action,score_no_distributor,score_confidence,score_brand,created_at) VALUES (4,87,'Diatron (STRATEC Group) officially lists Saudi Arabia as an open market on their own 2025 distributor recruitment country list, specifically for the hematology portfolio ("KSA (Hematology only)") -- confirming no current KSA hematology distributor from the manufacturer itself, not inferred.','Contact Diatron directly via their distributor application form (surveymonkey.com/s/Distributor_Form) or via their Our Distributors page, referencing the hematology-specific KSA gap on their own published country list. Their hematology line (Abacus 5/380/Junior 30, Aquila, Aquarius 3) is a natural complement to Attieh Medico''s existing Snibe/Sysmex/Mindray hematology expertise for entry-level and mid-tier segments.',3,3,2,'2024-01-01 00:00:00');
