INSERT INTO products (id,manufacturer_id,product_name,product_type,description,source,department,throughput,sample_types,certifications,brochure_url,image_url,specs_json) VALUES (18,19,'Atellica','Analyzer','Hematology/chemistry automation platform','NUPCO Tender NPT0038/24 Final Awardation + Announcement documents (17/03/2025 and 01/09/2024) -- uploaded by user','Hematology',NULL,NULL,NULL,NULL,NULL,'{"Platform": "Atellica Solution -- integrated immunoassay (IM) and clinical chemistry (CH) analyzer family, over 300 customizable configurations", "Throughput (immunoassay)": "Up to 440 tests/hour", "Assay menu": "170+ assays (Atellica IM), with several key cardiac, reproductive, and thyroid assays delivering results in about 10 minutes", "Sample transport": "Atellica Magline Transport -- patented bi-directional magnetic sample transport, reported up to 10x faster than conventional conveyors; aspiration occurs within 60 seconds of barcode reading", "Automation": "Individual sample routing/sorting, automatic QC and calibration, multi-camera vision system, AI-powered workflow intelligence", "Connectivity": "Can operate stand-alone or connect to Aptio Automation for a multidisciplinary lab solution (chemistry, immunoassay, hemostasis, hematology, plasma protein)", "Source": "Siemens Healthineers official Atellica Solution product page (siemens-healthineers.com/en-us/laboratory-diagnostics/clinical-chemistry-and-immunoassay-systems/atellica-solution-analyzers); BioSpace launch press release"}');
INSERT INTO products (id,manufacturer_id,product_name,product_type,description,source,department,throughput,sample_types,certifications,brochure_url,image_url,specs_json) VALUES (19,19,'ADVIA 2120i / ADVIA 560','Analyzer','Hematology analyzer line','NUPCO Tender NPT0038/24 Final Awardation + Announcement documents (17/03/2025 and 01/09/2024) -- uploaded by user','Hematology',NULL,NULL,NULL,NULL,NULL,'{"Throughput": "Up to 120 samples/hour", "Detection technology": "Laser light scatter combined with cytochemical (peroxidase) staining -- the gold-standard methodology for WBC differentials", "Test menu": "CBC with differential, reticulocyte analysis, 2-dimensional platelet analysis, and CSF analysis with reduced manual intervention", "Slide automation (optional)": "ADVIA Autoslide Slide Maker Stainer -- up to 120 high-quality slides/hour", "Sampling modes": "Autosampler, open mode, and closed-tube (manual) sampling", "Fluidics": "Unifluidics Technology -- reduced fluidics, no pinch valves, automated daily cleaning and completely automated start-up", "Connectivity": "ADVIA CentraLink Networking Solution for centralized data management and QC across client workstations", "Source": "Siemens Healthineers official ADVIA 2120i product page (siemens-healthineers.com/en-iq/hematology/systems/advia-2120-hematology-system-with-autoslide); MedWrench technical listing"}');
