INSERT INTO products (id,manufacturer_id,product_name,product_type,description,source,department,throughput,sample_types,certifications,brochure_url,image_url,specs_json) VALUES (46,13,'INTERCEPT','Blood processing device','Pathogen reduction technology system for platelets/plasma','NUPCO Tender NPT0038/24 Final Awardation + Announcement documents (17/03/2025 and 01/09/2024) -- uploaded by user','Blood Bank',NULL,NULL,NULL,NULL,NULL,'{"Technology": "Photochemical pathogen reduction using amotosalen (a psoralen compound) plus controlled UVA illumination", "Platform": "Disposable processing sets (plastic, PVC tubing) combined with the INTERCEPT Illuminator for UVA light dosing", "Components covered": "Platelets, plasma, and cryoprecipitation processing sets, all treated on the same illuminator platform", "Pathogen coverage": "Broad-spectrum inactivation of bacteria, viruses, protozoa, and residual leukocytes; certain non-enveloped viruses (e.g., HAV, HEV, B19) and Bacillus cereus spores show demonstrated resistance", "Regulatory status": "FDA-approved (PMA) pathogen reduction system for apheresis platelet and plasma components", "Source": "Cerus Corporation official INTERCEPT USA resource pages (intercept-usa.com; intercept-usa.com/resources/); FDA approved blood products listing (fda.gov/vaccines-blood-biologics/approved-blood-products/intercept-blood-system-platelets)"}');
INSERT INTO products (id,manufacturer_id,product_name,product_type,description,source,department,throughput,sample_types,certifications,brochure_url,image_url,specs_json) VALUES (47,33,'Panther','Analyzer','Automated molecular/NAT testing platform (reagents supplied by Grifols)','NUPCO Tender NPT0038/24 Final Awardation + Announcement documents (17/03/2025 and 01/09/2024) -- uploaded by user','Molecular Diagnostics',NULL,NULL,NULL,NULL,NULL,'{"Platform": "Fully automated molecular diagnostics system with true sample-to-result automation", "Throughput (TMA assays)": "Up to 275 samples in 8 hours", "Throughput (real-time TMA assays)": "Up to 320 samples in 8 hours, or up to 750 samples in 15.2 hours", "Workflow": "Random access (load samples in any order without batch constraints); processes multiple assays from one patient sample in a single run", "Assay menu": "Aptima assay menu covering STIs, women''s health, and virology on a single integrated instrument", "Automation": "Programmable/automated maintenance scheduling for off-hours operation; STAT sample prioritization", "Scalability": "Panther Scalable Solutions allows expansion of testing menu, capacity, and walkaway time; Panther Fusion adds an open-access PCR module", "Source": "Hologic official Panther System product page (hologic.com/hologic-products/diagnostic-solutions/panther-system); SelectScience verified throughput listing"}');
