INSERT INTO products (id,manufacturer_id,product_name,product_type,description,source,department,throughput,sample_types,certifications,brochure_url,image_url,specs_json) VALUES (49,23,'miniiSED i-SED','Analyzer','ESR (erythrocyte sedimentation rate) analyzer','NUPCO Tender NPT0038/24 Final Awardation (17/03/2025) -- primary source','Hematology',NULL,NULL,NULL,NULL,NULL,'{"Technology": "Photometric rheology / capillary photometry (syllectometry) -- directly measures red cell aggregation (rouleaux formation) rather than the traditional Westergren settling method", "Result time": "15-20 seconds per ESR result", "Sample requirement": "100 uL, drawn directly from a primary EDTA tube (no disposables or manual sample prep required)", "Correlation to reference method": "Highly correlated with the Westergren method; a published verification study found iSED bias of 0.0 (95% CI -1.4 to 1.5) mm/hr vs. Westergren across low/medium/high ESR ranges", "Efficiency": ">96% less hands-on time and up to 94% shorter turnaround time compared with the Westergren method", "Sample stability": "Up to 28 hours at room temperature (versus the short stability window of Westergren-based testing)", "Source": "ALCOR Scientific official iSED product page (alcorscientific.com/clinical-lab/ised/); PMC verification study (ncbi.nlm.nih.gov/pmc/articles/PMC8833250/)"}');
