INSERT INTO products (id,manufacturer_id,product_name,product_type,description,source,department,throughput,sample_types,certifications,brochure_url,image_url,specs_json) VALUES (149,45,'FilmArray Multiplex PCR Panels','Molecular PCR platform + reagent panels','Syndromic multiplex PCR panels: meningitis, respiratory, gastrointestinal, blood culture identification, joint infection, pneumonia','NUPCO Tender NPT0028/24, SN 8-14','Microbiology',NULL,NULL,NULL,NULL,NULL,'{"Hands-on time": "About 2 minutes per test", "Total run time": "45 minutes to about 1 hour (assay-dependent)", "Workflow": "Automated sample preparation, nested multiplexed nucleic acid amplification, DNA melting analysis, and results generation in a single closed disposable reagent pouch", "Respiratory panel (RP2.1)": "Tests for viral and bacterial respiratory pathogens; ~45 minute run time", "Blood Culture ID panel (BCID2)": "Identifies bacteria, fungi, and antimicrobial resistance markers directly from positive blood culture bottles", "Gastrointestinal panel": "22 pathogens (viruses, bacteria, parasites) from a single stool specimen; reduces turnaround time to under 2 hours vs. ~53 hours for routine PCR in published comparisons", "System options": "BioFire FilmArray 2.0, FilmArray Torch (higher-throughput multi-module), and CLIA-waived FilmArray 2.0 EZ Configuration", "Source": "bioMerieux/BioFire official panels page (biofiredx.com/products/the-filmarray-panels/); FIND landscape report on molecular platforms for near-patient testing"}');
INSERT INTO products (id,manufacturer_id,product_name,product_type,description,source,department,throughput,sample_types,certifications,brochure_url,image_url,specs_json) VALUES (150,46,'GeneXpert Platform + Cartridge Menu','Real-time PCR platform + single-use cartridges','Random-access single-cartridge PCR system with a broad assay menu: MTB/RIF, CRE/carbapenemase, HIV, C. diff, MRSA, GBS, HPV, Strep-A, SARS-CoV-2/RSV/Flu combo','NUPCO Tender NPT0028/24, SN 33-50, 83-95','Microbiology',NULL,NULL,NULL,NULL,'https://www.cepheid.com/content/dam/www-cepheid-com/images/pep/cards/cep-genexpert-4-module-system.jpeg','{"Module configurations": "1, 2, 4, 16, 48, or 80 modules (GeneXpert Infinity line for higher throughput)", "Result time": "Most assays deliver results in about an hour, including automated sample preparation", "Workflow": "Fully integrated -- sample prep, nucleic acid purification, real-time PCR amplification and detection in a single-use disposable cartridge", "Targets per cartridge": "Up to 6 genes per cartridge via multiple calibrated fluorophore dyes", "Portable option": "GeneXpert Omni -- 1.0 kg handheld, single cartridge module, battery-powered (up to 4h + 12h supplemental), cloud connectivity", "Cross-contamination control": "Self-contained single-use cartridges minimize cross-contamination between samples", "Source": "Cepheid official test menu page (cepheid.com/en-US/tests.html); ClinicalTrials.gov protocol documentation citing GeneXpert Omni specifications"}');
INSERT INTO products (id,manufacturer_id,product_name,product_type,description,source,department,throughput,sample_types,certifications,brochure_url,image_url,specs_json) VALUES (151,27,'VITEK 2 Compact','Automated ID/AST system','Fully automated bacterial identification and antibiotic susceptibility testing using colorimetric VITEK 2 ID/AST cards, 15/30/60-card configurations','biomerieux.com/corp/en/our-offer/clinical-products/vitek-2-compact.html','Coagulation',NULL,NULL,NULL,NULL,NULL,'{"Function": "Automated bacterial/yeast identification (ID) and antimicrobial susceptibility testing (AST) system, available in multiple sizes for labs of different volumes", "Technology": "Advanced Colorimetry for identification; ADVANCED EXPERT SYSTEM (AES) -- a second-generation expert system analyzing MIC patterns and detecting resistance phenotypes", "Cards": "Uses the same sealed, compact ID/AST cards as the larger VITEK 2 instrument, minimizing waste and biohazard risk", "Software": "Windows-based PC software with icon-driven workflow; OBSERVA information management module for epidemiology/statistical reporting and data export", "Ergonomics": "Reduced set-up time and manual steps versus manual ID/AST methods; ergonomic workflow to reduce repetitive-motion injury risk", "Source": "bioMerieux official VITEK 2 product page (biomerieux.com/us/en/our-offer/clinical-products/vitek-2.html)"}');
