INSERT INTO market_events (id,manufacturer_id,event_type,event_date,description,source) VALUES (1,3,'Acquisition','2023','Immucor was acquired by Werfen. Confirmed via SEC Form 8-K (Neogen Corp, filed Aug 2025), which states the former Immucor CEO ''led the company''s turnaround and its acquisition by Werfen in 2023.''','SEC Form 8-K, Neogen Corp, August 2025');
INSERT INTO market_events (id,manufacturer_id,event_type,event_date,description,source) VALUES (2,5,'Acquisition','Not precisely dated -- year not confirmed','Lorne Laboratories was acquired by Calibre Scientific (a US diagnostics group). The acquisition is confirmed but the exact year was not independently verified.','calibrescientificgroup.com acquisition notice');
INSERT INTO market_events (id,manufacturer_id,event_type,event_date,description,source) VALUES (3,7,'Market entry','2020','Stago established a direct KSA affiliate office in Riyadh, moving from third-party distribution to direct presence.','stago.com affiliate directory, Riyadh address listing');
INSERT INTO market_events (id,manufacturer_id,event_type,event_date,description,source) VALUES (4,1,'Market entry','2019','Grifols established its own representation office in Riyadh.','grifols.com/en/saudi-arabia');
INSERT INTO market_events (id,manufacturer_id,event_type,event_date,description,source) VALUES (5,1,'Acquisition','2017 (completed)','Grifols completed acquisition of Hologic''s share of the NAT donor screening business for $1.85B, taking over R&D/manufacturing of the Procleix NAT reagent line while Hologic retained ownership of the Panther/Tigris instrument platforms.','grifols.com official press release, January 2017');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (1,1,'Grifols has its own KSA representation office','official company page','grifols.com/en/saudi-arabia — office listed since 2019','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (2,1,'AFMS also distributes Grifols products in Riyadh','distributor''s own website','afmssc.com distributor product listing','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (3,1,'Grifols NAT reagents (Panther platform) confirmed via Abdulla Fouad for medical supplies for malaria and HBV/HCV/HIV NAT screening','primary government source','NUPCO Tender NPT0038/24 Final Awardation (17/03/2025), items 596 and 600','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (4,2,'Werfen has a Dubai regional office covering EMEA','official company page','werfen.com contact/office directory','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (5,2,'No KSA-specific distributor named for Werfen transfusion line','absence check — searched, found nothing','general web search, no contradicting result','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (6,3,'No KSA distributor found for Immucor (this specific finding was later superseded, see below)','absence check — searched official site + web','immucor.com + general web search, no contradicting result','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (7,3,'Immucor was acquired by Werfen in 2023 and is no longer an independent company','SEC filing (independent third party)','Neogen Corp Form 8-K, filed Aug 2025, states former Immucor CEO led its turnaround and acquisition by Werfen in 2023','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (8,3,'Immucor''s official contact page now redirects to Werfen''s site','official company page redirect','immucor.com/en-us/About redirects to transfusionandtransplant.werfen.com','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (9,4,'Samir Group confirmed as Macopharma KSA distributor','distributor''s own website','samirgroup.com Macolounge product listing','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (10,5,'GAMSCO Medical confirmed as Lorne Laboratories KSA distributor since 2008','manufacturer''s own distributor page','lornelabs.com/distributors/saudi-arabia','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (11,5,'Lorne Laboratories was acquired by Calibre Scientific','acquirer''s own announcement','calibrescientificgroup.com acquisition notice','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (12,6,'Saudi Medical Services confirmed as distributor for Teleflex LMA/airway line only','Teleflex-owned brand site','lmaco.com/distributors/saudi-medical-services','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (13,14,'NUPCO 2024 tender requested 396,288 NAT tests for Cobas 6800/5800 platforms, plus 13,056 for Modules S201 -- real demand signal, not an estimate','primary government source','NUPCO Tender NPT0038/24 Announcement (initial quantities), 01/09/2024','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (14,7,'NUPCO 2024 tender requested 1,731,840 fibrinogen tests and 8,109,600 heparin-sensitive APTT tests for STA R Max/STA Compact platforms -- among the highest single-line-item volumes in the entire tender','primary government source','NUPCO Tender NPT0038/24 Announcement (initial quantities), 01/09/2024','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (15,5,'Related IH1000/IH500-compatible reagent lines (same product category Lorne competes in) show extremely high demand -- e.g. 6,497,280 LISS Coombs cards and 3,631,488 ABO/D reverse-group cards requested in the 2024 tender','primary government source, category-level demand context','NUPCO Tender NPT0038/24 Announcement (initial quantities), 01/09/2024','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (16,6,'No directly matching line item found in the 2024 Announcement -- consistent with Teleflex''s transfusion-line KSA status remaining unconfirmed rather than a large, visible demand signal','absence check against primary source','NUPCO Tender NPT0038/24 Announcement (initial quantities), 01/09/2024','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (17,33,'NUPCO 2024 tender requested 10,000 malaria NAT tests and 1,170,000 HBV/HCV/HIV NAT tests compatible with the Panther platform -- confirms real, large-scale demand for the instrument Hologic owns (reagents supplied by Grifols)','primary government source','NUPCO Tender NPT0038/24 Announcement (initial quantities), 01/09/2024','2026-07-05');
INSERT INTO evidence (id,manufacturer_id,claim,evidence_type,source_detail,reviewed_date) VALUES (18,6,'Researched Teleflex''s actual product portfolio (Arrow vascular access catheters, MANTA vascular closure device) -- it is a vascular access/interventional company, not a blood bank reagent or transfusion diagnostics company. No genuine blood-bank-relevant product was found beyond the previously-confirmed LMA/airway line, which is unrelated to transfusion medicine.','web search, portfolio review','teleflex.com product area pages (Vascular Access, MANTA); this raises a real question about whether Teleflex belongs in the Blood Bank category at all','2026-07-05');
