INSERT INTO users (id,email,password_hash,company_name,full_name,role,is_active,created_at) VALUES (1,'amr@attieh-medico.com','$2b$12$vWmoWh9E4vDICE4SumsWh.j1YrUxZB/I9If0R6dtfNu8.Gp0oVs0y','Attieh Medico','Amr Elmorshedy','admin',1,'2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (1,'database',0,'init','Initial seed from verified July 2026 research','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (2,'database',0,'update','v1.3: Added 4 new Blood Bank manufacturers + enriched distributor records from NPT0032-25','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (3,'database',0,'update','v1.4: Added 3 Chinese IVD suppliers (Snibe, Dymind, URIT Medical) per user request; Snibe flagged as internal-knowledge sourced, Dymind and URIT verified via distributor websites','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (4,'products',0,'bulk_insert','v1.5: Web-researched and added real product catalogs for Macopharma, Diagast, Cerus, Lorne Laboratories, JMS (batch 1 of ongoing product-enrichment pass across all 40 manufacturers)','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (5,'products',0,'bulk_insert','v1.6: Completed full product research pass (batches 2-5) across all 40 manufacturers -- 141 total products on file; Teleflex remains the sole documented zero-product exception','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (6,'database',0,'bulk_insert','v1.7: Started Microbiology category expansion (BD, Copan, 77Elektronika, QIAGEN, BioFire, Cepheid) + extended bioMerieux with microbiology products, using previously-uploaded NPT0028/24 tender data cross-verified with live web research','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (7,'database',0,'bulk_insert','v1.8: Added regulatory_status table, seeded only with FDA/CE facts already verified during prior product research (8 rows) -- not a comprehensive regulatory audit','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (8,'database',0,'schema_migration','v1.9: Added origin classification (American/European/Chinese/Asian-other), extended products (department/throughput/certifications), created and populated company_distributors many-to-many join table (72 links total, including 23 formalized from prior text-only ksa_status mentions)','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (9,'database',0,'bulk_insert','v2.0: Added contact fields (phone/email/contact_url) to manufacturers -- shown only on manufacturer cards per requirement. Added 3 new manufacturers across 3 new lab departments: Euroimmun (Immunology & Serology), Randox Laboratories (Clinical Chemistry), Leica Biosystems (Histopathology & Cytology). This is a first batch (3 of the requested ~15); remaining categories/companies to be researched in follow-up rounds.','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (10,'database',0,'bulk_insert','v2.1: Added DiaSorin (Immunology & Serology) and Radiometer (Clinical Chemistry/POCT blood gas, verified via independent peer-reviewed KSA study) + extended existing Abbott Core Diagnostics with i-STAT POCT product line.','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (11,'database',0,'bulk_insert','Session 1 (Immunoassay): Added Fujirebio (unclear KSA status) + extended Ortho Clinical Diagnostics with VITROS ECiQ immunoassay product','2026-07-12 06:48:08');
INSERT INTO audit_log (id,table_name,record_id,action,detail,timestamp) VALUES (12,'products',0,'bulk_insert','Session 2 (Flow Cytometry): Extended BD with FACSLyric flow cytometer + Multitest/Trucount reagents (Immunology & Serology dept), extended Beckman Coulter with DxFLEX + ClearLLab 10C (Hematology dept) -- both use existing confirmed KSA distributor links. Cytek Biosciences deferred to a follow-up session.','2026-07-12 06:48:08');
