INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (1,'cbc','Complete Blood Count','صورة الدم الكاملة','CBC, Full Blood Count, FBC, CBC with differential','Hematology','Screens overall health and detects a wide range of disorders including anemia, infection, inflammation, bleeding disorders, and blood cancers. Commonly used in routine checkups and to monitor chronic conditions or treatment (e.g., chemotherapy).','فحص شامل لتقييم الصحة العامة والكشف عن اضطرابات متعددة مثل الأنيميا، الالتهابات، اضطرابات النزيف، وأورام الدم. يُستخدم بشكل روتيني في الفحوصات الدورية ولمتابعة الحالات المزمنة أو العلاج الكيميائي.','Venous whole blood, EDTA tube (lavender top)','No fasting required. Standard venipuncture; in infants, heel-stick may be used. Gentle inversion of the tube after draw to mix with anticoagulant.','لا يتطلب الصيام. سحب وريدي عادي؛ في الرضع يمكن استخدام وخز الكعب. يُقلب الأنبوب برفق بعد السحب لخلط العينة مع مانع التجلط.','Automated hematology analyzer (impedance/flow cytometry principles) for cell counts and indices; manual or digital peripheral blood smear review when abnormalities are flagged.','محلل دم آلي (بمبدأ المقاومة الكهربائية أو التدفق الخلوي) لحساب الخلايا والمؤشرات؛ مراجعة يدوية أو رقمية لمسحة الدم المحيطي عند وجود نتائج غير طبيعية.','[{"parameter": "Hemoglobin (Hb)", "population": "Adult male", "range": "13-18 g/dL", "notes": "WHO reference"}, {"parameter": "Hemoglobin (Hb)", "population": "Adult female (non-pregnant)", "range": "12-16 g/dL", "notes": "WHO reference"}, {"parameter": "RBC count", "population": "Adult male", "range": "4.6-6.2 million cells/\u00b5L"}, {"parameter": "RBC count", "population": "Adult female", "range": "4.2-5.4 million cells/\u00b5L"}, {"parameter": "WBC count", "population": "Adult", "range": "4,300-10,800 cells/mm\u00b3", "notes": "Typical range; lab-specific"}, {"parameter": "Platelets", "population": "Adult", "range": "150,000-450,000/\u00b5L", "notes": "Commonly cited general range"}]',1,'Low Hb/Hct/RBC suggests anemia (further workup with MCV, iron studies, B12/folate needed to classify type). High WBC may indicate infection, inflammation, steroid use, or hematologic malignancy; low WBC may suggest bone marrow suppression, viral infection, or autoimmune disease. Low platelets (thrombocytopenia) raise bleeding risk; high platelets may reflect reactive states or myeloproliferative disease. All CBC abnormalities should be interpreted together with clinical context and, when indicated, a peripheral smear.','انخفاض الهيموجلوبين/الهيماتوكريت/كريات الدم الحمراء يشير لأنيميا (يلزم فحوصات إضافية مثل MCV والحديد وفيتامين B12/الفوليك لتحديد النوع). ارتفاع كريات الدم البيضاء قد يدل على التهاب أو عدوى أو استخدام كورتيزون أو أورام دموية؛ انخفاضها قد يشير لتثبيط نخاع العظم أو عدوى فيروسية أو مرض مناعي ذاتي. انخفاض الصفائح يرفع خطر النزيف؛ ارتفاعها قد يكون تفاعلياً أو نتيجة اضطراب تكاثري نقوي. يجب تفسير أي خلل في صورة الدم الكاملة مع السياق الإكلينيكي، ومراجعة مسحة الدم عند الحاجة.','[{"condition": "Iron-deficiency anemia", "direction": "low Hb/Hct, microcytic"}, {"condition": "Bacterial infection", "direction": "high WBC, neutrophilia"}, {"condition": "Viral infection", "direction": "may show low or normal WBC, lymphocytosis"}, {"condition": "Leukemia / myeloproliferative disorders", "direction": "markedly abnormal WBC and/or blasts"}, {"condition": "Thrombocytopenia (ITP, marrow disorders, DIC)", "direction": "low platelets"}, {"condition": "Polycythemia vera / dehydration", "direction": "high Hb/Hct"}]','[{"name": "MedlinePlus (NIH/NLM) - Complete Blood Count (CBC)", "url": "https://medlineplus.gov/lab-tests/complete-blood-count-cbc/", "accessed": "2026-07-14"}, {"name": "StatPearls / NCBI Bookshelf - Normal and Abnormal CBC With Differential (cites WHO Hb ranges)", "url": "https://www.ncbi.nlm.nih.gov/books/NBK604207/", "accessed": "2026-07-14"}, {"name": "Cleveland Clinic - Complete Blood Count", "url": "https://my.clevelandclinic.org/health/diagnostics/4053-complete-blood-count", "accessed": "2026-07-14"}]',1,'2026-07-14 10:39:27','2026-07-14 10:39:27','["ferritin", "serum-iron", "tibc-transferrin-saturation", "vitamin-b12", "folate", "reticulocyte-count", "g6pd"]','Adult critical ranges (ARUP Laboratories): Hemoglobin <7.0 g/dL; Platelet count ≤20,000/µL or ≥1,000,000/µL; White blood cell count ≤2,000/µL or ≥40,000/µL. Severe anemia, severe thrombocytopenia (bleeding risk) or extreme thrombocytosis, and marked leukopenia (infection risk) or leukocytosis (possible leukemia/severe infection) all warrant urgent clinical correlation and often same-day physician notification.','Cold agglutinins or red cell clumping can cause a falsely low automated RBC/platelet count and falsely high MCV -- warming the sample or manual review can correct this. Platelet clumping (often EDTA-induced pseudothrombocytopenia) can cause a falsely low automated platelet count; a citrate-tube repeat or peripheral smear review confirms the true count. Marked leukocytosis can interfere with automated hemoglobin/hematocrit measurement on some analyzers.','Is my result normal for my age and sex? If something is abnormal, is it new or has it been trending this way over time? Do I need a peripheral blood smear or repeat testing to clarify the result? Could any of my current medications or recent illness explain an abnormal finding? Do I need iron, B12, or folate studies based on my red cell indices?','A normal CBC usually needs no further action beyond routine follow-up. An abnormal result typically leads to one of: a repeat test to confirm it isn''t a lab or collection artifact, additional targeted tests (e.g., iron studies, B12/folate, reticulocyte count, peripheral smear) to investigate the specific abnormality, or referral to hematology if the pattern suggests a more complex blood disorder. Your clinician will interpret the result alongside your symptoms and history rather than in isolation.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (2,'fasting-glucose','Fasting Plasma Glucose','سكر الدم الصائم','FPG, Fasting Blood Sugar, FBS','Clinical Chemistry','Primary screening and diagnostic test for diabetes mellitus and prediabetes; used for diagnosis, monitoring, and risk assessment.','الفحص الأساسي للكشف عن السكري ومقدمات السكري وتشخيصهما ومتابعتهما وتقييم المخاطر.','Venous plasma (fluoride oxalate/gray top preferred to prevent glycolysis) or serum','Patient must fast (no caloric intake) for at least 8 hours before the draw; water is permitted.','يجب صيام المريض (عدم تناول أي سعرات حرارية) لمدة 8 ساعات على الأقل قبل سحب العينة؛ يُسمح بشرب الماء.','Enzymatic method (hexokinase or glucose oxidase) on automated clinical chemistry analyzers.','طريقة إنزيمية (هيكسوكاينيز أو جلوكوز أوكسيديز) على أجهزة الكيمياء الإكلينيكية الآلية.','[{"parameter": "Fasting plasma glucose", "population": "Normal", "range": "<100 mg/dL (<5.6 mmol/L)"}, {"parameter": "Fasting plasma glucose", "population": "Prediabetes (impaired fasting glucose)", "range": "100-125 mg/dL (5.6-6.9 mmol/L)"}, {"parameter": "Fasting plasma glucose", "population": "Diabetes (requires confirmatory repeat test)", "range": "\u2265126 mg/dL (\u22657.0 mmol/L)"}]',1,'Elevated fasting glucose is diagnostic of diabetes mellitus when ≥126 mg/dL on two occasions (or one occasion with classic hyperglycemia symptoms), per ADA criteria. Values 100-125 mg/dL indicate prediabetes/impaired fasting glucose. Low fasting glucose (hypoglycemia) may indicate insulin excess, adrenal insufficiency, liver disease, or other metabolic causes and requires urgent clinical correlation.','ارتفاع سكر الصائم ≥126 مج/دل في مناسبتين منفصلتين (أو مرة واحدة مع أعراض ارتفاع سكر واضحة) يُشخّص السكري وفق معايير ADA. القيم بين 100-125 مج/دل تدل على مقدمات السكري. انخفاض سكر الصائم (نقص السكر) قد يشير لزيادة الأنسولين أو قصور الغدة الكظرية أو أمراض الكبد أو أسباب استقلابية أخرى، ويستوجب تقييمًا سريريًا عاجلاً.','[{"condition": "Type 2 diabetes mellitus", "direction": "high"}, {"condition": "Type 1 diabetes mellitus", "direction": "high"}, {"condition": "Prediabetes / metabolic syndrome", "direction": "borderline high"}, {"condition": "Insulinoma / excess exogenous insulin", "direction": "low"}, {"condition": "Adrenal insufficiency", "direction": "low"}]','[{"name": "American Diabetes Association (ADA) - Standards of Care in Diabetes, diagnostic criteria", "url": "https://emedicine.medscape.com/article/2172154-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 10:39:27','2026-07-14 10:39:27','["hba1c", "lipid-panel", "creatinine", "insulin", "c-peptide"]','Adult critical range: <55 mg/dL or >450 mg/dL (ARUP Laboratories; neonatal thresholds differ and are higher-risk at even less extreme values). Severe hypoglycemia can cause seizures, coma, and permanent neurologic injury if untreated; severe hyperglycemia raises concern for diabetic ketoacidosis or hyperosmolar hyperglycemic state.','Delayed sample processing allows ongoing glycolysis by red and white blood cells, which can falsely lower results if the tube isn''t a glycolysis-inhibitor (gray-top/fluoride) tube or isn''t processed promptly. Recent food/drink intake invalidates a ''fasting'' result -- confirm true fasting status before acting on a borderline value.','Was I truly fasting for at least 8 hours, and could that affect this result? Does this result need to be confirmed with a repeat test or an HbA1c before a diagnosis is made? What lifestyle changes are recommended if my glucose is borderline? If I''m diagnosed with prediabetes or diabetes, what''s the plan for monitoring and follow-up?','A single elevated result is not usually enough to diagnose diabetes -- ADA criteria generally require either two abnormal tests or one abnormal test plus classic symptoms of high blood sugar. Depending on the result, your clinician may order a repeat fasting glucose, an HbA1c, or an oral glucose tolerance test, and may discuss diet, weight, and activity changes even for borderline (prediabetes-range) results.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (3,'hba1c','Hemoglobin A1c (Glycated Hemoglobin)','السكر التراكمي (الهيموجلوبين السكري)','HbA1c, A1C, Glycohemoglobin','Clinical Chemistry','Reflects average blood glucose over the preceding 2-3 months. Used for diagnosing diabetes/prediabetes and for long-term monitoring of glycemic control in known diabetics.','يعكس متوسط سكر الدم خلال 2-3 أشهر السابقة. يُستخدم لتشخيص السكري ومقدماته ولمتابعة ضبط السكر على المدى الطويل لدى مرضى السكري المعروفين.','Venous whole blood, EDTA tube','No fasting required. Not reliable in conditions affecting red cell lifespan (hemolytic anemia, recent transfusion, certain hemoglobinopathies).','لا يتطلب الصيام. غير موثوق في الحالات التي تؤثر على عمر كريات الدم الحمراء (الأنيميا الانحلالية، نقل الدم الحديث، بعض أمراض الهيموجلوبين الوراثية).','High-performance liquid chromatography (HPLC), immunoassay, or enzymatic assay, standardized to the NGSP/IFCC reference methods.','كروماتوغرافيا سائلة عالية الأداء (HPLC) أو مقايسة مناعية أو إنزيمية، معايرة وفق مرجعية NGSP/IFCC.','[{"parameter": "HbA1c", "population": "Normal", "range": "<5.7%"}, {"parameter": "HbA1c", "population": "Prediabetes", "range": "5.7%-6.4%"}, {"parameter": "HbA1c", "population": "Diabetes", "range": "\u22656.5%"}]',1,'HbA1c ≥6.5% is diagnostic of diabetes per ADA criteria (should be confirmed with a repeat test unless unequivocal hyperglycemia is present). Used alongside fasting glucose/OGTT; results may be less reliable in pregnancy, hemoglobinopathies, or conditions altering red cell turnover.','قيمة HbA1c ≥6.5% تُشخّص السكري وفق معايير ADA (يُفضّل تأكيدها بفحص متكرر ما لم يكن هناك ارتفاع سكر واضح). يُستخدم مع سكر الصائم أو اختبار تحمل الجلوكوز؛ قد تقل موثوقية النتيجة في الحمل أو أمراض الهيموجلوبين الوراثية أو الحالات المؤثرة على عمر كريات الدم الحمراء.','[{"condition": "Diabetes mellitus (diagnosis and monitoring)", "direction": "high"}, {"condition": "Prediabetes", "direction": "borderline high"}, {"condition": "Hemolytic anemia / recent blood loss", "direction": "may cause falsely low result"}]','[{"name": "American Diabetes Association (ADA) HbA1c diagnostic criteria", "url": "https://www.droracle.ai/articles/1136568/what-hba1c-range-defines-pre-diabetes", "accessed": "2026-07-14"}]',1,'2026-07-14 10:39:27','2026-07-14 10:39:27','["fasting-glucose", "lipid-panel", "creatinine", "insulin", "c-peptide"]',NULL,NULL,'What is my target HbA1c, and does it differ from the general population target based on my age or other health conditions? How does this result compare to my last one -- am I improving, stable, or worsening? Could an underlying condition (e.g., anemia, hemoglobin variant) be making this result inaccurate? How often should I repeat this test going forward?','If this is a new diagnosis of prediabetes or diabetes, your clinician will typically discuss lifestyle modification and, for diabetes, may start or adjust medication, along with baseline screening for diabetes-related complications (eye exam, kidney function, foot exam). If you''re already being treated for diabetes, the result guides whether your current treatment plan needs to be intensified, continued, or reduced.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (4,'lipid-panel','Lipid Panel','بروفايل الدهون','Lipid Profile, Cholesterol Panel','Clinical Chemistry','Assesses cardiovascular disease risk by measuring total cholesterol, LDL-C, HDL-C, and triglycerides.','يقيّم خطر أمراض القلب والأوعية الدموية عن طريق قياس الكوليسترول الكلي وLDL وHDL والدهون الثلاثية.','Venous serum or plasma','Traditionally requires 9-12 hour fasting; many guidelines now accept non-fasting samples for general screening (fasting still preferred when triglycerides are the primary focus or if very high triglycerides are suspected).','تقليديًا يتطلب صيام 9-12 ساعة؛ العديد من الإرشادات الحديثة تقبل العينة غير الصائمة للفحص العام (يُفضّل الصيام إذا كان التركيز على الدهون الثلاثية أو عند الاشتباه بارتفاعها الشديد).','Total cholesterol, HDL-C, and triglycerides measured directly by enzymatic methods; LDL-C typically calculated via the Friedewald formula (LDL = Total Cholesterol - HDL - Triglycerides/5) or measured directly when triglycerides are very high.','يُقاس الكوليسترول الكلي وHDL والدهون الثلاثية مباشرة بطرق إنزيمية؛ يُحسب LDL عادة بمعادلة فريدوالد (LDL = الكوليسترول الكلي - HDL - الدهون الثلاثية/5) أو يُقاس مباشرة عند ارتفاع الدهون الثلاثية بشدة.','[{"parameter": "Total cholesterol", "population": "Desirable", "range": "<200 mg/dL"}, {"parameter": "Total cholesterol", "population": "Borderline high", "range": "200-239 mg/dL"}, {"parameter": "Total cholesterol", "population": "High", "range": "\u2265240 mg/dL"}, {"parameter": "LDL cholesterol", "population": "Optimal", "range": "<100 mg/dL"}, {"parameter": "LDL cholesterol", "population": "Near optimal", "range": "100-129 mg/dL"}, {"parameter": "LDL cholesterol", "population": "Borderline high", "range": "130-159 mg/dL"}, {"parameter": "LDL cholesterol", "population": "High", "range": "160-189 mg/dL"}, {"parameter": "LDL cholesterol", "population": "Very high", "range": "\u2265190 mg/dL"}, {"parameter": "HDL cholesterol", "population": "Low (male)", "range": "<40 mg/dL"}, {"parameter": "HDL cholesterol", "population": "Low (female)", "range": "<50 mg/dL"}, {"parameter": "HDL cholesterol", "population": "High (protective)", "range": "\u226560 mg/dL"}, {"parameter": "Triglycerides", "population": "Normal", "range": "<150 mg/dL"}]',1,'High LDL-C and total cholesterol are associated with increased atherosclerotic cardiovascular disease (ASCVD) risk; low HDL-C is an independent risk factor. High triglycerides are linked to metabolic syndrome and, at very high levels (>500 mg/dL), pancreatitis risk. Interpreted alongside overall ASCVD risk factors (age, smoking, blood pressure, diabetes, family history) per NCEP ATP III / current cardiology guidelines.','ارتفاع LDL والكوليسترول الكلي يرتبط بزيادة خطر تصلب الشرايين وأمراض القلب؛ انخفاض HDL عامل خطر مستقل. ارتفاع الدهون الثلاثية يرتبط بمتلازمة التمثيل الغذائي، وعند الارتفاع الشديد جدًا (>500 مج/دل) يزيد خطر التهاب البنكرياس. تُفسَّر النتائج مع عوامل الخطر الكلية لأمراض القلب (العمر، التدخين، ضغط الدم، السكري، التاريخ العائلي) وفق إرشادات NCEP ATP III أو الإرشادات القلبية الحديثة.','[{"condition": "Atherosclerotic cardiovascular disease risk", "direction": "high LDL/TC, low HDL"}, {"condition": "Metabolic syndrome", "direction": "high triglycerides, low HDL"}, {"condition": "Familial hypercholesterolemia", "direction": "markedly high LDL"}, {"condition": "Pancreatitis risk", "direction": "very high triglycerides (>500 mg/dL)"}]','[{"name": "NHLBI - Third Report of the National Cholesterol Education Program (NCEP ATP III)", "url": "https://www.nhlbi.nih.gov/files/docs/guidelines/atp3xsum.pdf", "accessed": "2026-07-14"}, {"name": "myADLM (AACC) - Routine Lipid Testing, NCEP ATP III cut points", "url": "https://myadlm.org/science-and-research/clinical-chemistry/clinical-chemistry-trainee-council/pearls-of-laboratory-medicine-in-english/2012/routine-lipid-testing", "accessed": "2026-07-14"}]',1,'2026-07-14 10:39:27','2026-07-14 10:39:27','["hba1c", "fasting-glucose", "homocysteine", "lipoprotein-a", "crp", "alt-ast"]',NULL,NULL,'What is my individual cardiovascular risk category, and how does that affect my treatment targets? Do I need additional testing (e.g., Lp(a), ApoB, coronary calcium score) to refine my risk assessment? Should I be on lipid-lowering medication, or are lifestyle changes enough at this stage? How often should this be rechecked?','Your clinician will interpret this result alongside your overall cardiovascular risk factors (age, blood pressure, smoking status, diabetes, family history) rather than any single number in isolation. Depending on your risk category, next steps may include dietary and exercise counseling, a statin or other lipid-lowering therapy, or further risk-stratifying tests before a treatment decision is made.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (5,'creatinine','Serum Creatinine','الكرياتينين في الدم','Cr, Creat','Clinical Chemistry','Assesses kidney function; used to calculate estimated glomerular filtration rate (eGFR) and monitor chronic kidney disease or acute kidney injury.','يقيّم وظائف الكلى؛ يُستخدم لحساب معدل الترشيح الكبيبي التقديري (eGFR) ولمتابعة أمراض الكلى المزمنة أو الإصابة الكلوية الحادة.','Venous serum or plasma','No special fasting required, though very high dietary protein/meat intake shortly before the test can mildly elevate results.','لا يتطلب صيامًا خاصًا، إلا أن تناول كمية كبيرة من البروتين/اللحوم قبل الفحص مباشرة قد يرفع النتيجة بشكل طفيف.','Jaffe reaction (kinetic, alkaline picrate) or enzymatic method on automated chemistry analyzers; enzymatic methods are less prone to interference.','تفاعل جافيه (الحركي، البيكرات القلوي) أو الطريقة الإنزيمية على أجهزة الكيمياء الآلية؛ الطريقة الإنزيمية أقل عرضة للتداخلات.','[{"parameter": "Serum creatinine", "population": "Adult male", "range": "0.6-1.2 mg/dL (53-106 \u00b5mol/L)"}, {"parameter": "Serum creatinine", "population": "Adult female", "range": "0.5-1.1 mg/dL (44-97 \u00b5mol/L)"}]',1,'Elevated creatinine indicates reduced kidney filtration (acute kidney injury or chronic kidney disease); the degree of elevation and eGFR help stage severity. Low creatinine may reflect reduced muscle mass, malnutrition, or pregnancy rather than disease. Creatinine varies significantly by muscle mass, so eGFR (which adjusts for age/sex) is now routinely reported alongside it. Reference ranges vary by lab and assay method (Jaffe vs enzymatic) -- always confirm against the local laboratory''s reported range.','ارتفاع الكرياتينين يدل على انخفاض ترشيح الكلى (إصابة كلوية حادة أو مرض كلوي مزمن)؛ درجة الارتفاع وقيمة eGFR تساعدان في تحديد شدة الحالة. انخفاض الكرياتينين قد يعكس انخفاض الكتلة العضلية أو سوء التغذية أو الحمل وليس بالضرورة مرضًا. يتأثر الكرياتينين بشكل كبير بالكتلة العضلية، لذا يُبلَّغ eGFR (الذي يأخذ العمر والجنس بالحسبان) بشكل روتيني معه. القيم المرجعية تختلف حسب المعمل وطريقة التحليل (جافيه أو إنزيمية) -- يجب دائمًا مراجعة القيمة المرجعية المعتمدة في المعمل المحلي.','[{"condition": "Chronic kidney disease (CKD)", "direction": "high"}, {"condition": "Acute kidney injury (AKI)", "direction": "high, rising trend"}, {"condition": "Dehydration / prerenal azotemia", "direction": "high"}, {"condition": "Low muscle mass / malnutrition / pregnancy", "direction": "low"}]','[{"name": "Medscape/eMedicine - Lab Values, Normal Adult reference table", "url": "https://emedicine.medscape.com/article/2172316-overview", "accessed": "2026-07-14"}, {"name": "Medscape/eMedicine - Creatinine: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2054342-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 10:39:27','2026-07-14 10:39:27','["bun", "sodium", "potassium", "uric-acid"]','No single universal panic value exists for creatinine (unlike potassium or glucose), since acute versus chronic elevation matters more than an absolute cutoff -- however, a rapidly rising creatinine (e.g., doubling within 48 hours) meets criteria for acute kidney injury (KDIGO) and warrants urgent clinical correlation regardless of the absolute value.','Very high bilirubin or hemolysis can interfere with the Jaffe (alkaline picrate) method, historically the most common source of assay-specific bias; enzymatic methods are less affected. Recent very high dietary protein/meat intake or intense exercise (muscle breakdown) can transiently raise results; certain medications (e.g., trimethoprim, cimetidine) can raise creatinine by blocking tubular secretion without truly reducing GFR.','What is my estimated GFR (eGFR) based on this result, and what stage of kidney function does that represent? Is this a new finding or has my kidney function been declining over time? Could any of my medications need dose adjustment based on this result? Do I need additional testing (e.g., urine albumin/creatinine ratio, renal ultrasound) to investigate further?','An isolated mild abnormality is often rechecked to confirm it isn''t due to dehydration, recent heavy exercise, or a temporary cause. A significant or persistent abnormality typically prompts calculation of eGFR, review of medications that affect or are affected by kidney function, urine testing (e.g., albumin/creatinine ratio), and possible referral to nephrology depending on severity and trend.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (6,'alt-ast','ALT & AST (Liver Transaminases)','إنزيمات الكبد ALT وAST','SGPT, SGOT, Alanine aminotransferase, Aspartate aminotransferase, Liver enzymes','Clinical Chemistry','Screens for and monitors liver cell injury/inflammation; part of standard liver function panels.','فحص ومتابعة تلف/التهاب خلايا الكبد؛ جزء من فحوصات وظائف الكبد الأساسية.','Venous serum or plasma','Fasting is often requested (8-12h) when part of a broader metabolic panel, but isolated ALT/AST does not strictly require fasting. Recent strenuous exercise can transiently raise AST.','يُطلب الصيام غالبًا (8-12 ساعة) عند إجرائه ضمن فحص استقلابي أوسع، لكن ALT/AST بمفردهما لا يتطلبان صيامًا بالضرورة. ممارسة رياضة شاقة مؤخرًا قد ترفع AST مؤقتًا.','Enzymatic kinetic assay (IFCC-standardized method) on automated clinical chemistry analyzers.','مقايسة إنزيمية حركية (بطريقة معيارية وفق IFCC) على أجهزة الكيمياء الإكلينيكية الآلية.','[{"parameter": "ALT (SGPT)", "population": "Adult, general lab range", "range": "7-56 U/L", "notes": "Varies by lab/sex; some labs report lower sex-specific upper limits (e.g. ~29-33 U/L men, ~19-25 U/L women)"}, {"parameter": "AST (SGOT)", "population": "Adult, general lab range", "range": "10-40 U/L", "notes": "Minimal sex difference; varies by lab"}]',1,'Elevated ALT is relatively liver-specific and suggests hepatocellular injury (viral hepatitis, NAFLD/MASLD, drug-induced liver injury, alcohol). AST is less liver-specific (also present in cardiac/skeletal muscle, kidney, red cells). An AST:ALT ratio >2 classically suggests alcohol-related liver disease; ALT>AST is more typical of viral hepatitis or fatty liver. Reference ranges vary significantly between laboratories and by sex -- always compare against the reporting lab''s own range.','ارتفاع ALT مؤشر أكثر تخصصًا لتلف خلايا الكبد (التهاب كبدي فيروسي، الكبد الدهني، تلف الكبد الدوائي، الكحول). AST أقل تخصصًا للكبد (موجود أيضًا في عضلة القلب والعضلات الهيكلية والكلى وكريات الدم الحمراء). نسبة AST:ALT أكبر من 2 تشير تقليديًا لمرض كبدي كحولي؛ بينما ALT أعلى من AST أكثر شيوعًا في التهاب الكبد الفيروسي أو الكبد الدهني. القيم المرجعية تختلف بشكل كبير بين المعامل وحسب الجنس -- يجب دائمًا مقارنة النتيجة بالقيمة المرجعية الخاصة بالمعمل الذي أجرى الفحص.','[{"condition": "Non-alcoholic fatty liver disease (NAFLD/MASLD)", "direction": "mild-moderate high, ALT>AST"}, {"condition": "Viral hepatitis (acute)", "direction": "markedly high, ALT>AST"}, {"condition": "Alcohol-related liver disease", "direction": "high, AST:ALT ratio >2"}, {"condition": "Drug-induced liver injury", "direction": "variable, can be marked"}, {"condition": "Muscle injury / rhabdomyolysis (isolated AST rise)", "direction": "high AST, normal ALT"}]','[{"name": "Medscape/eMedicine - Liver Function Tests reference intervals discussion", "url": "https://www.droracle.ai/articles/399545/what-are-the-normal-ranges-for-alanine-transaminase-alt", "accessed": "2026-07-14"}, {"name": "General clinical lab reference compilation (ALT 7-56 U/L, AST 10-40 U/L consensus across multiple lab sources)", "url": "https://www.doctronic.ai/blog/liver-function-tests-ast-alt-alp-explained/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:39:27','2026-07-14 10:39:27','["alkaline-phosphatase", "ggt", "total-bilirubin", "albumin", "total-protein", "pt-inr"]',NULL,NULL,'Is this likely from fatty liver, alcohol, a viral infection, or a medication? Do I need further testing (viral hepatitis panel, imaging) to find the cause? How often should this be rechecked?','Mild, isolated elevation is often rechecked in a few weeks along with a review of alcohol use and medications. Persistent or significant elevation typically leads to a broader liver workup -- viral hepatitis serology, liver imaging, and sometimes a liver biopsy -- depending on the pattern and your risk factors.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (7,'tsh','Thyroid-Stimulating Hormone','الهرمون المنبه للغدة الدرقية','TSH, Thyrotropin','Immunoassay / Endocrinology','First-line screening test for thyroid dysfunction (hypothyroidism and hyperthyroidism); most sensitive single test for thyroid function.','الفحص الأول للكشف عن اضطرابات الغدة الدرقية (قصور أو فرط نشاط)؛ أكثر فحص فردي حساسية لوظيفة الغدة الدرقية.','Venous serum or plasma','No fasting required. Can be drawn any time of day, though TSH has mild diurnal variation (slightly higher in early morning).','لا يتطلب الصيام. يمكن سحبه في أي وقت من اليوم، رغم وجود تفاوت يومي بسيط (يكون أعلى قليلاً في الصباح الباكر).','Chemiluminescent immunoassay (CLIA) or electrochemiluminescence immunoassay (ECLIA) on automated immunoassay analyzers.','مقايسة مناعية بالإشعاع الكيميائي (CLIA) أو الإشعاع الكيميائي الإلكتروني (ECLIA) على أجهزة المقايسة المناعية الآلية.','[{"parameter": "TSH", "population": "Non-pregnant adult", "range": "0.4-4.0 mIU/L", "notes": "Standard range used by most US labs; upper limit trends higher with age and varies by assay/lab (some report up to 4.5-5.0 mIU/L)"}]',1,'High TSH suggests primary hypothyroidism (underactive thyroid); low TSH suggests hyperthyroidism (overactive thyroid) or, less commonly, secondary/central hypothyroidism from pituitary dysfunction. Always interpreted with free T4 (and free T3 when relevant) to confirm and characterize thyroid status. Reference ranges shift with age (higher upper limit in older adults) and pregnancy (trimester-specific lower targets).','ارتفاع TSH يشير إلى قصور أولي في الغدة الدرقية؛ انخفاضه يشير إلى فرط نشاط الغدة الدرقية أو -بشكل أقل شيوعًا- قصور مركزي ناتج عن خلل في الغدة النخامية. يُفسَّر دائمًا مع T4 الحر (وT3 الحر عند الحاجة) لتأكيد وتوصيف حالة الغدة. القيم المرجعية تتغير مع العمر (الحد الأعلى يرتفع لدى كبار السن) والحمل (أهداف أقل خاصة بكل ثلث من الحمل).','[{"condition": "Primary hypothyroidism (e.g., Hashimoto''s thyroiditis)", "direction": "high"}, {"condition": "Hyperthyroidism (e.g., Graves'' disease, toxic nodule)", "direction": "low"}, {"condition": "Subclinical hypothyroidism", "direction": "mildly high with normal free T4"}, {"condition": "Central (pituitary) hypothyroidism", "direction": "low or inappropriately normal despite low free T4"}]','[{"name": "StatPearls / NCBI Bookshelf - Screening and Treatment of Subclinical Hypothyroidism/Hyperthyroidism", "url": "https://www.ncbi.nlm.nih.gov/books/NBK83492/", "accessed": "2026-07-14"}, {"name": "PMC - Biochemical Testing of the Thyroid: TSH is the Best and Oftentimes Only Test Needed", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC5321289/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:39:27','2026-07-14 10:39:27','["free-t4", "free-t3", "vitamin-d", "prolactin", "anti-tpo"]',NULL,NULL,'Do I need a free T4 (and possibly free T3) to fully interpret this result? Could any of my medications (e.g., biotin supplements, thyroid medication timing) be affecting the accuracy of this result? If my result is abnormal, is this likely to be a temporary or a chronic condition? How often will my thyroid function need to be monitored going forward?','An abnormal TSH is typically followed up with a free T4 (and sometimes free T3) to determine the type and severity of thyroid dysfunction before any treatment decision. Mildly abnormal results in an otherwise well patient are often rechecked in a few weeks to months before starting treatment, since transient illness and lab variability can affect a single result.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (8,'crp','C-Reactive Protein (CRP / hs-CRP)','البروتين المتفاعل C','CRP, hs-CRP, High-sensitivity CRP','Immunoassay / Inflammation Markers','Non-specific marker of acute inflammation or infection (standard CRP); the high-sensitivity assay (hs-CRP) is additionally used for cardiovascular risk assessment.','مؤشر غير نوعي للالتهاب الحاد أو العدوى (CRP العادي)؛ ويُستخدم الفحص عالي الحساسية (hs-CRP) إضافيًا لتقييم خطر أمراض القلب والأوعية الدموية.','Venous serum or plasma','No fasting required for standard CRP; fasting sample preferred if drawn alongside a lipid panel. Avoid testing during acute unrelated illness when using hs-CRP for cardiovascular risk assessment.','لا يتطلب CRP العادي صيامًا؛ يُفضَّل عينة صائمة إذا سُحبت مع بروفايل الدهون. يُنصح بتجنب الفحص أثناء مرض حاد غير متعلق عند استخدام hs-CRP لتقييم خطر القلب.','Immunoturbidimetric or immunonephelometric assay on automated chemistry analyzers; high-sensitivity assays use enhanced detection for the low mg/L range needed in cardiovascular risk assessment.','مقايسة بالعكارة المناعية أو الانتشار الضوئي المناعي على أجهزة الكيمياء الآلية؛ المقايسات عالية الحساسية تستخدم كشفًا معززًا للنطاق المنخفض اللازم لتقييم خطر القلب.','[{"parameter": "Standard CRP", "population": "Normal", "range": "<1.0 mg/dL (<10 mg/L)"}, {"parameter": "hs-CRP (cardiovascular risk)", "population": "Low risk", "range": "<1.0 mg/L"}, {"parameter": "hs-CRP (cardiovascular risk)", "population": "Moderate risk", "range": "1.0-3.0 mg/L"}, {"parameter": "hs-CRP (cardiovascular risk)", "population": "High risk", "range": ">3.0 mg/L"}, {"parameter": "CRP", "population": "Acute inflammation", "range": ">10 mg/L (not used for CV risk stratification)"}]',1,'Markedly elevated CRP (>10 mg/L) indicates active acute inflammation or infection (bacterial infections typically drive levels higher than viral ones) but does not identify the source; further workup is needed. For cardiovascular risk stratification, hs-CRP should be measured on two occasions at least 2 weeks apart in a metabolically stable state, and used as a risk-enhancing factor alongside traditional risk scores (per ACC/AHA guidance), not in isolation.','الارتفاع الملحوظ في CRP (>10 مج/لتر) يدل على التهاب حاد نشط أو عدوى (العدوى البكتيرية عادة ترفعه أكثر من الفيروسية) لكنه لا يحدد المصدر، ويستلزم فحوصات إضافية. لتقييم خطر القلب، يُفضَّل قياس hs-CRP مرتين بفارق أسبوعين على الأقل في حالة استقرار استقلابي، ويُستخدم كعامل مساعد لتعزيز تقييم الخطر مع المقاييس التقليدية (وفق إرشادات ACC/AHA) وليس بمفرده.','[{"condition": "Bacterial infection", "direction": "markedly high (often >40-50 mg/L)"}, {"condition": "Viral infection", "direction": "mild-moderate elevation (typically <20-30 mg/L)"}, {"condition": "Acute myocardial infarction / plaque rupture", "direction": "high"}, {"condition": "Chronic inflammatory conditions (e.g., rheumatoid arthritis, IBD)", "direction": "persistently elevated"}, {"condition": "Cardiovascular risk stratification (hs-CRP)", "direction": "elevated indicates higher residual risk"}]','[{"name": "Medscape/eMedicine - High-Sensitivity C-Reactive Protein: Reference Range, Interpretation", "url": "https://emedicine.medscape.com/article/2094831-overview", "accessed": "2026-07-14"}, {"name": "Medscape/eMedicine - C-Reactive Protein: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2086909-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 10:39:27','2026-07-14 10:39:27','["esr", "cbc", "lipid-panel", "ferritin"]',NULL,NULL,'Does this level point to a specific infection or inflammatory condition, or is it too general to tell? Do I need more specific testing to find the source? If this is for cardiovascular risk, was it drawn correctly (fasting, not during acute illness)?','A markedly elevated CRP with symptoms usually prompts a search for an infectious or inflammatory source (exam, cultures, imaging as indicated). If used for cardiovascular risk assessment, an elevated result is factored in alongside your other risk factors rather than treated as a standalone diagnosis.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (9,'sodium','Sodium (Na)','','Na, Serum Sodium','Clinical Chemistry','Assesses fluid balance, kidney function, and electrolyte status; part of the basic/comprehensive metabolic panel.',NULL,'Venous serum or plasma','No fasting required. Part of routine electrolyte/metabolic panels.',NULL,'Ion-selective electrode (ISE) method on automated chemistry analyzers.',NULL,'[{"parameter": "Sodium", "population": "Adult", "range": "135-145 mEq/L (135-145 mmol/L)"}]',1,'Hyponatremia (low sodium) may reflect fluid overload, SIADH, heart/liver/kidney failure, or diuretic use, and can cause confusion or seizures if severe/acute. Hypernatremia (high sodium) usually reflects free water loss or deficit (dehydration, diabetes insipidus) and can cause lethargy or seizures. Always interpreted alongside volume status and other electrolytes.',NULL,'[{"condition": "SIADH / fluid overload / heart failure", "direction": "low"}, {"condition": "Dehydration / diabetes insipidus", "direction": "high"}]','[{"name": "MedlinePlus (NIH/NLM) - Basic Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003462.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["potassium", "chloride", "bicarbonate-co2", "creatinine", "bun"]','Adult critical range: <120 mmol/L or >160 mmol/L (ARUP Laboratories). Severe hypo- or hypernatremia, especially if of rapid onset, can cause seizures, cerebral edema, or altered consciousness and requires urgent clinical correlation -- correction rate must be carefully controlled to avoid osmotic demyelination syndrome when correcting chronic hyponatremia.','Severe hyperlipidemia or hyperproteinemia can cause spuriously low sodium on older indirect ion-selective electrode methods (pseudohyponatremia) -- less of an issue with modern direct ISE methods, but worth considering if the result doesn''t fit the clinical picture. Drawing from an arm receiving IV fluids can dilute or skew the result.','Is my result related to fluid intake, a medication, or an underlying medical condition? How quickly does this need to be corrected, and what''s the safe pace? Do I need further testing (like urine sodium or osmolality) to find the cause?','Mild abnormalities are often monitored with repeat testing and a review of fluid intake and medications. More significant abnormalities prompt a workup for the underlying cause and, if needed, careful correction under medical supervision -- correction that''s too fast can itself cause serious complications, so this is not something to self-manage.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (10,'potassium','Potassium (K)','','K, Serum Potassium','Clinical Chemistry','Assesses electrolyte balance, kidney function, and cardiac/neuromuscular risk; critical value in emergency settings.',NULL,'Venous serum or plasma','No fasting required. Avoid prolonged tourniquet time or hemolysis, which can falsely elevate results.',NULL,'Ion-selective electrode (ISE) method on automated chemistry analyzers.',NULL,'[{"parameter": "Potassium", "population": "Adult", "range": "3.7-5.2 mEq/L (3.7-5.2 mmol/L)", "notes": "Some labs report 3.5-5.0 mEq/L; always confirm against local range"}]',1,'Hypokalemia (low potassium) can cause muscle weakness and cardiac arrhythmias; common causes include diuretics, vomiting/diarrhea, or inadequate intake. Hyperkalemia (high potassium) is a medical emergency at high levels -- can cause life-threatening cardiac arrhythmias; common causes include renal failure, certain medications (ACE inhibitors, potassium-sparing diuretics), and tissue breakdown.',NULL,'[{"condition": "Diuretic use / GI losses (vomiting, diarrhea)", "direction": "low"}, {"condition": "Renal failure / ACE inhibitor or ARB use / tissue breakdown", "direction": "high"}]','[{"name": "MedlinePlus (NIH/NLM) - Basic Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003462.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["sodium", "chloride", "bicarbonate-co2", "creatinine"]','Adult critical range: <3.0 mmol/L or >6.1 mmol/L (ARUP Laboratories). Severe hypo- or hyperkalemia can cause life-threatening cardiac arrhythmias and requires immediate physician notification and, often, emergency treatment (e.g., IV calcium, insulin/glucose, or potassium replacement depending on direction).','Hemolysis during or after collection (e.g., difficult draw, prolonged tourniquet time, vigorous mixing) releases intracellular potassium and is the most common cause of a falsely elevated result -- a hemolyzed sample should prompt a repeat draw before acting on an unexpectedly high value. Fist clenching during venipuncture can also transiently raise results. Marked leukocytosis or thrombocytosis can cause pseudohyperkalemia in vitro from cell lysis in the tube after collection, without reflecting the true in-vivo level.','Was this sample checked for hemolysis, since that''s a common cause of a falsely high reading? Do I need an ECG given this result? Are any of my medications (like ACE inhibitors, ARBs, or potassium-sparing diuretics) affecting this level?','A significantly abnormal result often prompts an ECG to check for cardiac effects, a repeat blood draw to confirm the value wasn''t a lab artifact, and review of medications that affect potassium. Treatment (if needed) depends on the direction and severity, and severe cases require urgent medical care.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (11,'chloride','Chloride (Cl)','','Cl, Serum Chloride','Clinical Chemistry','Assesses electrolyte and acid-base balance; usually interpreted together with sodium, bicarbonate, and anion gap.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Ion-selective electrode (ISE) method on automated chemistry analyzers.',NULL,'[{"parameter": "Chloride", "population": "Adult", "range": "96-106 mEq/L (96-106 mmol/L)"}]',1,'Low chloride can accompany metabolic alkalosis, prolonged vomiting, or SIADH. High chloride can accompany metabolic acidosis (e.g., diarrhea, renal tubular acidosis) or dehydration. Chloride is most useful interpreted alongside sodium, bicarbonate, and the calculated anion gap.',NULL,'[{"condition": "Metabolic alkalosis / prolonged vomiting", "direction": "low"}, {"condition": "Non-anion-gap metabolic acidosis / dehydration", "direction": "high"}]','[{"name": "MedlinePlus (NIH/NLM) - Basic Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003462.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["sodium", "potassium", "bicarbonate-co2"]','Adult critical range: <81 mmol/L or >119 mmol/L (commonly cited hospital critical-value threshold; confirm against the reporting lab''s own policy, as chloride appears on a minority of institutional critical-value lists).','Severe hypertriglyceridemia can cause a spurious result (pseudohypochloremia) with older methodologies, similar to the sodium electrode interference. Bromide intoxication can falsely elevate chloride results on some analyzer methods due to cross-reactivity.','How does this fit with my other electrolyte results (sodium, bicarbonate)? Is there a specific acid-base or fluid balance issue this is pointing to?','Chloride is rarely acted on alone -- your clinician will look at it together with sodium, bicarbonate, and the anion gap to understand the full picture, and further testing depends on what that combination suggests.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (12,'bicarbonate-co2','Bicarbonate (CO2, Total Carbon Dioxide)','','CO2, HCO3, Bicarb, TCO2','Clinical Chemistry','Reflects the body''s acid-base (bicarbonate buffer) status; part of the basic/comprehensive metabolic panel.',NULL,'Venous serum or plasma','No fasting required. Sample should be analyzed promptly, as CO2 can be lost from an exposed sample over time.',NULL,'Enzymatic or electrode-based method on automated chemistry analyzers.',NULL,'[{"parameter": "Bicarbonate (CO2)", "population": "Adult", "range": "23-29 mEq/L (23-29 mmol/L)"}]',1,'Low bicarbonate suggests metabolic acidosis (e.g., diabetic ketoacidosis, renal failure, lactic acidosis, diarrhea) or respiratory compensation for chronic respiratory alkalosis. High bicarbonate suggests metabolic alkalosis (e.g., prolonged vomiting, diuretic use) or renal compensation for chronic respiratory acidosis (e.g., COPD). Best interpreted alongside blood gas analysis when acid-base status is the primary concern.',NULL,'[{"condition": "Diabetic ketoacidosis / renal failure / lactic acidosis", "direction": "low"}, {"condition": "Prolonged vomiting / chronic CO2 retention (e.g., COPD)", "direction": "high"}]','[{"name": "MedlinePlus (NIH/NLM) - Basic Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003462.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["sodium", "potassium", "chloride"]','Adult critical range: <11 mmol/L or >39 mmol/L (commonly cited hospital critical-value threshold). Severe derangement reflects a significant underlying acid-base disorder (e.g., severe metabolic acidosis or a compensatory response to chronic respiratory disease) and should prompt correlation with an arterial blood gas.','Bicarbonate measured on a routine chemistry panel is total CO2 (bicarbonate plus a small amount of dissolved CO2), which is not identical to the calculated HCO3 on an arterial blood gas -- results can differ slightly between a venous chemistry panel and an ABG drawn at the same time. A sample left uncapped or handled improperly can lose CO2 to the air, falsely lowering the result.','Does this suggest a breathing (respiratory) or metabolic issue? Do I need a blood gas test to get a clearer picture? Is this related to my kidney function or a medication I''m taking?','An abnormal result usually prompts review of the full electrolyte panel and clinical context; if the cause isn''t clear from that, an arterial blood gas may be ordered to directly assess your acid-base status.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (13,'bun','Blood Urea Nitrogen (BUN)','','BUN, Urea Nitrogen','Clinical Chemistry','Assesses kidney function and hydration status; used alongside creatinine to evaluate renal function (BUN:creatinine ratio).',NULL,'Venous serum or plasma','No special fasting required; high-protein meals or GI bleeding can transiently raise results.',NULL,'Enzymatic (urease-based) method on automated chemistry analyzers.',NULL,'[{"parameter": "BUN", "population": "Adult", "range": "6-20 mg/dL (2.14-7.14 mmol/L)"}]',1,'Elevated BUN suggests reduced kidney filtration, dehydration, high protein intake, or GI bleeding (digested blood raises urea). A BUN:creatinine ratio >20:1 suggests a prerenal cause (dehydration, GI bleed) rather than intrinsic kidney disease. Low BUN may reflect liver disease, malnutrition, or overhydration.',NULL,'[{"condition": "Dehydration / prerenal azotemia / GI bleeding", "direction": "high, elevated BUN:creatinine ratio"}, {"condition": "Intrinsic kidney disease", "direction": "high, proportionate rise with creatinine"}, {"condition": "Liver disease / malnutrition / overhydration", "direction": "low"}]','[{"name": "MedlinePlus (NIH/NLM) - Basic Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003462.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["creatinine", "sodium", "potassium", "albumin"]','No single universal panic value; markedly elevated BUN (often with a disproportionately high BUN:creatinine ratio) in an acutely ill patient warrants urgent evaluation for GI bleeding, severe dehydration, or acute kidney injury.','High-protein diet, GI bleeding (digested blood is a protein load metabolized to urea), and corticosteroid use raise BUN independent of true kidney function. Dehydration/volume depletion raises BUN more than creatinine (elevated BUN:creatinine ratio), while liver disease and malnutrition can lower it independent of kidney function.','Does this reflect a hydration issue, my diet, or an actual change in kidney function? How does this compare with my creatinine result? Do I need repeat testing to see if this is a trend?','BUN is usually interpreted together with creatinine -- if both are elevated together, it points more toward a true kidney issue; if BUN is elevated out of proportion to creatinine, dehydration or GI bleeding are considered. Your clinician will decide on further testing based on that pattern.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (14,'calcium','Calcium, Total (Serum)','','Ca, Serum Calcium, Total Calcium','Clinical Chemistry','Assesses bone, parathyroid, and kidney health; important in neuromuscular and cardiac function.',NULL,'Venous serum or plasma','No fasting required. Total calcium should be interpreted alongside serum albumin, since roughly 40% of calcium is protein-bound (a ''corrected calcium'' calculation is used when albumin is abnormal).',NULL,'Colorimetric (e.g., o-cresolphthalein complexone) method on automated chemistry analyzers.',NULL,'[{"parameter": "Total calcium", "population": "Adult", "range": "8.5-10.2 mg/dL (2.13-2.55 mmol/L)"}]',1,'Hypercalcemia is most commonly caused by primary hyperparathyroidism or malignancy; symptoms may include fatigue, constipation, kidney stones, and confusion at high levels. Hypocalcemia may be caused by hypoparathyroidism, vitamin D deficiency, or renal failure, and can cause neuromuscular irritability (tingling, muscle cramps, tetany). Always check ionized calcium or corrected calcium (for albumin) when the total calcium result is borderline or albumin is abnormal.',NULL,'[{"condition": "Primary hyperparathyroidism / malignancy", "direction": "high"}, {"condition": "Hypoparathyroidism / vitamin D deficiency / renal failure", "direction": "low"}]','[{"name": "MedlinePlus (NIH/NLM) - Comprehensive Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003468.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["phosphorus", "magnesium", "albumin", "pth", "vitamin-d"]','Adult critical range for total calcium: <6.0 mg/dL or >13.0 mg/dL (ARUP Laboratories). Severe hypocalcemia can cause tetany, seizures, or cardiac arrhythmia (prolonged QT); severe hypercalcemia can cause altered mental status, cardiac arrhythmia, and is a medical emergency.','Total calcium result is significantly affected by serum albumin, since roughly 40% of calcium is protein-bound -- a low albumin can make total calcium appear falsely low even when the physiologically active ionized calcium is normal (a ''corrected calcium'' calculation, or a direct ionized calcium measurement, should be used when albumin is abnormal). Prolonged tourniquet time and drawing above an IV line with calcium-containing fluids can also skew results.','Was this corrected for my albumin level, or do I need an ionized calcium test for a clearer picture? Do I need a PTH or vitamin D test to find the cause? Are there symptoms I should watch for?','Borderline results are often re-checked alongside albumin (or with a direct ionized calcium test). A confirmed abnormality typically leads to PTH and vitamin D testing to identify the cause, since treatment differs significantly depending on whether the source is parathyroid, kidney, bone, or nutritional.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (15,'magnesium','Magnesium (Mg)','','Mg, Serum Magnesium','Clinical Chemistry','Assesses magnesium status, relevant to neuromuscular, cardiac, and metabolic function; often checked alongside calcium and potassium in unexplained arrhythmia or refractory hypokalemia/hypocalcemia.',NULL,'Venous serum or plasma','No special fasting required.',NULL,'Colorimetric method on automated chemistry analyzers.',NULL,'[{"parameter": "Serum magnesium", "population": "Adult", "range": "1.7-2.2 mg/dL (0.70-0.91 mmol/L)", "notes": "Serum level reflects only ~1% of total body magnesium and may not detect intracellular depletion"}]',1,'Hypomagnesemia is associated with alcohol use disorder, GI losses (diarrhea, malabsorption), certain diuretics/proton pump inhibitors, and can cause or worsen refractory hypokalemia and hypocalcemia, as well as cardiac arrhythmias. Hypermagnesemia is uncommon outside renal failure or magnesium supplementation/antacid overuse, and can cause weakness, hypotension, or cardiac conduction abnormalities at high levels.',NULL,'[{"condition": "Alcohol use disorder / GI losses / diuretic or PPI use", "direction": "low"}, {"condition": "Renal failure / magnesium supplementation overuse", "direction": "high"}]','[{"name": "MedlinePlus (NIH/NLM) - Magnesium Blood Test", "url": "https://medlineplus.gov/ency/article/003487.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["calcium", "phosphorus", "potassium"]','Adult critical range: <1.0 mg/dL or >9.0 mg/dL (ARUP Laboratories). Severe hypomagnesemia can cause seizures and cardiac arrhythmias (including torsades de pointes); severe hypermagnesemia (usually from renal failure plus magnesium administration, e.g., in eclampsia treatment) can cause respiratory depression and cardiac arrest.','Hemolysis falsely raises results, since intracellular magnesium concentration is higher than serum. Serum magnesium reflects only about 1% of total body stores, so a normal result does not rule out significant intracellular/total body depletion.','Could this be related to a medication I''m taking (like a diuretic or PPI) or my diet? Does this explain any symptoms I''ve been having? Do I need supplementation, and for how long?','Mild deficiency is often managed with oral supplementation and addressing the underlying cause (medication review, diet). More significant deficiency, especially with symptoms, may need IV replacement and closer monitoring, particularly if potassium or calcium are also low.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (16,'phosphorus','Phosphorus (Inorganic Phosphate)','','Phosphate, PO4, Serum Phosphorus','Clinical Chemistry','Assesses bone, kidney, and parathyroid-related mineral metabolism; often checked alongside calcium and magnesium.',NULL,'Venous serum or plasma','Morning fasting sample preferred, as phosphorus has diurnal variation and is affected by recent meals.',NULL,'Colorimetric (ammonium molybdate) method on automated chemistry analyzers.',NULL,'[{"parameter": "Serum phosphorus", "population": "Adult", "range": "2.5-4.5 mg/dL (0.81-1.45 mmol/L)", "notes": "Higher in children; varies modestly across labs"}]',1,'Hypophosphatemia may occur with refeeding syndrome, hyperparathyroidism, or malnutrition, and severe cases can cause muscle weakness or respiratory failure. Hyperphosphatemia is most often seen in chronic kidney disease (reduced renal excretion) or tumor lysis syndrome, and contributes to secondary hyperparathyroidism and vascular calcification in CKD.',NULL,'[{"condition": "Refeeding syndrome / hyperparathyroidism / malnutrition", "direction": "low"}, {"condition": "Chronic kidney disease / tumor lysis syndrome", "direction": "high"}]','[{"name": "ScienceDirect - Magnesium and phosphorus (clinical review, adult reference range)", "url": "https://www.sciencedirect.com/science/article/abs/pii/S0140673697105359", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["calcium", "magnesium", "pth", "vitamin-d"]','Adult critical range: <1.0 mg/dL or >9.0 mg/dL (ARUP Laboratories). Severe hypophosphatemia can cause muscle weakness, respiratory failure, and cardiac dysfunction (classically seen in refeeding syndrome); severe hyperphosphatemia (usually in renal failure or tumor lysis syndrome) contributes to hypocalcemia and metastatic calcification risk.','Hemolysis falsely raises results. Recent meals (phosphorus has diurnal variation and is affected by carbohydrate intake, which shifts phosphate intracellularly) can lower results -- a fasting morning sample is preferred for accurate interpretation.','Is this related to my kidney function, my diet, or a medication? Do I need this monitored regularly given my other health conditions? What symptoms should prompt me to seek care sooner?','Management depends heavily on the cause and direction of the abnormality -- kidney disease-related elevation is managed differently than a nutritional deficiency, so your clinician will look at your overall clinical picture (especially kidney function and calcium) before deciding on treatment.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (17,'albumin','Albumin, Serum','','Serum Albumin','Clinical Chemistry','Assesses liver synthetic function and nutritional/inflammatory status; also affects interpretation of total calcium and drug levels.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Colorimetric (bromocresol green or bromocresol purple dye-binding) method on automated chemistry analyzers.',NULL,'[{"parameter": "Serum albumin", "population": "Adult", "range": "3.4-5.4 g/dL (34-54 g/L)"}]',1,'Low albumin can reflect chronic liver disease (reduced synthesis), malnutrition, nephrotic syndrome (urinary loss), or acute/chronic inflammation (albumin is a negative acute-phase reactant). It is not a reliable acute marker on its own, since its half-life (~20 days) makes it slow to change. High albumin is uncommon and usually reflects dehydration/hemoconcentration.',NULL,'[{"condition": "Chronic liver disease", "direction": "low"}, {"condition": "Nephrotic syndrome (urinary protein loss)", "direction": "low"}, {"condition": "Malnutrition / chronic inflammation", "direction": "low"}, {"condition": "Dehydration", "direction": "high (relative hemoconcentration)"}]','[{"name": "MedlinePlus (NIH/NLM) - Comprehensive Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003468.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["total-protein", "alt-ast"]',NULL,NULL,'Is this more likely related to nutrition, liver function, kidney protein loss, or inflammation? Does this affect how other test results (like calcium) should be interpreted? Do I need further liver or kidney testing?','A low albumin prompts your clinician to consider liver disease, kidney protein loss, malnutrition, or chronic inflammation as possible causes, and further testing (liver panel, urine protein, nutritional assessment) is guided by which of these seems most likely given your history and other results.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (18,'total-bilirubin','Total Bilirubin','','Bilirubin, T. Bili','Clinical Chemistry','Assesses liver function and red blood cell breakdown (hemolysis); part of standard liver function panels.',NULL,'Venous serum or plasma','Fasting preferred but not strictly required; protect sample from light, as bilirubin degrades on exposure.',NULL,'Diazo colorimetric method on automated chemistry analyzers.',NULL,'[{"parameter": "Total bilirubin", "population": "Adult", "range": "0.1-1.2 mg/dL (2-21 \u00b5mol/L)"}]',1,'Elevated total bilirubin causes jaundice when sufficiently high. Predominantly unconjugated (indirect) elevation suggests hemolysis, ineffective erythropoiesis, or Gilbert syndrome. Predominantly conjugated (direct) elevation suggests hepatocellular or cholestatic (bile duct obstruction) liver disease. Fractionation into direct/indirect bilirubin is needed to distinguish these causes.',NULL,'[{"condition": "Hemolysis / Gilbert syndrome (unconjugated)", "direction": "high, indirect predominant"}, {"condition": "Biliary obstruction / cholestatic or hepatocellular liver disease (conjugated)", "direction": "high, direct predominant"}]','[{"name": "MedlinePlus (NIH/NLM) - Comprehensive Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003468.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["alt-ast", "alkaline-phosphatase", "ggt", "cbc"]',NULL,NULL,'Is this from a liver problem, a bile duct blockage, or red blood cell breakdown? Do I need the direct/indirect breakdown to clarify the cause? Are my liver enzymes affected too?','Your clinician will look at the direct vs. indirect fractions together with your liver enzymes (ALT, AST, ALP) to narrow down the cause, and further testing (imaging, hemolysis workup) depends on that pattern.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (19,'alkaline-phosphatase','Alkaline Phosphatase (ALP)','','ALP, Alk Phos','Clinical Chemistry','Screens for bile duct/liver (cholestatic) disease and bone disorders; part of standard liver function panels.',NULL,'Venous serum or plasma','No special fasting required.',NULL,'Enzymatic kinetic assay (IFCC-standardized method) on automated chemistry analyzers.',NULL,'[{"parameter": "Alkaline phosphatase", "population": "Adult", "range": "20-130 U/L (0.33-2.17 \u00b5kat/L)", "notes": "Markedly higher in growing children/adolescents due to bone turnover"}]',1,'Elevated ALP suggests bile duct obstruction/cholestatic liver disease or a bone disorder with increased osteoblastic activity (e.g., Paget disease, bone metastases, fractures healing). GGT can help distinguish a liver source (GGT also elevated) from a bone source (GGT normal). Physiologically elevated during pregnancy (placental source) and childhood growth.',NULL,'[{"condition": "Biliary obstruction / cholestatic liver disease", "direction": "high, with elevated GGT"}, {"condition": "Bone disease (Paget disease, bone metastases, fractures)", "direction": "high, with normal GGT"}]','[{"name": "MedlinePlus (NIH/NLM) - Comprehensive Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003468.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["ggt", "alt-ast", "total-bilirubin", "calcium", "phosphorus"]',NULL,NULL,'Does this look like it''s coming from my liver or my bones? Do I need a GGT test to help clarify that? Is this related to a medication or a normal life stage (like pregnancy or growth)?','A GGT test is typically added to determine whether an elevated ALP is coming from the liver/biliary system (GGT also elevated) or from bone (GGT normal), which then guides whether liver imaging or a bone-focused workup is the next step.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (20,'ggt','Gamma-Glutamyl Transferase (GGT)','','GGT, Gamma-GT','Clinical Chemistry','Helps determine whether an elevated alkaline phosphatase originates from the liver/biliary tract or from bone; sensitive marker of alcohol use and biliary disease.',NULL,'Venous serum or plasma','No special fasting required.',NULL,'Enzymatic kinetic assay on automated chemistry analyzers.',NULL,'[{"parameter": "GGT", "population": "Adults \u226545 years (both sexes)", "range": "8-38 U/L"}, {"parameter": "GGT", "population": "Women <45 years", "range": "5-27 U/L"}]',1,'Elevated GGT is a sensitive marker for biliary tract disease, alcohol-related liver injury, and can be induced by certain medications. Used mainly to confirm a hepatic/biliary source when ALP is elevated (GGT is not made by bone, so a normal GGT with high ALP points to a bone cause instead).',NULL,'[{"condition": "Biliary disease / cholestasis", "direction": "high"}, {"condition": "Alcohol-related liver injury / chronic alcohol use", "direction": "high"}, {"condition": "Medication induction (e.g., anticonvulsants)", "direction": "high"}]','[{"name": "Medscape/eMedicine - Lab Values, Normal Adult (reference table)", "url": "https://emedicine.medscape.com/article/2172316-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["alkaline-phosphatase", "alt-ast", "total-bilirubin"]',NULL,NULL,'Does this confirm a liver or biliary source for another abnormal result (like ALP)? Could alcohol use or a medication be contributing? Do I need imaging of my liver or bile ducts?','An elevated GGT alongside other liver test abnormalities typically prompts further evaluation of the liver and biliary system, which may include imaging (ultrasound) and a review of alcohol intake and medications.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (21,'uric-acid','Uric Acid, Serum','','Serum Urate','Clinical Chemistry','Diagnoses and monitors gout and evaluates kidney stone risk; also used to monitor tumor lysis syndrome risk during chemotherapy.',NULL,'Venous serum or plasma','Fasting is not strictly required but is often requested alongside other metabolic tests.',NULL,'Enzymatic (uricase-based) colorimetric method on automated chemistry analyzers.',NULL,'[{"parameter": "Uric acid", "population": "Adult male", "range": "4.0-8.5 mg/dL (0.24-0.51 mmol/L)"}, {"parameter": "Uric acid", "population": "Adult female", "range": "2.7-7.3 mg/dL (0.16-0.43 mmol/L)"}]',1,'Elevated uric acid (hyperuricemia) is associated with gout, kidney stones, and tumor lysis syndrome, though many people with high uric acid never develop gout. Low uric acid is less commonly clinically significant and may be seen with some kidney tubular disorders or overtreatment with urate-lowering therapy.',NULL,'[{"condition": "Gout", "direction": "high"}, {"condition": "Uric acid kidney stones", "direction": "high"}, {"condition": "Tumor lysis syndrome", "direction": "high"}]','[{"name": "Medscape/eMedicine - Lab Values, Normal Adult (reference table)", "url": "https://emedicine.medscape.com/article/2172316-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["creatinine", "bun", "lipid-panel"]',NULL,NULL,'Does this explain my joint symptoms, or is it an incidental finding? Do I need treatment even without symptoms? Are my kidneys at risk from this level?','If you have gout symptoms, this result supports that diagnosis and guides urate-lowering treatment decisions. An incidental high level without symptoms is often just monitored, since not everyone with elevated uric acid develops gout.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (22,'ferritin','Ferritin, Serum','','Serum Ferritin','Clinical Chemistry / Hematology','Primary marker of the body''s iron stores; used to diagnose iron deficiency and iron overload, usually alongside serum iron and TIBC/transferrin saturation.',NULL,'Venous serum or plasma','No fasting required. Ferritin is an acute-phase reactant, so results can be falsely elevated during acute or chronic inflammation/infection.',NULL,'Chemiluminescent or electrochemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "Ferritin", "population": "Adult female", "range": "10-150 ng/mL (10-150 \u00b5g/L)"}, {"parameter": "Ferritin", "population": "Adult male", "range": "12-300 ng/mL (12-300 \u00b5g/L)"}]',1,'Low ferritin is a sensitive and specific marker of iron deficiency (in the absence of inflammation). High ferritin may indicate iron overload (hereditary hemochromatosis, transfusion-related) but is also a nonspecific acute-phase reactant that rises with inflammation, infection, liver disease, or malignancy -- so an elevated result must be interpreted alongside CRP/clinical context, not iron status alone.',NULL,'[{"condition": "Iron deficiency anemia", "direction": "low"}, {"condition": "Hereditary hemochromatosis / iron overload", "direction": "high"}, {"condition": "Acute-phase response (infection, inflammation, malignancy)", "direction": "high, non-iron-related"}]','[{"name": "Medscape/eMedicine - Lab Values, Normal Adult (reference table)", "url": "https://emedicine.medscape.com/article/2172316-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["serum-iron", "tibc-transferrin-saturation", "cbc", "vitamin-b12", "folate", "crp"]',NULL,NULL,'Is this level reflecting true iron status, or could inflammation be affecting it? Do I need additional iron studies (serum iron, TIBC) for a clearer picture? If elevated, do I need testing for iron overload?','A low ferritin generally confirms iron deficiency and leads to iron replacement and investigation of the cause (diet, blood loss, malabsorption). An elevated ferritin needs correlation with CRP and other iron studies to distinguish true iron overload from an inflammatory response.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (23,'total-protein','Total Protein, Serum','','Serum Total Protein','Clinical Chemistry','Screens for liver, kidney, and bone marrow/immunoglobulin disorders; measures the sum of albumin and globulins.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Biuret colorimetric method on automated chemistry analyzers.',NULL,'[{"parameter": "Total protein", "population": "Adult", "range": "6.0-8.3 g/dL (60-83 g/L)"}]',1,'Low total protein may reflect malnutrition, liver disease, nephrotic syndrome, or malabsorption. High total protein may suggest chronic inflammation, dehydration, or a monoclonal gammopathy/multiple myeloma (in which case serum protein electrophoresis is indicated to characterize the globulin fraction).',NULL,'[{"condition": "Malnutrition / liver disease / nephrotic syndrome", "direction": "low"}, {"condition": "Multiple myeloma / monoclonal gammopathy / chronic inflammation", "direction": "high"}]','[{"name": "MedlinePlus (NIH/NLM) - Comprehensive Metabolic Panel", "url": "https://medlineplus.gov/ency/article/003468.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["albumin", "alt-ast"]',NULL,NULL,'Does this need to be broken down further with a protein electrophoresis? Could this be related to my nutrition, liver, kidneys, or immune system? Is there a follow-up test recommended?','An unexplained abnormality, especially on the high side, often prompts serum protein electrophoresis to look at the specific protein fractions and rule out a monoclonal gammopathy, particularly if there''s no obvious explanation like dehydration or known liver/kidney disease.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (24,'vitamin-d','Vitamin D, 25-Hydroxy [25(OH)D]','','Vitamin D, 25-OH Vitamin D, Calcidiol','Immunoassay / Endocrinology','Best indicator of overall vitamin D status (from sun exposure, diet, and supplements); used to evaluate bone health and investigate calcium/PTH abnormalities.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Chemiluminescent immunoassay (CLIA) or LC-MS/MS on automated immunoassay analyzers.',NULL,'[{"parameter": "25(OH)D", "population": "Deficient", "range": "<20 ng/mL (<50 nmol/L)"}, {"parameter": "25(OH)D", "population": "Insufficient", "range": "20-29 ng/mL (50-72 nmol/L)"}, {"parameter": "25(OH)D", "population": "Sufficient", "range": "\u226530 ng/mL (\u226575 nmol/L)", "notes": "Thresholds vary by guideline body; some societies use different cutoffs -- see clinical significance"}, {"parameter": "25(OH)D", "population": "Potential toxicity", "range": ">100 ng/mL"}]',1,'Deficiency is linked to secondary hyperparathyroidism, osteomalacia/rickets, and increased fracture risk. Note that different guideline bodies use different cutoffs -- the widely-cited Endocrine Society thresholds are used here, but the Institute of Medicine/NIH generally considers levels below 20 ng/mL as deficient for the general population without recommending routine universal screening or a specific target above that. Interpret alongside calcium, phosphorus, and PTH when relevant.',NULL,'[{"condition": "Osteomalacia / rickets / secondary hyperparathyroidism", "direction": "low"}, {"condition": "Vitamin D toxicity (rare, usually from excessive supplementation)", "direction": "very high, with hypercalcemia"}]','[{"name": "Medscape/eMedicine - Vitamin D3 25-Hydroxyvitamin D: Reference Range, Interpretation", "url": "https://emedicine.medscape.com/article/2088694-overview", "accessed": "2026-07-14"}, {"name": "StatPearls / NCBI Bookshelf - Vitamin D (Endocrine Society guideline thresholds)", "url": "https://www.ncbi.nlm.nih.gov/books/NBK441912/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["calcium", "phosphorus", "pth", "tsh"]',NULL,NULL,'Given my result, do I need supplementation, and if so, what dose and for how long? Should this be rechecked after starting supplementation, and if so, when? Could my result be related to limited sun exposure, diet, malabsorption, or a medication I''m taking? Are there other tests (e.g., calcium, PTH) I should have alongside this?','Deficient or insufficient results are commonly managed with vitamin D supplementation, with the dose and duration depending on how low the result is and your individual risk factors; a repeat level is often checked after a few months of supplementation to confirm the response. Levels within the sufficient range generally need no action beyond routine monitoring as advised by your clinician.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (25,'vitamin-b12','Vitamin B12 (Cobalamin), Serum','','B12, Cobalamin, Serum B12','Immunoassay / Hematology','Evaluates for B12 deficiency, a cause of megaloblastic anemia and neurologic symptoms (peripheral neuropathy, cognitive changes).',NULL,'Venous serum or plasma','Fasting sample generally preferred; recent B12 injection or high-dose supplementation should be noted, as it can affect results.',NULL,'Chemiluminescent or competitive-binding immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "Vitamin B12", "population": "Normal", "range": "200-900 ng/L (pg/mL)", "notes": "Varies by lab/assay"}, {"parameter": "Vitamin B12", "population": "Deficient", "range": "<150 ng/L"}, {"parameter": "Vitamin B12", "population": "Borderline", "range": "150-400 ng/L", "notes": "Consider methylmalonic acid (MMA) or homocysteine testing if clinically suspicious despite borderline/normal result"}]',1,'Low B12 causes megaloblastic (macrocytic) anemia and can cause irreversible neurologic damage if untreated (peripheral neuropathy, subacute combined degeneration of the spinal cord). Common causes include pernicious anemia (autoimmune, needs intrinsic factor antibody testing), malabsorption, strict vegan diet, and metformin use. A normal serum B12 does not fully exclude tissue-level deficiency -- methylmalonic acid (MMA) is a more sensitive functional marker when clinical suspicion is high.',NULL,'[{"condition": "Pernicious anemia / B12 malabsorption / strict vegan diet / metformin use", "direction": "low"}]','[{"name": "Mayo Clinic Laboratories - Vitamin B12 Assay, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/Overview/9154", "accessed": "2026-07-14"}, {"name": "University Hospitals - Vitamin B-12 and Folate patient reference range", "url": "https://www.uhhospitals.org/health-information/health-and-wellness-library/article/lab-tests-v1/vitamin-b12-and-folate", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["folate", "cbc", "reticulocyte-count", "homocysteine"]',NULL,NULL,'Is my level definitively normal, or could I still have a functional deficiency despite a borderline-normal result? Do I need injections or is an oral supplement enough? What''s causing my deficiency (diet, absorption, medication)?','Confirmed deficiency is treated with B12 supplementation (oral or injectable, depending on severity and cause) and investigation of the underlying cause, especially ruling out pernicious anemia if malabsorption is suspected. Borderline results with strong clinical suspicion may prompt additional testing (methylmalonic acid) for confirmation.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (26,'folate','Folate (Folic Acid), Serum','','Folic Acid, Vitamin B9, Serum Folate','Immunoassay / Hematology','Evaluates for folate deficiency, a cause of megaloblastic anemia; usually tested alongside vitamin B12.',NULL,'Venous serum or plasma','Ideally an 8-hour fast; recent dietary folate intake can transiently raise serum levels even with normal tissue stores.',NULL,'Competitive-binding immunoassay or chemiluminescent assay on automated immunoassay analyzers.',NULL,'[{"parameter": "Serum folate", "population": "Normal", "range": "2-10 ng/mL"}, {"parameter": "Serum folate", "population": "Suggestive of deficiency", "range": "<4 \u00b5g/L (per Mayo Clinic Laboratories cutoff)"}]',1,'Low folate causes megaloblastic (macrocytic) anemia, similar to B12 deficiency, and is linked to neural tube defects in pregnancy when maternal folate is low. Common causes include poor dietary intake, alcohol use disorder, malabsorption, and certain medications (e.g., methotrexate). Serum folate reflects recent intake and can fluctuate; RBC folate is a more stable long-term marker in some clinical settings, though serum folate is generally preferred per Mayo Clinic Laboratories due to less assay variability.',NULL,'[{"condition": "Poor dietary intake / alcohol use disorder / malabsorption / methotrexate use", "direction": "low"}, {"condition": "Neural tube defect risk in pregnancy (maternal deficiency)", "direction": "low"}]','[{"name": "Mayo Clinic Laboratories - Vitamin B12 and Folate, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/9156", "accessed": "2026-07-14"}, {"name": "University Hospitals - Vitamin B-12 and Folate patient reference range", "url": "https://www.uhhospitals.org/health-information/health-and-wellness-library/article/lab-tests-v1/vitamin-b12-and-folate", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["vitamin-b12", "cbc", "reticulocyte-count"]',NULL,NULL,'Could my diet, alcohol use, or a medication (like methotrexate) be contributing to this result? Do I need to also check my B12, since the two deficiencies can look similar? If I''m pregnant or planning to be, does this affect my folic acid dosing?','Confirmed deficiency is treated with folate supplementation alongside addressing the underlying cause. Since folate and B12 deficiency can cause a similar blood picture, both are usually checked together before starting treatment, particularly since folate supplementation alone can mask a B12 deficiency.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (27,'pt-inr','Prothrombin Time (PT) & INR','','PT, INR, International Normalized Ratio','Hematology / Coagulation','Assesses the extrinsic and common coagulation pathways; used to monitor warfarin therapy, screen for bleeding disorders, and evaluate liver synthetic function/vitamin K status.',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Tube must be filled to the correct volume for the citrate:blood ratio to be accurate; avoid drawing from a line containing heparin.',NULL,'Clot-based (optical or mechanical clot detection) assay on automated coagulation analyzers; INR is calculated from the PT ratio adjusted for reagent sensitivity (ISI).',NULL,'[{"parameter": "PT", "population": "Adult", "range": "9-13 seconds", "notes": "Lab/reagent-dependent"}, {"parameter": "INR", "population": "Adult, not anticoagulated", "range": "0.8-1.2"}, {"parameter": "INR", "population": "Therapeutic target, standard warfarin indication (e.g., AFib)", "range": "2.0-3.0", "notes": "Target varies by indication (e.g., mechanical heart valve targets are higher) -- follow the prescribing indication"}]',1,'Prolonged PT/INR suggests warfarin effect, vitamin K deficiency, liver disease (reduced clotting factor synthesis), or specific factor deficiencies (factor VII). INR is specifically standardized for monitoring warfarin therapy. A markedly prolonged PT with a normal aPTT suggests an isolated factor VII or extrinsic pathway problem; prolongation of both PT and aPTT suggests a common pathway problem, liver disease, DIC, or vitamin K deficiency.',NULL,'[{"condition": "Warfarin therapy (expected/monitored effect)", "direction": "high, by design within target range"}, {"condition": "Liver disease / vitamin K deficiency", "direction": "high"}, {"condition": "Disseminated intravascular coagulation (DIC)", "direction": "high, with prolonged aPTT too"}]','[{"name": "StatPearls / NCBI Bookshelf - Interpretation of Blood Clotting Studies and Values (PT, PTT, aPTT, INR, D-Dimer)", "url": "https://www.ncbi.nlm.nih.gov/books/NBK604215/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["aptt", "fibrinogen", "d-dimer", "alt-ast"]','ARUP Laboratories critical values: Prothrombin Time ≥46.4 seconds; INR ≥5.0. A markedly elevated INR substantially increases spontaneous bleeding risk, particularly in warfarin-treated patients, and requires urgent clinical correlation and possible reversal therapy.','Under-filled citrate tubes (wrong blood-to-anticoagulant ratio) falsely prolong PT/INR -- this is one of the most common preanalytical errors in coagulation testing. Traumatic or difficult venipuncture can activate clotting factors in the sample and give a falsely shortened or unreliable result.','If I''m on warfarin, is my INR in the target range for my specific condition? Do I need a dose adjustment? If I''m not on blood thinners, what''s causing this result -- liver function, vitamin K, or something else?','For patients on warfarin, results guide dose adjustments per your anticoagulation clinic''s protocol. For patients not on blood thinners, an unexpectedly abnormal result prompts investigation of liver function and vitamin K status, and possibly further coagulation testing if a bleeding disorder is suspected.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (28,'aptt','Activated Partial Thromboplastin Time (aPTT)','','PTT, aPTT, Partial Thromboplastin Time','Hematology / Coagulation','Assesses the intrinsic and common coagulation pathways; used to monitor unfractionated heparin therapy and screen for bleeding disorders/factor deficiencies.',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Tube must be filled to the correct volume for the citrate:blood ratio to be accurate; avoid drawing from a line containing heparin unless heparin monitoring is the purpose of the test.',NULL,'Clot-based (optical or mechanical clot detection) assay on automated coagulation analyzers.',NULL,'[{"parameter": "aPTT", "population": "Adult", "range": "25-35 seconds", "notes": "Reagent- and lab-dependent; therapeutic heparin target is typically 1.5-2.5x the lab''s control value"}]',1,'Prolonged aPTT suggests unfractionated heparin effect, hemophilia A/B (factor VIII/IX deficiency), von Willebrand disease, lupus anticoagulant/antiphospholipid antibodies, or other intrinsic-pathway factor deficiencies. Isolated aPTT prolongation with a normal PT points toward the intrinsic pathway (factors VIII, IX, XI, XII) or heparin effect; prolongation of both PT and aPTT suggests a common pathway problem, liver disease, DIC, or vitamin K deficiency.',NULL,'[{"condition": "Unfractionated heparin therapy (expected/monitored effect)", "direction": "high, by design within target range"}, {"condition": "Hemophilia A or B", "direction": "high, isolated"}, {"condition": "Lupus anticoagulant / antiphospholipid syndrome", "direction": "high, isolated, may not correlate with bleeding risk"}]','[{"name": "StatPearls / NCBI Bookshelf - Interpretation of Blood Clotting Studies and Values (PT, PTT, aPTT, INR, D-Dimer)", "url": "https://www.ncbi.nlm.nih.gov/books/NBK604215/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["pt-inr", "fibrinogen", "d-dimer"]','ARUP Laboratories critical value: aPTT ≥85 seconds. A markedly prolonged aPTT increases bleeding risk and, in a patient on unfractionated heparin, may indicate the dose is well above the therapeutic target.','Under-filled citrate tubes (wrong blood-to-anticoagulant ratio) falsely prolong the result -- a common and important preanalytical error. Drawing the sample from or near a heparinized IV line/catheter can contaminate the sample and falsely prolong the result even when the patient is not therapeutically anticoagulated.','If I''m on heparin, is my level in the therapeutic range? If not on blood thinners, could this indicate a bleeding disorder, and do I need further coagulation testing (like factor levels or a mixing study)?','For heparin-monitored patients, results guide dose adjustment per protocol. An unexplained prolongation in someone not on anticoagulants typically leads to further testing (mixing studies, specific factor levels) to identify the cause, especially before any planned surgery.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (29,'d-dimer','D-Dimer','','D-Dimer, Fibrin Degradation Product','Hematology / Coagulation','Primarily used to help rule out venous thromboembolism (DVT/PE) in patients with low-to-moderate clinical probability; also elevated in DIC.',NULL,'Venous whole blood, sodium citrate tube (light blue top)','No fasting required. Tube must be filled to the correct volume for accurate results.',NULL,'Immunoturbidimetric or ELISA-based assay on automated coagulation analyzers.',NULL,'[{"parameter": "D-dimer", "population": "Normal", "range": "<500 ng/mL (FEU)", "notes": "Units and cutoffs vary by assay; age-adjusted cutoffs are commonly used in patients over 50"}]',1,'D-dimer has high sensitivity but low specificity for venous thromboembolism (DVT/PE) -- a normal result in a patient with low-to-moderate pretest probability helps rule out VTE, but an elevated result does not confirm it, since D-dimer also rises with surgery, trauma, pregnancy, malignancy, infection, and normal aging. It is a key marker in DIC alongside prolonged PT/aPTT and low platelets/fibrinogen. Always interpreted together with clinical pretest probability scoring (e.g., Wells score).',NULL,'[{"condition": "Deep vein thrombosis (DVT) / pulmonary embolism (PE)", "direction": "high (sensitive but non-specific)"}, {"condition": "Disseminated intravascular coagulation (DIC)", "direction": "high, with prolonged PT/aPTT and low fibrinogen/platelets"}, {"condition": "Recent surgery, trauma, pregnancy, malignancy, infection (non-thrombotic elevation)", "direction": "high, non-specific"}]','[{"name": "StatPearls / NCBI Bookshelf - Interpretation of Blood Clotting Studies and Values (PT, PTT, aPTT, INR, D-Dimer)", "url": "https://www.ncbi.nlm.nih.gov/books/NBK604215/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:50:12','2026-07-14 10:50:12','["pt-inr", "aptt", "fibrinogen"]',NULL,NULL,'Given my symptoms and risk factors, does this result rule out a blood clot, or do I need imaging to be sure? Could something else (recent surgery, pregnancy, infection) explain an elevated result?','A normal result in someone with low clinical suspicion generally helps rule out a clot without further testing. An elevated result, or any result in someone with higher clinical suspicion, typically leads to imaging (like a CT scan or ultrasound) to directly look for a blood clot, since D-dimer alone can''t confirm the diagnosis.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (30,'abo-rh-typing','ABO Grouping & Rh(D) Typing','','Blood Typing, ABO/Rh, Blood Group and Type','Blood Bank / Immunohematology','Determines a person''s ABO blood group (A, B, AB, or O) and RhD status (positive/negative). Foundational test for transfusion candidates, prenatal/newborn care (risk of ABO or Rh hemolytic disease of the newborn), and organ/tissue/bone marrow transplant workup.',NULL,'Venous whole blood, EDTA tube (lavender top)','Positive patient identification at the time of collection is critical -- mislabeled samples are a leading cause of ABO-incompatible transfusion errors. A second confirmatory sample is often required for first-time patients per institutional policy.',NULL,'Hemagglutination technique: forward typing (patient RBCs mixed with known anti-A and anti-B reagent antisera) and reverse typing (patient serum/plasma mixed with known A and B reagent red cells) to cross-check results; Rh(D) typing uses anti-D reagent antiserum. Performed by tube, gel-card (column agglutination), or automated solid-phase methods.',NULL,'[{"parameter": "ABO group", "population": "Result categories", "range": "A, B, AB, or O"}, {"parameter": "Rh(D) type", "population": "Result categories", "range": "Positive or Negative"}]',1,'ABO and RhD are the most immunogenic red cell antigens; mismatched transfusion can cause acute hemolytic transfusion reactions, which can be fatal. RhD-negative individuals (especially pregnant women) who are exposed to RhD-positive blood (transfusion, delivery, sensitizing events in pregnancy) are at risk of forming anti-D antibodies, which can cause hemolytic disease of the fetus/newborn in future RhD-positive pregnancies -- this risk is mitigated by giving Rh immune globulin at appropriate times. Discrepancies between forward and reverse typing require investigation before a result is finalized (e.g., weak/partial D variants, cold autoagglutinins, recent transfusion, or abnormal plasma proteins).',NULL,'[{"condition": "ABO-incompatible transfusion risk", "direction": "mismatch between donor/recipient ABO group"}, {"condition": "Rh alloimmunization / hemolytic disease of the fetus and newborn (HDFN)", "direction": "RhD-negative patient exposed to RhD-positive cells"}]','[{"name": "PMC - Practical Solutions for Problems in Blood Grouping and Crossmatching", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC8886265/", "accessed": "2026-07-14"}, {"name": "Labcorp - ABO Grouping and Rho(D) Typing test description", "url": "https://www.labcorp.com/tests/006049/abo-grouping-and-rho-d-typing", "accessed": "2026-07-14"}]',1,'2026-07-14 10:52:41','2026-07-14 10:52:41','["antibody-screen", "crossmatch", "dat-coombs"]','A discrepancy between forward and reverse ABO typing, or any ABO/Rh typing result that does not match a patient''s historical blood type on record, is treated as a critical/actionable finding requiring immediate investigation before any transfusion proceeds -- this is one of the few ''critical values'' in blood banking that is procedural/qualitative rather than a numeric threshold.','Recent transfusion of non-identical blood group components, bone marrow/stem cell transplant, and certain B-cell malignancies or IV immunoglobulin therapy can all cause a transient or persistent mixed-field or discrepant typing result that does not reflect the patient''s native blood group -- transfusion and transplant history must always be reviewed when interpreting an unexpected typing result.','Has this result been confirmed with a second sample, as required before major transfusion in many facilities? If I''m RhD-negative, do I need Rh immune globulin (e.g., during pregnancy or after a sensitizing event)? Does my blood type have any implications for donating blood or organ/tissue matching?','For transfusion purposes, your blood type is recorded in your record and used alongside an antibody screen and crossmatch before any blood product is issued to you. If you are RhD-negative and pregnant (or have had a potentially sensitizing event), your care team will discuss the timing of Rh immune globulin to prevent Rh alloimmunization in future pregnancies.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (31,'antibody-screen','Antibody Screen (Indirect Antiglobulin Test / IAT)','','Antibody Screen, IAT, Indirect Coombs Test, Type and Screen','Blood Bank / Immunohematology','Detects clinically significant unexpected (non-ABO) antibodies in a patient''s plasma/serum against red cell antigens, prior to transfusion or during pregnancy workup. Forms the ''screen'' half of routine pretransfusion ''type and screen'' testing.',NULL,'Venous whole blood, EDTA tube (lavender top) or clot tube','Sample validity period for pretransfusion testing is typically limited (commonly 72 hours) if the patient has been pregnant or transfused within the prior 3 months, per institutional/AABB-aligned policy, due to the risk of new antibody formation.',NULL,'Patient plasma/serum is incubated with 2-3 reagent group O red cells of known antigen profile (selected to detect clinically significant antibodies), then tested through saline, 37°C, and antihuman globulin (AHG) phases; agglutination at the AHG phase indicates a positive screen. Performed by tube, gel-card, or solid-phase methods.',NULL,'[{"parameter": "Antibody screen", "population": "Result categories", "range": "Negative (no clinically significant antibody detected) or Positive (requires antibody identification panel)"}]',1,'A negative screen with no history of clinically significant antibodies generally allows an immediate-spin or electronic crossmatch, speeding blood availability. A positive screen requires antibody identification to determine specificity and clinical significance before selecting compatible donor units -- this can delay transfusion, so early testing is important in patients likely to need blood (e.g., before scheduled surgery). In pregnancy, a positive screen with a clinically significant antibody (e.g., anti-D, anti-Kell) prompts titer monitoring for risk of hemolytic disease of the fetus/newborn.',NULL,'[{"condition": "Alloimmunization from prior transfusion or pregnancy", "direction": "positive"}, {"condition": "Delayed hemolytic transfusion reaction risk", "direction": "positive, with history of undetected antibody"}, {"condition": "Hemolytic disease of the fetus/newborn risk (pregnancy)", "direction": "positive, with clinically significant antibody"}]','[{"name": "StatPearls / NCBI Bookshelf - Pretransfusion Testing", "url": "https://www.ncbi.nlm.nih.gov/books/NBK585033/", "accessed": "2026-07-14"}, {"name": "PMC - Practical Solutions for Problems in Blood Grouping and Crossmatching", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC8886265/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:52:41','2026-07-14 10:52:41','["abo-rh-typing", "crossmatch", "antibody-identification"]',NULL,NULL,'If positive, do I need antibody identification to find out exactly which antibody this is? Does this affect how quickly compatible blood can be found for me if I need a transfusion? Should this be noted in my medical record for future reference?','A positive screen leads to antibody identification testing to pinpoint the specific antibody, which then determines what antigen-negative blood units need to be selected for any future transfusion -- this information is typically recorded for your ongoing care, since these antibodies can persist or recur.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (32,'dat-coombs','Direct Antiglobulin Test (DAT / Direct Coombs Test)','','DAT, Direct Coombs, Direct Antiglobulin','Blood Bank / Immunohematology','Detects antibodies and/or complement already bound to a patient''s own red blood cells in vivo. Used to investigate suspected autoimmune hemolytic anemia, hemolytic disease of the newborn, and suspected transfusion or drug-induced hemolysis.',NULL,'Venous whole blood, EDTA tube (lavender top)','Not used for routine pretransfusion compatibility testing on its own (it does not assess the patient''s plasma antibodies) -- it evaluates the patient''s own red cells.',NULL,'Patient red cells are washed with saline to remove unbound antibody, then antihuman globulin (AHG) reagent (polyspecific, or monospecific anti-IgG / anti-complement) is added; agglutination indicates antibody and/or complement is bound to the cells.',NULL,'[{"parameter": "DAT", "population": "Result categories", "range": "Negative (no bound antibody/complement detected) or Positive"}]',1,'A positive DAT supports a diagnosis of autoimmune hemolytic anemia (AIHA), hemolytic disease of the fetus/newborn, hemolytic transfusion reaction, or drug-induced immune hemolysis, but must be interpreted alongside clinical and other laboratory findings (e.g., LDH, haptoglobin, bilirubin, reticulocyte count) since 2-4% of patients with clinical AIHA can have a negative DAT, and some healthy individuals have a weakly positive DAT with no hemolysis.',NULL,'[{"condition": "Autoimmune hemolytic anemia (AIHA)", "direction": "positive"}, {"condition": "Hemolytic disease of the fetus/newborn (HDFN)", "direction": "positive, on newborn''s cells"}, {"condition": "Hemolytic transfusion reaction", "direction": "positive, post-transfusion"}, {"condition": "Drug-induced immune hemolysis", "direction": "positive"}]','[{"name": "StatPearls / NCBI Bookshelf - Coombs Test", "url": "https://www.ncbi.nlm.nih.gov/books/NBK547707/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:52:41','2026-07-14 10:52:41','["abo-rh-typing", "cbc", "total-bilirubin"]',NULL,NULL,'Does this explain symptoms I''ve been having (like fatigue or jaundice)? Do I need further blood tests to understand the pattern of anemia? Could a medication I''m taking be responsible?','A positive result in someone with anemia typically leads to further hemolysis workup (LDH, haptoglobin, bilirubin, reticulocyte count) and a review of medications, since certain drugs can trigger this pattern -- treatment then depends on identifying the underlying cause.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (33,'crossmatch','Crossmatch (Compatibility Testing)','','Crossmatch, XM, Type and Crossmatch, Compatibility Test','Blood Bank / Immunohematology','Final pretransfusion step confirming serologic compatibility between a specific donor red cell unit and the intended recipient, before the unit is released for transfusion.',NULL,'Venous whole blood, EDTA tube (lavender top) or clot tube','Requires a valid ABO/Rh type and antibody screen on file; sample validity period rules (commonly 72 hours if recently pregnant/transfused) apply as with the antibody screen.',NULL,'Three main methods depending on antibody screen results and local policy: (1) Immediate-spin crossmatch -- rapid room-temperature check for ABO incompatibility only, used when the antibody screen is negative and no clinically significant antibody history exists; (2) Antiglobulin (AHG/IAT) crossmatch -- donor cells incubated with recipient plasma through saline, 37°C, and AHG phases, required if a clinically significant antibody is present or suspected; (3) Electronic (computer) crossmatch -- a validated computer system verifies ABO compatibility against donor unit records without physical serologic testing, used only when the antibody screen is negative and the system meets validation requirements.',NULL,'[{"parameter": "Crossmatch", "population": "Result categories", "range": "Compatible (no agglutination/hemolysis -- unit may be released) or Incompatible (unit must not be released for that patient)"}]',1,'An incompatible crossmatch means the selected donor unit is not safe for that patient and another unit must be selected/tested; it may indicate a clinically significant antibody was missed on screening, a technical/clerical error, or a rare antigen incompatibility. In urgent situations, uncrossmatched group O (RhD-negative for females of childbearing potential) red cells may be issued per institutional emergency-release protocols while full compatibility testing is completed.',NULL,'[{"condition": "Undetected or newly-identified alloantibody", "direction": "incompatible result"}, {"condition": "Clerical/technical error in sample or unit identification", "direction": "incompatible result"}]','[{"name": "StatPearls / NCBI Bookshelf - Pretransfusion Testing", "url": "https://www.ncbi.nlm.nih.gov/books/NBK585033/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:52:41','2026-07-14 10:52:41','["abo-rh-typing", "antibody-screen"]','An incompatible crossmatch result is itself a critical, actionable finding -- the unit must not be released for that patient, and the blood bank must immediately investigate (repeat testing, antibody workup) and select alternative compatible units, especially urgent when the patient has an active transfusion need.','Cold agglutinins, rouleaux formation (e.g., in multiple myeloma), and recent high-dose IV immunoglobulin or monoclonal antibody therapy (e.g., anti-CD38 agents like daratumumab) can cause pan-reactive or falsely incompatible crossmatch results that require specialized techniques (e.g., DTT treatment) to resolve.','If incompatible, how will this affect the timing of my planned transfusion or surgery? Do I need special antigen-matched blood going forward?','An incompatible result means the blood bank will select and test alternative units before any transfusion proceeds -- this is a routine safety step, though it may take some additional time, which your care team will factor into planning if a transfusion is time-sensitive.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (34,'antibody-identification','Antibody Identification Panel','','Antibody ID Panel, Panel Reactive Antibody Identification','Blood Bank / Immunohematology','Determines the specific identity (e.g., anti-D, anti-K, anti-Fya) of an unexpected red cell antibody detected on a positive antibody screen, so that antigen-negative, compatible donor units can be selected.',NULL,'Venous whole blood, EDTA tube (lavender top) or clot tube','Requires a positive antibody screen result to trigger; testing follows the same sample validity rules as the antibody screen.',NULL,'Patient plasma is tested against a panel of typically 10-16 reagent red cells of known, differing antigen profiles (antigram) through saline, 37°C, and antihuman globulin phases; the reaction pattern across the panel cells is matched against their known antigen profiles to identify the antibody specificity (or specificities, if more than one is present).',NULL,'[{"parameter": "Antibody identification", "population": "Result categories", "range": "Specific antibody identified (e.g., anti-D, anti-K, anti-E) or unresolved/multiple antibodies requiring further workup"}]',1,'Identifying the antibody specificity determines which donor units must be selected (antigen-negative for that specificity) to avoid a hemolytic transfusion reaction, and whether the antibody is clinically significant (capable of causing in-vivo hemolysis) versus clinically insignificant (e.g., some cold-reactive antibodies). In pregnancy, identifying antibodies known to cause hemolytic disease of the fetus/newborn (notably anti-D, anti-c, anti-K) guides titer monitoring and fetal surveillance.',NULL,'[{"condition": "Alloimmunization requiring antigen-matched blood for future transfusions", "direction": "clinically significant antibody identified"}, {"condition": "Hemolytic disease of the fetus/newborn risk (pregnancy)", "direction": "anti-D, anti-c, or anti-K identified"}]','[{"name": "PMC - Practical Solutions for Problems in Blood Grouping and Crossmatching", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC8886265/", "accessed": "2026-07-14"}]',1,'2026-07-14 10:52:41','2026-07-14 10:52:41','["antibody-screen", "crossmatch"]',NULL,NULL,'What is the specific antibody, and how does it affect my future transfusion needs? If I''m pregnant, does this antibody carry a risk to the baby? Should I carry documentation of this for future medical visits?','Once identified, the specific antibody determines which antigen-negative blood units are safe for you going forward, and this is typically documented for future reference since re-identifying it can take time in an emergency. If the antibody is one associated with pregnancy risk, you''ll be referred for appropriate monitoring.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (35,'kleihauer-betke','Kleihauer-Betke Test (Fetomaternal Hemorrhage Quantification)','','KB Test, KB Stain, Fetomaternal Hemorrhage Test, Acid Elution Test','Blood Bank / Immunohematology','Quantifies the volume of fetal blood that has entered the maternal circulation (fetomaternal hemorrhage), most often after trauma, delivery, or other sensitizing events in RhD-negative mothers, to calculate the correct dose of Rh immune globulin needed to prevent maternal RhD alloimmunization.',NULL,'Maternal venous whole blood, EDTA tube (lavender top)','Typically performed only after a qualitative screening test (e.g., rosette test) is positive, since the rosette test is more sensitive for excluding clinically significant hemorrhage and the Kleihauer-Betke test is used to precisely quantify it.',NULL,'A maternal blood smear is exposed to an acid buffer (citric acid-phosphate), which elutes adult hemoglobin (HbA) from maternal red cells but not fetal hemoglobin (HbF), which is acid-resistant; after staining, fetal cells appear dark/rose-pink while maternal ''ghost'' cells appear pale, and the percentage of fetal cells is counted microscopically (flow cytometry is an alternative, more precise method in some centers).',NULL,'[{"parameter": "Fetal cells on smear", "population": "Interpretation", "range": "Percentage observed is used directly in the RhIG dosing calculation (see clinical significance) -- there is no single ''normal'' cutoff value"}]',1,'The standard 300 mcg dose of Rh immune globulin covers a fetomaternal hemorrhage of up to 30 mL of whole fetal blood (15 mL of fetal red cells). When the Kleihauer-Betke result indicates a larger hemorrhage, additional vials are calculated as: volume of fetal blood (mL) = % fetal cells x 50; number of additional 300 mcg vials = that volume / 30 (rounding per institutional protocol). As little as 0.01-0.03 mL of fetal blood can be enough to cause maternal Rh sensitization, which is why RhIG is given even when the screening test is negative for detectable hemorrhage.',NULL,'[{"condition": "Large fetomaternal hemorrhage after trauma, abruption, or invasive obstetric procedures", "direction": "high percentage of fetal cells -- requires additional RhIG dosing"}, {"condition": "Rh alloimmunization prevention in RhD-negative mothers", "direction": "guides correct RhIG dose"}]','[{"name": "StatPearls / NCBI Bookshelf - Kleihauer-Betke Test", "url": "https://www.ncbi.nlm.nih.gov/books/NBK430876/", "accessed": "2026-07-14"}, {"name": "WikEM - Kleihauer-Betke test (mechanism and clinical summary)", "url": "https://www.wikem.org/wiki/Kleihauer-Betke_test", "accessed": "2026-07-14"}]',1,'2026-07-14 10:52:41','2026-07-14 10:52:41','["abo-rh-typing", "antibody-screen"]',NULL,NULL,'Based on this result, how much Rh immune globulin do I need? Is one dose enough, or will I need additional doses? Does this affect monitoring for the rest of my pregnancy?','The result is used directly to calculate whether the standard dose of Rh immune globulin is sufficient or whether additional doses are needed, which your obstetric team will arrange promptly given the time-sensitive nature of RhIG administration after a sensitizing event.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (36,'free-t4','Free Thyroxine (Free T4)','','FT4, Free T4','Immunoassay / Endocrinology','Measures the unbound, biologically active fraction of thyroxine; used with TSH to diagnose and monitor thyroid disorders, especially when pituitary/central causes are suspected or TSH results are discordant with symptoms.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Automated immunoassay (competitive analog immunoassay); equilibrium dialysis is used as a reference method when binding-protein abnormalities are suspected to interfere with routine assays.',NULL,'[{"parameter": "Free T4", "population": "Adult", "range": "0.8-1.8 ng/dL", "notes": "Assay-dependent; some labs report 0.8-1.7 or 0.9-1.7 ng/dL"}]',1,'Low free T4 with high TSH indicates primary hypothyroidism; low free T4 with low/inappropriately normal TSH suggests central (pituitary/hypothalamic) hypothyroidism. High free T4 with low TSH indicates hyperthyroidism. Certain medications (e.g., phenytoin, heparin) and non-thyroidal illness can cause artifactually abnormal free T4 on routine immunoassays -- equilibrium dialysis is more accurate in these situations.',NULL,'[{"condition": "Primary hypothyroidism", "direction": "low, with high TSH"}, {"condition": "Central (pituitary) hypothyroidism", "direction": "low, with low/normal TSH"}, {"condition": "Hyperthyroidism", "direction": "high, with low TSH"}]','[{"name": "Mayo Clinic Laboratories - T4 (Thyroxine), Free, Dialysis, Serum (test catalog)", "url": "https://endocrinology.testcatalog.org/show/FRT4D", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["tsh", "free-t3"]',NULL,NULL,'How does this fit with my TSH result -- do they agree, or is there a discrepancy that needs explaining? Do I need my dose of thyroid medication adjusted? Is this a temporary or ongoing issue?','Free T4 is interpreted together with TSH to fully characterize your thyroid status; if you''re on thyroid medication, this result often guides a dose adjustment, with a repeat test typically done 6-8 weeks after any change to allow levels to stabilize.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (37,'free-t3','Free Triiodothyronine (Free T3)','','FT3, Free T3','Immunoassay / Endocrinology','Measures the unbound, active fraction of triiodothyronine; used mainly to help diagnose hyperthyroidism (including T3 toxicosis, where T3 is elevated but T4 is normal) or when TSH/free T4 do not fully explain symptoms.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Automated competitive immunoassay on immunoassay analyzers.',NULL,'[{"parameter": "Free T3", "population": "Adult", "range": "2.3-4.2 pg/mL", "notes": "Assay-dependent; some labs report 2.0-4.4 pg/mL"}]',1,'Elevated free T3 with a suppressed TSH supports hyperthyroidism, including T3 toxicosis (isolated T3 elevation with normal T4, seen especially in early Graves disease or toxic nodules). Low free T3 can occur in hypothyroidism, but is also commonly seen in non-thyroidal illness (''euthyroid sick syndrome'') where TSH and free T4 may be normal -- so free T3 alone is not routinely used to diagnose hypothyroidism.',NULL,'[{"condition": "Hyperthyroidism / T3 toxicosis", "direction": "high"}, {"condition": "Non-thyroidal illness (euthyroid sick syndrome)", "direction": "low, without primary thyroid disease"}]','[{"name": "Testing.com - Thyroid Test Results Chart (reference ranges compiled from lab reports)", "url": "https://www.testing.com/thyroid-testing-example-results/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["tsh", "free-t4"]',NULL,NULL,'Why was this ordered in addition to TSH and free T4 -- is there a specific concern (like hyperthyroidism)? Does this change my treatment plan?','Free T3 is typically added when hyperthyroidism is suspected but free T4 is normal (since some hyperthyroid patients have isolated T3 elevation), or to assess severity in confirmed hyperthyroidism -- results are interpreted alongside TSH and free T4, not alone.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (38,'pth','Parathyroid Hormone, Intact (PTH)','','PTH, Intact PTH, Parathormone','Immunoassay / Endocrinology','Assesses parathyroid gland function; used to investigate abnormal calcium levels and diagnose primary, secondary, or tertiary hyperparathyroidism, and hypoparathyroidism.',NULL,'Venous serum or plasma (EDTA plasma preferred by some assays for stability)','Best interpreted alongside a simultaneously-drawn calcium (ideally ionized calcium) and vitamin D level; morning fasting sample often preferred due to diurnal variation.',NULL,'Second- or third-generation immunoassay (chemiluminescent) detecting intact PTH molecule on automated immunoassay analyzers.',NULL,'[{"parameter": "Intact PTH", "population": "Adult, normal calcium and vitamin D status", "range": "15-65 pg/mL", "notes": "Assay-dependent; some labs report 10-65 pg/mL. Must be interpreted alongside simultaneous calcium level"}]',1,'PTH must always be interpreted together with the calcium level: high PTH with high calcium suggests primary hyperparathyroidism; high PTH with low/normal calcium suggests secondary hyperparathyroidism (commonly from vitamin D deficiency or chronic kidney disease); low PTH with high calcium suggests a non-parathyroid cause of hypercalcemia (e.g., malignancy); low PTH with low calcium suggests hypoparathyroidism.',NULL,'[{"condition": "Primary hyperparathyroidism", "direction": "high PTH, high calcium"}, {"condition": "Secondary hyperparathyroidism (vitamin D deficiency, CKD)", "direction": "high PTH, low/normal calcium"}, {"condition": "Hypoparathyroidism", "direction": "low PTH, low calcium"}, {"condition": "Malignancy-associated hypercalcemia (PTH-independent)", "direction": "low/suppressed PTH, high calcium"}]','[{"name": "Cleveland Clinic - Parathyroid Hormone: What It Is, Function & Normal Levels", "url": "https://my.clevelandclinic.org/health/articles/22355-parathyroid-hormone", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["calcium", "phosphorus", "vitamin-d"]',NULL,NULL,'Does this explain my calcium result? Do I need vitamin D and kidney function testing to fully understand this? Do I need imaging of my parathyroid glands?','PTH is always interpreted together with calcium -- the combination determines whether the picture fits primary hyperparathyroidism, secondary hyperparathyroidism (often from vitamin D deficiency or kidney disease), or hypoparathyroidism, which then guides whether imaging or further hormone testing is needed.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (39,'cortisol','Cortisol, Serum (AM)','','Cortisol, Morning Cortisol','Immunoassay / Endocrinology','Assesses adrenal (HPA axis) function; used to investigate suspected adrenal insufficiency (Addison disease) or Cushing syndrome.',NULL,'Venous serum or plasma','Cortisol has strong diurnal variation (highest in early morning, lowest at night), so timing of the draw (typically 7-9 AM) must be specified and matched against the appropriate reference range; stress, illness, and exogenous steroid use affect results.',NULL,'Chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "Cortisol", "population": "Adult, 8 AM specimen", "range": "5-23 \u00b5g/dL", "notes": "Reference range is specific to morning collection; afternoon/evening levels are normally lower"}]',1,'A low morning cortisol raises concern for adrenal insufficiency and typically prompts an ACTH stimulation test to confirm. A high cortisol, especially if it fails to suppress with a dexamethasone suppression test, raises concern for Cushing syndrome. Random single cortisol values are of limited use without knowing the time of day and the clinical context (acute illness/stress physiologically raises cortisol).',NULL,'[{"condition": "Adrenal insufficiency (Addison disease, or secondary to pituitary/steroid withdrawal)", "direction": "low"}, {"condition": "Cushing syndrome (endogenous or exogenous steroid excess)", "direction": "high, loss of normal diurnal variation"}]','[{"name": "NBME Laboratory Reference Values (academic reference table, 0800h cortisol)", "url": "https://www.nbme.org/sites/default/files/2025-03/NBME_Laboratory_Reference_Values.pdf", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["tsh", "prolactin"]',NULL,NULL,'Was this drawn at the right time of day, since cortisol varies a lot through the day? Do I need a stimulation or suppression test to confirm a diagnosis? Could stress, illness, or a medication be affecting this result?','An abnormal random or morning cortisol is rarely diagnostic on its own -- it typically leads to a dynamic test (like a cosyntropin stimulation test for suspected insufficiency, or a dexamethasone suppression test for suspected excess) to confirm the diagnosis before any treatment decision.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (40,'serum-iron','Iron, Serum','','Serum Iron, Fe','Clinical Chemistry / Hematology','Measures iron currently circulating in the blood bound to transferrin; part of a full iron panel alongside ferritin, TIBC, and transferrin saturation to evaluate iron deficiency or overload.',NULL,'Venous serum or plasma','Morning fasting sample preferred, since serum iron has diurnal variation (higher in the morning, lower in the afternoon/evening) and is affected by recent iron intake/supplementation.',NULL,'Colorimetric method on automated chemistry analyzers.',NULL,'[{"parameter": "Serum iron", "population": "Adult male", "range": "59-158 \u00b5g/dL (10.6-28.3 \u00b5mol/L)"}, {"parameter": "Serum iron", "population": "Adult female", "range": "37-145 \u00b5g/dL (6.6-25.9 \u00b5mol/L)"}]',1,'Serum iron alone is not reliable for diagnosing iron deficiency or overload because of its wide diurnal swing and sensitivity to recent intake -- it is always interpreted together with TIBC/transferrin saturation and ferritin. Low serum iron with high TIBC and low saturation suggests iron deficiency; low serum iron with low/normal TIBC suggests anemia of chronic disease/inflammation instead. High serum iron with high saturation suggests iron overload (e.g., hereditary hemochromatosis).',NULL,'[{"condition": "Iron deficiency (with high TIBC, low saturation)", "direction": "low"}, {"condition": "Anemia of chronic disease/inflammation (with low/normal TIBC)", "direction": "low"}, {"condition": "Hereditary hemochromatosis / iron overload", "direction": "high, with high saturation"}]','[{"name": "MedlinePlus (NIH/NLM) - Serum Iron Test", "url": "https://medlineplus.gov/ency/article/003488.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["ferritin", "tibc-transferrin-saturation", "cbc"]',NULL,NULL,'Should this be interpreted alongside ferritin and TIBC for a full picture of my iron status? Could recent food or supplement intake have affected this result? Do I need this repeated fasting?','Serum iron is rarely interpreted alone -- your clinician will look at it together with ferritin and TIBC/transferrin saturation to distinguish iron deficiency from other causes of anemia or from iron overload, and a fasting morning sample is often requested for accuracy.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (41,'tibc-transferrin-saturation','TIBC & Transferrin Saturation','','Total Iron-Binding Capacity, TIBC, Transferrin Saturation, TSAT','Clinical Chemistry / Hematology','Measures the blood''s total capacity to bind iron (TIBC, a reflection of transferrin level) and the percentage of that capacity currently occupied by iron (transferrin saturation); used together with serum iron and ferritin to distinguish iron deficiency from other causes of anemia or from iron overload.',NULL,'Venous serum or plasma','Should be drawn alongside serum iron, ideally as a fasting morning sample, since transferrin saturation is calculated from both values.',NULL,'TIBC measured colorimetrically after saturating the sample with excess iron; transferrin saturation is calculated as (serum iron / TIBC) x 100.',NULL,'[{"parameter": "TIBC", "population": "Adult male", "range": "171-505 \u00b5g/dL (30.6-90.3 \u00b5mol/L)"}, {"parameter": "TIBC", "population": "Adult female", "range": "149-492 \u00b5g/dL (26.7-88.0 \u00b5mol/L)"}, {"parameter": "Transferrin saturation", "population": "Adult male", "range": "20-50%"}, {"parameter": "Transferrin saturation", "population": "Adult female", "range": "15-45%"}]',1,'In uncomplicated iron deficiency, TIBC (transferrin) rises while transferrin saturation falls. In anemia of chronic disease, TIBC is typically low-to-normal while saturation is low-to-normal (a pattern that helps distinguish it from true iron deficiency). A transferrin saturation above roughly 45-50% raises concern for iron overload (e.g., hereditary hemochromatosis) and often prompts genetic testing (HFE gene) and ferritin correlation.',NULL,'[{"condition": "Iron deficiency anemia", "direction": "high TIBC, low saturation"}, {"condition": "Anemia of chronic disease/inflammation", "direction": "low/normal TIBC, low/normal saturation"}, {"condition": "Hereditary hemochromatosis / iron overload", "direction": "saturation >45-50%"}]','[{"name": "MedlinePlus (NIH/NLM) - Serum Iron Test (includes TIBC and saturation)", "url": "https://medlineplus.gov/ency/article/003488.htm", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["ferritin", "serum-iron", "cbc"]',NULL,NULL,'Does this pattern point more toward iron deficiency or a chronic disease process? Do I need additional testing (ferritin, CRP) to clarify? Should my diet or supplements change based on this?','The combination of TIBC and transferrin saturation, together with ferritin, is used to distinguish true iron deficiency from anemia of chronic disease -- if the picture is unclear, your clinician may add a CRP or repeat testing after treating any suspected underlying condition.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (42,'esr','Erythrocyte Sedimentation Rate (ESR)','','ESR, Sed Rate','Hematology / Inflammation Markers','Non-specific marker of inflammation; used to support diagnosis and monitor disease activity in inflammatory and rheumatologic conditions (e.g., polymyalgia rheumatica, giant cell arteritis, rheumatoid arthritis), and to screen for infection or malignancy in unexplained symptoms.',NULL,'Venous whole blood, EDTA tube (lavender top)','No fasting required. Sample should be tested within a few hours of collection, as prolonged storage affects the result. Anemia, pregnancy, and age can all raise ESR independent of inflammation.',NULL,'Westergren method (classic reference method: rate of red cell sedimentation in a vertical tube over 1 hour) or automated modified methods calibrated against it.',NULL,'[{"parameter": "ESR", "population": "Men <50 years", "range": "0-15 mm/hr"}, {"parameter": "ESR", "population": "Men \u226550 years", "range": "0-20 mm/hr"}, {"parameter": "ESR", "population": "Women <50 years", "range": "0-20 mm/hr"}, {"parameter": "ESR", "population": "Women \u226550 years", "range": "0-30 mm/hr"}]',1,'ESR is a non-specific marker -- it rises with essentially any inflammatory, infectious, or neoplastic process, and can also be affected by anemia, pregnancy, obesity, and aging independent of disease. It is most useful in monitoring disease activity over time in a known condition (e.g., polymyalgia rheumatica, temporal arteritis) rather than as a standalone diagnostic test. CRP is generally preferred for detecting acute changes, since it rises and falls faster than ESR.',NULL,'[{"condition": "Polymyalgia rheumatica / giant cell arteritis", "direction": "high, often markedly"}, {"condition": "Rheumatoid arthritis / other inflammatory arthritis (disease activity monitoring)", "direction": "high"}, {"condition": "Chronic infection or malignancy (e.g., multiple myeloma)", "direction": "high"}]','[{"name": "Hospital for Special Surgery (HSS) - Understanding Rheumatoid Arthritis Blood Test Results", "url": "https://www.hss.edu/health-library/conditions-and-treatments/understanding-rheumatoid-arthritis-lab-tests-results", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["crp", "cbc", "rheumatoid-factor", "anti-ccp"]',NULL,NULL,'Does this level fit with a specific condition I''m being evaluated for, or is it a nonspecific finding? Do I need more specific testing (like CRP or targeted autoimmune panels) to narrow things down? Should this be tracked over time?','Because ESR is very nonspecific, an abnormal result usually prompts your clinician to correlate it with your symptoms and consider more specific tests depending on what''s suspected -- it''s often tracked serially rather than acted on from a single value.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (43,'rheumatoid-factor','Rheumatoid Factor (RF)','','RF','Immunoassay / Inflammation Markers','Supports the diagnosis of rheumatoid arthritis and helps evaluate other autoimmune/inflammatory conditions, usually alongside anti-CCP antibodies (which are more specific for RA).',NULL,'Venous serum or plasma','No fasting required.',NULL,'Nephelometric or turbidimetric immunoassay on automated analyzers.',NULL,'[{"parameter": "Rheumatoid factor", "population": "Adult", "range": "Negative, or <20-30 IU/mL by nephelometry", "notes": "Cutoff varies by lab/method"}]',1,'A positive RF supports but does not confirm rheumatoid arthritis -- it is present in roughly 70-80% of RA patients but also occurs in other autoimmune conditions (Sjogren syndrome, SLE), chronic infections (hepatitis C, endocarditis), and in a smaller percentage of healthy people (especially older adults). Anti-CCP antibodies are more specific for RA and are often tested alongside RF. A negative RF does not exclude RA (''seronegative RA'').',NULL,'[{"condition": "Rheumatoid arthritis", "direction": "positive (70-80% sensitivity)"}, {"condition": "Sjogren syndrome / SLE / chronic infections", "direction": "positive, non-specific"}]','[{"name": "droracle.ai - Normal reference ranges for rheumatoid factor and ESR (clinical reference summary)", "url": "https://www.droracle.ai/articles/990908/what-are-the-normal-reference-ranges-for-rheumatoid-factor", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["anti-ccp", "esr", "crp", "ana"]',NULL,NULL,'Does a positive result confirm rheumatoid arthritis, or do I need more specific testing (like anti-CCP)? Could this be positive for another reason unrelated to RA? How does my titer level affect the interpretation?','A positive RF is usually interpreted alongside anti-CCP antibody testing and your clinical exam/imaging findings, since RF alone isn''t specific enough to diagnose RA -- a rheumatology referral is typical if RA is suspected based on the full picture.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (44,'ana','Antinuclear Antibody (ANA)','','ANA, FANA','Immunoassay / Inflammation Markers','First-line screening test for systemic lupus erythematosus (SLE) and other connective tissue diseases; detects autoantibodies against components of the cell nucleus.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Indirect immunofluorescence (IIF) on Hep-2 cells is the gold-standard method, reporting both a titer (dilution) and a fluorescence pattern (e.g., homogeneous, speckled, nucleolar); solid-phase assays (ELISA, multiplex bead) are also used as screening tools, with reflex IIF titering on positive/equivocal results.',NULL,'[{"parameter": "ANA titer", "population": "Negative", "range": "\u22641:40 dilution (varies by lab)"}, {"parameter": "ANA titer", "population": "Significantly positive", "range": "\u22651:160 dilution", "notes": "The 2019 EULAR/ACR SLE classification criteria use \u22651:80 as the entry criterion"}]',1,'ANA is highly sensitive for SLE (a negative ANA makes SLE unlikely) but not specific -- roughly 5-15% of the healthy general population is ANA-positive at low titer (1:40), increasing with age, and positivity also occurs in other autoimmune diseases, chronic infections, and malignancy. A positive ANA is never diagnostic alone; the titer, pattern, and specific reflex antibody testing (anti-dsDNA, anti-Sm, anti-SSA/Ro, anti-SSB/La, anti-Scl-70, anti-Jo-1, anti-centromere) together with clinical findings are needed to reach a diagnosis.',NULL,'[{"condition": "Systemic lupus erythematosus (SLE)", "direction": "positive, high sensitivity"}, {"condition": "Other connective tissue diseases (Sjogren syndrome, scleroderma, mixed connective tissue disease)", "direction": "positive, pattern-dependent"}, {"condition": "Low-titer incidental positivity in healthy individuals (especially older adults)", "direction": "positive, low titer, non-pathological"}]','[{"name": "Medscape/eMedicine - Antinuclear Antibody: Reference Range, Interpretation", "url": "https://emedicine.medscape.com/article/2086616-overview", "accessed": "2026-07-14"}, {"name": "PMC - The Art of Interpreting Antinuclear Antibodies (ANAs) in Everyday Practice", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC12348033/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["anti-dsdna", "complement-c3", "complement-c4", "rheumatoid-factor"]',NULL,NULL,'Given this titer and pattern, do I need more specific antibody testing (like the ENA panel or anti-dsDNA) to identify a specific condition? Could this be a positive result without me having an autoimmune disease?','A positive ANA, especially at a significant titer, typically leads to reflex testing for more specific antibodies (anti-dsDNA, ENA panel) to help identify a specific condition -- a low-titer positive without symptoms is often not further pursued, since ANA can be positive in healthy people too.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (45,'troponin','Cardiac Troponin (I or T)','','Troponin, cTnI, cTnT, hs-Troponin','Immunoassay / Cardiac Biomarkers','The preferred and most specific biomarker for diagnosing acute myocardial infarction and myocardial injury; central to acute coronary syndrome (ACS) evaluation in the emergency setting.',NULL,'Venous serum or plasma','Serial measurements (e.g., at presentation and again at 1-3 hours or 3-6 hours depending on the assay/protocol) are standard practice, since a single value is far less informative than the rise-and-fall pattern.',NULL,'Chemiluminescent or electrochemiluminescent immunoassay; high-sensitivity troponin (hs-cTn) assays can detect concentrations 10-100 times lower than older-generation assays and are now the standard of care in most emergency settings.',NULL,'[{"parameter": "Cardiac troponin", "population": "Reference cutoff concept", "range": "Elevated when above the assay''s 99th-percentile upper reference limit", "notes": "Exact numeric cutoffs are highly assay-specific (conventional vs high-sensitivity, troponin I vs T) -- always use the reporting laboratory''s own cutoff, never a generic number"}]',1,'Cardiac troponin rises within 1-3 hours of myocardial injury (earlier with high-sensitivity assays) and can remain elevated for up to 1-2 weeks, making it both sensitive for early detection and useful for confirming a recent event. Elevation above the 99th-percentile cutoff, especially with a rising/falling pattern on serial testing, supports acute myocardial infarction, but troponin can also be elevated in other conditions causing myocardial strain or injury (heart failure, myocarditis, pulmonary embolism, sepsis, renal failure, strenuous exercise) -- so results must always be interpreted alongside the clinical presentation and ECG.',NULL,'[{"condition": "Acute myocardial infarction", "direction": "high, with rise-and-fall pattern"}, {"condition": "Myocarditis / pulmonary embolism / sepsis / renal failure (non-ACS causes)", "direction": "high, without classic ACS pattern"}]','[{"name": "University of Rochester Medical Center - Cardiac Biomarkers (Blood)", "url": "https://www.urmc.rochester.edu/encyclopedia/content?contenttypeid=167&contentid=cardiac_biomarkers", "accessed": "2026-07-14"}, {"name": "PMC - Cardiac Biomarkers: What Is and What Can Be", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC6957084/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["ck-mb", "bnp"]','ARUP Laboratories lists a high-sensitivity troponin I critical value of ≥200 ng/L; local critical-value thresholds vary by assay generation and institution -- always use the reporting lab''s own critical-value policy for high-sensitivity assays, which are far more sensitive than older-generation troponin tests.','Skeletal muscle injury, strenuous exercise, renal failure (reduced clearance), and tachyarrhythmias can all cause troponin elevation without acute coronary syndrome -- the pattern of rise and fall on serial testing, not a single value, is what distinguishes acute myocardial injury from chronically elevated troponin (e.g., in chronic kidney disease).','Is this trending up, down, or staying flat on repeat testing, since the pattern matters more than one number? Does this level fit with a heart attack, or could something else (like kidney disease) explain it? What''s the next step in my evaluation?','Troponin is virtually always interpreted through serial testing (a rise and/or fall pattern) rather than a single value, alongside your symptoms and ECG -- your care team will use an established rule-in/rule-out protocol to decide on further cardiac testing or treatment.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (46,'bnp','B-Type Natriuretic Peptide (BNP / NT-proBNP)','','BNP, NT-proBNP, Natriuretic Peptide','Immunoassay / Cardiac Biomarkers','Used to diagnose and gauge the severity of heart failure, and to help distinguish cardiac from non-cardiac causes of dyspnea (shortness of breath).',NULL,'Venous serum or plasma (EDTA plasma commonly used for BNP)','No fasting required. Note that BNP and NT-proBNP are metabolized at different rates and have distinct reference ranges -- results must be compared against the range for the specific assay used, not interchanged.',NULL,'Chemiluminescent or electrochemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "BNP", "population": "Normal (heart failure unlikely)", "range": "<100 pg/mL", "notes": "NT-proBNP has a separate, generally higher-numbered reference range and age-adjusted cutoffs -- do not apply the BNP cutoff to an NT-proBNP result"}]',1,'Elevated BNP/NT-proBNP supports a diagnosis of heart failure and correlates broadly with severity, and is used to help distinguish cardiac dyspnea from primarily pulmonary causes. Levels also rise with renal impairment, atrial fibrillation, pulmonary embolism, sepsis, and advancing age, so results must be interpreted in the full clinical context rather than as a standalone diagnostic cutoff, and age/renal-function-adjusted reference ranges are often used, particularly for NT-proBNP.',NULL,'[{"condition": "Heart failure (diagnosis and severity assessment)", "direction": "high"}, {"condition": "Renal impairment / atrial fibrillation / pulmonary embolism (non-heart-failure elevation)", "direction": "high, confounding factor"}]','[{"name": "SmarterBlood - Cardiac Biomarkers: Troponin, BNP, CK-MB Heart Tests (clinical summary)", "url": "https://www.smarterblood.org/markers/cardiac-biomarkers", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["troponin", "ck-mb", "creatinine"]',NULL,NULL,'Does this level support heart failure as the cause of my symptoms, or point toward another explanation? What''s my baseline level for future comparison? Do I need an echocardiogram to complete the picture?','An elevated result in someone with shortness of breath or swelling supports a heart failure diagnosis and often prompts an echocardiogram to assess heart function; in known heart failure patients, serial levels can help track treatment response, though trends matter more than any single value.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (47,'ck-mb','Creatine Kinase-MB (CK-MB)','','CK-MB, CPK-MB','Clinical Chemistry / Cardiac Biomarkers','Historically used cardiac injury marker, now largely superseded by troponin for diagnosing acute MI, but still used in specific settings such as detecting reinfarction shortly after a recent MI, or when troponin assays are unavailable/unreliable (e.g., severe renal failure).',NULL,'Venous serum or plasma','Serial sampling over 24 hours is traditionally used, similar to troponin protocols, though CK-MB has been largely replaced by high-sensitivity troponin in most modern emergency department protocols.',NULL,'Immunoassay (mass or activity-based) on automated chemistry/immunoassay analyzers.',NULL,'[{"parameter": "CK-MB", "population": "General guidance", "range": "Elevated when >5% of total CK activity, or above the assay-specific upper reference limit", "notes": "Numeric cutoffs are highly assay-dependent; always use the reporting lab''s own reference range"}]',1,'CK-MB rises within 4-6 hours of myocardial injury and typically returns to normal within 1-2 days, making it useful for detecting a new (re-infarction) event in a patient whose troponin is already elevated from a recent MI. It is less specific than troponin, since CK-MB can also rise with skeletal muscle injury, making troponin the preferred marker per AHA/ACC guidelines for primary MI diagnosis.',NULL,'[{"condition": "Acute myocardial infarction / reinfarction (especially when troponin already elevated)", "direction": "high"}, {"condition": "Skeletal muscle injury (non-specific elevation)", "direction": "high, without cardiac cause"}]','[{"name": "PMC - The Best of Both Worlds: Eliminating CK-MB Testing in the Emergency Department", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8214836/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["troponin", "bnp"]',NULL,NULL,'How does this compare with my troponin result, since troponin is generally the more specific marker? Could recent muscle injury or exercise explain an elevated result?','CK-MB is now mainly used alongside troponin (rather than instead of it) in specific situations, such as detecting a re-infarction shortly after a first heart attack, since troponin stays elevated for days and CK-MB''s faster return to normal can help identify a new event.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (48,'psa','Prostate-Specific Antigen (PSA)','','PSA, Total PSA','Immunoassay / Tumor Markers','Used for prostate cancer screening (where locally recommended) and for monitoring known prostate cancer or benign prostatic hyperplasia (BPH).',NULL,'Venous serum or plasma','Should ideally be drawn before a digital rectal exam, prostate biopsy, or ejaculation, all of which can transiently raise PSA; recent urinary tract infection or catheterization can also elevate results.',NULL,'Chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "Total PSA", "population": "Historically used general cutoff", "range": "<4.0 ng/mL", "notes": "Age-specific reference ranges are now generally preferred over a single fixed cutoff; screening/threshold recommendations vary by guideline body and clinical context"}]',1,'PSA is prostate-specific but not cancer-specific -- it is also elevated by BPH, prostatitis, and recent prostate manipulation, and a substantial proportion of men with a ''normal'' PSA below 4.0 ng/mL still have prostate cancer detected on biopsy, while many men with a modestly elevated PSA do not have cancer. The free-to-total PSA ratio and PSA velocity (rate of change over time) can help refine risk assessment. PSA screening decisions should follow current, locally-endorsed clinical guidelines given the trade-offs between early detection and overdiagnosis.',NULL,'[{"condition": "Prostate cancer", "direction": "high (imperfect sensitivity and specificity)"}, {"condition": "Benign prostatic hyperplasia (BPH) / prostatitis", "direction": "high, non-malignant cause"}]','[{"name": "ScienceDirect Topics - Elevated Alpha-Fetoprotein (includes PSA reference discussion)", "url": "https://www.sciencedirect.com/topics/medicine-and-dentistry/elevated-alpha-fetoprotein", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["psa", "urinalysis", "free-psa"]',NULL,NULL,'Given my age and risk factors, is this level concerning enough to warrant a biopsy, or is monitoring reasonable? Would checking % free PSA help clarify the picture? Was this drawn before or after a prostate exam, since that can affect the result?','A borderline result often leads to additional risk-refining tests (like % free PSA or a repeat PSA) before deciding on biopsy, while your urologist weighs the result together with your age, family history, and exam findings to recommend the best next step.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (49,'afp','Alpha-Fetoprotein (AFP)','','AFP','Immunoassay / Tumor Markers','Tumor marker used to help diagnose and monitor hepatocellular carcinoma and non-seminomatous germ cell tumors (testicular/ovarian); also used in maternal serum screening during pregnancy for neural tube defects and certain chromosomal conditions (a separate, pregnancy-specific application).',NULL,'Venous serum or plasma','No fasting required. Results are not meaningful during pregnancy for the oncologic application (AFP is physiologically elevated) -- pregnancy-related AFP screening uses separate, gestational-age-specific reference ranges.',NULL,'Chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "AFP", "population": "Non-pregnant adult", "range": "<10-15 ng/mL (\u00b5g/L)", "notes": "Essentially undetectable in healthy adult men and non-pregnant women"}]',1,'Markedly elevated AFP in a patient with liver disease or a liver mass strongly supports hepatocellular carcinoma, and AFP is used both diagnostically and to monitor treatment response (a falling AFP after treatment is reassuring; a persistently high or rising level suggests residual/recurrent disease). AFP is also elevated in non-seminomatous germ cell tumors (embryonal carcinoma, yolk sac tumor) but not in pure seminoma or choriocarcinoma -- helping distinguish these tumor types alongside beta-hCG and LDH.',NULL,'[{"condition": "Hepatocellular carcinoma", "direction": "high"}, {"condition": "Non-seminomatous germ cell tumors (testicular/ovarian)", "direction": "high"}, {"condition": "Pregnancy (physiological elevation, separate reference ranges apply)", "direction": "high, non-pathological in pregnancy"}]','[{"name": "ScienceDirect Topics - Elevated Alpha-Fetoprotein", "url": "https://www.sciencedirect.com/topics/medicine-and-dentistry/elevated-alpha-fetoprotein", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["beta-hcg", "ca-125"]',NULL,NULL,'If I have known liver disease, is this rise expected or a warning sign of cancer? Do I need imaging to look for a liver tumor? If this was done during pregnancy, does it need to be repeated or combined with other screening tests?','In liver disease patients, a rising AFP typically prompts liver imaging to look for hepatocellular carcinoma. In pregnancy, an abnormal result is usually interpreted alongside other screening markers and ultrasound findings, with dating accuracy checked first since that significantly affects interpretation.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (50,'cea','Carcinoembryonic Antigen (CEA)','','CEA','Immunoassay / Tumor Markers','Tumor marker primarily used to monitor treatment response and detect recurrence in colorectal cancer; also used, less specifically, in some other GI and gynecological malignancies.',NULL,'Venous serum or plasma','No fasting required. Smoking can modestly raise CEA even without malignancy.',NULL,'Chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "CEA", "population": "Non-smoking adult", "range": "<5 ng/mL", "notes": "Smokers may have a modestly higher normal range"}]',1,'CEA is not recommended as a general cancer screening test due to low sensitivity and specificity for early disease, but it is well-established for postoperative surveillance in colorectal cancer -- a rising CEA after treatment raises concern for recurrence and prompts further imaging workup. Non-malignant causes of mild elevation include smoking, inflammatory bowel disease, pancreatitis, and liver disease.',NULL,'[{"condition": "Colorectal cancer recurrence (postoperative monitoring)", "direction": "rising trend after treatment"}, {"condition": "Smoking / inflammatory bowel disease / pancreatitis (non-malignant elevation)", "direction": "mildly high, non-specific"}]','[{"name": "PMC - Serum CA19-9, CA-125 and CEA as tumor markers for mucinous ovarian tumors (cites standard CEA reference range)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7693209/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["ca19-9", "ca-125", "afp"]',NULL,NULL,'Was my baseline level known before treatment, so this can be compared properly? Does a rising trend mean my cancer has come back or progressed? Could smoking or another benign condition explain this result?','CEA is most useful when tracked over time against your own baseline -- a rising trend after treatment for colorectal cancer typically prompts imaging to look for recurrence, while a single elevated value without a prior baseline is interpreted more cautiously given its many non-cancer causes.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (51,'ca-125','Cancer Antigen 125 (CA-125)','','CA-125, CA125','Immunoassay / Tumor Markers','Tumor marker primarily used to monitor treatment response and detect recurrence in epithelial ovarian cancer; also used as part of risk-of-malignancy assessment for an adnexal mass alongside imaging.',NULL,'Venous serum or plasma','No fasting required. Levels fluctuate with the menstrual cycle and are commonly elevated by benign conditions (endometriosis, fibroids, pelvic inflammatory disease, pregnancy, menstruation), limiting its use as a standalone screening test.',NULL,'Chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "CA-125", "population": "Adult", "range": "<35 U/mL"}]',1,'Roughly 85% of women with epithelial ovarian cancer have an elevated CA-125, but it is not specific -- many benign gynecological conditions also raise it, so CA-125 is not recommended as a general population screening test for ovarian cancer. It is most useful for monitoring known ovarian cancer during and after treatment, where a rising trend suggests recurrence, and as one input (alongside imaging and menopausal status) in risk-of-malignancy algorithms for an incidentally found ovarian mass.',NULL,'[{"condition": "Epithelial ovarian cancer (monitoring/recurrence)", "direction": "high, rising trend after treatment"}, {"condition": "Endometriosis / fibroids / pelvic inflammatory disease / pregnancy (benign causes)", "direction": "mildly-moderately high, non-malignant"}]','[{"name": "PMC - Serum CA19-9, CA-125 and CEA as tumor markers for mucinous ovarian tumors", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7693209/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["afp", "cea"]',NULL,NULL,'Given my age and menopausal status, does this result need pelvic imaging or further workup? Could a benign condition (like endometriosis or fibroids) explain this? If I have known ovarian cancer, does this reflect treatment response?','An elevated result in a postmenopausal woman, or with a pelvic mass on exam, typically prompts pelvic ultrasound and possibly gynecologic oncology referral. In someone already diagnosed with ovarian cancer, serial CA-125 is used to help track treatment response and watch for recurrence.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (52,'ca19-9','Cancer Antigen 19-9 (CA 19-9)','','CA 19-9, CA19-9','Immunoassay / Tumor Markers','Tumor marker primarily used to help differentiate pancreatic cancer from other conditions and to monitor treatment response/recurrence; also used in some biliary tract and colorectal cancers.',NULL,'Venous serum or plasma','No fasting required. Individuals who are Lewis antigen-negative (a minority of the population) cannot produce CA 19-9 and will have a falsely low/undetectable result regardless of tumor burden.',NULL,'Chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "CA 19-9", "population": "Adult", "range": "<37 U/mL"}]',1,'CA 19-9 is not sensitive or specific enough for pancreatic cancer screening in the general population, but is useful for monitoring known pancreatic or biliary tract cancer, where a marked or rising elevation after treatment suggests residual/recurrent disease. Benign causes of elevation include cholestasis/biliary obstruction, pancreatitis, and other GI inflammatory conditions -- an elevated CA 19-9 with biliary obstruction should be reassessed after the obstruction resolves.',NULL,'[{"condition": "Pancreatic cancer (monitoring/recurrence)", "direction": "high, rising trend"}, {"condition": "Biliary obstruction / cholestasis / pancreatitis (benign elevation)", "direction": "high, non-malignant"}]','[{"name": "Medscape/eMedicine - CA 19-9: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2087513-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["cea", "afp"]',NULL,NULL,'Do I need imaging (like a CT scan) to look for a pancreatic or biliary problem? Could bile duct blockage from a non-cancer cause explain this? If I have known pancreatic cancer, does this reflect how treatment is working?','An elevated result often prompts abdominal imaging to look for a pancreatic or biliary mass, especially with compatible symptoms (weight loss, jaundice, abdominal pain). In diagnosed pancreatic cancer, serial levels help track treatment response and watch for recurrence.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (53,'ca15-3','Cancer Antigen 15-3 (CA 15-3)','','CA 15-3, CA15-3','Immunoassay / Tumor Markers','Tumor marker used mainly to monitor treatment response and detect recurrence in breast cancer; not recommended for screening or initial diagnosis.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "CA 15-3", "population": "Adult", "range": "<25 U/mL"}]',1,'CA 15-3 is often normal in early-stage breast cancer, limiting its use for screening or diagnosis; it is used mainly for monitoring metastatic or advanced breast cancer during and after treatment, where trends over serial measurements are more informative than any single value. Benign conditions such as liver disease, cirrhosis, hepatitis, and benign breast disease can also elevate it.',NULL,'[{"condition": "Breast cancer (monitoring metastatic/advanced disease)", "direction": "high, rising trend suggests progression"}, {"condition": "Liver disease / benign breast disease (non-malignant elevation)", "direction": "high, non-specific"}]','[{"name": "PMC - Diagnostic Role of Tumour Markers CEA, CA15-3, CA19-9 and CA125 in Lung Cancer", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC3547445/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["cea"]',NULL,NULL,'If I have a history of breast cancer, does this suggest recurrence, or could it be a false alarm? Do I need imaging to confirm? How does this compare to my previous levels?','In someone with a breast cancer history, a rising CA 15-3 typically prompts imaging to look for recurrence or metastasis; it''s not used as a general screening test for breast cancer in people without a prior diagnosis, since it lacks the sensitivity and specificity needed for that purpose.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (54,'blood-donor-tti-screening','Blood Donor Infectious Disease Screening Panel (TTI Panel)','','TTI Screening, Donor Screening Panel, HIV/HBsAg/HCV/Syphilis Panel','Blood Bank / Immunohematology','Mandatory screening of every blood donation for the major transfusion-transmissible infections (TTIs), performed before any unit is released for clinical use, per WHO minimum requirements and national blood safety regulations.',NULL,'Venous whole blood/serum, collected from the donor at the time of donation','Testing is performed on every single donation, not just at first-time donor screening; positive/reactive results trigger donor notification, deferral, and confirmatory testing protocols per institutional and national blood safety policy.',NULL,'Chemiluminescent microparticle immunoassay (CMIA) or ELISA for HIV Ag/Ab combo, HBsAg, and anti-HCV Ab/Ag; treponemal antibody assay (or RPR/VDRL with treponemal confirmation) for syphilis. Nucleic acid testing (NAT) is used in many blood services in addition to serology to shorten the diagnostic window period.',NULL,'[{"parameter": "HIV-1/2 Ag/Ab", "population": "Result categories", "range": "Non-reactive (required for release) or Reactive"}, {"parameter": "HBsAg (Hepatitis B surface antigen)", "population": "Result categories", "range": "Non-reactive (required for release) or Reactive"}, {"parameter": "Anti-HCV Ab/Ag", "population": "Result categories", "range": "Non-reactive (required for release) or Reactive"}, {"parameter": "Treponemal antibody (Syphilis)", "population": "Result categories", "range": "Non-reactive (required for release) or Reactive"}]',1,'Per WHO guidance, only donations that are non-reactive on all four mandatory markers should be released for clinical or manufacturing use. A reactive screening result requires the unit to be discarded, the donor to be deferred, and confirmatory/supplemental testing plus donor notification and counseling per national protocol. Even with universal serologic and NAT screening, a small residual risk remains during the ''window period'' (the interval after infection before markers become detectable), which is part of the rationale for combining serology with NAT in many blood services and for maintaining strict donor risk-history screening as a complementary safeguard.',NULL,'[{"condition": "HIV, Hepatitis B, Hepatitis C, or syphilis infection in the donor", "direction": "reactive result -- unit discarded, donor deferred"}, {"condition": "Window-period infection (recently acquired, not yet detectable)", "direction": "false-negative risk despite screening -- rationale for NAT and donor history screening"}]','[{"name": "NCBI Bookshelf / WHO - Screening for transfusion-transmissible infections", "url": "https://www.ncbi.nlm.nih.gov/books/NBK142989/", "accessed": "2026-07-14"}, {"name": "PMC - Blood Supply Testing for Infectious Diseases", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC7157473/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','[]',NULL,NULL,'If any test came back reactive, what confirmatory testing is being done next? Does a reactive result definitely mean I have an infection, or could it be a false positive? Will I be notified and counseled regardless of the result?','Any reactive screening result triggers confirmatory testing before a diagnosis is communicated, and donors with confirmed reactive results are notified, counseled, and typically deferred from future donation per blood bank protocol, with referral for appropriate follow-up care.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (55,'amylase','Amylase, Serum','','Serum Amylase','Clinical Chemistry','Used, alongside lipase, to help diagnose and monitor acute pancreatitis and other pancreatic disorders.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Enzymatic kinetic assay on automated chemistry analyzers.',NULL,'[{"parameter": "Serum amylase", "population": "Adult", "range": "40-140 U/L"}]',1,'Serum amylase rises within 6-48 hours of acute pancreatitis onset but does not correlate with disease severity, and typically normalizes within 3-5 days -- lipase is generally preferred because it stays elevated longer and is more pancreas-specific. Amylase can also be elevated in non-pancreatic conditions such as bowel perforation, peptic ulcer penetration, salivary gland disease (mumps, parotitis), and macroamylasemia.',NULL,'[{"condition": "Acute pancreatitis", "direction": "high, rises within 6-48h"}, {"condition": "Salivary gland disease (mumps, parotitis) / bowel perforation (non-pancreatic causes)", "direction": "high, non-specific"}]','[{"name": "Medscape/eMedicine - Amylase: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2054386-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','[]',NULL,NULL,'Does this level, together with my symptoms, support a diagnosis of pancreatitis? Do I need a lipase test too, since it''s often more specific? Could a non-pancreatic cause (like salivary gland issues) explain this?','In suspected acute pancreatitis, amylase is typically interpreted alongside lipase (which is more specific and stays elevated longer) and imaging; a markedly elevated result with compatible abdominal pain supports the diagnosis, while a mildly elevated result without typical symptoms may not need urgent action.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (56,'lipase','Lipase, Serum','','Serum Lipase','Clinical Chemistry','The preferred enzyme marker (alongside or instead of amylase) for diagnosing and monitoring acute pancreatitis, due to its greater pancreas-specificity and longer window of elevation.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Enzymatic kinetic assay on automated chemistry analyzers.',NULL,'[{"parameter": "Serum lipase", "population": "Adult", "range": "7-60 U/L", "notes": "Varies by lab/assay"}]',1,'Lipase greater than 3x the upper limit of normal, in the appropriate clinical context (epigastric pain radiating to the back, nausea/vomiting), is one of the diagnostic criteria for acute pancreatitis. Lipase remains elevated longer than amylase (up to 8-14 days), making it useful even when a patient presents somewhat later in the course of illness. It is more specific to the pancreas than amylase, though renal failure and some non-pancreatic abdominal conditions can also raise it.',NULL,'[{"condition": "Acute pancreatitis", "direction": "high, typically >3x upper limit of normal"}, {"condition": "Renal failure (reduced clearance, non-pancreatic elevation)", "direction": "mildly high, non-specific"}]','[{"name": "Clinical trial protocol reference range compilation (multi-site laboratory reference table)", "url": "https://cdn.clinicaltrials.gov/large-docs/87/NCT05025787/Prot_002.pdf", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','[]',NULL,NULL,'Does this confirm pancreatitis, and how severe does it look based on this level plus my symptoms? Do I need imaging (like a CT or ultrasound) to look for a cause (gallstones, etc.)? How will this be monitored going forward?','A markedly elevated lipase with compatible symptoms generally confirms acute pancreatitis and prompts imaging to identify the cause (commonly gallstones or alcohol) and assess severity, guiding hospital management and monitoring.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (57,'beta-hcg','Human Chorionic Gonadotropin, Beta Subunit (Beta-hCG)','','hCG, Beta-hCG, Pregnancy Test (Quantitative)','Immunoassay / Reproductive Endocrinology','Confirms and monitors early pregnancy; also used as a tumor marker in suspected gestational trophoblastic disease and, alongside AFP and LDH, in the workup of suspected testicular/germ cell tumors.',NULL,'Venous serum or plasma (quantitative); urine (qualitative point-of-care testing)','No fasting required. Serial quantitative levels (drawn 48 hours apart) are used in early pregnancy to assess whether a pregnancy is progressing normally (levels should roughly double every 48-72 hours in early normal pregnancy) or raise concern for ectopic pregnancy/miscarriage.',NULL,'Chemiluminescent immunoassay (quantitative, serum) or lateral-flow immunochromatographic assay (qualitative, urine point-of-care).',NULL,'[{"parameter": "Beta-hCG", "population": "Non-pregnant", "range": "<5 mIU/mL"}, {"parameter": "Beta-hCG", "population": "Early pregnancy detection threshold", "range": "\u226525 mIU/mL typically detectable, often positive by ~2-3 days before expected menses"}]',1,'A positive/detectable hCG confirms pregnancy; quantitative serial levels that fail to roughly double over 48-72 hours in early pregnancy raise concern for an ectopic pregnancy or a failing intrauterine pregnancy and prompt further evaluation (ultrasound correlation). Markedly elevated hCG for gestational age can suggest multiple gestation or gestational trophoblastic disease (molar pregnancy). Outside of pregnancy, elevated hCG can indicate a germ cell tumor or, rarely, other malignancies.',NULL,'[{"condition": "Normal early pregnancy", "direction": "positive, appropriately rising serial levels"}, {"condition": "Ectopic pregnancy / failing pregnancy", "direction": "positive, abnormally slow rise or fall"}, {"condition": "Gestational trophoblastic disease (molar pregnancy)", "direction": "markedly high for gestational age"}, {"condition": "Germ cell tumors (non-pregnant)", "direction": "high"}]','[{"name": "Children''s Minnesota Lab Reference - Pregnancy Test, Urine (hCG kinetics in early pregnancy)", "url": "https://www.childrensmn.org/references/lab/urinestool/pregnancy-test-urine.pdf", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["afp", "progesterone"]',NULL,NULL,'Is this level appropriate for how many weeks pregnant I am thought to be? Do I need a repeat test in 48 hours to check the trend? If this isn''t a pregnancy-related test, what does an elevated result mean for me?','In early pregnancy, results are often followed with a repeat test 48 hours later to check that the level is rising appropriately, which helps distinguish a normal early pregnancy from a possible miscarriage or ectopic pregnancy -- ultrasound is added once levels reach the range where a pregnancy should be visible.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (58,'urinalysis','Urinalysis (Routine)','','UA, Urine Analysis, Routine Urinalysis','Clinical Chemistry / Urinalysis','Broad screening test for urinary tract, kidney, and metabolic disorders, evaluating the physical, chemical, and microscopic characteristics of urine in a single panel.',NULL,'Random, first-morning, or clean-catch midstream urine (clean-catch preferred to reduce contamination for culture correlation)','First-morning specimens are most concentrated and preferred when feasible; clean-catch technique reduces contamination that can confound interpretation (especially white cells/bacteria).',NULL,'Physical examination (color, clarity), chemical analysis by reagent dipstick (pH, specific gravity, protein, glucose, ketones, blood, leukocyte esterase, nitrite, bilirubin, urobilinogen), and microscopic examination of urine sediment (red cells, white cells, casts, crystals, bacteria) when indicated.',NULL,'[{"parameter": "Color/clarity", "population": "Normal", "range": "Pale yellow to amber, clear"}, {"parameter": "Specific gravity", "population": "Normal", "range": "1.005-1.030"}, {"parameter": "pH", "population": "Normal", "range": "4.5-8.0"}, {"parameter": "Protein, glucose, ketones, blood, leukocyte esterase, nitrite, bilirubin", "population": "Normal", "range": "Negative"}, {"parameter": "Microscopic RBC/WBC", "population": "Normal", "range": "0-2 RBC/hpf; 0-5 WBC/hpf (varies by lab)"}]',1,'Protein or blood on dipstick prompts further evaluation for glomerular or urinary tract disease (and quantitative urine protein/albumin-creatinine ratio if persistent). Leukocyte esterase and nitrite positivity suggest urinary tract infection, ideally confirmed with urine culture. Glucose and ketones can indicate diabetes/diabetic ketoacidosis. Microscopic findings such as red cell casts, white cell casts, or specific crystal types point toward particular kidney diseases and require correlation with the full clinical picture -- urinalysis is a screening tool, not a standalone diagnosis.',NULL,'[{"condition": "Urinary tract infection", "direction": "positive leukocyte esterase/nitrite, pyuria"}, {"condition": "Glomerular disease / nephrotic or nephritic syndrome", "direction": "proteinuria and/or hematuria, possible casts"}, {"condition": "Diabetes mellitus / diabetic ketoacidosis", "direction": "glucosuria and/or ketonuria"}]','[{"name": "MedlinePlus (NIH/NLM) - Basic Metabolic Panel reference table cross-referenced with standard urinalysis parameters", "url": "https://medlineplus.gov/lab-tests/basic-metabolic-panel-bmp/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:00:36','2026-07-14 11:00:36','["creatinine", "urine-culture"]',NULL,NULL,'Does this suggest a urinary tract infection, kidney issue, or something else? Do I need a urine culture to confirm and guide antibiotic choice if infection is suspected? Should this be repeated after treatment to confirm resolution?','Findings suggestive of infection (positive leukocyte esterase/nitrite, elevated white cells) typically lead to a urine culture to confirm and guide antibiotic selection. Findings suggestive of kidney involvement (protein, blood, abnormal casts) typically prompt further kidney function testing and possible referral.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (59,'total-testosterone','Testosterone, Total, Serum','','Total Testosterone, T','Immunoassay / Reproductive Endocrinology','Evaluates androgen status; used to investigate hypogonadism, erectile dysfunction, and low libido in men, and hirsutism/virilization or suspected androgen-secreting tumors in women.',NULL,'Venous serum or plasma','Morning sample (before 10 AM) strongly preferred in men, as testosterone follows a diurnal pattern and peaks in the early morning.',NULL,'Chemiluminescent immunoassay (CLIA) for routine screening; LC-MS/MS is the preferred, more specific method at low concentrations (e.g., in women, children, and hypogonadal men) per current endocrine guidelines.',NULL,'[{"parameter": "Total testosterone", "population": "Adult male (\u226519 years)", "range": "240-950 ng/dL"}, {"parameter": "Total testosterone", "population": "Adult female (\u226519 years)", "range": "8-60 ng/dL"}]',1,'Low testosterone in men (with compatible symptoms, confirmed on a repeat morning sample) supports a diagnosis of hypogonadism; LH/FSH levels help distinguish primary (testicular) from secondary (pituitary/hypothalamic) causes. Elevated testosterone in women can suggest PCOS (usually mild elevation) or, when total testosterone exceeds roughly 150-200 ng/dL, raises concern for an androgen-secreting ovarian or adrenal tumor requiring further workup.',NULL,'[{"condition": "Male hypogonadism (primary or secondary)", "direction": "low, in men"}, {"condition": "Polycystic ovary syndrome (PCOS)", "direction": "mildly high, in women"}, {"condition": "Androgen-secreting ovarian/adrenal tumor", "direction": "markedly high, in women"}]','[{"name": "Mayo Clinic Laboratories - Testosterone, Total and Bioavailable, Serum (test catalog)", "url": "https://endocrinology.testcatalog.org/show/TTBS", "accessed": "2026-07-14"}]',1,'2026-07-14 11:05:58','2026-07-14 11:05:58','["free-testosterone", "fsh", "lh", "prolactin"]',NULL,NULL,'Was this drawn in the morning, since levels vary through the day? Do I need a repeat test to confirm before any treatment decision? Should free testosterone or SHBG be checked too for a fuller picture?','A low result is typically confirmed with a repeat morning sample before diagnosing hypogonadism, and further testing (LH, FSH) helps determine whether the cause is testicular or related to the pituitary/hypothalamus, which guides treatment options.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (60,'free-testosterone','Testosterone, Free, Serum','','Free Testosterone','Immunoassay / Reproductive Endocrinology','Measures the biologically active, unbound fraction of testosterone; useful when total testosterone is borderline or when sex hormone-binding globulin (SHBG) is abnormal (e.g., obesity, thyroid disease, aging), which can distort the total testosterone result.',NULL,'Venous serum or plasma','Morning sample preferred, same rationale as total testosterone.',NULL,'Equilibrium dialysis (reference method) or calculated from total testosterone, SHBG, and albumin; direct immunoassay methods for free testosterone are less reliable and generally discouraged by endocrine societies.',NULL,'[{"parameter": "Free testosterone", "population": "Adult male", "range": "9-30 ng/dL"}, {"parameter": "Free testosterone", "population": "Adult female", "range": "0.3-1.9 ng/dL"}]',1,'Free testosterone is most useful when total testosterone is equivocal but SHBG is abnormal -- for example, a normal total testosterone with low free testosterone can occur when SHBG is elevated, masking true androgen deficiency. Interpretation should follow the same clinical framework as total testosterone (hypogonadism workup in men, hyperandrogenism workup in women).',NULL,'[{"condition": "Male hypogonadism masked by abnormal SHBG on total testosterone alone", "direction": "low"}, {"condition": "Hyperandrogenism (PCOS and related conditions)", "direction": "high, in women"}]','[{"name": "USPTO patent literature citing Mayo Clinic 2013 reference ranges for testosterone (free and total)", "url": "https://image-ppubs.uspto.gov/dirsearch-public/print/downloadPdf/9482678", "accessed": "2026-07-14"}]',1,'2026-07-14 11:05:58','2026-07-14 11:05:58','["total-testosterone", "prolactin"]',NULL,NULL,'Does this change the interpretation of my total testosterone result? Could an SHBG abnormality (from weight, thyroid, or other factors) be affecting this? What does this mean for my symptoms and treatment options?','This result is used alongside total testosterone and SHBG to get the clearest picture of your androgen status, particularly when the total testosterone alone doesn''t fully explain your symptoms.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (61,'prolactin','Prolactin, Serum','','PRL','Immunoassay / Reproductive Endocrinology','Evaluates suspected hyperprolactinemia (galactorrhea, menstrual irregularity, infertility, erectile dysfunction/low libido) and helps investigate suspected pituitary adenoma (prolactinoma).',NULL,'Venous serum or plasma','Draw when the patient is relaxed and fasting is not required; avoid recent breast exam, sexual activity, or significant stress/exercise before the draw, as these can transiently raise prolactin. Consider repeating an elevated result before extensive workup, as prolactin secretion is pulsatile and stress-sensitive.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "Prolactin", "population": "Adult male", "range": "<20 ng/mL", "notes": "Upper limit varies by lab/assay, commonly cited as 15-25 ng/mL"}, {"parameter": "Prolactin", "population": "Adult female, non-pregnant", "range": "<25 ng/mL", "notes": "Upper limit varies by lab/assay"}]',1,'Mild-to-moderate elevation is commonly caused by medications (antipsychotics, some antiemetics/antidepressants), hypothyroidism, renal failure, or physiologic causes (pregnancy, stress, nipple stimulation). Marked elevation (often >200 ng/mL) is more specific for a prolactin-secreting pituitary adenoma (prolactinoma) and warrants pituitary imaging. High prolactin suppresses GnRH, causing low LH/FSH and secondary hypogonadism -- explaining menstrual irregularity in women and low testosterone/libido in men. Low prolactin is less commonly clinically significant.',NULL,'[{"condition": "Medication-induced hyperprolactinemia (antipsychotics, etc.)", "direction": "mild-moderate high"}, {"condition": "Prolactinoma (pituitary adenoma)", "direction": "markedly high, often >200 ng/mL"}, {"condition": "Primary hypothyroidism", "direction": "mild high (via elevated TRH)"}, {"condition": "Secondary hypogonadism from prolactin excess", "direction": "high prolactin with low LH/FSH/testosterone or estradiol"}]','[{"name": "Jinfiniti Precision Medicine - Prolactin Blood Test Levels, citing Canadian Medical Association primary care guidance", "url": "https://www.jinfiniti.com/prolactin-blood-test-levels/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:05:58','2026-07-14 11:05:58','["fsh", "lh", "total-testosterone", "tsh"]',NULL,NULL,'Could a medication I''m taking be causing this elevation? Do I need pituitary imaging? If markedly elevated, does this need urgent follow-up?','Mild elevation is often rechecked and reviewed against your medication list and recent activity before the day of the draw. Marked elevation typically prompts pituitary MRI to look for a prolactin-secreting tumor, along with thyroid function testing to rule out that as a contributing cause.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (62,'semen-analysis','Semen Analysis (WHO 2021)','','Sperm Analysis, Spermiogram, Sperm Count','Andrology','Evaluates male fertility potential by assessing semen volume, sperm concentration, motility, and morphology; a core component of the infertility workup for couples, and used to confirm sterility after vasectomy.',NULL,'Semen sample, collected by masturbation into a sterile container after 2-7 days of sexual abstinence (per WHO recommendation)','Sample should reach the laboratory and be analyzed within 1 hour of collection, kept close to body temperature during transport. Because sperm parameters vary significantly between ejaculates and spermatogenesis takes about 72 days, a single abnormal result should be confirmed with a repeat analysis 4-8 weeks later before drawing conclusions.',NULL,'Manual microscopic assessment (hemocytometer counting chamber for concentration, motility and morphology graded per WHO criteria) or computer-assisted sperm analysis (CASA) systems.',NULL,'[{"parameter": "Semen volume", "population": "WHO 2021 lower reference limit (5th centile)", "range": "\u22651.4 mL"}, {"parameter": "Sperm concentration", "population": "WHO 2021 lower reference limit", "range": "\u226516 million/mL"}, {"parameter": "Total motility", "population": "WHO 2021 lower reference limit", "range": "\u226542%"}, {"parameter": "Progressive motility", "population": "WHO 2021 lower reference limit", "range": "\u226530%"}, {"parameter": "Normal morphology (strict criteria)", "population": "WHO 2021 lower reference limit", "range": "\u22654%"}]',1,'WHO 2021 lower reference limits represent the 5th percentile of semen parameters from a large cohort of fertile men whose partners conceived naturally within 12 months -- they are a statistical benchmark, not a strict pass/fail cutoff, and a single below-threshold result does not by itself diagnose infertility. Common patterns include oligozoospermia (low concentration), asthenozoospermia (reduced motility), teratozoospermia (abnormal morphology), or azoospermia (no sperm seen), which require correlation with hormonal workup (FSH, LH, testosterone) and clinical evaluation. Results are compared against the specific WHO edition used by the reporting laboratory, since thresholds have changed across the 1999, 2010, and 2021 editions.',NULL,'[{"condition": "Male factor infertility (oligo-/astheno-/teratozoospermia)", "direction": "below WHO lower reference limit(s)"}, {"condition": "Obstructive or non-obstructive azoospermia", "direction": "no sperm observed"}, {"condition": "Post-vasectomy sterility confirmation", "direction": "azoospermia expected post-procedure"}]','[{"name": "Boeri et al., Andrology (Wiley) - The impact of different WHO reference criteria for semen analysis in clinical practice (WHO 1999/2010/2021 comparison table)", "url": "https://onlinelibrary.wiley.com/doi/10.1111/andr.13213", "accessed": "2026-07-14"}, {"name": "PMC - Trends in sperm quality by computer-assisted sperm analysis (WHO 5th edition/2021 reference values)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC10390301/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:05:58','2026-07-14 11:05:58','["total-testosterone", "free-testosterone", "prolactin"]',NULL,NULL,'Given that results can vary between samples, do I need a repeat test to confirm this finding? Does this explain our fertility difficulties, or do we need more testing? What are our options based on this result?','An abnormal result is usually confirmed with a repeat analysis 4-8 weeks later before drawing conclusions, since sperm parameters vary naturally. Persistently abnormal results typically lead to hormonal testing (testosterone, FSH, LH) and a discussion of fertility treatment options with a specialist.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (63,'hbsag','Hepatitis B Surface Antigen (HBsAg)','','HBsAg, Hepatitis B Surface Antigen','Immunoassay / Infectious Disease Serology','Primary screening test for current hepatitis B virus (HBV) infection (acute or chronic); required for blood/organ donor screening, prenatal screening, and routine adult HBV screening per CDC recommendations.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Chemiluminescent microparticle immunoassay (CMIA) or similar automated immunoassay; reactive (positive) results are typically confirmed by a neutralization assay before being reported as confirmed-positive, and may reflex to quantitative HBV DNA PCR.',NULL,'[{"parameter": "HBsAg", "population": "Result categories", "range": "Non-reactive (negative) or Reactive (positive) -- reported by signal-to-cutoff ratio, not a numeric concentration"}]',1,'A reactive HBsAg indicates the person is currently infected with hepatitis B (acute or chronic) and is potentially infectious. Persistence of HBsAg beyond 6 months defines chronic HBV infection, which requires further evaluation (HBeAg, HBV DNA viral load, liver function) and specialist referral for possible antiviral therapy. HBsAg is one of three tests (with anti-HBc and anti-HBs) used together to fully characterize a person''s HBV status (never infected, actively infected, resolved infection/immune, or vaccinated/immune).',NULL,'[{"condition": "Acute hepatitis B infection", "direction": "reactive, with symptoms/elevated ALT"}, {"condition": "Chronic hepatitis B infection", "direction": "reactive, persisting beyond 6 months"}]','[{"name": "UW Medicine - Hepatitis B Surface Antigen (HBsAg) with reflex to PCR, Laboratory Test Guide", "url": "https://dlmp.uw.edu/test-guide/view/HBSAG", "accessed": "2026-07-14"}]',1,'2026-07-14 11:05:58','2026-07-14 11:05:58','["hbsab", "alt-ast", "total-bilirubin"]',NULL,NULL,'Does this mean I have an active infection, and is it acute or chronic? Do family members or close contacts need to be tested or vaccinated? What follow-up care do I need?','A reactive result leads to further testing (HBeAg, HBV DNA viral load, liver function tests) to characterize the infection and referral to a specialist for ongoing monitoring and consideration of antiviral treatment if chronic infection is confirmed.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (64,'hbsab','Hepatitis B Surface Antibody (Anti-HBs)','','HBsAb, Anti-HBs, Hepatitis B Surface Antibody','Immunoassay / Infectious Disease Serology','Determines immunity to hepatitis B, either from prior vaccination or from resolved past infection; used to confirm post-vaccination immune response, especially in healthcare workers.',NULL,'Venous serum or plasma','No fasting required. If checking post-vaccination response, timing is typically 1-2 months after completing the vaccine series.',NULL,'Chemiluminescent immunoassay (CLIA); available as qualitative (reactive/non-reactive) or quantitative (mIU/mL) testing.',NULL,'[{"parameter": "Anti-HBs (qualitative)", "population": "Result categories", "range": "Reactive (immune) or Non-reactive (not immune)"}, {"parameter": "Anti-HBs (quantitative)", "population": "Protective threshold", "range": "\u226510 mIU/mL considered protective"}]',1,'A reactive anti-HBs with a non-reactive HBsAg and non-reactive anti-HBc indicates vaccine-induced immunity. A reactive anti-HBs together with reactive anti-HBc indicates immunity from a past, resolved natural infection. A quantitative titer below 10 mIU/mL after vaccination suggests an inadequate response, and revaccination may be recommended, particularly in healthcare workers or immunocompromised patients.',NULL,'[{"condition": "Vaccine-induced immunity", "direction": "reactive anti-HBs, non-reactive anti-HBc"}, {"condition": "Immunity from resolved past infection", "direction": "reactive anti-HBs, reactive anti-HBc"}, {"condition": "Inadequate vaccine response", "direction": "quantitative titer <10 mIU/mL post-vaccination"}]','[{"name": "HealthMatters.io - Hepatitis B Surface Antibody (Qual): Reactive and Non-Reactive Results", "url": "https://healthmatters.io/understand-blood-test-results/hep-b-surface-ab-qual", "accessed": "2026-07-14"}]',1,'2026-07-14 11:05:58','2026-07-14 11:05:58','["hbsag", "alt-ast"]',NULL,NULL,'Does this confirm I''m protected against hepatitis B? If my level is below the protective threshold, do I need a booster vaccine? Should this be rechecked periodically given my occupation or health status?','A protective level generally means no further action is needed. A level below the protective threshold after vaccination typically leads to a booster dose, particularly important for healthcare workers or others with ongoing exposure risk.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (65,'hiv-ag-ab-combo','HIV Antigen/Antibody Combination Screen','','HIV Combo, HIV Ag/Ab, 4th Generation HIV Test, HIV p24/Antibody Screen','Immunoassay / Infectious Disease Serology','Fourth-generation screening test for HIV-1 and HIV-2 infection, detecting both the HIV-1 p24 antigen (present early in acute infection, before antibodies develop) and antibodies to HIV-1/HIV-2; recommended as the standard initial screening assay by current testing algorithms.',NULL,'Venous serum or plasma','No fasting required. Antibodies are not reliably detectable until roughly 3 weeks after exposure, so a very recent (acute) exposure may still test negative even with the more sensitive combo assay.',NULL,'Chemiluminescent immunoassay (CMIA) detecting both p24 antigen and HIV-1/2 antibodies simultaneously; reactive (positive) results are confirmed with an HIV-1/HIV-2 antibody-differentiating immunoassay, with reflex to HIV-1 RNA nucleic acid testing (NAT) when the differentiating assay is negative or indeterminate.',NULL,'[{"parameter": "HIV Ag/Ab Combo", "population": "Result categories", "range": "Non-reactive (negative) or Reactive (positive, requires confirmatory testing) -- reported by signal-to-cutoff ratio"}]',1,'A non-reactive result on the initial screen generally means no HIV infection, without need for further confirmatory antibody-differentiating testing, when outside the window period. A reactive screening result with a non-reactive or indeterminate differentiating assay may indicate very recent (acute) HIV infection and requires HIV-1 RNA testing to clarify. A reactive screen confirmed by a reactive differentiating assay establishes the diagnosis and identifies HIV-1 versus HIV-2.',NULL,'[{"condition": "Acute HIV infection (early window period)", "direction": "reactive combo screen, non-reactive/indeterminate differentiating assay -- needs RNA testing"}, {"condition": "Established HIV-1 or HIV-2 infection", "direction": "reactive screen confirmed by reactive differentiating assay"}]','[{"name": "UW Medicine - HIV Antigen and Antibody Screen, Laboratory Test Guide", "url": "https://dlmp.uw.edu/test-guide/view/HVAGAB", "accessed": "2026-07-14"}, {"name": "Virginia Dept. of Health - Current HIV Testing Guidelines and Additional Considerations", "url": "https://www.vdh.virginia.gov/content/uploads/sites/10/2021/02/Provider_Messaging_2019_Final.pdf", "accessed": "2026-07-14"}]',1,'2026-07-14 11:05:58','2026-07-14 11:05:58','["cbc", "hbsag"]',NULL,NULL,'If reactive, what confirmatory testing is being done, and how soon will I know the result? Given the timing of my possible exposure, could this be a false negative from testing too early? What support and next steps are available regardless of the result?','A reactive result is followed by a confirmatory differentiating test and, if needed, HIV RNA testing before a diagnosis is finalized -- your care team will guide you through this process with appropriate counseling and support at every step.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (66,'fibrinogen','Fibrinogen, Plasma','','Factor I, Clauss Fibrinogen','Hematology / Coagulation','Assesses the final common pathway of coagulation; used to investigate unexplained bleeding, monitor DIC and massive transfusion/obstetric hemorrhage, and evaluate for congenital fibrinogen disorders.',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Tube must be filled to the correct volume for the citrate:blood ratio to be accurate.',NULL,'Clauss (functional/clot-based) method is the most common; a fibrinogen antigen (immunologic) assay measures total protein regardless of function and is used to distinguish hypo- from dysfibrinogenemia.',NULL,'[{"parameter": "Fibrinogen (Clauss/functional)", "population": "Adult", "range": "150-400 mg/dL", "notes": "Some labs report a slightly wider range (e.g., 150-450 mg/dL)"}]',1,'Low fibrinogen (<100 mg/dL) is associated with bleeding risk and is seen in DIC, severe liver disease, massive transfusion/dilutional coagulopathy, and rare congenital fibrinogen disorders (afibrinogenemia, hypofibrinogenemia, dysfibrinogenemia). As an acute-phase reactant, fibrinogen rises with inflammation, infection, pregnancy, and malignancy, and elevated levels are also an independent cardiovascular risk marker. In DIC, fibrinogen is monitored serially alongside platelets, D-dimer, and PT/aPTT.',NULL,'[{"condition": "Disseminated intravascular coagulation (DIC)", "direction": "low, falling trend"}, {"condition": "Severe liver disease", "direction": "low"}, {"condition": "Congenital afibrinogenemia/hypofibrinogenemia/dysfibrinogenemia", "direction": "low (or normal antigen with abnormal function in dysfibrinogenemia)"}, {"condition": "Acute-phase response / inflammation / pregnancy", "direction": "high"}]','[{"name": "Medscape/eMedicine - Fibrinogen: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2085501-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 11:11:12','2026-07-14 11:11:12','["pt-inr", "aptt", "d-dimer"]','Fibrinogen <100 mg/dL is generally considered a critical/actionable value indicating significant bleeding risk, and is a common trigger for fibrinogen replacement (cryoprecipitate or fibrinogen concentrate) in actively bleeding patients, particularly in DIC or massive transfusion settings.','As an acute-phase reactant, fibrinogen is nonspecifically elevated by any acute inflammation, infection, recent surgery, or pregnancy, which can mask an underlying mild congenital deficiency. Sample clotting during collection (inadequate mixing with the citrate anticoagulant) falsely lowers the measured level.','Does this level explain any bleeding I''ve experienced? If low, do I need replacement (like cryoprecipitate) before a procedure? Could this be related to my liver function or an ongoing clotting disorder?','A low level, especially with bleeding or before a planned procedure, often prompts fibrinogen replacement and investigation of the underlying cause (liver disease, DIC, or a rare congenital disorder if there''s no other explanation).');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (67,'antithrombin-iii','Antithrombin III (Antithrombin Activity)','','AT-III, Antithrombin Activity','Hematology / Coagulation','Screens for hereditary or acquired antithrombin deficiency as part of a thrombophilia workup, typically after an unprovoked or recurrent venous thromboembolism, especially at a young age or with a positive family history.',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Testing is ideally deferred until at least 2-6 weeks after an acute thrombotic event and while off anticoagulation (or with awareness that heparin and warfarin can affect results), since acute thrombosis and anticoagulant therapy can transiently lower levels and confound interpretation.',NULL,'Chromogenic (functional activity) assay is standard; an antigen (immunologic) assay is used to distinguish Type I (reduced protein and activity) from Type II (normal protein, reduced activity) hereditary deficiency.',NULL,'[{"parameter": "Antithrombin activity", "population": "Adult", "range": "80-120%", "notes": "Reference intervals vary by lab/method"}]',1,'Hereditary antithrombin deficiency is a rare but strong risk factor for venous thromboembolism, typically presenting with a first clot in early adulthood. Acquired reductions occur with liver disease/cirrhosis, nephrotic syndrome (urinary loss), DIC, acute thrombosis itself (consumption), L-asparaginase therapy, and pregnancy/estrogen use (mild reduction). Antithrombin is also the cofactor for heparin''s anticoagulant effect, so severe deficiency can cause apparent heparin resistance.',NULL,'[{"condition": "Hereditary antithrombin deficiency (venous thromboembolism risk)", "direction": "low"}, {"condition": "Liver disease / nephrotic syndrome / DIC / acute thrombosis", "direction": "low, acquired"}, {"condition": "Heparin resistance", "direction": "low, causing reduced heparin effect"}]','[{"name": "Medscape/eMedicine - Antithrombin III: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2084978-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 11:11:12','2026-07-14 11:11:12','["protein-c", "protein-s", "pt-inr", "aptt"]',NULL,NULL,'Does this explain my history of blood clots? Do family members need to be tested? How does this affect my anticoagulation treatment, especially around starting or stopping heparin?','A confirmed deficiency typically leads to hematology referral for guidance on long-term anticoagulation strategy and, since it''s often hereditary, consideration of family member testing, particularly if there''s a personal or family history of blood clots.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (68,'protein-c','Protein C Activity','','Protein C','Hematology / Coagulation','Screens for hereditary or acquired protein C deficiency as part of a thrombophilia workup; also relevant when starting warfarin, since severe deficiency carries a risk of warfarin-induced skin necrosis.',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Should not be tested during an acute thrombotic event or while on warfarin (which lowers protein C, a vitamin K-dependent factor) unless interpreted with that context in mind; testing is ideally deferred to a stable, non-anticoagulated state when possible.',NULL,'Chromogenic or clot-based (functional activity) assay on automated coagulation analyzers.',NULL,'[{"parameter": "Protein C activity", "population": "Adult", "range": "70-140%", "notes": "Reference intervals vary by lab/method"}]',1,'Protein C is a natural anticoagulant that, together with protein S, inactivates factors Va and VIIIa. Hereditary deficiency increases venous thromboembolism risk. Acquired reductions occur with warfarin therapy, liver disease, DIC, and vitamin K deficiency. Because protein C has a short half-life, starting warfarin without concurrent heparin bridging in a patient with protein C deficiency can transiently create a hypercoagulable state, causing warfarin-induced skin necrosis -- a key reason protein C status is considered before/during warfarin initiation in high-risk patients.',NULL,'[{"condition": "Hereditary protein C deficiency (venous thromboembolism risk)", "direction": "low"}, {"condition": "Warfarin-induced skin necrosis risk", "direction": "low, especially if warfarin started without heparin bridging"}, {"condition": "Liver disease / vitamin K deficiency / DIC", "direction": "low, acquired"}]','[{"name": "PMC - High prevalence of protein C, protein S, antithrombin deficiency, and Factor V Leiden mutation as a cause of hereditary thrombophilia", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4320724/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:11:12','2026-07-14 11:11:12','["protein-s", "antithrombin-iii", "pt-inr"]',NULL,NULL,'Does this explain my clotting history? If I need to start warfarin, does this affect how that''s managed to avoid complications? Should other family members be tested?','A confirmed deficiency is factored into your anticoagulation plan (particularly ensuring heparin bridging if warfarin is started, to avoid warfarin-induced skin necrosis) and often prompts a hematology referral and consideration of family testing.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (69,'protein-s','Protein S (Free Antigen or Activity)','','Protein S','Hematology / Coagulation','Screens for hereditary or acquired protein S deficiency as part of a thrombophilia workup, usually alongside protein C and antithrombin.',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Same timing caveats as protein C -- avoid testing during acute thrombosis, pregnancy, estrogen/oral contraceptive use, or warfarin therapy when possible, as all of these lower protein S levels.',NULL,'Free protein S antigen (immunologic, measuring the active unbound fraction) or a functional clot-based activity assay.',NULL,'[{"parameter": "Free protein S", "population": "Adult male", "range": "75-145%", "notes": "Reference intervals vary by lab/method"}, {"parameter": "Free protein S", "population": "Adult female", "range": "55-125%", "notes": "Lower than males; further reduced by pregnancy and estrogen use"}]',1,'Protein S is a cofactor for protein C''s anticoagulant activity; hereditary deficiency increases venous thromboembolism risk, similar to protein C deficiency. Levels are physiologically lower in women, and further reduced by pregnancy, estrogen-containing contraceptives/hormone therapy, warfarin, liver disease, DIC, and nephrotic syndrome (urinary loss) -- all of which must be considered before diagnosing a hereditary deficiency from a single low result.',NULL,'[{"condition": "Hereditary protein S deficiency (venous thromboembolism risk)", "direction": "low"}, {"condition": "Pregnancy / estrogen therapy / oral contraceptive use", "direction": "low, physiologic/acquired"}, {"condition": "Warfarin therapy / liver disease / nephrotic syndrome", "direction": "low, acquired"}]','[{"name": "PMC - High prevalence of protein C, protein S, antithrombin deficiency, and Factor V Leiden mutation as a cause of hereditary thrombophilia", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4320724/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:11:12','2026-07-14 11:11:12','["protein-c", "antithrombin-iii", "pt-inr"]',NULL,NULL,'Could pregnancy, hormone therapy, or another medication be lowering this result rather than a true deficiency? Does this explain my clotting history? Do I need this rechecked at a different time?','Given how many things can lower protein S levels, a low result is often rechecked once you''re off relevant medications/hormones and not acutely ill or pregnant, before a hereditary deficiency is diagnosed and long-term management planned.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (70,'reticulocyte-count','Reticulocyte Count','','Retic Count, Reticulocytes','Hematology','Assesses bone marrow''s red blood cell production activity; used to classify anemia (production vs. destruction/loss) and to monitor marrow recovery after treatment (e.g., chemotherapy, iron/B12 replacement, bone marrow transplant).',NULL,'Venous whole blood, EDTA tube (lavender top)','No fasting required. Best interpreted alongside hemoglobin/hematocrit, since the raw percentage can be misleadingly elevated in anemia -- a corrected reticulocyte count or reticulocyte production index should be used when anemia is present.',NULL,'Automated flow cytometry with fluorescent RNA-binding dyes (e.g., thiazole orange) on hematology analyzers, or manual microscopic counting with supravital staining (e.g., new methylene blue).',NULL,'[{"parameter": "Reticulocyte percentage", "population": "Adult, non-anemic", "range": "0.5%-2.5%"}, {"parameter": "Absolute reticulocyte count", "population": "Adult", "range": "~25,000-75,000/\u00b5L", "notes": "Some sources cite up to 100,000/\u00b5L as the upper limit"}]',1,'A high (corrected) reticulocyte count in the setting of anemia indicates an appropriate marrow response to blood loss or hemolysis (e.g., hemolytic anemia, acute bleeding, or recovery phase after treatment). A low or inappropriately normal reticulocyte count in the setting of anemia suggests decreased marrow production, as seen in iron/B12/folate deficiency, chronic kidney disease (reduced erythropoietin), marrow infiltration by malignancy, or marrow failure syndromes. The reticulocyte production index (RPI), which corrects for both anemia severity and reticulocyte maturation time, is the most reliable way to interpret the result when hematocrit is reduced.',NULL,'[{"condition": "Hemolytic anemia / acute blood loss / marrow recovery", "direction": "high (appropriate marrow response)"}, {"condition": "Iron, B12, or folate deficiency anemia", "direction": "low or inappropriately normal for degree of anemia"}, {"condition": "Chronic kidney disease / marrow failure / marrow infiltration", "direction": "low"}]','[{"name": "MedlinePlus (NIH/NLM) - Reticulocyte count", "url": "https://medlineplus.gov/ency/article/003637.htm", "accessed": "2026-07-14"}, {"name": "Medscape/eMedicine - Reticulocyte Count and Reticulocyte Hemoglobin Content: Reference Range", "url": "https://emedicine.medscape.com/article/2086146-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 11:11:12','2026-07-14 11:11:12','["cbc", "ferritin", "vitamin-b12", "folate"]',NULL,NULL,'Does this suggest my bone marrow is responding appropriately to my anemia, or not producing enough new blood cells? Do I need iron, B12, or folate testing based on this result? How does this fit with my other blood counts?','A low or inappropriately normal result in the setting of anemia typically prompts iron studies, B12, and folate testing to look for a nutritional cause, or further workup for bone marrow function if those are normal.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (71,'g6pd','Glucose-6-Phosphate Dehydrogenase (G6PD) Screen','','G6PD, G6PD Deficiency Screen','Hematology','Screens for G6PD deficiency, an X-linked enzyme deficiency that predisposes red blood cells to oxidative hemolysis; used to investigate unexplained hemolytic anemia and before prescribing certain oxidant drugs (e.g., some antimalarials, dapsone, sulfonamides) in at-risk populations.',NULL,'Venous whole blood, EDTA tube (lavender top)','Testing during or shortly after an acute hemolytic episode can give a falsely normal result, because the oldest (most deficient) red cells have already been destroyed and young cells/reticulocytes have relatively higher enzyme activity -- retesting several weeks after recovery is recommended if an acute-phase result is normal but suspicion remains high.',NULL,'Quantitative spectrophotometric enzyme activity assay (reference method) or qualitative/semi-quantitative point-of-care fluorescent spot tests used for rapid screening.',NULL,'[{"parameter": "G6PD activity", "population": "Normal", "range": "Approximately 7-11 IU/g Hb", "notes": "Reference range and deficient/intermediate cutoffs vary by assay and are typically expressed relative to a population median; a result below 80% of the lower limit of normal is generally considered deficient"}]',1,'Deficient G6PD activity predisposes to acute hemolytic episodes triggered by oxidative stressors -- classically fava beans (favism), certain infections, and oxidant medications (some antimalarials such as primaquine, sulfonamides, dapsone, nitrofurantoin). Because G6PD is X-linked, deficiency is more common and typically more severe in males; heterozygous females can have intermediate activity due to random X-inactivation (mosaicism) and may be missed by qualitative screening tests, sometimes requiring quantitative testing or genetic confirmation.',NULL,'[{"condition": "Favism / drug-induced oxidative hemolysis", "direction": "low activity (deficient)"}, {"condition": "Neonatal hyperbilirubinemia risk", "direction": "low activity (deficient), in affected newborns"}]','[{"name": "ScienceDirect - Glucose-6-phosphate dehydrogenase deficiency (clinical review)", "url": "https://www.sciencedirect.com/science/article/pii/S0006497120617190", "accessed": "2026-07-14"}]',1,'2026-07-14 11:11:12','2026-07-14 11:11:12','["cbc", "reticulocyte-count", "total-bilirubin"]',NULL,NULL,'Given this result, are there specific medications or foods I need to avoid? Should my family members be tested, since this can be hereditary? If this was tested during an acute episode, do I need it repeated later to confirm?','A deficient result leads to counseling about medications and foods (like fava beans) to avoid, and family testing may be recommended given the hereditary nature of this condition. If tested during acute hemolysis, a normal result may need to be repeated weeks later to confirm it wasn''t falsely normalized by recent cell turnover.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (72,'homocysteine','Homocysteine, Total, Plasma','','Homocysteine, tHcy','Clinical Chemistry / Cardiac Biomarkers','Evaluates for vitamin B12/folate deficiency (functional marker, elevated even when serum B12 is borderline-normal) and is used as a secondary cardiovascular risk marker.',NULL,'Venous plasma (EDTA tube, kept on ice and processed promptly)','Ideally fasting; the sample should be centrifuged and separated promptly (or kept on ice) since homocysteine continues to be released from blood cells after collection, which can falsely raise results if processing is delayed.',NULL,'Immunoassay or HPLC/LC-MS/MS on automated analyzers.',NULL,'[{"parameter": "Total homocysteine", "population": "Adult", "range": "Approximately 5-15 \u00b5mol/L", "notes": "Reference ranges vary by lab/assay and rise with age and reduced kidney function"}]',1,'Elevated homocysteine (hyperhomocysteinemia) is most commonly caused by vitamin B12, folate, or B6 deficiency, reduced kidney function, hypothyroidism, or certain medications; it is also seen in the rare inherited disorder homocystinuria. It is an independent, though modest, cardiovascular risk marker and has been studied in combination with elevated Lp(a) for synergistic cardiovascular risk, though homocysteine-lowering therapy (B-vitamin supplementation) has not been shown to reduce cardiovascular events in most large trials, limiting its use as a routine risk-modifying target.',NULL,'[{"condition": "Vitamin B12 or folate deficiency", "direction": "high"}, {"condition": "Chronic kidney disease", "direction": "high"}, {"condition": "Homocystinuria (rare inherited disorder)", "direction": "markedly high"}, {"condition": "Cardiovascular risk (modest, independent marker)", "direction": "high"}]','[{"name": "Kang et al., Arteriosclerosis, Thrombosis, and Vascular Biology (AHA Journals) - Homocysteine and Lipoprotein(a) Interact to Increase CAD Risk", "url": "https://www.ahajournals.org/doi/10.1161/01.atv.20.2.493", "accessed": "2026-07-14"}]',1,'2026-07-14 11:11:12','2026-07-14 11:11:12','["vitamin-b12", "folate", "lipid-panel", "lipoprotein-a"]',NULL,NULL,'Could this be related to a B12 or folate deficiency? Does this affect my cardiovascular risk management? Do I need supplementation, and would that meaningfully reduce my risk?','An elevated level often prompts checking B12 and folate status, since deficiency is a common correctable cause; supplementation may be recommended for nutritional reasons, though it''s not typically used specifically to reduce cardiovascular risk given mixed trial evidence.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (73,'lipoprotein-a','Lipoprotein(a) [Lp(a)]','','Lp(a), Lipoprotein a','Clinical Chemistry / Cardiac Biomarkers','Independent, largely genetically-determined cardiovascular risk marker; major cardiology societies now recommend measuring it at least once in a person''s lifetime to refine atherosclerotic cardiovascular disease (ASCVD) risk assessment.',NULL,'Venous serum or plasma','Fasting is not required. Because Lp(a) is genetically determined and stays relatively stable over a lifetime, a single measurement is generally considered sufficient (repeat testing is not usually needed).',NULL,'Immunoturbidimetric or immunonephelometric assay; results may be reported in mg/dL (mass) or nmol/L (particle concentration) -- these units are not directly interconvertible due to variation in particle size between individuals, so the reporting unit should always be noted.',NULL,'[{"parameter": "Lp(a)", "population": "Lower risk", "range": "<30 mg/dL (approximately <75 nmol/L)"}, {"parameter": "Lp(a)", "population": "Elevated / increased risk", "range": "\u226530-50 mg/dL (approximately \u226575-125 nmol/L)", "notes": "Thresholds vary slightly by society (EAS, ACC/AHA, NLA); risk is highest in the top 5-10% of the population"}]',1,'Elevated Lp(a) is an independent, causal risk factor for atherosclerotic cardiovascular disease (coronary artery disease, stroke, peripheral artery disease) and calcific aortic valve stenosis, and is not reliably lowered by standard lifestyle changes or statins. It is used to refine risk in patients with intermediate calculated ASCVD risk or a strong family history of early cardiovascular disease out of proportion to standard risk factors, prompting more aggressive management of other modifiable risk factors (e.g., LDL/ApoB targets) even though Lp(a)-specific therapies are still emerging.',NULL,'[{"condition": "Premature/familial atherosclerotic cardiovascular disease", "direction": "high"}, {"condition": "Calcific aortic valve stenosis", "direction": "high"}]','[{"name": "Medscape/eMedicine - Lipoprotein (a): Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2088118-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 11:11:12','2026-07-14 11:11:12','["lipid-panel", "homocysteine", "crp"]',NULL,NULL,'Given this is largely genetic, does it change my overall cardiovascular risk management? Do family members need to be tested? Since this doesn''t need to be rechecked often, when would repeat testing make sense?','An elevated result is used to refine your overall cardiovascular risk assessment and may prompt more aggressive management of other modifiable risk factors (like LDL cholesterol); since levels are genetically determined, this test is generally only needed once in your lifetime.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (74,'anti-ccp','Anti-Cyclic Citrullinated Peptide Antibody (Anti-CCP)','','Anti-CCP, CCP Antibody, ACPA','Immunoassay / Inflammation Markers','Highly specific serologic marker for rheumatoid arthritis (RA), used alongside rheumatoid factor (RF) to support diagnosis, particularly in early or RF-negative disease, and to help predict a more erosive disease course.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Enzyme immunoassay (EIA) or chemiluminescent immunoassay using cyclic citrullinated peptide (CCP2 or CCP3 generation) antigens.',NULL,'[{"parameter": "Anti-CCP", "population": "Negative (normal)", "range": "Typically <20 U/mL", "notes": "Cutoff varies by assay/manufacturer, commonly reported in the 5-20 U/mL range -- always use the reporting lab''s stated cutoff; results are often further classified as low-positive (up to 3x the upper limit) or high-positive (>3x the upper limit) per 2010 ACR/EULAR criteria"}]',1,'Anti-CCP has approximately 95-98% specificity for rheumatoid arthritis, meaning a positive result strongly supports the diagnosis in a patient with compatible joint symptoms, and can appear years before clinical disease onset. It is more specific than rheumatoid factor (which is also positive in other conditions and healthy aging individuals) though somewhat less sensitive; testing both together improves diagnostic accuracy. Higher titers, especially high-positive results, are associated with more aggressive disease and greater risk of joint erosion.',NULL,'[{"condition": "Rheumatoid arthritis (RA)", "direction": "positive"}, {"condition": "Erosive/aggressive RA disease course", "direction": "high-positive titer"}]','[{"name": "PMC - Anti-CCP Revised Criteria for the Classification of Rheumatoid Arthritis", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC2964864/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:12:21','2026-07-14 11:12:21','["rheumatoid-factor", "esr", "crp"]',NULL,NULL,'Does this, combined with my symptoms, support a diagnosis of rheumatoid arthritis? Does my titer level (low vs. high positive) affect my prognosis? Do I need a rheumatology referral?','A positive result in someone with joint symptoms typically supports rheumatoid arthritis and prompts rheumatology referral for further evaluation and early treatment, since earlier treatment is linked to better long-term joint outcomes.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (75,'complement-c3','Complement C3','','C3, Complement C3','Immunoassay / Inflammation Markers','Assesses complement system activation; used mainly to monitor systemic lupus erythematosus (SLE) disease activity and to investigate suspected complement deficiency or immune complex-mediated disease.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Immunoturbidimetric or immunonephelometric assay on automated chemistry analyzers.',NULL,'[{"parameter": "Complement C3", "population": "Adult", "range": "Approximately 90-180 mg/dL", "notes": "Reference range varies by lab/method"}]',1,'Low C3 (especially falling alongside rising anti-dsDNA titers) is the most specific laboratory combination for identifying active lupus, particularly lupus nephritis, and can precede abnormalities on urinalysis. Low C3 is also seen in other immune complex-mediated conditions (post-infectious glomerulonephritis, cryoglobulinemia) and consumptive states. Rare hereditary C3 deficiency causes recurrent serious bacterial infections (especially encapsulated organisms) and lupus-like autoimmune features. High C3 is a nonspecific acute-phase reactant finding, of limited clinical significance on its own.',NULL,'[{"condition": "Active systemic lupus erythematosus / lupus nephritis", "direction": "low, especially with rising anti-dsDNA"}, {"condition": "Post-infectious glomerulonephritis / cryoglobulinemia", "direction": "low"}, {"condition": "Hereditary C3 deficiency", "direction": "very low/absent, recurrent bacterial infections"}]','[{"name": "Lamkin Clinic - Complement C3: Optimal Levels, Reference Ranges & Immune Interpretation", "url": "https://lamkinclinic.com/complement-c3/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:12:21','2026-07-14 11:12:21','["complement-c4", "ana", "anti-dsdna"]',NULL,NULL,'Does this fit with active lupus or another condition I''m being monitored for? Should this be tracked alongside my other antibody tests? Do I need kidney function testing given this result?','In someone with lupus, a low result alongside rising anti-dsDNA often prompts closer monitoring for a flare, including kidney function and urine testing to check for lupus nephritis.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (76,'complement-c4','Complement C4','','C4, Complement C4','Immunoassay / Inflammation Markers','Assesses complement system activation via the classical pathway; used mainly alongside C3 to monitor SLE disease activity and to investigate hereditary angioedema or complement deficiency.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Immunoturbidimetric or immunonephelometric assay on automated chemistry analyzers.',NULL,'[{"parameter": "Complement C4", "population": "Adult", "range": "Approximately 10-40 mg/dL", "notes": "Reference range varies by lab/method"}]',1,'Low C4 is seen in active SLE (often alongside low C3), immune complex diseases, and hereditary angioedema (due to C1 esterase inhibitor deficiency, which secondarily consumes C4 -- a persistently low C4 between angioedema attacks supports that diagnosis). A chronically low C4 with normal C3 can also reflect hereditary partial C4 deficiency, which is common and usually clinically insignificant on its own but can be a lupus susceptibility factor.',NULL,'[{"condition": "Active systemic lupus erythematosus", "direction": "low, often with low C3"}, {"condition": "Hereditary angioedema (C1 esterase inhibitor deficiency)", "direction": "low, even between attacks"}]','[{"name": "Bloodsight - Reading an Autoimmune Panel: ANA, RF, Anti-CCP & Complement", "url": "https://bloodsight.com/learn/reading-autoimmune-panel", "accessed": "2026-07-14"}]',1,'2026-07-14 11:12:21','2026-07-14 11:12:21','["complement-c3", "ana", "anti-dsdna"]',NULL,NULL,'Does this fit with active lupus, or could this be a hereditary pattern unrelated to disease activity? If I have recurrent swelling episodes, could this point to hereditary angioedema?','In lupus monitoring, a low result alongside other markers may prompt closer disease activity assessment. In someone with recurrent unexplained swelling, a persistently low C4 supports further workup for hereditary angioedema.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (77,'anti-dsdna','Anti-Double-Stranded DNA Antibody (Anti-dsDNA)','','Anti-dsDNA, dsDNA Antibody','Immunoassay / Inflammation Markers','Highly specific marker for systemic lupus erythematosus (SLE); used to support diagnosis and, because titers correlate with disease activity in many patients, to help monitor lupus flares (especially lupus nephritis).',NULL,'Venous serum or plasma','Typically ordered as a reflex/follow-up test after a positive ANA (antinuclear antibody) screen.',NULL,'Enzyme immunoassay (EIA), Crithidia luciliae immunofluorescence assay (considered most specific), or the Farr radioimmunoassay technique.',NULL,'[{"parameter": "Anti-dsDNA", "population": "Result categories", "range": "Negative or Positive (titer-dependent) -- reported by assay-specific units/titer, not a single universal numeric cutoff"}]',1,'Anti-dsDNA is highly specific for SLE (much more specific than the broader ANA screen, though less sensitive), and rising titers -- especially alongside falling complement (C3/C4) -- are the most specific laboratory pattern for active lupus, particularly lupus nephritis, and may precede clinical/urinary findings. Titers can fluctuate with disease activity and are sometimes used to help guide treatment intensity in patients with an established SLE diagnosis, though the correlation with activity is not perfect in every patient.',NULL,'[{"condition": "Systemic lupus erythematosus (SLE)", "direction": "positive, high specificity"}, {"condition": "Active lupus nephritis / SLE flare", "direction": "rising titer, especially with falling C3/C4"}]','[{"name": "Lamkin Clinic - Complement C3, citing anti-dsDNA/C3 inverse relationship in SLE monitoring", "url": "https://lamkinclinic.com/complement-c3/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:12:21','2026-07-14 11:12:21','["ana", "complement-c3", "complement-c4"]',NULL,NULL,'Does this confirm a lupus diagnosis, or is more testing needed? Does a rising titer mean my disease is becoming more active? Do I need kidney testing given this result?','A positive result supports a lupus diagnosis when combined with clinical features, and rising titers (especially with falling complement) often prompt closer monitoring for a flare, including kidney function and urine testing.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (78,'anca','Anti-Neutrophil Cytoplasmic Antibody (ANCA)','','ANCA, c-ANCA, p-ANCA, Anti-PR3, Anti-MPO','Immunoassay / Inflammation Markers','Screens for ANCA-associated vasculitis (granulomatosis with polyangiitis, microscopic polyangiitis, eosinophilic granulomatosis with polyangiitis), particularly when there is unexplained glomerulonephritis, pulmonary hemorrhage, or systemic small-vessel vasculitis.',NULL,'Venous serum or plasma','No fasting required. A positive screen by immunofluorescence (IFA) is typically confirmed with specific antigen testing (anti-proteinase 3 [PR3] and anti-myeloperoxidase [MPO]).',NULL,'Indirect immunofluorescence assay (IFA) for initial pattern screening (cytoplasmic [c-ANCA] or perinuclear [p-ANCA] pattern), confirmed by antigen-specific enzyme immunoassay for anti-PR3 and anti-MPO antibodies.',NULL,'[{"parameter": "ANCA (IFA screen and PR3/MPO antigen-specific)", "population": "Result categories", "range": "Negative or Positive, with pattern (c-ANCA/p-ANCA) and antigen specificity (PR3/MPO) reported for positive results"}]',1,'c-ANCA with anti-PR3 specificity is classically associated with granulomatosis with polyangiitis (formerly Wegener''s granulomatosis). p-ANCA with anti-MPO specificity is more associated with microscopic polyangiitis and eosinophilic granulomatosis with polyangiitis (formerly Churg-Strauss syndrome), though there is overlap. ANCA testing is used alongside clinical findings and often kidney/lung biopsy to diagnose ANCA-associated vasculitis, and antigen-specific titers can help monitor disease activity and relapse risk in some patients, though this correlation is imperfect.',NULL,'[{"condition": "Granulomatosis with polyangiitis (GPA)", "direction": "c-ANCA / anti-PR3 positive"}, {"condition": "Microscopic polyangiitis (MPA) / eosinophilic granulomatosis with polyangiitis (EGPA)", "direction": "p-ANCA / anti-MPO positive"}]','[{"name": "Labcorp - Patient Care in Rheumatology & Autoimmune Disease (ANCA/anti-MPO/anti-PR3 diagnostic panels)", "url": "https://www.labcorp.com/treatment-areas/rheumatology/clinical-testing/autoimmune-profiles", "accessed": "2026-07-14"}]',1,'2026-07-14 11:12:21','2026-07-14 11:12:21','["creatinine", "urinalysis"]',NULL,NULL,'Does this pattern (c-ANCA vs. p-ANCA) point to a specific type of vasculitis? Do I need a biopsy to confirm? Given my symptoms (like kidney or lung involvement), how urgent is further workup?','A positive result with compatible symptoms (unexplained kidney disease, lung involvement, sinus disease) typically prompts urgent rheumatology or nephrology referral, since ANCA-associated vasculitis can progress quickly and benefits from early treatment.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (79,'blood-culture','Blood Culture','','BC, Blood C&S, Culture and Sensitivity (Blood)','Microbiology','Detects bacteria or fungi circulating in the bloodstream (bacteremia/fungemia); the cornerstone diagnostic test for suspected sepsis, endocarditis, and other serious bloodstream infections.',NULL,'Venous whole blood, drawn directly into aerobic and anaerobic blood culture bottles','Strict aseptic skin preparation is essential to minimize contamination. Two or more culture sets should be drawn from separate venipuncture sites (not through an existing IV line unless specifically evaluating catheter-related infection), ideally before starting antibiotics, since prior antibiotic exposure can cause false-negative results. Adequate blood volume per bottle significantly improves sensitivity.',NULL,'Inoculated bottles are incubated in a continuous-monitoring automated blood culture system (e.g., BACTEC, BacT/ALERT) that detects microbial growth via CO2/pressure changes; positive bottles are Gram-stained and subcultured for identification and antibiotic susceptibility testing, increasingly supplemented by rapid molecular identification panels.',NULL,'[{"parameter": "Blood culture", "population": "Result categories", "range": "No growth (negative) after the standard incubation period (typically 5 days), or growth of a specific organism (positive) -- not a numeric value"}]',1,'A positive blood culture requires distinguishing true bacteremia from contamination. Growth of a recognized pathogen (e.g., E. coli, S. aureus, Streptococcus pneumoniae) in one or more bottles is almost always clinically significant. Growth of common skin commensals (e.g., coagulase-negative staphylococci, Corynebacterium, Cutibacterium) in only one of multiple sets more often represents contamination, though the same organisms can cause true infection (e.g., catheter-related bloodstream infection), especially if grown from multiple separate draws. Results guide antibiotic selection via susceptibility testing and help monitor treatment response with repeat cultures in conditions like endocarditis.',NULL,'[{"condition": "Sepsis / bacteremia / fungemia", "direction": "positive with a recognized pathogen"}, {"condition": "Infective endocarditis", "direction": "persistently positive with a typical organism"}, {"condition": "Blood culture contamination", "direction": "positive in only one of multiple sets, typical skin commensal"}]','[{"name": "Medscape/eMedicine - Blood Culture: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2093349-overview", "accessed": "2026-07-14"}, {"name": "PMC - A Guide to Bacterial Culture Identification And Results Interpretation", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC6428495/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:13:33','2026-07-14 11:13:33','["crp", "cbc", "esr"]',NULL,NULL,'Did the organism grow in more than one bottle, since that affects whether it''s a true infection or contamination? What antibiotic is this organism sensitive to? How long will I need treatment?','A confirmed true positive guides antibiotic selection based on susceptibility results, with treatment duration depending on the source and organism; a likely contaminant usually needs no treatment, though your clinician will weigh this against your clinical picture.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (80,'urine-culture','Urine Culture','','Urine C&S, Culture and Sensitivity (Urine)','Microbiology','Identifies and quantifies bacteria in urine to diagnose urinary tract infection (UTI) and guide antibiotic selection via susceptibility testing.',NULL,'Clean-catch midstream urine, or catheterized/suprapubic aspirate specimen when indicated','Proper clean-catch technique (cleansing before collection, midstream collection) is essential to minimize contamination from perineal/urethral flora; the sample should reach the lab promptly or be refrigerated, since bacteria can multiply at room temperature and falsely raise the colony count.',NULL,'Quantitative culture on selective/differential agar (e.g., blood agar, MacConkey agar) using a calibrated inoculating loop to determine colony-forming units per milliliter (CFU/mL); identification and susceptibility testing performed on significant growth.',NULL,'[{"parameter": "Colony count, clean-catch midstream specimen", "population": "Traditional threshold for significant bacteriuria", "range": "\u2265100,000 CFU/mL (10^5) of a single uropathogen"}, {"parameter": "Colony count, symptomatic patients (lower thresholds increasingly accepted)", "population": "IDSA-referenced lower thresholds", "range": "\u22651,000 CFU/mL (cystitis) or \u226510,000 CFU/mL (pyelonephritis) in symptomatic women, clean-catch"}, {"parameter": "Colony count, catheterized specimen", "population": "Lower threshold applies", "range": "\u22651,000 CFU/mL"}]',1,'The classic 100,000 CFU/mL threshold (established in the 1950s) has high specificity but can miss up to half of symptomatic infections, so current guidance accepts lower colony counts as significant in symptomatic patients, particularly women and catheterized patients. Growth of multiple organism types (mixed flora) more often reflects contamination or, in catheterized patients, colonization rather than true infection, and is generally not worked up further. Asymptomatic bacteriuria (significant growth without symptoms) generally does not require treatment except in specific situations such as pregnancy or before urologic procedures involving mucosal trauma.',NULL,'[{"condition": "Urinary tract infection (cystitis, pyelonephritis)", "direction": "positive, single uropathogen above the relevant threshold"}, {"condition": "Asymptomatic bacteriuria", "direction": "positive, significant growth without symptoms -- treatment generally not indicated"}, {"condition": "Sample contamination / catheter colonization", "direction": "mixed growth of multiple organisms"}]','[{"name": "Medscape/eMedicine - Urine Culture: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2093272-overview", "accessed": "2026-07-14"}, {"name": "ScienceDirect Topics - Urine Culture, citing 2010 IDSA consensus thresholds", "url": "https://www.sciencedirect.com/topics/medicine-and-dentistry/urine-culture", "accessed": "2026-07-14"}]',1,'2026-07-14 11:13:33','2026-07-14 11:13:33','["urinalysis", "creatinine"]',NULL,NULL,'Does this colony count and organism confirm a urinary tract infection, or could this be contamination/colonization? What antibiotic is this organism sensitive to? Do I need this repeated after treatment to confirm it''s cleared?','A significant single-organism growth with compatible symptoms confirms UTI and guides antibiotic selection based on susceptibility results; growth without symptoms (asymptomatic bacteriuria) generally doesn''t need treatment except in specific situations like pregnancy.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (81,'h-pylori-testing','Helicobacter pylori Testing (Stool Antigen / Urea Breath Test / Serology)','','H. pylori, HP Stool Antigen, Urea Breath Test, H. pylori IgG','Microbiology / Immunoassay','Diagnoses active H. pylori infection, a major cause of peptic ulcer disease, chronic gastritis, and a risk factor for gastric cancer; also used non-invasively to confirm eradication after treatment.',NULL,'Stool sample (stool antigen test), exhaled breath sample after ingesting labeled urea (urea breath test), or venous serum (serology)','Proton pump inhibitors, bismuth, and antibiotics can cause false-negative results on the stool antigen test and urea breath test, and are typically withheld for 1-2 weeks (PPIs) or 4 weeks (antibiotics/bismuth) before testing. Serology cannot distinguish active from past/resolved infection and is not recommended for confirming eradication.',NULL,'Stool antigen: enzyme immunoassay (ELISA) or lateral-flow chromatographic immunoassay detecting H. pylori antigen in stool. Urea breath test: patient ingests 13C- or 14C-labeled urea; H. pylori urease splits the urea, releasing labeled CO2 that is detected in exhaled breath. Serology: enzyme immunoassay detecting IgG antibodies against H. pylori.',NULL,'[{"parameter": "H. pylori test", "population": "Result categories", "range": "Negative or Positive -- qualitative result; serology may report a numeric index/titer but interpretation remains categorical (positive/negative/equivocal)"}]',1,'The urea breath test and stool antigen test are the preferred methods for both initial diagnosis and confirming eradication after treatment, because they detect active infection with good sensitivity and specificity (each generally 85-95%+ in most studies, though estimates vary by population and reference standard used). Serology is useful as an initial screening tool in populations not recently treated (high sensitivity, good negative predictive value to rule out infection), but a positive serology cannot distinguish current from past infection and should be confirmed with stool antigen or urea breath testing before treatment decisions, especially for confirming cure.',NULL,'[{"condition": "Peptic ulcer disease", "direction": "positive"}, {"condition": "Chronic gastritis", "direction": "positive"}, {"condition": "Gastric cancer risk factor (chronic untreated infection)", "direction": "positive, long-standing"}]','[{"name": "ARUP Consult - Helicobacter pylori", "url": "https://arupconsult.com/content/helicobacter-pylori", "accessed": "2026-07-14"}, {"name": "American Family Physician (AAFP) - Noninvasive Diagnostic Tests for Helicobacter pylori Infection", "url": "https://www.aafp.org/pubs/afp/issues/2019/0701/p16.html", "accessed": "2026-07-14"}]',1,'2026-07-14 11:13:33','2026-07-14 11:13:33','["alt-ast"]',NULL,NULL,'Was I off proton pump inhibitors and antibiotics long enough before this test for an accurate result? Do I need treatment, and if so, for how long? Should I be retested after treatment to confirm it''s cleared?','A positive result generally leads to a course of combination antibiotic therapy, and confirmation of eradication (via a repeat stool antigen or breath test, not serology) is recommended afterward, especially if you had an ulcer or ongoing symptoms.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (82,'gram-stain','Gram Stain','','Gram Stain, Direct Smear','Microbiology','Rapid, same-day microscopic test that provides preliminary information about the presence, morphology, and Gram-reaction of bacteria in a clinical specimen, guiding initial (empiric) antibiotic therapy while culture results are pending.',NULL,'Varies by clinical specimen: sputum, wound/abscess fluid, CSF, body fluid, or a positive blood culture broth, among others','Specimen quality matters significantly -- for example, a sputum sample with excessive squamous epithelial cells suggests oral contamination rather than a true lower respiratory sample and may be rejected or reported with a caveat.',NULL,'A heat- or methanol-fixed smear is sequentially stained with crystal violet, iodine (mordant), an alcohol/acetone decolorizer, and a safranin counterstain; Gram-positive organisms retain the crystal violet-iodine complex and appear purple/blue, while Gram-negative organisms lose it during decolorization and take up the pink/red safranin counterstain. The smear is examined for organism morphology (cocci, bacilli, arrangement) and for host inflammatory cells (white blood cells).',NULL,'[{"parameter": "Gram stain", "population": "Result categories", "range": "No organisms seen, or organisms present described by Gram reaction and morphology (e.g., ''Gram-positive cocci in clusters'', ''Gram-negative bacilli'') -- a descriptive, not numeric, result"}]',1,'The Gram stain gives clinicians same-day guidance on likely organism categories (e.g., Gram-positive cocci in clusters suggesting Staphylococcus, Gram-negative bacilli suggesting Enterobacteriaceae) to help select empiric antibiotics before final culture and susceptibility results (which take 24-72+ hours) are available. It also assesses specimen adequacy and the presence of inflammatory cells, which supports (or argues against) a true infectious process versus contamination/colonization. It does not identify the specific organism species or provide susceptibility data, which require culture.',NULL,'[{"condition": "Guides empiric antibiotic selection pending culture", "direction": "organism morphology/Gram reaction observed"}, {"condition": "Specimen quality/contamination assessment", "direction": "e.g., excess squamous cells in sputum suggesting oral contamination"}]','[{"name": "PMC - A Guide to Bacterial Culture Identification And Results Interpretation", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC6428495/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:13:33','2026-07-14 11:13:33','[]',NULL,NULL,'What does this preliminary result suggest, and how is it guiding my antibiotic treatment while we wait for the full culture? Will the antibiotics be adjusted once the final culture and sensitivity results come back?','This result guides an initial (empiric) antibiotic choice while the full culture and susceptibility testing are still pending (typically 24-72 hours); treatment is often adjusted once those more definitive results are available.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (83,'abg','Arterial Blood Gas (ABG)','','ABG, Blood Gas Analysis','Clinical Chemistry / Point of Care','Assesses acid-base status, oxygenation, and ventilation; essential in respiratory failure, critical illness, and metabolic derangements (e.g., DKA, sepsis) where rapid bedside results guide immediate management.',NULL,'Arterial whole blood (heparinized syringe), typically from the radial, brachial, or femoral artery','Sample must be free of air bubbles and analyzed promptly (or kept on ice if delayed) since gas exchange with air or ongoing cellular metabolism in the syringe can alter pH, pCO2, and pO2 results within minutes.',NULL,'Ion-selective electrodes measure pH and pCO2 directly; pO2 is measured by an amperometric (Clark-type) electrode; bicarbonate (HCO3) and base excess are calculated from the measured pH and pCO2 using the Henderson-Hasselbalch equation, not measured directly.',NULL,'[{"parameter": "pH", "population": "Adult, arterial", "range": "7.35-7.45"}, {"parameter": "pCO2 (PaCO2)", "population": "Adult, arterial", "range": "35-45 mmHg"}, {"parameter": "HCO3 (bicarbonate, calculated)", "population": "Adult, arterial", "range": "22-26 mEq/L"}, {"parameter": "pO2 (PaO2)", "population": "Adult, arterial, room air", "range": "80-100 mmHg"}]',1,'Interpretation follows a stepwise approach: (1) check pH to determine acidemia (<7.35) or alkalemia (>7.45); (2) check pCO2 -- a change in the same direction as the pH abnormality (e.g., low pH with high pCO2) indicates a respiratory cause, while a change in the opposite direction suggests metabolic compensation; (3) check HCO3 similarly for a primary metabolic process versus renal compensation. A normal pH with abnormal pCO2 and HCO3 suggests a fully compensated disorder or a mixed disorder, and should be interpreted alongside the clinical picture. pO2 assesses oxygenation but is not used to classify the acid-base disorder itself.',NULL,'[{"condition": "Respiratory acidosis (e.g., COPD exacerbation, respiratory depression)", "direction": "low pH, high pCO2"}, {"condition": "Respiratory alkalosis (e.g., hyperventilation, anxiety, PE)", "direction": "high pH, low pCO2"}, {"condition": "Metabolic acidosis (e.g., DKA, lactic acidosis, renal failure)", "direction": "low pH, low HCO3"}, {"condition": "Metabolic alkalosis (e.g., prolonged vomiting, diuretic use)", "direction": "high pH, high HCO3"}, {"condition": "Hypoxemic respiratory failure", "direction": "low pO2"}]','[{"name": "Nurse.org - Arterial Blood Gas (ABG) Analysis: Values & Interpretation", "url": "https://nurse.org/articles/arterial-blood-gas-test/", "accessed": "2026-07-14"}, {"name": "Respiratory Therapy Zone - ABG Interpretation Made Easy", "url": "https://www.respiratorytherapyzone.com/abg-interpretation/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:45:00','2026-07-14 11:45:00','[]','There is no single universal ABG panic-value list, but markedly abnormal values (e.g., pH <7.20 or >7.60, pCO2 >70 mmHg, pO2 <40 mmHg) generally represent a medical emergency requiring immediate intervention. Always follow the reporting lab/point-of-care device''s own critical-value policy.','Air bubbles in the syringe cause the sample to equilibrate toward room air, falsely raising pO2 and lowering pCO2. Delayed analysis allows continued cellular metabolism (glycolysis, oxygen consumption) in the sample, falsely lowering pH and pO2 and raising pCO2 -- icing the sample slows this if analysis will be delayed. Venous contamination of an arterial sample falsely lowers pO2 and raises pCO2.','What is the underlying cause of this acid-base pattern, and how urgently does it need to be addressed? Do I need this repeated to track whether treatment is working? Is my oxygen level adequate?','Results guide immediate management of the underlying respiratory or metabolic problem, and repeat testing is common to track response to treatment, especially in a hospital or emergency setting.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (84,'ammonia','Ammonia, Blood','','NH3, Serum Ammonia','Clinical Chemistry','Evaluates suspected hepatic encephalopathy in patients with liver disease and altered mental status, and investigates suspected inherited urea cycle disorders, particularly in neonates/children with unexplained encephalopathy.',NULL,'Venous whole blood, EDTA (lavender top) or heparin (green top) tube, drawn without a tourniquet if possible','Critical preanalytical requirements: draw without prolonged tourniquet time or fist clenching, transport on ice, and have the lab analyze it within about 15-20 minutes (or centrifuge and freeze the plasma promptly if immediate analysis isn''t possible) -- delayed or improper handling is the most common cause of a falsely elevated result.',NULL,'Enzymatic (glutamate dehydrogenase-based) assay on automated chemistry analyzers.',NULL,'[{"parameter": "Ammonia", "population": "Adult", "range": "\u226435 \u00b5mol/L (\u226460 \u00b5g/dL)", "notes": "Neonatal and pediatric reference ranges are substantially different and higher"}]',1,'Elevated ammonia in a patient with liver disease and altered mental status supports hepatic encephalopathy, since the diseased/bypassed liver can no longer clear ammonia produced by gut bacterial protein metabolism, allowing it to cross the blood-brain barrier and cause neurotoxicity. The degree of elevation correlates only loosely with the severity of encephalopathy -- clinical staging (mental status, asterixis) matters more than the absolute level for grading severity or guiding treatment, though a rising level over time or a very high level can support the diagnosis when the picture is ambiguous. In neonates and children, markedly elevated ammonia without liver disease raises concern for an inherited urea cycle disorder, a pediatric emergency requiring rapid identification and treatment given the risk of irreversible neurological injury.',NULL,'[{"condition": "Hepatic encephalopathy (cirrhosis, acute liver failure)", "direction": "high"}, {"condition": "Inherited urea cycle disorders (neonates/children)", "direction": "high"}, {"condition": "Reye syndrome", "direction": "high"}]','[{"name": "droracle.ai - What is the normal serum ammonia concentration in adults? (clinical reference synthesis)", "url": "https://www.droracle.ai/articles/853651/what-is-the-normal-serum-ammonia-concentration-in-adults", "accessed": "2026-07-14"}]',1,'2026-07-14 11:45:00','2026-07-20 05:50:41','[]','Levels >200 µmol/L are associated with poor neurological outcomes; severe hyperammonemia (>400 µmol/L) may require urgent dialysis/kidney replacement therapy, particularly in neonates with suspected urea cycle disorders. Rapidly rising or markedly elevated ammonia warrants urgent clinical correlation and consideration of emergency treatment.','Hemolysis releases ammonia from red blood cells and is a major cause of falsely elevated results. Prolonged tourniquet application, fist clenching during the draw, and delayed sample processing/transport all falsely raise results -- an unexpectedly high ammonia in a clinically well-appearing patient should prompt review of collection technique before acting on the result.','Was this sample collected and handled correctly, since that affects accuracy? Does this explain any confusion or altered mental status I''ve had? What''s being done to lower this level?','An elevated result in someone with liver disease and altered mental status typically prompts treatment aimed at lowering ammonia (such as lactulose) and investigation for triggers of hepatic encephalopathy; in infants/children, urgent metabolic workup may be needed.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (85,'lactate','Lactate, Blood','','Lactic Acid, Serum Lactate','Clinical Chemistry / Point of Care','Marker of tissue hypoperfusion and anaerobic metabolism; used to identify and risk-stratify sepsis/septic shock, assess the severity of shock states generally, and guide resuscitation (serial lactate clearance).',NULL,'Arterial or venous whole blood (point-of-care) or plasma (central lab); often measured on the same sample as an ABG','Avoid prolonged tourniquet use and fist clenching, which can falsely raise results through local muscle anaerobic metabolism; process promptly, as ongoing glycolysis in an unprocessed sample raises lactate over time (a fluoride-oxalate tube or rapid processing minimizes this).',NULL,'Enzymatic (lactate oxidase or lactate dehydrogenase-based) assay on point-of-care blood gas analyzers or central laboratory chemistry analyzers.',NULL,'[{"parameter": "Lactate", "population": "Normal, unstressed adult", "range": "~0.5-1.5 mmol/L", "notes": "Critically ill patients are generally considered to have a ''normal'' lactate below 2 mmol/L; even lactate levels within the traditional reference range have been associated with increased mortality risk in critically ill populations in some studies"}]',1,'Elevated lactate reflects tissue hypoperfusion or hypoxia driving anaerobic metabolism, and is a key marker of illness severity in sepsis and other shock states -- a level ≥4 mmol/L is part of the Sepsis-3 criteria for septic shock and is associated with higher mortality. Serial lactate measurements (lactate clearance) are used to track response to resuscitation, with a failure to clear lactate despite treatment signaling ongoing tissue hypoperfusion and prompting escalation of care. Elevation is not specific to sepsis -- any shock state (cardiogenic, hypovolemic, obstructive), severe exertion, seizure activity, or certain medications (including metformin in the setting of renal impairment) can also raise lactate, so the result is interpreted alongside the full clinical picture.',NULL,'[{"condition": "Septic shock / severe sepsis", "direction": "high, \u22654 mmol/L"}, {"condition": "Any shock state (cardiogenic, hypovolemic, obstructive)", "direction": "high"}, {"condition": "Tissue hypoxia / severe exertion / seizure", "direction": "high, transiently"}]','[{"name": "PMC - Even Mild Hyperlactatemia Is Associated with Increased Mortality in Critically Ill Patients", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4056896/", "accessed": "2026-07-14"}, {"name": "PMC - Relative hyperlactatemia and hospital mortality in critically ill patients", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2875540/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:45:00','2026-07-20 05:50:41','[]','Lactate ≥4 mmol/L is a key criterion supporting a diagnosis of septic shock (per Sepsis-3 criteria, alongside vasopressor requirement) and is generally treated as a value requiring urgent clinical attention and aggressive resuscitation.','Tourniquet use and muscle activity (fist clenching, struggling) during the draw cause local anaerobic metabolism that falsely raises the result. Delayed processing of the sample allows continued glycolysis by blood cells, also falsely raising the result -- use of a lactate-stabilizing (fluoride) tube or prompt analysis minimizes this artifact.','Does this level indicate how sick I am right now? Is this trending down with treatment, which would be a good sign? What''s causing this elevation?','An elevated level, especially in the context of suspected sepsis or shock, prompts aggressive treatment and fluid resuscitation, with serial measurements used to track whether treatment is working (a falling lactate is a reassuring sign).');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (86,'microalbumin','Urine Albumin-to-Creatinine Ratio (ACR / Microalbumin)','','ACR, Microalbumin, uACR, Urine Microalbumin/Creatinine Ratio','Clinical Chemistry / Urinalysis','Early screening test for diabetic and hypertensive kidney disease -- detects small amounts of albumin in urine below the detection threshold of a standard urine dipstick, before overt proteinuria or a drop in eGFR develops.',NULL,'Spot (random) urine sample, ideally first-morning; 24-hour urine collection is the historical gold standard but a spot ACR is now considered sufficient for screening and monitoring','Avoid testing during a urinary tract infection, after heavy exercise, or during acute illness/fever, as these can all cause a transient false elevation; a positive result should be confirmed with a repeat test, ideally first-morning, before diagnosing microalbuminuria.',NULL,'Immunoturbidimetric or immunonephelometric assay for urine albumin, paired with a urine creatinine measurement (Jaffe or enzymatic method) to calculate the ratio, which corrects for variation in urine concentration.',NULL,'[{"parameter": "Albumin-to-creatinine ratio", "population": "Normal", "range": "<30 mg/g creatinine"}, {"parameter": "Albumin-to-creatinine ratio", "population": "Microalbuminuria (moderately increased albuminuria)", "range": "30-299 mg/g creatinine"}, {"parameter": "Albumin-to-creatinine ratio", "population": "Macroalbuminuria (severely increased albuminuria)", "range": "\u2265300 mg/g creatinine"}]',1,'Microalbuminuria is an early, reversible marker of diabetic nephropathy and is also an independent marker of generalized cardiovascular risk, associated with increased risk of stroke and heart disease even outside of diabetes. The American Diabetes Association recommends annual screening in type 1 diabetics with disease duration >5 years and in all type 2 diabetics from diagnosis. Detecting microalbuminuria prompts intensified blood pressure control (typically with an ACE inhibitor or ARB) and glycemic control, which can slow or reverse progression to macroalbuminuria and kidney failure.',NULL,'[{"condition": "Diabetic nephropathy (early stage)", "direction": "high (30-299 mg/g)"}, {"condition": "Hypertensive nephrosclerosis", "direction": "high"}, {"condition": "Generalized cardiovascular risk marker", "direction": "high, even at levels below the microalbuminuria threshold in some studies"}]','[{"name": "Medscape/eMedicine - Microalbumin: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2088184-overview", "accessed": "2026-07-14"}, {"name": "MLabs (University of Michigan) - Urine Albumin Creatinine Ratio (ACR), citing ADA interpretation guidelines", "url": "https://mlabs.umich.edu/tests/microalbumin-urine", "accessed": "2026-07-14"}]',1,'2026-07-14 11:45:00','2026-07-14 11:45:00','[]',NULL,'Urinary tract infection, fever/acute illness, heavy exercise before collection, marked hyperglycemia, and menstrual blood contamination can all cause a transient false elevation -- clinically significant microalbuminuria should be confirmed on a repeat sample under standard conditions (2 of 3 samples over 3-6 months per ADA guidance) before being treated as a persistent finding.','Does this mean my diabetes or blood pressure is affecting my kidneys? Do I need my medications adjusted (like starting an ACE inhibitor or ARB)? How often should this be rechecked?','A confirmed elevated result (on repeat testing) typically prompts starting or intensifying blood pressure medications that also protect the kidneys (ACE inhibitors or ARBs), along with tighter blood sugar control if you have diabetes, and regular monitoring going forward.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (87,'lh','Luteinizing Hormone (LH), Serum','','LH, Lutropin','Immunoassay / Reproductive Endocrinology','Evaluates ovarian/testicular function, menstrual cycle status, ovulation timing, and pituitary-gonadal axis disorders; used in fertility workups, precocious/delayed puberty evaluation, and menopause assessment.',NULL,'Venous serum or plasma','In women, timing relative to the menstrual cycle is critical for interpretation -- results are meaningless without knowing the cycle day (or menopausal status); a series of daily measurements is sometimes used to detect the ovulatory LH surge.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "LH", "population": "Adult female, follicular phase", "range": "~2-13 mIU/mL", "notes": "Varies by assay and reference population"}, {"parameter": "LH", "population": "Adult female, ovulatory peak", "range": "~8-73 mIU/mL", "notes": "Wide range reflects the sharp mid-cycle surge; timing of the draw relative to the surge greatly affects the result"}, {"parameter": "LH", "population": "Adult female, luteal phase", "range": "~1-13 mIU/mL"}, {"parameter": "LH", "population": "Postmenopausal", "range": "~11-59 mIU/mL", "notes": "Elevated due to loss of negative feedback from declining estrogen"}]',1,'High LH with low estradiol/testosterone suggests primary gonadal failure (ovarian or testicular); low or inappropriately normal LH with low sex hormones suggests a hypothalamic/pituitary (secondary) cause. In women, persistently elevated LH relative to FSH (high LH:FSH ratio) is a classic, though not universal, finding in polycystic ovary syndrome. LH is interpreted alongside FSH, estradiol/testosterone, and clinical context (cycle day, menopausal status) rather than in isolation.',NULL,'[{"condition": "Primary ovarian insufficiency / menopause", "direction": "high"}, {"condition": "Male primary hypogonadism (testicular failure)", "direction": "high"}, {"condition": "Hypothalamic/pituitary (secondary) hypogonadism", "direction": "low or inappropriately normal"}, {"condition": "Polycystic ovary syndrome (PCOS)", "direction": "high LH:FSH ratio, a supportive but not required finding"}]','[{"name": "Mayo Clinic Laboratories - Luteinizing Hormone (LH), Serum (test catalog)", "url": "https://endocrinology.testcatalog.org/show/LH", "accessed": "2026-07-14"}, {"name": "ScienceDirect Topics - Follitropin Blood Level, citing commercial immunoassay LH/FSH reference ranges", "url": "https://www.sciencedirect.com/topics/biochemistry-genetics-and-molecular-biology/follitropin-blood-level", "accessed": "2026-07-14"}]',1,'2026-07-14 11:51:33','2026-07-14 11:51:33','["estradiol", "fsh", "progesterone", "prolactin", "total-testosterone"]',NULL,NULL,'Does this fit with where I am in my cycle, or does it suggest an issue with ovulation or menopause? Should this be checked alongside FSH and estradiol for a clearer picture? What does this mean for my fertility?','Results are interpreted together with FSH, estradiol, and your cycle timing to assess ovarian function; unexpected results may prompt additional hormone testing or a fertility specialist referral depending on your goals and symptoms.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (88,'fsh','Follicle-Stimulating Hormone (FSH), Serum','','FSH, Follitropin','Immunoassay / Reproductive Endocrinology','Evaluates ovarian reserve, menstrual cycle status, and pituitary-gonadal axis disorders; a key component of fertility workups (day-3 FSH), precocious/delayed puberty evaluation, and menopause assessment.',NULL,'Venous serum or plasma','In women being evaluated for fertility, FSH is conventionally drawn on cycle day 2-4 (early follicular phase) for the most standardized, interpretable result.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "FSH", "population": "Adult female, reproductive years (cycle-dependent)", "range": "~4.7-21.5 mIU/mL", "notes": "Varies by cycle phase and assay"}, {"parameter": "FSH", "population": "Postmenopausal", "range": "~25.8-134.8 mIU/mL", "notes": "Elevated due to loss of negative feedback from declining estrogen"}]',1,'An elevated day-3 FSH (commonly cited threshold above ~10-12 mIU/mL, though lab-specific) suggests diminished ovarian reserve and is associated with a lower chance of success with fertility treatment including IVF. High FSH with low estradiol confirms primary ovarian insufficiency or menopause. Low or inappropriately normal FSH with low estradiol/testosterone suggests a hypothalamic/pituitary cause. In men, elevated FSH suggests impaired spermatogenesis (primary testicular failure).',NULL,'[{"condition": "Diminished ovarian reserve", "direction": "high, day-3 FSH"}, {"condition": "Primary ovarian insufficiency / menopause", "direction": "high"}, {"condition": "Male primary testicular failure / impaired spermatogenesis", "direction": "high"}, {"condition": "Hypothalamic/pituitary (secondary) hypogonadism", "direction": "low or inappropriately normal"}]','[{"name": "Cleveland Clinic - Follicle-Stimulating Hormone (FSH): What It Is & Function", "url": "https://my.clevelandclinic.org/health/articles/24638-follicle-stimulating-hormone-fsh", "accessed": "2026-07-14"}, {"name": "Mayo Clinic Laboratories - Follicle-Stimulating Hormone (FSH), Serum (test catalog)", "url": "https://endocrinology.testcatalog.org/show/FSH", "accessed": "2026-07-14"}]',1,'2026-07-14 11:51:33','2026-07-14 11:51:33','["estradiol", "lh", "progesterone", "total-testosterone"]',NULL,NULL,'Does this suggest reduced ovarian reserve, or is this within a normal range for my age? Should this affect my fertility treatment timeline? Do I need this combined with an antral follicle count for a fuller picture?','An elevated result, especially with fertility concerns, often leads to further ovarian reserve testing (AMH, antral follicle count) and a conversation with a fertility specialist about your options and timeline.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (89,'estradiol','Estradiol (E2), Serum','','E2, Estradiol','Immunoassay / Reproductive Endocrinology','Assesses ovarian function and estrogen status; used in fertility monitoring, menstrual cycle evaluation, precocious puberty workup, and monitoring of assisted reproduction (ovarian stimulation).',NULL,'Venous serum or plasma','In women, timing relative to the menstrual cycle is essential for interpretation; results are only meaningful when the cycle day (or menopausal/pregnancy status) is known.',NULL,'Chemiluminescent immunoassay (CLIA); mass spectrometry (LC-MS/MS) is preferred for low concentrations (children, postmenopausal women, men) where immunoassay specificity is limited.',NULL,'[{"parameter": "Estradiol", "population": "Adult female, follicular phase (5th-95th percentile)", "range": "~31-90 pg/mL"}, {"parameter": "Estradiol", "population": "Adult female, ovulatory peak (5th-95th percentile)", "range": "~60-534 pg/mL", "notes": "Wide range reflects the sharp periovulatory rise"}, {"parameter": "Estradiol", "population": "Adult female, luteal phase (5th-95th percentile)", "range": "~60-233 pg/mL"}, {"parameter": "Estradiol", "population": "Postmenopausal", "range": "Typically <20 pg/mL"}]',1,'Low estradiol with high LH/FSH indicates primary ovarian insufficiency or menopause. Low estradiol with low/inappropriately normal LH/FSH suggests a hypothalamic/pituitary cause (e.g., functional hypothalamic amenorrhea, pituitary disease). Elevated estradiol outside the expected cyclical pattern can suggest an estrogen-producing ovarian or adrenal tumor, or reflect exogenous estrogen exposure. In assisted reproduction, serial estradiol measurements are used to monitor follicular development and response to ovarian stimulation.',NULL,'[{"condition": "Primary ovarian insufficiency / menopause", "direction": "low, with high LH/FSH"}, {"condition": "Hypothalamic amenorrhea / pituitary dysfunction", "direction": "low, with low/normal LH/FSH"}, {"condition": "Estrogen-secreting ovarian or adrenal tumor", "direction": "high, outside expected cyclical pattern"}]','[{"name": "PMC - Extensive monitoring of the natural menstrual cycle using serum biomarkers estradiol, LH and progesterone (peer-reviewed multicenter reference study)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8042396/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:51:33','2026-07-14 11:51:33','["fsh", "lh", "progesterone"]',NULL,NULL,'Does this fit with my cycle day or menopausal status? If I''m undergoing fertility treatment, is my ovarian response on track? Could this be pointing to another cause I should be worried about?','In fertility treatment, results guide adjustments to your stimulation medication dosing. Outside of that context, an unexpected result prompts correlation with LH/FSH and, if persistently abnormal without a clear reason, further evaluation for a hormone-producing source.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (90,'progesterone','Progesterone, Serum','','P4, Progesterone','Immunoassay / Reproductive Endocrinology','Confirms ovulation (mid-luteal progesterone) and evaluates luteal phase function; also used to monitor early pregnancy viability and assess corpus luteum function.',NULL,'Venous serum or plasma','For confirming ovulation, the sample should be drawn approximately 7 days after the presumed ovulation (mid-luteal phase, e.g., cycle day 21 in a standard 28-day cycle) -- timing relative to ovulation is essential for correct interpretation.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "Progesterone", "population": "Adult female, follicular phase (5th-95th percentile)", "range": "~0.05-0.19 ng/mL"}, {"parameter": "Progesterone", "population": "Adult female, ovulation (5th-95th percentile)", "range": "~0.06-4.15 ng/mL"}, {"parameter": "Progesterone", "population": "Adult female, mid-luteal phase (5th-95th percentile)", "range": "~4.1-14.6 ng/mL", "notes": "A mid-luteal level >3 ng/mL is commonly used as presumptive evidence of ovulation, though the exact cutoff varies by lab/reference"}]',1,'A mid-luteal progesterone consistent with the luteal-phase range supports that ovulation occurred; a low result at the expected mid-luteal timing suggests anovulation or luteal phase defect. In early pregnancy, a low progesterone can be associated with (though does not definitively diagnose) an abnormal or non-viable pregnancy, and is sometimes used alongside serial beta-hCG and ultrasound in the evaluation of suspected miscarriage or ectopic pregnancy, though its diagnostic role here is debated and varies by clinical protocol.',NULL,'[{"condition": "Anovulation / luteal phase defect", "direction": "low at expected mid-luteal timing"}, {"condition": "Confirmed ovulation", "direction": "appropriately elevated mid-luteal level"}, {"condition": "Possible non-viable early pregnancy (adjunct marker)", "direction": "low, interpreted alongside beta-hCG and ultrasound"}]','[{"name": "PMC - Extensive monitoring of the natural menstrual cycle using serum biomarkers estradiol, LH and progesterone (peer-reviewed multicenter reference study)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8042396/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:51:33','2026-07-14 11:51:33','["beta-hcg", "estradiol", "fsh", "lh"]',NULL,NULL,'Does this confirm that I ovulated this cycle? If I''m pregnant, does this level raise any concern about the pregnancy''s viability? Do I need this repeated or combined with other tests (like hCG)?','A result consistent with ovulation is reassuring; a low result at the expected time may prompt further fertility evaluation. In early pregnancy, a low level is usually interpreted alongside serial hCG and ultrasound rather than acted on alone.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (91,'anti-hcv','Hepatitis C Virus Antibody (Anti-HCV)','','Anti-HCV, HCV Antibody, Hepatitis C Screen','Immunoassay / Infectious Disease Serology','Screening test for current or past hepatitis C virus (HCV) infection; used for routine adult screening (per current CDC one-time screening recommendations), blood donor screening, and evaluation of unexplained liver enzyme elevation.',NULL,'Venous serum or plasma','No fasting required. A reactive result requires reflex/confirmatory HCV RNA testing to distinguish current (active) infection from a resolved past infection, since antibodies persist for life even after the virus has cleared (spontaneously or with treatment).',NULL,'Chemiluminescent immunoassay (CIA) or enzyme immunoassay (EIA); reactive screening results are typically reflexed to HCV RNA (viral load) testing by the laboratory.',NULL,'[{"parameter": "Anti-HCV", "population": "Result categories", "range": "Non-reactive (negative) or Reactive (positive) -- reported by signal-to-cutoff ratio, not a numeric concentration"}]',1,'A reactive anti-HCV antibody result indicates exposure to HCV at some point but does not confirm current infection -- a positive antibody with a negative/undetectable HCV RNA indicates a resolved past infection (either spontaneous clearance or successful prior treatment), while a positive antibody with detectable HCV RNA confirms current active infection requiring evaluation for antiviral treatment. In immunocompromised patients or those tested very early after exposure (acute infection), antibody testing can be falsely negative, and direct HCV RNA testing may be needed if suspicion is high.',NULL,'[{"condition": "Current (active) hepatitis C infection", "direction": "reactive antibody + detectable HCV RNA"}, {"condition": "Resolved past hepatitis C infection", "direction": "reactive antibody + undetectable HCV RNA"}, {"condition": "Chronic hepatitis C (cirrhosis/hepatocellular carcinoma risk if untreated)", "direction": "reactive antibody + persistently detectable HCV RNA"}]','[{"name": "Mayo Clinic Laboratories - Hepatitis C Virus Antibody Confirmation, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/63063", "accessed": "2026-07-14"}]',1,'2026-07-14 11:51:33','2026-07-14 11:51:33','["alt-ast", "hbsag", "hiv-ag-ab-combo"]',NULL,NULL,'Does this mean I currently have hepatitis C, or could this be a past resolved infection? Do I need an HCV RNA test to clarify? If I have active infection, what treatment options are available?','A reactive antibody result is followed by HCV RNA testing to determine whether the infection is currently active; if active, you''ll be referred for antiviral treatment, which is highly effective at curing hepatitis C in most cases.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (92,'syphilis-screening','Syphilis Screening (RPR/VDRL with Treponemal Confirmation)','','RPR, VDRL, TPHA, TPPA, FTA-ABS, Syphilis Serology','Immunoassay / Infectious Disease Serology','Screens for syphilis infection; used in routine prenatal screening, STI evaluation, and blood donor screening. Two complementary test types are used together: non-treponemal tests (RPR/VDRL) for screening and activity/treatment monitoring, and treponemal tests (TPHA/TPPA/FTA-ABS or treponemal EIA/CIA) for confirmation.',NULL,'Venous serum or plasma','No fasting required. Testing algorithms vary by laboratory: the ''traditional'' algorithm screens with a non-treponemal test (RPR/VDRL) and confirms reactive results with a treponemal test, while the ''reverse'' algorithm (increasingly common) screens with a treponemal EIA/CIA first and confirms with RPR/VDRL, which changes how discordant results are interpreted.',NULL,'Non-treponemal tests (RPR, VDRL) detect antibodies to cardiolipin-lecithin-cholesterol antigen released from damaged host cells and are reported as reactive/non-reactive with a titer; treponemal tests (TPHA, TPPA, FTA-ABS, or automated treponemal EIA/CIA) detect antibodies specific to Treponema pallidum antigens.',NULL,'[{"parameter": "RPR/VDRL and treponemal test", "population": "Result categories", "range": "Non-reactive or Reactive (with titer for RPR/VDRL) -- interpretation depends on the pattern of both test types together, not either alone"}]',1,'A reactive non-treponemal test (RPR/VDRL) confirmed by a reactive treponemal test supports active or previously treated syphilis (the treponemal test typically remains reactive for life even after successful treatment, so it cannot distinguish current from past treated infection on its own). A reactive RPR/VDRL with a non-reactive treponemal test suggests a biologic false-positive, which can occur with other conditions including pregnancy, autoimmune disease, and other infections such as chronic hepatitis C. Declining RPR/VDRL titers after treatment indicate treatment response; a sustained fourfold titer rise suggests reinfection or treatment failure.',NULL,'[{"condition": "Active or previously treated syphilis", "direction": "reactive non-treponemal + reactive treponemal test"}, {"condition": "Biologic false-positive (pregnancy, autoimmune disease, other infections)", "direction": "reactive non-treponemal + non-reactive treponemal test"}, {"condition": "Treatment response monitoring", "direction": "declining RPR/VDRL titer over time"}]','[{"name": "CDC NHANES Laboratory Procedure Manual - Syphilis (RPR methodology)", "url": "https://wwwn.cdc.gov/nchs/data/nhanes/public/2003/labmethods/l36_c_met_rpr.pdf", "accessed": "2026-07-14"}, {"name": "ScienceDirect - Hepatitis C virus infection and biological false-positive syphilis test (RPR/TPHA discordance context)", "url": "https://www.sciencedirect.com/science/article/abs/pii/S1499387211600672", "accessed": "2026-07-14"}]',1,'2026-07-14 11:51:33','2026-07-14 11:51:33','["anti-hcv", "hbsag", "hiv-ag-ab-combo"]',NULL,NULL,'Do both parts of this test agree, or is there a discordant result that needs explaining? Does this represent an active infection needing treatment, or a past treated infection? Do my partners need to be tested?','A confirmed positive result leads to staging (determining how long the infection has likely been present) and antibiotic treatment, with partner notification and testing recommended; declining RPR titers after treatment confirm response.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (93,'rubella-igg','Rubella IgG (Immunity Status)','','Rubella Antibody, German Measles Immunity','Immunoassay / Infectious Disease Serology','Determines immune status to rubella (German measles), most commonly as part of prenatal/preconception screening, since maternal rubella infection in early pregnancy can cause congenital rubella syndrome with serious fetal malformations.',NULL,'Venous serum or plasma','No fasting required. Part of standard prenatal panels; a non-immune result in a pregnant woman prompts postpartum vaccination (rubella vaccine is a live vaccine and cannot be given during pregnancy).',NULL,'Chemiluminescent or enzyme immunoassay, calibrated against the WHO International Standard (RUBI-1-94) and reported in IU/mL.',NULL,'[{"parameter": "Rubella IgG", "population": "Seropositive (immune)", "range": "\u226510 IU/mL (conventional WHO-standardized cutoff)", "notes": "Assay calibration and cutoffs vary between manufacturers; results near the cutoff (equivocal) may need confirmatory testing, particularly in vaccinated (versus naturally infected) individuals"}]',1,'A positive (seropositive) result indicates immunity, either from prior vaccination or past natural infection, and no specific action is needed. A negative (non-immune) result in a woman of reproductive age, especially when planning pregnancy, prompts vaccination before conception or postpartum (since the vaccine cannot be given during pregnancy). If a pregnant woman has a suspected rubella exposure or rash illness, IgG and IgM testing together (with attention to timing and possible paired acute/convalescent samples) helps determine whether an acute infection is occurring.',NULL,'[{"condition": "Rubella immunity (from vaccination or past infection)", "direction": "positive/seropositive"}, {"condition": "Susceptibility to rubella infection", "direction": "negative -- prompts vaccination when not pregnant"}, {"condition": "Congenital rubella syndrome risk (if maternal infection occurs in pregnancy)", "direction": "relevant when a pregnant patient is non-immune and exposed"}]','[{"name": "PMC - Evaluation of Commercial Immunoassays for Rubella Virus IgG Detection (WHO standard cutoff)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC12844522/", "accessed": "2026-07-14"}]',1,'2026-07-14 11:51:33','2026-07-14 11:51:33','["beta-hcg", "toxoplasma-igg-igm", "cmv-igg-igm"]',NULL,NULL,'Am I immune, or do I need vaccination? If I''m currently pregnant and not immune, what precautions should I take, and when can I get vaccinated? Do I need this rechecked before a future pregnancy?','A non-immune result outside of pregnancy leads to vaccination; during pregnancy, vaccination is deferred until after delivery since it''s a live vaccine, and precautions against exposure are discussed in the meantime.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (94,'insulin','Insulin, Serum','','Fasting Insulin, Serum Insulin','Immunoassay / Endocrinology','Investigates the cause of hypoglycemia (its primary use), evaluates insulin resistance, and helps guide treatment decisions in type 2 diabetes; also used to monitor pancreatic islet cell transplant function.',NULL,'Venous serum or plasma','Typically drawn fasting (8-12 hours); stop biotin (vitamin B7) supplements for at least a day before testing, as biotin can interfere with many immunoassay platforms. Usually collected together with a simultaneous glucose level for meaningful interpretation.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "Fasting insulin", "population": "Adult", "range": "~2-25 \u00b5U/mL (\u00b5IU/mL)", "notes": "Reference ranges vary considerably between labs/assays; some clinicians and researchers consider levels well below the upper limit (e.g., under ~10 \u00b5U/mL) more consistent with good insulin sensitivity, though this is not a formal diagnostic cutoff"}]',1,'High insulin with normal or elevated glucose suggests insulin resistance, a precursor to type 2 diabetes and a feature of metabolic syndrome and PCOS. High or inappropriately normal insulin with low glucose suggests excess insulin action -- causes include insulinoma, exogenous insulin administration (including surreptitious use), sulfonylurea use, or Cushing syndrome. Low insulin with high glucose suggests inadequate insulin production, as in type 1 diabetes or pancreatitis-related beta-cell loss.',NULL,'[{"condition": "Insulin resistance / metabolic syndrome / PCOS", "direction": "high, with normal-high glucose"}, {"condition": "Insulinoma / exogenous insulin administration", "direction": "high or inappropriately normal, with low glucose"}, {"condition": "Type 1 diabetes / beta-cell failure", "direction": "low, with high glucose"}]','[{"name": "MedlinePlus (NIH/NLM) - Insulin in Blood, citing Mayo Clinic Laboratories Test ID: INS", "url": "https://medlineplus.gov/lab-tests/insulin-in-blood/", "accessed": "2026-07-14"}]',1,'2026-07-14 22:07:28','2026-07-14 22:07:28','["c-peptide", "fasting-glucose", "hba1c"]',NULL,'Biotin (vitamin B7) supplementation can cause significant interference (falsely low or falsely high results depending on the assay design) on many immunoassay platforms -- patients should stop biotin at least 24-48 hours before testing per the specific assay''s recommendation. Recent food intake invalidates a ''fasting'' interpretation.','Was my glucose measured at the same time, and how do the two results relate to each other? Could my result reflect insulin resistance, and if so, what does that mean for my future diabetes risk? Do I need additional testing (e.g., HOMA-IR calculation, C-peptide) to clarify the picture? Is there anything in my diet, medications, or recent activity that could have affected this result?','Insulin results are always interpreted alongside a simultaneous glucose level, since the two must be considered together (e.g., high insulin with normal-to-high glucose suggests insulin resistance; high insulin with low glucose suggests inappropriate insulin excess). Depending on the pattern, your clinician may discuss lifestyle changes, calculate a HOMA-IR insulin resistance index, or investigate further with a C-peptide test or extended fasting study if hypoglycemia is a concern.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (95,'c-peptide','C-Peptide, Serum','','C-Peptide, Connecting Peptide','Immunoassay / Endocrinology','Marker of the body''s own (endogenous) insulin production -- used to distinguish type 1 from type 2 diabetes, investigate hypoglycemia (including suspected surreptitious insulin use, since injected insulin doesn''t raise C-peptide), and monitor islet/pancreas transplant function.',NULL,'Venous serum or plasma','Usually drawn fasting alongside a simultaneous glucose level; stop biotin supplements for at least 12 hours before testing per most assay manufacturer recommendations, as biotin can interfere with the assay.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "Fasting C-peptide", "population": "Adult", "range": "~0.3-3.3 ng/mL (or ~0.2-1.0 nmol/L)", "notes": "Reference ranges vary by lab/assay; result should always be interpreted alongside a simultaneous glucose"}]',1,'Low C-peptide indicates little remaining endogenous insulin production, as seen in longstanding type 1 diabetes, advanced type 2 diabetes with beta-cell exhaustion, or after pancreatectomy. Normal-to-high C-peptide with hyperglycemia is typical of insulin-resistant type 2 diabetes, where the pancreas is still producing (often excess) insulin but the body isn''t responding effectively. Because C-peptide is co-secreted with the person''s own insulin but is not present in most injected insulin formulations, a discordantly low C-peptide with a high insulin level in a hypoglycemic patient suggests exogenous insulin administration rather than an insulin-producing tumor.',NULL,'[{"condition": "Type 1 diabetes / advanced beta-cell failure", "direction": "low"}, {"condition": "Type 2 diabetes / insulin resistance", "direction": "normal to high, with hyperglycemia"}, {"condition": "Exogenous (injected) insulin as cause of hypoglycemia", "direction": "low C-peptide despite high measured insulin"}, {"condition": "Insulinoma", "direction": "inappropriately high relative to a low glucose"}]','[{"name": "UCSF Health - Insulin C-peptide test", "url": "https://www.ucsfhealth.org/care/medical-tests/insulin-c-peptide-test", "accessed": "2026-07-14"}, {"name": "Medscape/eMedicine - C-Peptide: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2087824-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 22:07:28','2026-07-14 22:07:28','["fasting-glucose", "hba1c", "insulin"]',NULL,'Even mild hemolysis can artifactually lower C-peptide values. Biotin supplementation can interfere with the assay. Very high C-peptide levels (rare, typically only in specific research/pathological contexts) can cause a falsely low result due to a ''hook effect'' on some immunoassay platforms.','Was my glucose checked at the same time, and how should the two results be interpreted together? Does this result help clarify whether I have type 1 or type 2 diabetes? If I''m on insulin therapy, does this tell us anything about how much of my own insulin production remains? Do I need islet cell antibody testing alongside this to further clarify the diabetes type?','C-peptide results are interpreted together with the simultaneous glucose level and, often, diabetes-related autoantibody testing. A low C-peptide with high glucose supports a type 1 diabetes diagnosis (little remaining endogenous insulin production); a normal-to-high C-peptide in a person with diabetes and insulin resistance supports type 2 diabetes. In suspected factitious hypoglycemia, a low C-peptide despite a high measured insulin level points to exogenous (injected) insulin as the cause.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (96,'osmolality','Osmolality, Serum','','Serum Osmolality, Plasma Osmolality','Clinical Chemistry','Assesses the body''s fluid/water balance and screens for toxic alcohol ingestion (via the osmolal gap); used to evaluate hyponatremia/hypernatremia, suspected diabetes insipidus, and unexplained altered mental status.',NULL,'Venous serum or plasma','No fasting required; can be drawn at any time. Often ordered alongside sodium, glucose, and BUN so a calculated osmolality (and the osmolal gap versus the measured value) can be determined.',NULL,'Directly measured by freezing point depression osmometry (captures all osmotically active particles); calculated osmolality is derived mathematically from sodium, glucose, and BUN (Posm = 2[Na] + glucose/18 + BUN/2.8) and is not a true independent measurement.',NULL,'[{"parameter": "Serum osmolality", "population": "Adult", "range": "275-295 mOsm/kg H2O"}]',1,'Low osmolality most often reflects hyponatremia (since sodium accounts for the majority of the osmolality value) and can be caused by SIADH, heart failure, cirrhosis, or excessive water intake. High osmolality reflects free water loss or a solute gain, seen in dehydration, hyperglycemia, or diabetes insipidus (in which urine remains inappropriately dilute despite high plasma osmolality). An elevated osmolal gap (measured minus calculated osmolality) is a key screening clue for toxic alcohol ingestion even before specific levels are available.',NULL,'[{"condition": "SIADH / hyponatremia", "direction": "low"}, {"condition": "Dehydration / diabetes insipidus / hyperglycemia", "direction": "high"}, {"condition": "Toxic alcohol ingestion (methanol, ethylene glycol)", "direction": "elevated osmolal gap"}]','[{"name": "StatPearls / NCBI Bookshelf - Serum Osmolality", "url": "https://www.ncbi.nlm.nih.gov/books/NBK567764/", "accessed": "2026-07-14"}, {"name": "Medscape/eMedicine - Serum Osmolality: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2099042-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 22:07:28','2026-07-14 22:07:28','["bun", "creatinine", "sodium"]','Serum osmolality above roughly 420 mOsm/kg can be lethal regardless of underlying cause and represents a medical emergency; in critically ill patients, values above 300 mOsm/kg are independently associated with higher risk of acute kidney injury and mortality.','A discrepancy of more than ~10 mOsm/kg between measured and calculated osmolality (the ''osmolal gap'') suggests the presence of unmeasured osmotically active substances -- classically toxic alcohols (methanol, ethylene glycol), mannitol, or ethanol -- and should prompt urgent toxicologic evaluation when clinically suspected.','Is my osmolality result consistent with my sodium level, or is there a gap that needs further investigation? Could dehydration, a medication, or an ingestion explain this result? Do I need urine osmolality testing as well to fully evaluate my fluid balance? What is the underlying cause, and how will it be treated?','Depending on the result and clinical context, your clinician may compare the measured value with a calculated osmolality to check for an osmolal gap (which raises concern for toxic alcohol ingestion or other unmeasured substances), order a urine osmolality to help distinguish causes of abnormal sodium/water balance, or investigate for underlying causes such as SIADH, diabetes insipidus, or dehydration.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (97,'free-psa','Free PSA (% Free PSA)','','Free PSA, %fPSA, Free-to-Total PSA Ratio','Immunoassay / Tumor Markers','Refines prostate cancer risk when total PSA falls in the diagnostically ambiguous ''gray zone'' (roughly 4-10 ng/mL), helping decide whether a biopsy is warranted and reducing unnecessary biopsies for benign prostatic hyperplasia (BPH).',NULL,'Venous serum, ideally processed promptly (free PSA is less stable than total PSA and can degrade with storage/delay)','Should be drawn before a digital rectal exam, prostate biopsy, or catheterization when possible, as manipulation of the prostate can transiently raise both total and free PSA. Recent ejaculation can also transiently affect results.',NULL,'Chemiluminescent immunoassay (CLIA) measuring free (unbound) PSA, reported as a percentage of the simultaneously measured total PSA (% free PSA = free PSA / total PSA x 100).',NULL,'[{"parameter": "% Free PSA", "population": "Lower risk (benign disease more likely)", "range": ">25%"}, {"parameter": "% Free PSA", "population": "Intermediate risk", "range": "10-25%"}, {"parameter": "% Free PSA", "population": "Higher risk", "range": "<10%", "notes": "Most clinically useful when total PSA is 4-10 ng/mL; cutoffs vary somewhat by lab, age, and guideline source"}]',1,'Men with prostate cancer tend to have a lower percentage of free (unbound) PSA relative to total PSA than men with benign prostatic hyperplasia, even at the same total PSA level. In the 4-10 ng/mL total PSA gray zone, a % free PSA below roughly 10% is associated with a substantially higher probability of a positive biopsy (historically cited around 50%) compared to a % free PSA above 25% (historically cited around 10-16%). This test does not replace biopsy for diagnosis but helps stratify who is more or less likely to benefit from one, reducing unnecessary biopsies in men with a high % free PSA.',NULL,'[{"condition": "Prostate cancer (higher probability)", "direction": "low % free PSA (<10%), especially with total PSA 4-10 ng/mL"}, {"condition": "Benign prostatic hyperplasia (more likely)", "direction": "high % free PSA (>25%)"}]','[{"name": "Mayo Clinic Proceedings - Percent Free Prostate-Specific Antigen: Entering a New Era in the Detection of Prostate Cancer", "url": "https://www.mayoclinicproceedings.org/article/S0025-6196(11)63334-X/fulltext", "accessed": "2026-07-14"}, {"name": "PMC - Using the Free-to-total Prostate-specific Antigen Ratio to Detect Prostate Cancer in Men with Nonspecific Elevations of PSA Levels", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC1495603/", "accessed": "2026-07-14"}]',1,'2026-07-14 22:23:53','2026-07-14 22:23:53','["psa"]',NULL,'Recent digital rectal exam, prostate biopsy, catheterization, or ejaculation can transiently raise PSA (both total and free) and should be avoided before the draw when possible. Free PSA is less stable than total PSA in a stored/delayed sample, so prompt processing improves accuracy.','Given my total PSA and % free PSA together, what is my estimated risk of prostate cancer? Do I need a biopsy now, or is continued PSA monitoring reasonable? Are there other tools (e.g., PSA density, MRI, newer biomarker tests) that could help refine this decision further? How often should PSA and % free PSA be rechecked if we decide to monitor rather than biopsy?','Your urologist will weigh your % free PSA together with your total PSA, age, family history, and DRE findings to decide whether biopsy, active PSA/free PSA surveillance, or additional imaging (such as prostate MRI) is the most appropriate next step -- a low % free PSA increases suspicion but does not alone confirm cancer, just as a reassuring % free PSA does not completely exclude it.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (98,'prealbumin','Prealbumin (Transthyretin), Serum','','Prealbumin, Transthyretin, TTR','Clinical Chemistry','Sensitive short-term marker of nutritional status and protein-calorie malnutrition; used to assess and monitor nutritional status in hospitalized, critically ill, or chronically ill patients, since it responds faster to changes in nutrition than albumin.',NULL,'Venous serum or plasma','No fasting required. Because prealbumin is also a negative acute-phase reactant, it should ideally be interpreted alongside CRP to distinguish true malnutrition from an acute inflammatory drop.',NULL,'Immunoturbidimetric or immunonephelometric assay on automated chemistry analyzers.',NULL,'[{"parameter": "Prealbumin", "population": "Adult", "range": "15-30 mg/dL (150-300 mg/L)", "notes": "Some labs cite up to 35-40 mg/dL as the upper limit"}, {"parameter": "Prealbumin", "population": "Moderate malnutrition risk", "range": "10-17 mg/dL"}, {"parameter": "Prealbumin", "population": "Severe malnutrition risk", "range": "<10 mg/dL"}]',1,'Because prealbumin has a short half-life (about 2-3 days, compared to roughly 20 days for albumin), it reflects recent changes in nutritional status more quickly and is useful for monitoring response to nutritional support over days to weeks rather than months. As a negative acute-phase reactant, prealbumin also falls during acute illness, inflammation, infection, surgery, or trauma independent of true nutritional intake, so a low level should be interpreted alongside CRP or clinical context before attributing it purely to malnutrition. It can also be falsely elevated in dehydration and in some cases of acute alcohol-related liver injury.',NULL,'[{"condition": "Protein-calorie malnutrition", "direction": "low"}, {"condition": "Acute-phase response (infection, inflammation, surgery, trauma)", "direction": "low, independent of nutrition"}, {"condition": "Chronic liver disease (reduced synthesis)", "direction": "low"}]','[{"name": "American Family Physician (AAFP) - Prealbumin: A Marker for Nutritional Evaluation", "url": "https://www.aafp.org/pubs/afp/issues/2002/0415/p1575.html", "accessed": "2026-07-14"}]',1,'2026-07-14 22:23:53','2026-07-14 22:23:53','["albumin", "total-protein", "transferrin"]',NULL,NULL,'Does this reflect true malnutrition, or could recent illness/inflammation be lowering it? Is my nutritional support plan working, based on the trend? Should this be rechecked soon to track progress?','A low result often prompts nutritional assessment and support planning, with serial testing used to track response over days to weeks given how quickly this marker changes compared to albumin.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (99,'transferrin','Transferrin, Serum','','Transferrin','Clinical Chemistry / Hematology','Iron transport protein used both as an iron-status marker (with iron and TIBC) and, historically, as a longer-term nutritional status marker; low transferrin is one of several markers used to assess protein malnutrition.',NULL,'Venous serum or plasma','Morning fasting sample preferred when assessed together with serum iron, due to diurnal variation in iron studies.',NULL,'Immunoturbidimetric or immunonephelometric assay on automated chemistry analyzers; TIBC (total iron-binding capacity) is closely related and can be calculated from transferrin, or measured directly.',NULL,'[{"parameter": "Transferrin", "population": "Adult", "range": "~200-360 mg/dL", "notes": "Reference range varies modestly by lab/method"}]',1,'Low transferrin is seen in protein-calorie malnutrition, chronic liver disease (reduced synthesis), nephrotic syndrome (urinary loss), and chronic inflammation (transferrin is a negative acute-phase reactant, similar to albumin). High transferrin is the classic finding in iron-deficiency anemia, where the body upregulates transferrin production in an attempt to maximize iron transport despite low iron stores -- this is why transferrin/TIBC rises while ferritin and serum iron fall in iron deficiency, a pattern that helps distinguish it from anemia of chronic disease (where transferrin is typically low-normal or low despite also having low iron).',NULL,'[{"condition": "Iron-deficiency anemia", "direction": "high (elevated TIBC)"}, {"condition": "Protein-calorie malnutrition / chronic liver disease / nephrotic syndrome", "direction": "low"}, {"condition": "Anemia of chronic disease/inflammation", "direction": "low-normal, despite also having low iron"}]','[{"name": "Medscape - Nutritional Support and the Surgical Patient (transferrin as nutritional marker)", "url": "https://www.medscape.com/viewarticle/474066_6", "accessed": "2026-07-14"}]',1,'2026-07-14 22:23:53','2026-07-14 22:23:53','["ferritin", "prealbumin", "serum-iron", "tibc-transferrin-saturation"]',NULL,NULL,'Does this fit with iron deficiency, or could this reflect a nutritional or liver issue instead? Should this be interpreted alongside my ferritin and iron results? Do I need further testing to clarify the cause?','Results are interpreted together with ferritin, serum iron, and clinical context to distinguish iron deficiency from other causes (malnutrition, liver disease, chronic inflammation) before deciding on treatment.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (100,'dhea-s','Dehydroepiandrosterone Sulfate (DHEA-S), Serum','','DHEA-S, DHEAS, DHEA Sulfate','Immunoassay / Reproductive Endocrinology','Evaluates adrenal androgen production; used to investigate hirsutism and virilization in women, distinguish adrenal from ovarian sources of excess androgen, evaluate suspected congenital adrenal hyperplasia, and investigate premature adrenarche in children.',NULL,'Venous serum or plasma','No fasting required. Unlike testosterone, DHEA-S has minimal diurnal variation (because of its long half-life and stable sulfate conjugation), so timing of the draw during the day is less critical than for testosterone or cortisol.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers; LC-MS/MS offers greater specificity at the extremes.',NULL,'[{"parameter": "DHEA-S", "population": "Adult male", "range": "~28-640 \u00b5g/dL", "notes": "Wide range reflects natural decline with age after young adulthood; reference intervals vary by lab/assay and age band"}]',1,'DHEA-S is produced almost exclusively by the adrenal gland (unlike testosterone, which has both ovarian/testicular and adrenal sources), making it useful for distinguishing an adrenal from a gonadal cause of excess androgen. Mild elevation is usually idiopathic or related to PCOS; a level 5-fold or more above the upper limit of normal (often cited around 600 µg/dL or higher) raises significant concern for an androgen-secreting adrenal tumor, since DHEA-S is elevated in over 90% of such tumors, particularly adrenal carcinomas. DHEA-S is also used alongside 17-hydroxyprogesterone and cortisol in the evaluation of congenital adrenal hyperplasia and premature adrenarche in children.',NULL,'[{"condition": "Polycystic ovary syndrome (PCOS) / idiopathic hyperandrogenism", "direction": "mildly high"}, {"condition": "Androgen-secreting adrenal tumor (adenoma or carcinoma)", "direction": "markedly high, often \u2265600 \u00b5g/dL or \u22655x upper limit"}, {"condition": "Congenital adrenal hyperplasia / premature adrenarche", "direction": "high, interpreted alongside 17-OH progesterone"}, {"condition": "Adrenal insufficiency", "direction": "low"}]','[{"name": "Mayo Clinic Laboratories - Dehydroepiandrosterone Sulfate (DHEA-S), Serum (test catalog)", "url": "https://pediatric.testcatalog.org/show/DHES1", "accessed": "2026-07-14"}, {"name": "ClinicalTrials.gov - Enzalutamide + External Beam RT for Prostate (documented adult male DHEA-S reference range)", "url": "https://clinicaltrials.gov/study/NCT02028988", "accessed": "2026-07-14"}]',1,'2026-07-14 22:24:37','2026-07-14 22:24:37','["total-testosterone", "free-testosterone", "cortisol", "lh", "fsh"]',NULL,NULL,'Does this point to an adrenal or ovarian source for my symptoms (like excess hair growth)? Given how elevated this is, do I need imaging to rule out a tumor? Do I need additional hormone testing?','Mild elevation is often managed as part of a broader hyperandrogenism workup (often PCOS-related). Markedly elevated results prompt adrenal imaging to rule out a tumor, given the strong association between very high levels and adrenal masses.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (101,'hemoglobin-electrophoresis','Hemoglobin Electrophoresis (Hemoglobinopathy Evaluation)','','Hb Electrophoresis, HPLC Hemoglobin Analysis, Thalassemia Screen, Sickle Cell Screen','Hematology','Identifies and quantifies normal and abnormal hemoglobin types to diagnose hemoglobinopathies (sickle cell trait/disease, hemoglobin C/E/D and other variants) and thalassemias; used for newborn screening, premarital/carrier screening, prenatal screening, and workup of unexplained microcytic anemia not responding to iron therapy.',NULL,'Venous whole blood, EDTA tube (lavender top); heel-stick for newborn screening','No fasting required. Recent blood transfusion can mask or dilute the patient''s own hemoglobin pattern with donor hemoglobin -- testing should ideally be deferred at least 3 months after transfusion when possible, or the transfusion history noted for interpretation.',NULL,'Cation-exchange high-performance liquid chromatography (HPLC) and/or capillary electrophoresis are the current standard methods (having largely superseded older cellulose acetate gel electrophoresis), separating hemoglobin fractions by charge/size and quantifying each as a percentage of total hemoglobin.',NULL,'[{"parameter": "Hemoglobin A (HbA)", "population": "Adult", "range": "95-98%"}, {"parameter": "Hemoglobin A2 (HbA2)", "population": "Adult", "range": "2-3%", "notes": "Some labs cite up to 3.5% as the upper limit"}, {"parameter": "Hemoglobin F (HbF)", "population": "Adult (age >3 years)", "range": "<1-2%", "notes": "Levels above ~2% in individuals older than 3 are considered elevated"}]',1,'Elevated HbA2 (commonly >3.5%) with a microcytic blood picture supports beta-thalassemia trait; in HbS/beta-thalassemia, HbA2 can be even higher (median around 6.5% in some series). Presence of HbS with roughly 60% HbA and 40% HbS indicates sickle cell trait (usually asymptomatic carrier status); absence of HbA with predominant HbS (often 80-95%) indicates sickle cell disease (HbSS). HbSC disease shows roughly equal HbS and HbC. Elevated HbF can be seen in beta-thalassemia major, hereditary persistence of fetal hemoglobin, and in sickle cell patients on hydroxyurea therapy (where higher HbF is therapeutically beneficial, reducing sickling). Results should always be interpreted alongside the CBC (particularly MCV/MCH) and iron studies, since thalassemia trait can be confused with iron deficiency on red cell indices alone.',NULL,'[{"condition": "Sickle cell trait (HbAS)", "direction": "~60% HbA, ~40% HbS"}, {"condition": "Sickle cell disease (HbSS)", "direction": "predominant HbS, little/no HbA"}, {"condition": "Beta-thalassemia trait (minor)", "direction": "elevated HbA2 (>3.5%), microcytosis"}, {"condition": "Beta-thalassemia major", "direction": "predominant HbF, minimal/no HbA"}, {"condition": "Hemoglobin C or E disease/trait", "direction": "presence of HbC or HbE variant"}]','[{"name": "Medscape/eMedicine - Hemoglobin Electrophoresis: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2085637-overview", "accessed": "2026-07-14"}, {"name": "Hematology.org (ASH) - Hemoglobin Electrophoresis in Sickle Cell Disease: A Primer for the Clinician", "url": "https://www.hematology.org/education/trainees/fellows/hematopoiesis/2021/hemoglobin-electrophoresis-in-sickle-cell-disease", "accessed": "2026-07-14"}]',1,'2026-07-14 22:25:21','2026-07-14 22:25:21','["cbc", "ferritin", "serum-iron", "reticulocyte-count"]',NULL,'Recent blood transfusion introduces donor hemoglobin that can mask or dilute the patient''s true hemoglobin pattern -- testing should note transfusion history and ideally be deferred when a non-transfused sample is needed. Concurrent iron deficiency can lower HbA2 percentage in beta-thalassemia trait carriers, sometimes masking the diagnosis until iron status is corrected and the test repeated.','What specific hemoglobin variant or pattern was found, and what does it mean for my health? Am I a carrier (trait) or do I have the disease form of this condition? Do my partner and I need testing together if we''re planning a pregnancy, given the risk to offspring? Do I need genetic counseling, and should other family members be screened? If I have sickle cell trait, are there any activity or environmental precautions I should know about?','A carrier (trait) result in someone planning a family typically prompts partner testing, since two carriers of a compatible trait have a chance of having a child with the more severe disease form, and genetic counseling is recommended in that situation. A disease-level result (e.g., sickle cell disease, thalassemia major) leads to referral to hematology for ongoing specialized management. Trait results in an otherwise healthy person usually require no treatment, only awareness for family planning and, for sickle cell trait, certain precautions in extreme physical exertion or high-altitude/low-oxygen situations.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (102,'fit-fobt','Fecal Immunochemical Test (FIT / FOBT)','','FIT, FOBT, Fecal Occult Blood Test, Stool Occult Blood','Clinical Chemistry / Point of Care','Screens for colorectal cancer and precancerous polyps by detecting hidden (occult) blood in stool; the modern fecal immunochemical test (FIT) has largely replaced the older guaiac-based test (gFOBT) as the standard non-invasive stool screening option, alongside colonoscopy and multitarget stool DNA testing.',NULL,'Stool sample, collected by the patient at home using the kit provided','FIT (immunochemical) testing requires no dietary or medication restrictions, unlike the older guaiac-based test, since it uses antibodies specific to human hemoglobin and is not affected by dietary blood, vitamin C, or red meat. Only a single stool sample is typically required for FIT-based colorectal cancer screening (versus multiple samples historically needed for guaiac testing).',NULL,'Immunochromatographic or automated immunoturbidimetric assay using antibodies specific to human hemoglobin, distinguishing it from the older guaiac (chemical peroxidase) method that could react with non-human or upper-GI-degraded blood and dietary substances.',NULL,'[{"parameter": "FIT result", "population": "Result categories", "range": "Negative (below the assay''s positivity cutoff, commonly around 100 ng/mL hemoglobin) or Positive"}]',1,'A positive FIT result requires follow-up colonoscopy to evaluate for colorectal cancer or advanced polyps, and should not be repeated as a way to ''confirm'' the result -- any positive FIT warrants colonoscopy regardless of a subsequent negative repeat test. FIT specificity is routinely above 95%, but sensitivity for cancer detection varies by population (roughly 40-70% per average-risk screening data, higher in some study populations), meaning a negative FIT reduces but does not eliminate colorectal cancer risk, which is why average-risk guidelines recommend annual FIT testing (versus a longer interval for colonoscopy) if FIT is the chosen screening method. A positive result can also reflect other sources of GI bleeding (hemorrhoids, diverticulosis, peptic ulcer, inflammatory bowel disease) rather than cancer.',NULL,'[{"condition": "Colorectal cancer / advanced adenomatous polyps", "direction": "positive"}, {"condition": "Other GI bleeding sources (hemorrhoids, diverticulosis, peptic ulcer, IBD)", "direction": "positive, non-malignant cause"}]','[{"name": "Mayo Clinic Laboratories - Fecal Occult Blood, Colorectal Cancer Screen, Qualitative, Immunochemical, Feces (test catalog)", "url": "https://gi.testcatalog.org/show/FOBT", "accessed": "2026-07-14"}, {"name": "StatPearls / NCBI Bookshelf - Fecal Occult Blood Test", "url": "https://www.ncbi.nlm.nih.gov/books/NBK537138/", "accessed": "2026-07-14"}]',1,'2026-07-14 22:26:06','2026-07-14 22:26:06','["cea", "cbc", "ferritin"]',NULL,'Unlike the older guaiac-based test, FIT is not affected by diet (red meat), vitamin C, or most medications, since it specifically detects human hemoglobin via antibodies -- this is a key advantage that eliminated the need for pre-test dietary restriction. Active menstrual bleeding or bleeding hemorrhoids contaminating the sample can cause a false-positive result unrelated to colorectal pathology.','Since my result is positive, when should I schedule my follow-up colonoscopy? Does a positive result mean I definitely have cancer, or could it be from something else? If negative, when should I repeat this screening test, and is that the right screening strategy for my risk level, or should I consider colonoscopy instead? Do I have any risk factors (family history, symptoms) that should change my screening plan?','A positive result should prompt scheduling of a diagnostic colonoscopy -- this is the standard next step regardless of symptoms, and should not be delayed or substituted with a repeat FIT. A negative result in an average-risk person means continuing with annual FIT screening (or the screening interval recommended by your clinician) as part of ongoing colorectal cancer prevention, alongside attention to any new symptoms (rectal bleeding, unexplained weight loss, change in bowel habits) that would warrant earlier evaluation regardless of the FIT result.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (103,'zinc','Zinc, Serum','','Serum Zinc','Clinical Chemistry','Evaluates suspected zinc deficiency, most often in the context of malabsorption, prolonged parenteral nutrition, burns, chronic liver/kidney disease, or characteristic clinical findings (poor wound healing, dermatitis, hair loss, taste/smell disturbance, impaired immunity).',NULL,'Venous serum or plasma, collected in a zinc-free (trace-element) tube using a stainless steel needle','Requires specialized zinc-free collection tubes and avoidance of rubber stopper contact; ideally a fasting morning sample, separated from cells within about 45 minutes to prevent contamination or redistribution artifacts.',NULL,'Atomic absorption spectrophotometry or inductively coupled plasma mass spectrometry (ICP-MS).',NULL,'[{"parameter": "Serum zinc", "population": "Adult", "range": "~66-106 \u00b5g/dL", "notes": "Reference ranges vary meaningfully between labs/sources (some cite 60-130 \u00b5g/dL); always confirm against the reporting lab''s own range"}]',1,'Zinc deficiency causes impaired wound healing, dermatitis (classically acrodermatitis enteropathica in severe/congenital deficiency), hair loss, diarrhea, taste and smell disturbance, growth impairment in children, and impaired immune function. Common causes include malabsorption (e.g., Crohn''s disease, short bowel syndrome), inadequate zinc in parenteral nutrition, chronic liver disease, chronic kidney disease with dialysis, burns (zinc lost through wound exudate), and excess dietary copper or iron (which competes with zinc absorption). Elevated zinc is of minimal independent clinical significance and is uncommon outside of supplementation or occupational/environmental exposure.',NULL,'[{"condition": "Malabsorption (e.g., Crohn''s disease, short bowel syndrome)", "direction": "low"}, {"condition": "Chronic liver or kidney disease", "direction": "low"}, {"condition": "Acrodermatitis enteropathica (congenital zinc transport defect)", "direction": "very low"}, {"condition": "Burns (zinc loss through wound exudate)", "direction": "low"}]','[{"name": "Mayo Clinic Laboratories - Zinc, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/7735", "accessed": "2026-07-14"}]',1,'2026-07-14 22:27:58','2026-07-14 22:27:58','["ceruloplasmin"]',NULL,'Hemolysis causes false elevation, since red blood cells contain much higher zinc concentrations than plasma. Contact with rubber stoppers or non-trace-element collection tubes can contaminate the sample and falsely raise results. Zinc is also a negative acute-phase reactant, so acute illness/inflammation can transiently lower levels independent of true zinc status, similar to albumin.','Could my low zinc level explain some of my symptoms (e.g., poor wound healing, taste changes, hair loss)? Do I need supplementation, and if so, for how long and at what dose? Is there an underlying cause (malabsorption, diet, chronic illness) that also needs to be addressed? Should copper be checked too, since zinc supplementation can affect copper status?','Confirmed deficiency is typically managed with oral zinc supplementation, with the underlying cause (dietary, malabsorptive, or disease-related) investigated and addressed where possible. Because high-dose or prolonged zinc supplementation can cause copper deficiency, copper status is sometimes monitored alongside zinc during treatment, and a repeat zinc level may be checked after a period of supplementation to confirm improvement.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (104,'ceruloplasmin','Ceruloplasmin, Serum','','Ceruloplasmin','Clinical Chemistry','Primary first-line screening test for Wilson disease (an inherited disorder of copper metabolism), particularly in patients with unexplained liver disease, neurological, or psychiatric symptoms at a young age.',NULL,'Venous serum or plasma','No fasting required. As an acute-phase reactant, results should ideally be interpreted outside of acute illness/inflammation when possible, or with that context noted.',NULL,'Immunoturbidimetric or immunonephelometric assay on automated chemistry analyzers.',NULL,'[{"parameter": "Ceruloplasmin", "population": "Adult", "range": "~20-40 mg/dL", "notes": "Reference ranges vary modestly by lab/method; levels are physiologically low in newborns and rise over the first 2 years of life"}]',1,'Approximately 85-90% of patients with Wilson disease have a ceruloplasmin below 20 mg/dL, and this remains the standard first-line screening test, especially when combined with slit-lamp examination for Kayser-Fleischer corneal rings and 24-hour urine copper. However, ceruloplasmin is also a positive acute-phase reactant that can rise with inflammation, pregnancy, estrogen use, or infection -- and can be falsely low in general protein deficiency/malnutrition or nephrotic syndrome (urinary loss) -- so an isolated low or borderline result should be interpreted alongside the full clinical picture, and a normal ceruloplasmin does not completely exclude Wilson disease (a minority of confirmed cases have levels within or near the normal range). Cutoff values for diagnosing Wilson disease may also vary somewhat by population/laboratory.',NULL,'[{"condition": "Wilson disease (hepatolenticular degeneration)", "direction": "low, typically <20 mg/dL"}, {"condition": "Malnutrition / protein-losing states (nephrotic syndrome, protein-losing enteropathy)", "direction": "low, non-Wilson cause"}, {"condition": "Acute-phase response (inflammation, infection, pregnancy, estrogen use)", "direction": "high, can mask an underlying low baseline"}]','[{"name": "Medscape/eMedicine - Wilson Disease Workup: Serum Ceruloplasmin", "url": "https://emedicine.medscape.com/article/183456-workup", "accessed": "2026-07-14"}, {"name": "University of Rochester Medical Center - Ceruloplasmin (Blood)", "url": "https://www.urmc.rochester.edu/encyclopedia/content?contenttypeid=167&contentid=ceruloplasmin_blood", "accessed": "2026-07-14"}]',1,'2026-07-14 22:27:58','2026-07-14 22:27:58','["zinc", "alt-ast", "total-bilirubin"]',NULL,NULL,'Does this support or rule out Wilson disease as the cause of my symptoms? Do I need additional testing (like a slit-lamp eye exam or urine copper) to confirm? Could something else explain a low result?','A low result in someone with unexplained liver or neurological symptoms typically leads to further Wilson disease workup (slit-lamp exam for Kayser-Fleischer rings, 24-hour urine copper, possibly genetic testing) before treatment decisions are made.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (105,'anti-tpo','Thyroid Antibodies (TPOAb and TgAb)','','Anti-TPO, TPO Antibody, Thyroid Peroxidase Antibody, Thyroglobulin Antibody, TgAb, Anti-Thyroid Antibodies','Immunoassay / Endocrinology','Confirms an autoimmune cause of thyroid dysfunction (Hashimoto''s thyroiditis or Graves'' disease) when TSH/free T4 are abnormal, and helps predict future thyroid dysfunction in subclinical hypothyroidism or during pregnancy planning; thyroglobulin antibody (TgAb) is also required alongside thyroglobulin tumor marker testing to validate that result in thyroid cancer surveillance.',NULL,'Venous serum or plasma','No fasting required. Usually ordered together with TSH and free T4 rather than in isolation.',NULL,'Chemiluminescent immunoassay (CLIA) or enzyme immunoassay (EIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "Thyroid peroxidase antibody (TPOAb)", "population": "Normal", "range": "<35 IU/mL", "notes": "Some labs use cutoffs up to 60 IU/mL; assay-dependent"}, {"parameter": "Thyroglobulin antibody (TgAb)", "population": "Normal", "range": "<20 IU/mL", "notes": "Assay-dependent"}]',1,'Elevated TPOAb is the most sensitive marker for autoimmune thyroid disease and is positive in the large majority of Hashimoto''s thyroiditis cases and roughly 70-80% of Graves'' disease cases. TgAb is positive in a similar proportion of Hashimoto''s cases and is the only positive antibody in a minority (roughly 10-15%) of cases where TPOAb is negative, which is why both are typically tested together. Both antibodies can be present in roughly 10-15% of the general population without clinical thyroid disease, so a positive result supports but does not by itself diagnose autoimmune thyroid disease -- it must be interpreted alongside TSH, free T4, and clinical findings. TgAb positivity also invalidates thyroglobulin as a reliable tumor marker in post-thyroidectomy cancer surveillance, since the antibody interferes with the assay and can mask a rising thyroglobulin that would otherwise indicate cancer recurrence.',NULL,'[{"condition": "Hashimoto''s thyroiditis (autoimmune hypothyroidism)", "direction": "positive TPOAb and/or TgAb"}, {"condition": "Graves'' disease (autoimmune hyperthyroidism)", "direction": "positive TPOAb, positive TRAb (a separate, stimulating antibody) is more specific"}, {"condition": "Postpartum thyroiditis risk", "direction": "positive TPOAb predicts higher risk"}, {"condition": "Invalidated thyroglobulin tumor marker (post-thyroidectomy)", "direction": "positive TgAb interferes with the Tg assay"}]','[{"name": "Medscape/eMedicine - Antithyroid Antibody: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2086819-overview", "accessed": "2026-07-14"}]',1,'2026-07-14 22:28:42','2026-07-14 22:28:42','["tsh", "free-t4", "free-t3"]',NULL,'TgAb positivity artificially suppresses measured thyroglobulin levels in the same blood draw, so a ''low'' or ''undetectable'' thyroglobulin result cannot be trusted for cancer surveillance purposes when TgAb is positive -- this is a critical interaction to flag when both tests are ordered together in a post-thyroidectomy patient.','Given a positive result, do I currently have (or am I at risk of developing) overt thyroid dysfunction, and how often should my TSH be monitored? If I''m planning a pregnancy, does this affect my risk of pregnancy complications or postpartum thyroiditis? If I''m being monitored for thyroid cancer, does a positive TgAb mean my thyroglobulin results can''t be trusted, and what alternative monitoring is being used instead?','A positive antibody result with normal thyroid function usually leads to periodic TSH monitoring (since autoimmune thyroid antibodies predict a higher future risk of developing over dysfunction), rather than immediate treatment. If thyroid function is already abnormal, treatment follows standard management for hypothyroidism (Hashimoto''s) or hyperthyroidism (Graves''). In pregnancy or preconception, a positive TPOAb may prompt closer monitoring given the association with pregnancy complications and postpartum thyroiditis.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (106,'toxoplasma-igg-igm','Toxoplasma gondii IgG/IgM','','Toxoplasma Serology, Toxo IgG, Toxo IgM, TORCH - Toxoplasmosis','Immunoassay / Infectious Disease Serology','Screens for Toxoplasma gondii infection, most importantly during pregnancy, since primary maternal infection can cause congenital toxoplasmosis with serious fetal harm (chorioretinitis, intracranial calcifications, hydrocephalus); also used in immunocompromised patients at risk of reactivation (e.g., cerebral toxoplasmosis in advanced HIV).',NULL,'Venous serum or plasma','No fasting required. In pregnancy, testing is often done at the first prenatal visit and, if seronegative, may be repeated later in pregnancy in regions/populations with higher prevalence, to catch a new infection acquired during pregnancy.',NULL,'Chemiluminescent or enzyme immunoassay detecting IgG and IgM separately; IgG avidity testing (a related assay) helps estimate how long ago an IgG-positive infection occurred, which is important for timing risk in pregnancy.',NULL,'[{"parameter": "Toxoplasma IgG", "population": "Negative (non-immune)", "range": "<7.2 IU/mL (assay-dependent cutoff)"}, {"parameter": "Toxoplasma IgM", "population": "Negative", "range": "<10.0 AU/mL (assay-dependent cutoff)"}]',1,'IgG-positive/IgM-negative indicates past infection and immunity, generally not a concern in pregnancy since reactivation causing fetal harm is rare in immunocompetent people. IgM-positive results (with or without IgG) require careful interpretation, since IgM can remain detectable for months to over a year after infection and false-positive IgM results are common on initial (non-reference-laboratory) assays -- a positive IgM should prompt confirmatory testing at a reference toxoplasma laboratory, including IgG avidity testing, before concluding a recent infection occurred. A confirmed recent/acute infection during pregnancy requires urgent obstetric and infectious disease consultation, since treatment can reduce (though not eliminate) the risk of congenital transmission.',NULL,'[{"condition": "Congenital toxoplasmosis risk (acute maternal infection during pregnancy)", "direction": "IgM positive, confirmed recent infection"}, {"condition": "Past infection / immunity", "direction": "IgG positive, IgM negative"}, {"condition": "Cerebral toxoplasmosis (reactivation in advanced immunosuppression, e.g., AIDS)", "direction": "IgG positive (prior infection) with new neurologic symptoms -- imaging and often empiric treatment take precedence over serology in this setting"}]','[{"name": "droracle.ai - Interpretation and management of a positive TORCH panel report (clinical synthesis)", "url": "https://www.droracle.ai/articles/423819/what-is-the-interpretation-and-management-of-a-positive", "accessed": "2026-07-14"}, {"name": "Maurya Labs - TORCH Panel reference ranges", "url": "https://mauryalabs.com/patients-corner/pathology-tests/torch-panel/", "accessed": "2026-07-14"}]',1,'2026-07-15 05:33:30','2026-07-15 05:33:30','["rubella-igg", "hiv-ag-ab-combo"]',NULL,'Toxoplasma IgM has a well-documented tendency toward false positives on many commercial assays and can also remain positive for over a year after the true infection, so a positive IgM alone (especially from a non-reference laboratory) should not be used to diagnose acute infection or guide major clinical decisions (such as termination of pregnancy) without confirmatory reference-laboratory testing.','Does my result indicate a new infection or immunity from a past infection? If IgM is positive, do I need confirmatory testing at a reference laboratory before we act on this result? If I''m pregnant and non-immune (IgG negative), what precautions should I take to avoid a new infection during pregnancy? If a recent infection is confirmed, what is the plan for monitoring and possibly treating the pregnancy?','A positive IgM result should prompt referral to (or consultation with) a reference toxoplasma serology laboratory for confirmatory testing and IgG avidity testing before concluding a recent infection has occurred, given the high false-positive rate of IgM on standard assays. If acute infection in pregnancy is confirmed, this requires close collaboration between obstetrics, infectious disease, and maternal-fetal medicine to guide treatment and fetal monitoring (which may include amniocentesis for PCR testing after 18 weeks gestation).');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (107,'cmv-igg-igm','Cytomegalovirus (CMV) IgG/IgM','','CMV Serology, CMV IgG, CMV IgM, TORCH - Cytomegalovirus','Immunoassay / Infectious Disease Serology','Screens for CMV infection, most importantly during pregnancy (congenital CMV is a leading infectious cause of hearing loss and developmental disability), and evaluates CMV status before transplant (donor/recipient matching) and in immunocompromised patients at risk of reactivation.',NULL,'Venous serum or plasma','No fasting required. In suspected active/congenital infection, CMV serology is often paired with CMV PCR (viral load) testing, which more directly detects active viral replication.',NULL,'Chemiluminescent or enzyme immunoassay detecting IgG and IgM separately; IgG avidity testing helps estimate timing of infection (low avidity suggests infection within the past ~3-4 months).',NULL,'[{"parameter": "CMV IgG", "population": "Negative (non-immune)", "range": "<12.0 IU/mL (assay-dependent cutoff)"}, {"parameter": "CMV IgM", "population": "Negative", "range": "<18.0 AU/mL (assay-dependent cutoff)"}]',1,'CMV seroprevalence is very high in the general population (commonly cited around 60-99% depending on the population studied), so IgG positivity alone is common and mainly indicates past infection/immunity, not current risk, in an immunocompetent person. As with toxoplasma, CMV IgM can persist for many months after primary infection and can also appear during reactivation or reinfection with a different strain, so a positive IgM (with or without positive IgG) requires IgG avidity testing to help distinguish a recent primary infection (the scenario of greatest concern in pregnancy) from an older infection or reactivation. Confirmed primary maternal infection carries the highest risk of severe congenital CMV; reactivation/reinfection in an already-immune mother carries substantially lower risk but is not zero.',NULL,'[{"condition": "Congenital CMV risk (primary maternal infection during pregnancy)", "direction": "IgM positive with low IgG avidity, confirmed recent primary infection"}, {"condition": "Past infection / immunity", "direction": "IgG positive, IgM negative, high avidity"}, {"condition": "CMV reactivation (immunocompromised patients, transplant recipients)", "direction": "positive CMV PCR/viral load is the more direct marker; serology has limited utility for detecting reactivation in this setting"}]','[{"name": "Today''s Clinical Lab - Prenatal Diagnosis of TORCH Pathogens", "url": "https://www.clinicallab.com/prenatal-diagnosis-of-torch-pathogens-21819", "accessed": "2026-07-14"}, {"name": "Maurya Labs - TORCH Panel reference ranges", "url": "https://mauryalabs.com/patients-corner/pathology-tests/torch-panel/", "accessed": "2026-07-14"}]',1,'2026-07-15 05:33:30','2026-07-15 05:33:30','["rubella-igg", "hiv-ag-ab-combo"]',NULL,'As with toxoplasma, CMV IgM can remain detectable for an extended period after primary infection and can be falsely positive, so it should not be used alone to date an infection or guide major clinical decisions -- IgG avidity testing and, where relevant, direct CMV PCR are needed for a confident interpretation. In immunocompromised or transplant patients, serology has limited value for detecting reactivation, since a new antibody response may not develop or may be blunted -- CMV PCR (viral load) is the preferred monitoring test in that setting.','Does my result mean I''m immune from a past infection, or could this be a new (primary) infection? If I''m pregnant, do I need IgG avidity testing to clarify the timing? If I''m being evaluated before a transplant, how does my CMV status affect donor selection or post-transplant monitoring? If I''m already immunosuppressed, should CMV PCR be used instead of (or alongside) serology to monitor for reactivation?','In pregnancy, a positive IgM prompts IgG avidity testing to estimate timing of infection; a confirmed recent primary infection is discussed with maternal-fetal medicine regarding fetal monitoring and potential treatment options. In transplant candidates, CMV IgG status (positive or negative) is recorded and used alongside donor CMV status to guide post-transplant prophylaxis or monitoring strategy. In immunosuppressed patients with suspected active disease, CMV PCR (viral load) rather than serology is typically used to guide diagnosis and treatment decisions.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (108,'von-willebrand-factor','von Willebrand Factor (Antigen + Ristocetin Cofactor Activity)','','vWF, vWF:Ag, vWF:RCo, Von Willebrand Panel','Hematology / Coagulation','Diagnoses and classifies von Willebrand disease (vWD), the most common inherited bleeding disorder, and differentiates it from hemophilia A; used to investigate mucocutaneous bleeding symptoms (easy bruising, heavy menstrual bleeding, prolonged bleeding after dental work or surgery).',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Avoid warfarin for 2 weeks and heparin for 2 days before testing when possible, and do not draw from an arm with a heparin lock. Sample should reach the lab within about 3 hours of collection at room temperature (or be double-centrifuged and frozen promptly per the specific lab''s protocol) for accurate results.',NULL,'vWF antigen (vWF:Ag) is measured by immunoturbidimetric or ELISA methods (protein mass, regardless of function); vWF ristocetin cofactor activity (vWF:RCo) is a functional platelet agglutination assay measuring how well vWF supports platelet binding; newer collagen-binding (vWF:CB) assays are increasingly used as well. Factor VIII activity is typically measured alongside, since vWF stabilizes circulating factor VIII.',NULL,'[{"parameter": "vWF Antigen (vWF:Ag)", "population": "Adult, non-O blood group", "range": "~50-150%", "notes": "Blood group O individuals normally run lower (as low as 40-50%), which must be considered before diagnosing a deficiency"}, {"parameter": "vWF Ristocetin Cofactor Activity (vWF:RCo)", "population": "Adult", "range": "~50-150%", "notes": "A level <30% is considered diagnostic of vWD; 30-50% is a gray zone requiring correlation with bleeding history"}]',1,'Low vWF:Ag and vWF:RCo together (with a normal RCo:Ag ratio) suggest type 1 vWD (a partial quantitative deficiency, the most common form). A disproportionately low vWF:RCo relative to vWF:Ag (RCo:Ag ratio below about 0.7) suggests type 2 vWD (a qualitative/functional defect). Very low or undetectable levels of both suggest type 3 vWD (severe, near-complete deficiency). Because vWF is an acute-phase reactant, levels rise with pregnancy, estrogen therapy, inflammation, acute infection, surgery, and stress -- which can transiently normalize results in a person with mild congenital vWD, sometimes requiring repeat testing outside of these conditions. Blood group O individuals have physiologically lower vWF levels (roughly 25-30% lower) than other blood groups, which must be factored in before diagnosing deficiency.',NULL,'[{"condition": "Von Willebrand disease, type 1 (partial quantitative deficiency)", "direction": "low vWF:Ag and vWF:RCo, proportionate (RCo:Ag ratio >0.7)"}, {"condition": "Von Willebrand disease, type 2 (qualitative/functional defect)", "direction": "disproportionately low vWF:RCo relative to vWF:Ag (ratio <0.7)"}, {"condition": "Von Willebrand disease, type 3 (severe deficiency)", "direction": "very low/undetectable vWF:Ag and vWF:RCo"}, {"condition": "Acquired von Willebrand syndrome (e.g., lymphoproliferative disease, aortic stenosis)", "direction": "low, in a patient without a prior personal/family bleeding history"}]','[{"name": "Mayo Clinic Laboratories - von Willebrand Factor Antigen, Plasma (test catalog)", "url": "https://hematology.testcatalog.org/show/VWAG", "accessed": "2026-07-14"}, {"name": "Medscape/eMedicine - Ristocetin Cofactor (Functional von Willebrand Factor): Reference Range, Interpretation", "url": "https://emedicine.medscape.com/article/2086190-overview", "accessed": "2026-07-14"}, {"name": "Labcorp - von Willebrand Factor (vWF) Antigen test description", "url": "https://www.labcorp.com/tests/086280/von-willebrand-factor-vwf-antigen", "accessed": "2026-07-14"}]',1,'2026-07-15 05:41:28','2026-07-15 05:41:28','["pt-inr", "aptt", "fibrinogen", "abo-rh-typing"]',NULL,'ABO blood group significantly affects baseline vWF levels (lower in group O), acute-phase reactant physiology means results rise with pregnancy, stress, inflammation, infection, surgery, and exercise (potentially masking a mild underlying deficiency), and recent warfarin or heparin use can affect related coagulation testing -- all must be considered when interpreting a result, and repeat testing away from these confounders is often needed before a definitive diagnosis.','Which subtype of von Willebrand disease do I have, and how does that affect my treatment options (e.g., desmopressin/DDAVP responsiveness versus need for factor concentrate)? Does my blood group affect how this result should be interpreted? Do I need repeat testing at a different time, given that results can be affected by stress, illness, or hormonal factors? What precautions should I take before surgery, dental work, or childbirth?','A borderline or mildly low result is often repeated at a separate visit, ideally when not acutely ill, stressed, pregnant, or on estrogen therapy, since these can transiently raise levels and mask a mild deficiency. A confirmed diagnosis leads to classification of the vWD subtype (which guides whether desmopressin/DDAVP or vWF/factor VIII concentrate is the appropriate treatment for bleeding episodes or procedures) and referral to hematology for a comprehensive bleeding disorder management plan, including precautions for future surgery, dental procedures, and childbirth.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (109,'ldh','Lactate Dehydrogenase (LDH), Serum','','LDH, Lactic Dehydrogenase','Clinical Chemistry','Nonspecific marker of cell/tissue damage and turnover; used in hemolysis workup, as part of tumor marker panels (germ cell tumors, lymphoma), and to assess tissue injury (e.g., muscle, liver, myocardial).',NULL,'Venous serum or plasma','No fasting required. Avoid hemolysis during collection, since red cells contain high LDH concentrations and in-vitro hemolysis will falsely raise results.',NULL,'Enzymatic kinetic assay (lactate-to-pyruvate conversion, measuring NADH formation) on automated chemistry analyzers.',NULL,'[{"parameter": "LDH", "population": "Adult", "range": "~140-280 U/L", "notes": "Reference ranges vary meaningfully between labs/methods (some report up to 333 U/L); always confirm against the reporting lab''s range"}]',1,'Elevated LDH is a nonspecific finding seen in hemolysis, myocardial infarction, hepatitis, muscle injury, pulmonary infarction, and many malignancies (notably germ cell tumors and lymphoma, where it is used as a prognostic marker). In suspected hemolytic anemia, elevated LDH together with low haptoglobin and elevated indirect bilirubin supports the diagnosis, though a meaningful minority of confirmed hemolytic anemia cases (roughly 25% in some case series) can have a normal LDH, so a normal result does not exclude hemolysis. LDH lacks organ specificity on its own; isoenzyme fractionation (historically used to help localize the source, e.g., a ''flipped'' LDH1:LDH2 ratio in myocardial infarction) has been largely superseded by more specific tests like troponin.',NULL,'[{"condition": "Hemolytic anemia", "direction": "high, alongside low haptoglobin and high indirect bilirubin"}, {"condition": "Germ cell tumors / lymphoma (tumor burden marker)", "direction": "high"}, {"condition": "Tissue injury (myocardial, hepatic, muscle, pulmonary infarction)", "direction": "high"}]','[{"name": "The Role of the LDH Test in Diagnosing Haemolytic Anaemia - Lupin Diagnostics (clinical reference range synthesis)", "url": "https://www.lupindiagnostics.com/blog/chemistry/the-role-of-the-ldh-test-in-diagnosing-hemolytic-anemia", "accessed": "2026-07-14"}, {"name": "droracle.ai - Significance of Lactate Dehydrogenase (LDH) and Haptoglobin (clinical synthesis)", "url": "https://www.droracle.ai/articles/111831/what-is-the-significance-of-lactate-dehydrogenase-ldh-and", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["cbc", "haptoglobin", "reticulocyte-count", "total-bilirubin"]',NULL,'In-vitro hemolysis during or after sample collection is a major cause of falsely elevated results, since red blood cells contain LDH concentrations far exceeding plasma -- a hemolyzed sample should prompt a repeat draw before an elevated LDH is acted upon in isolation.','Given my other results (haptoglobin, bilirubin, reticulocyte count), does this LDH level support a diagnosis of hemolysis or point to a different cause? If I have a known tumor, how is my LDH being used to guide prognosis or treatment monitoring? Do I need further testing to identify the source of an elevated LDH?','An isolated elevated LDH is usually interpreted alongside other tests (haptoglobin, bilirubin, reticulocyte count for hemolysis; troponin for cardiac injury; liver enzymes for hepatic injury) rather than acted on by itself, since LDH alone doesn''t identify the source. In oncology, LDH is often tracked serially as part of established prognostic scoring systems and treatment monitoring.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (110,'haptoglobin','Haptoglobin, Serum','','Haptoglobin','Clinical Chemistry / Hematology','Key marker of intravascular hemolysis -- haptoglobin binds and clears free hemoglobin released from destroyed red cells, so its level falls as it is consumed during active hemolysis.',NULL,'Venous serum or plasma','No fasting required. As an acute-phase reactant, results should be interpreted with awareness of concurrent inflammation, which can raise haptoglobin independent of hemolysis.',NULL,'Immunoturbidimetric or immunonephelometric assay on automated chemistry analyzers.',NULL,'[{"parameter": "Haptoglobin", "population": "Adult", "range": "~30-200 mg/dL", "notes": "Reference range varies by lab/method"}]',1,'Low or undetectable haptoglobin, together with elevated LDH and indirect bilirubin, supports a diagnosis of hemolytic anemia -- haptoglobin is consumed as it binds free hemoglobin, making it one of the more specific markers of hemolysis (particularly intravascular hemolysis). As a positive acute-phase reactant, haptoglobin can also rise with inflammation, infection, or malignancy, which can mask a mild concurrent hemolytic process -- a ''normal'' haptoglobin in an acutely ill patient does not fully exclude hemolysis. Absent or very low haptoglobin can also reflect a rare congenital haptoglobin deficiency (anhaptoglobinemia), more common in some populations, which is not itself pathologic.',NULL,'[{"condition": "Hemolytic anemia (especially intravascular)", "direction": "low/undetectable"}, {"condition": "Acute-phase response (inflammation, infection, malignancy) masking hemolysis", "direction": "high, potentially obscuring a concurrent low value"}, {"condition": "Congenital haptoglobin deficiency (anhaptoglobinemia)", "direction": "very low/absent, without hemolysis"}]','[{"name": "droracle.ai - Significance of Lactate Dehydrogenase (LDH) and Haptoglobin (clinical synthesis)", "url": "https://www.droracle.ai/articles/111831/what-is-the-significance-of-lactate-dehydrogenase-ldh-and", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["cbc", "dat-coombs", "ldh", "total-bilirubin"]',NULL,'As an acute-phase reactant, concurrent inflammation, infection, or malignancy can elevate haptoglobin and mask a true underlying low level from mild hemolysis -- interpret alongside LDH, indirect bilirubin, and reticulocyte count rather than in isolation.','Does my low haptoglobin, together with my other results, confirm active hemolysis? If so, what is the underlying cause, and does it need urgent treatment? If my haptoglobin is normal despite suspected hemolysis, could inflammation be masking a low result?','A low haptoglobin supporting hemolysis typically prompts further workup to identify the cause -- a direct antiglobulin test (Coombs test) to check for immune-mediated hemolysis, peripheral blood smear review, and consideration of hereditary causes (e.g., hemoglobinopathy, G6PD deficiency, hereditary spherocytosis) depending on the clinical picture.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (111,'17-ohp','17-Hydroxyprogesterone (17-OHP), Serum','','17-OHP, 17-Hydroxyprogesterone','Immunoassay / Reproductive Endocrinology','Primary screening test for congenital adrenal hyperplasia (CAH) due to 21-hydroxylase deficiency, used alongside cortisol and androstenedione; also part of the workup for hirsutism and infertility in women with suspected non-classic CAH.',NULL,'Venous serum or plasma','Morning sample preferred, given adrenal steroid diurnal variation. In equivocal cases, an ACTH stimulation test (with 17-OHP measured before and after synthetic ACTH) improves diagnostic accuracy for non-classic CAH.',NULL,'Liquid chromatography-tandem mass spectrometry (LC-MS/MS), the preferred modern method for accuracy at low concentrations and to avoid cross-reactivity issues seen with older immunoassays.',NULL,'[{"parameter": "17-OHP", "population": "Adult male", "range": "<220 ng/dL"}, {"parameter": "17-OHP", "population": "Adult female, follicular phase", "range": "<80 ng/dL"}, {"parameter": "17-OHP", "population": "Adult female, luteal phase", "range": "<285 ng/dL"}, {"parameter": "17-OHP", "population": "Postmenopausal female", "range": "<51 ng/dL"}]',1,'Markedly elevated 17-OHP (classically several-fold above the upper limit) supports classic congenital adrenal hyperplasia from 21-hydroxylase deficiency, typically diagnosed in infancy via newborn screening. Moderately elevated levels, especially with a level above roughly 30 ng/mL (300 ng/dL) after ACTH stimulation, support non-classic (late-onset) CAH, which can present later in life with hirsutism, irregular menses, or infertility. All three analytes (17-OHP, androstenedione, cortisol) should be measured together, since the two rarer forms of CAH (11-hydroxylase and 17-hydroxylase deficiency) do not show the same 17-OHP elevation pattern and require a different diagnostic approach (deoxycorticosterone and progesterone, respectively).',NULL,'[{"condition": "Classic congenital adrenal hyperplasia (21-hydroxylase deficiency)", "direction": "markedly high"}, {"condition": "Non-classic (late-onset) congenital adrenal hyperplasia", "direction": "moderately high, especially post-ACTH stimulation"}, {"condition": "17-alpha-hydroxylase deficiency (rare)", "direction": "low, with elevated mineralocorticoid precursors instead"}]','[{"name": "Mayo Clinic Laboratories - 17-Hydroxyprogesterone, Serum (test catalog)", "url": "https://pediatric.testcatalog.org/show/OHPG", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["cortisol", "dhea-s", "total-testosterone"]',NULL,NULL,'Does this confirm congenital adrenal hyperplasia, or do I need a stimulation test to be sure? Does this affect my fertility or menstrual symptoms? Do family members need screening?','A markedly elevated result supports the diagnosis, while a borderline result often leads to an ACTH stimulation test for confirmation, followed by endocrinology referral to discuss management, especially for non-classic forms presenting in adulthood.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (112,'aldosterone-renin-ratio','Aldosterone and Renin (Aldosterone-Renin Ratio)','','ARR, Aldosterone-Renin Ratio, Plasma Aldosterone Concentration, Plasma Renin Activity, PAC, PRA','Immunoassay / Endocrinology','Recommended first-line screening test for primary aldosteronism (Conn syndrome), the most common identifiable and curable cause of secondary hypertension; ordered in patients with resistant hypertension, hypertension with hypokalemia, or hypertension with an adrenal incidentaloma.',NULL,'Venous serum or plasma','Testing should ideally be done seated after being upright for at least 2 hours, mid-morning; potassium should be corrected before testing (hypokalemia suppresses aldosterone and can mask the diagnosis); spironolactone/eplerenone must be stopped for 4-6 weeks before testing, and other antihypertensives that affect the renin-aldosterone axis (beta-blockers, ACE inhibitors, ARBs, diuretics) are ideally adjusted per endocrinology guidance, though the screening test can still be performed on most other medications with appropriate interpretation caveats.',NULL,'Plasma aldosterone concentration (PAC) measured by immunoassay or LC-MS/MS; renin measured either as plasma renin activity (PRA, an enzymatic assay) or direct renin concentration (DRC, an immunoassay) -- the two renin methods are not directly interchangeable, and conversion factors vary by laboratory.',NULL,'[{"parameter": "Aldosterone-Renin Ratio (ARR)", "population": "Positive screen threshold", "range": "\u226520-30 (ng/dL)/(ng/mL/h) with PAC \u226515 ng/dL (using PRA); ratio cutoffs differ when direct renin concentration is used instead", "notes": "Exact cutoff varies by guideline/laboratory; both PAC and the ratio must be elevated together for the screen to be considered positive"}]',1,'A high ARR (elevated aldosterone relative to suppressed renin) with PAC above the threshold is a positive screening result for primary aldosteronism and warrants confirmatory testing (e.g., saline infusion test, oral sodium loading test) before subtype classification (adrenal adenoma vs. bilateral adrenal hyperplasia) via adrenal CT and, often, adrenal venous sampling. A low ARR with elevated renin instead suggests secondary hyperaldosteronism (renal artery stenosis, heart failure, cirrhosis with ascites, diuretic use) rather than a primary adrenal cause. ACE inhibitors and ARBs can falsely elevate renin, potentially masking primary aldosteronism (a low/undetectable renin on an ACE inhibitor is actually a strong predictor of primary aldosteronism despite the medication).',NULL,'[{"condition": "Primary aldosteronism (adrenal adenoma or bilateral hyperplasia)", "direction": "high aldosterone, suppressed renin -- high ratio"}, {"condition": "Secondary hyperaldosteronism (renal artery stenosis, heart failure, cirrhosis)", "direction": "high aldosterone, high renin -- normal/low ratio"}]','[{"name": "Mayo Clinic Laboratories - Aldosterone, Serum and Renin Activity, Plasma (test catalog)", "url": "https://endocrinology.testcatalog.org/show/ALDS", "accessed": "2026-07-14"}, {"name": "Cleveland Clinic Journal of Medicine - Our evolving understanding of primary aldosteronism (Endocrine Society guideline summary)", "url": "https://www.ccjm.org/content/88/4/221", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["cortisol", "potassium", "sodium"]',NULL,'Spironolactone and eplerenone must be stopped 4-6 weeks before testing, as they invalidate results. Beta-blockers can lower renin (falsely raising the ratio); ACE inhibitors/ARBs and diuretics can raise renin (potentially masking a true positive ratio, though a suppressed renin despite an ACE inhibitor still strongly suggests primary aldosteronism). Posture (supine vs. upright), time of day, and dietary sodium intake at the time of the blood draw significantly affect both aldosterone and renin and must be standardized per the testing protocol.','Does my result require confirmatory testing before a diagnosis is made? Do any of my current blood pressure medications need to be adjusted or stopped before repeating this test for an accurate result? If primary aldosteronism is confirmed, what additional imaging or testing (adrenal CT, adrenal venous sampling) will be needed to determine the best treatment (surgery vs. medication)?','A positive screen (high ARR with elevated PAC) is followed by a confirmatory test (such as saline infusion or oral sodium loading) to establish the diagnosis, since the screening ratio alone has a meaningful false-positive rate. A confirmed diagnosis leads to adrenal CT imaging and, in surgical candidates, adrenal venous sampling to determine whether the source is unilateral (favoring surgery) or bilateral (favoring mineralocorticoid receptor antagonist therapy).');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (113,'amh','Anti-Mullerian Hormone (AMH), Serum','','AMH, Anti-Mullerian Hormone','Immunoassay / Reproductive Endocrinology','Assesses ovarian reserve (the remaining egg supply) for fertility counseling and IVF stimulation planning; also used to help diagnose PCOS (where AMH is often elevated) and to predict menopause timing in some contexts.',NULL,'Venous serum or plasma','Can be drawn on any day of the menstrual cycle (unlike FSH/estradiol), since AMH shows relatively little cycle-dependent variation compared to other reproductive hormones, though some intra- and inter-cycle variability has been documented with newer, more sensitive assays.',NULL,'Chemiluminescent or enzyme immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "AMH", "population": "Reproductive-age woman, general reference", "range": "~1.0-4.0 ng/mL", "notes": "Strongly age-dependent -- peaks around age 25 and declines steadily thereafter; no single universal cutoff exists, and age-specific nomograms are increasingly used"}, {"parameter": "AMH", "population": "Diminished ovarian reserve (commonly cited threshold)", "range": "<1.0-1.1 ng/mL"}]',1,'Low AMH indicates diminished ovarian reserve and is associated with a reduced number of eggs retrieved during IVF stimulation, though it does not directly predict egg quality or the ability to conceive naturally, and should not be used alone to counsel a woman against attempting pregnancy. AMH declines with age and becomes undetectable around menopause. Elevated AMH is commonly seen in polycystic ovary syndrome (PCOS), reflecting the increased number of small antral follicles characteristic of that condition, and is sometimes used as a supportive (though not diagnostic) marker in PCOS evaluation.',NULL,'[{"condition": "Diminished ovarian reserve", "direction": "low"}, {"condition": "Polycystic ovary syndrome (PCOS)", "direction": "high"}, {"condition": "Premature ovarian insufficiency", "direction": "very low/undetectable"}]','[{"name": "MedPark Hospital - Anti-Mullerian Hormone (AMH) Test: Levels, Results", "url": "https://www.medparkhospital.com/en-US/disease-and-treatment/anti-mullerian-hormone-test", "accessed": "2026-07-14"}, {"name": "PMC - Using anti-Mullerian hormone to predict premature ovarian insufficiency (Bologna Criteria threshold)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC11611575/", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["estradiol", "fsh", "lh"]',NULL,NULL,'Given my age, how should my AMH level be interpreted -- is it typical for my age group or lower/higher than expected? Does this result change my fertility treatment plan or timeline? Should this be repeated, or combined with antral follicle count, for a fuller picture of my ovarian reserve? If elevated, does this support a PCOS diagnosis alongside my other symptoms/tests?','Low AMH in someone considering pregnancy often prompts a conversation about timelines and, if fertility treatment is being considered, about expected response to ovarian stimulation. AMH is typically interpreted alongside antral follicle count (by ultrasound) and FSH for the most complete ovarian reserve assessment, rather than as a standalone test.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (114,'beta-2-microglobulin','Beta-2 Microglobulin, Serum','','B2M, Beta-2 Microglobulin','Immunoassay / Tumor Markers','Prognostic marker in multiple myeloma, chronic lymphocytic leukemia, and lymphoma (higher levels correlate with greater tumor burden and worse prognosis); also used as a marker of kidney function/tubular damage in some settings.',NULL,'Venous serum or plasma; also measurable in urine and CSF for specific indications','No fasting required.',NULL,'Immunoturbidimetric, immunonephelometric, or chemiluminescent immunoassay.',NULL,'[{"parameter": "Beta-2 microglobulin", "population": "Adult", "range": "~1-3 \u00b5g/mL", "notes": "Reference range varies by lab/method"}]',1,'In multiple myeloma, beta-2 microglobulin is a key component of the International Staging System (ISS), with higher levels indicating greater tumor burden and worse prognosis. It is also elevated in lymphoma and chronic lymphocytic leukemia, where it has independent prognostic value for remission duration and survival. Because beta-2 microglobulin is cleared by the kidneys, reduced kidney function (regardless of malignancy) also raises levels, so results must be interpreted alongside renal function -- an elevated level in a patient with impaired kidney function may reflect reduced clearance rather than increased tumor burden.',NULL,'[{"condition": "Multiple myeloma (staging/prognosis)", "direction": "high, correlates with tumor burden"}, {"condition": "Lymphoma / chronic lymphocytic leukemia (prognosis)", "direction": "high"}, {"condition": "Reduced kidney function (non-malignant cause of elevation)", "direction": "high, due to reduced clearance"}]','[{"name": "Medscape/eMedicine - Beta2 Microglobulin: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2086864-overview", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["creatinine", "ldh"]',NULL,NULL,'Does this reflect my disease activity, or could reduced kidney function be raising this result instead? How does this fit into my overall staging/prognosis? Should this be tracked over time?','Results are interpreted alongside kidney function tests to determine how much of the level reflects disease burden versus reduced clearance, and serial monitoring is often used to track disease activity or treatment response in confirmed cases.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (115,'alpha-1-antitrypsin','Alpha-1 Antitrypsin (A1AT), Serum','','A1AT, AAT, Alpha-1 Antitrypsin','Clinical Chemistry','Screens for alpha-1 antitrypsin deficiency, a genetic condition predisposing to early-onset emphysema/COPD (especially in non-smokers or with disproportionate lung disease for smoking history) and liver disease (cirrhosis, hepatocellular carcinoma).',NULL,'Venous serum or plasma','No fasting required. As a positive acute-phase reactant, a normal or elevated result during acute illness/inflammation does not fully exclude an underlying deficiency allele -- retesting when clinically stable, or direct genotyping/phenotyping, may be needed if suspicion remains.',NULL,'Immunoturbidimetric or immunonephelometric assay for quantification; phenotyping (isoelectric focusing) or genotyping is used to identify the specific deficiency allele (e.g., PiZZ, PiSZ) when levels are low.',NULL,'[{"parameter": "Alpha-1 antitrypsin (normal M/M phenotype)", "population": "Adult", "range": "~100-273 mg/dL", "notes": "Reference range varies modestly by lab/method"}]',1,'Low alpha-1 antitrypsin suggests a deficiency genotype (most significantly the ZZ genotype, causing severe deficiency), which predisposes to early-onset panacinar emphysema (accelerated by smoking) and can cause liver disease including cirrhosis and hepatocellular carcinoma, since the abnormal protein accumulates and damages hepatocytes. As a positive acute-phase reactant, levels rise with inflammation, infection, or malignancy, which can transiently mask a mild deficiency -- phenotyping or genotyping is more reliable than a single quantitative level when deficiency is strongly suspected clinically.',NULL,'[{"condition": "Alpha-1 antitrypsin deficiency (e.g., PiZZ genotype)", "direction": "low"}, {"condition": "Early-onset emphysema/COPD (especially in non-smokers)", "direction": "low, underlying cause"}, {"condition": "Liver cirrhosis / hepatocellular carcinoma (from protein accumulation)", "direction": "low serum level despite hepatocyte accumulation of abnormal protein"}]','[{"name": "PubMed - Reference and interpretive ranges for alpha(1)-antitrypsin quantitation by phenotype in adult and pediatric populations", "url": "https://pubmed.ncbi.nlm.nih.gov/22912357/", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["alt-ast", "total-bilirubin"]',NULL,NULL,'Does this explain my lung or liver symptoms? Do I need phenotyping or genotyping to confirm a specific deficiency type? Should my family members be tested?','A low result typically leads to phenotyping or genotyping to confirm the specific genetic variant, pulmonology and/or hepatology referral depending on symptoms, and consideration of family testing given the hereditary nature of this condition.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (116,'shbg','Sex Hormone-Binding Globulin (SHBG), Serum','','SHBG','Immunoassay / Reproductive Endocrinology','Measures the main carrier protein for testosterone and estradiol in blood; used alongside total testosterone to calculate free/bioavailable testosterone, and as a marker of insulin resistance/metabolic risk (low SHBG correlates with insulin resistance).',NULL,'Venous serum or plasma','No fasting required. Often ordered together with total testosterone for calculation of free testosterone.',NULL,'Chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "SHBG", "population": "Adult male, 20-49 years", "range": "16.5-55.9 nmol/L"}, {"parameter": "SHBG", "population": "Adult male, >49 years", "range": "19.3-76.4 nmol/L"}, {"parameter": "SHBG", "population": "Adult female, 20-49 years", "range": "24.6-122.0 nmol/L"}, {"parameter": "SHBG", "population": "Adult female, >49 years", "range": "17.3-125.0 nmol/L"}]',1,'Low SHBG is associated with obesity, insulin resistance, type 2 diabetes, and non-alcoholic fatty liver disease, and can cause a normal total testosterone to actually reflect low free (bioavailable) testosterone -- or the reverse in a woman with PCOS, where low SHBG amplifies the effect of even modestly elevated total testosterone, worsening clinical hyperandrogenism. High SHBG is seen with estrogen therapy/pregnancy, hyperthyroidism, and liver disease, and can cause a normal or even low-normal total testosterone to still result in adequate free testosterone, or conversely can make total testosterone appear falsely reassuring in true androgen deficiency. SHBG is essential context whenever total testosterone results are borderline or don''t match the clinical picture.',NULL,'[{"condition": "Obesity / insulin resistance / type 2 diabetes / NAFLD", "direction": "low"}, {"condition": "PCOS (low SHBG amplifying hyperandrogenism)", "direction": "low"}, {"condition": "Estrogen therapy / pregnancy / hyperthyroidism / liver disease", "direction": "high"}]','[{"name": "Labcorp - Sex Hormone-binding Globulin (SHBG), Serum (specialty test catalog)", "url": "https://specialtytesting.labcorp.com/tests/500848/sex-hormone-binding-globulin-shbg-serum", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["free-testosterone", "total-testosterone"]',NULL,NULL,'Does this help explain my testosterone or estrogen-related symptoms? Could my weight, thyroid function, or a medication be affecting this? Should my free hormone levels be checked alongside this?','This result is used together with total testosterone or estradiol to calculate free/bioavailable hormone levels, giving a more accurate picture than the total level alone, especially when symptoms don''t match the total hormone result.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (117,'acth','Adrenocorticotropic Hormone (ACTH), Plasma','','ACTH, Corticotropin','Immunoassay / Endocrinology','Evaluates the hypothalamic-pituitary-adrenal axis; used together with cortisol to distinguish primary from secondary/tertiary adrenal insufficiency, and to distinguish ACTH-dependent from ACTH-independent causes of Cushing syndrome.',NULL,'Venous plasma, EDTA tube, collected on ice and processed/frozen promptly','Requires morning collection (typically 08:00-09:00h) due to strong diurnal variation (highest early morning, lowest in the evening); the hormone is unstable with a plasma half-life of only about 22-30 minutes, so the sample must be chilled and processed rapidly to avoid falsely low results from ex-vivo degradation. Recent exogenous steroid use (even inhaled or topical) can suppress ACTH and must be noted.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "ACTH", "population": "Adult, morning sample (08:00-09:00h)", "range": "~10-60 pg/mL (2.2-13.3 pmol/L)", "notes": "Levels are physiologically lower in the evening (often <20 pg/mL); reference ranges vary by lab/assay"}]',1,'ACTH must always be interpreted alongside a simultaneous cortisol level. Low cortisol with elevated ACTH indicates primary adrenal insufficiency (Addison''s disease) -- the adrenal gland cannot respond despite appropriate pituitary stimulation. Low cortisol with low or inappropriately normal ACTH indicates secondary (pituitary) or tertiary (hypothalamic) adrenal insufficiency. In suspected Cushing syndrome, a detectable/normal-to-high ACTH suggests an ACTH-dependent cause (pituitary Cushing disease or ectopic ACTH secretion), while a suppressed/undetectable ACTH suggests an ACTH-independent adrenal source (adrenal adenoma or carcinoma).',NULL,'[{"condition": "Primary adrenal insufficiency (Addison''s disease)", "direction": "high, with low cortisol"}, {"condition": "Secondary/tertiary adrenal insufficiency (pituitary/hypothalamic)", "direction": "low or inappropriately normal, with low cortisol"}, {"condition": "Cushing disease (pituitary) / ectopic ACTH syndrome", "direction": "detectable/high, with elevated cortisol"}, {"condition": "Adrenal Cushing syndrome (adenoma/carcinoma)", "direction": "suppressed/undetectable, with elevated cortisol"}]','[{"name": "University of Rochester Medical Center - ACTH blood test", "url": "https://www.urmc.rochester.edu/encyclopedia/content?contenttypeid=167&contentid=acth_blood", "accessed": "2026-07-14"}, {"name": "UMass Memorial Health - ACTH (Blood)", "url": "https://www.ummhealth.org/health-library/acth-blood", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["cortisol", "dhea-s"]',NULL,'Exogenous corticosteroid use (oral, inhaled, or topical) suppresses endogenous ACTH and invalidates interpretation unless this is specifically accounted for. Physical or emotional stress at the time of the draw can appropriately raise ACTH. Improper sample handling (delayed processing, not kept on ice) causes rapid ex-vivo degradation and falsely low results, given the hormone''s very short half-life.','Was my cortisol measured at the same time, and how do the two results fit together? Does this pattern point to a pituitary, hypothalamic, or adrenal cause? Do I need additional dynamic testing (e.g., cosyntropin stimulation test, dexamethasone suppression test) to clarify the diagnosis? Could any medications (including inhaled or topical steroids) be affecting this result?','Depending on the ACTH/cortisol pattern, your clinician may order a cosyntropin (synthetic ACTH) stimulation test to confirm adrenal insufficiency, pituitary imaging if a central (secondary/tertiary) cause is suspected, or a dexamethasone suppression test and/or adrenal imaging if Cushing syndrome is being investigated. Results are never used to start or stop steroid treatment without this fuller diagnostic workup.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (118,'factor-viii-activity','Coagulation Factor VIII Activity Assay','','Factor VIII, F8, FVIII Activity','Hematology / Coagulation','Diagnoses and classifies severity of hemophilia A (factor VIII deficiency), and helps distinguish von Willebrand disease from hemophilia A (since vWF stabilizes factor VIII, vWD can also cause low factor VIII levels).',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Avoid warfarin for 2 weeks and heparin for 2 days before testing when possible; do not draw from a line containing heparin. Sample should reach the lab promptly per the coagulation lab''s protocol.',NULL,'One-stage clot-based assay (most common) or chromogenic assay on automated coagulation analyzers.',NULL,'[{"parameter": "Factor VIII activity", "population": "Adult", "range": "~50-150%", "notes": "Reference range varies by lab/method; results are reported relative to a pooled normal plasma standard"}]',1,'Low factor VIII activity (<40%) with a personal/family history of bleeding supports hemophilia A; severity is classified as severe (<1%), moderate (1-5%), or mild (5-40%), which correlates with bleeding frequency and severity. Because von Willebrand factor carries and stabilizes factor VIII in circulation, von Willebrand disease can also present with reduced factor VIII -- vWF antigen and activity testing are needed to distinguish the two conditions, since their treatment differs. Factor VIII is also an acute-phase reactant and rises with inflammation, stress, and pregnancy, which can transiently normalize a mild deficiency.',NULL,'[{"condition": "Hemophilia A (factor VIII deficiency)", "direction": "low, isolated (normal vWF)"}, {"condition": "Von Willebrand disease (factor VIII secondarily reduced)", "direction": "low, with concurrently low/abnormal vWF"}]','[{"name": "Mayo Clinic Laboratories - von Willebrand Factor Antigen, Plasma, referencing Factor VIII coagulant activity assay as a companion test", "url": "https://hematology.testcatalog.org/show/VWAG", "accessed": "2026-07-14"}]',1,'2026-07-15 05:45:19','2026-07-15 05:45:19','["aptt", "pt-inr", "von-willebrand-factor"]',NULL,NULL,'Does this confirm hemophilia A, or could this be related to von Willebrand disease instead? How severe is my condition based on this level? What precautions should I take for procedures or activities?','A low result prompts von Willebrand factor testing to distinguish hemophilia A from von Willebrand disease (since the two can look similar), and the specific level obtained determines severity classification and guides precautions for surgery, dental work, and physical activity.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (119,'ebv-antibody-panel','Epstein-Barr Virus (EBV) Antibody Panel','','EBV Panel, VCA IgM, VCA IgG, EBNA, Mono Test, Infectious Mononucleosis Serology','Immunoassay / Infectious Disease Serology','Diagnoses infectious mononucleosis and distinguishes acute/recent from past EBV infection, particularly when the rapid heterophile (''Monospot'') test is negative -- common in young children and in roughly 10% of adults with true acute EBV infection.',NULL,'Venous serum or plasma','No fasting required. If drawn very early in illness, antibodies may not yet be detectable; a repeat sample 1-2 weeks later may be needed if clinical suspicion remains high with an initial negative/indeterminate result.',NULL,'Enzyme immunoassay or chemiluminescent immunoassay measuring three components together: viral capsid antigen (VCA) IgM, VCA IgG, and EBV nuclear antigen (EBNA) IgG.',NULL,'[{"parameter": "VCA IgM, VCA IgG, EBNA IgG", "population": "Result categories", "range": "Each reported as Negative or Positive (index-value based); interpretation depends on the combined pattern of all three, not any single result alone"}]',1,'The presence of VCA IgM together with VCA IgG but without EBNA IgG indicates acute/recent primary EBV infection (EBNA typically takes 6-12 weeks to appear after primary infection). The presence of VCA IgG and EBNA IgG without VCA IgM indicates past infection with lifelong immunity -- since over 90% of adults have been infected with EBV at some point, this past-infection pattern is very common and not itself clinically significant. Absence of all three markers indicates no prior EBV exposure (EBV-naive). Some profiles are atypical or difficult to interpret (e.g., isolated VCA IgG, or all three markers positive simultaneously, which can reflect either recent infection with an early EBNA response or reactivation) and may require additional testing or clinical correlation.',NULL,'[{"condition": "Acute/primary infectious mononucleosis", "direction": "VCA IgM positive, EBNA IgG negative"}, {"condition": "Past EBV infection (lifelong immunity)", "direction": "VCA IgG and EBNA IgG positive, VCA IgM negative"}, {"condition": "No prior EBV exposure", "direction": "all three markers negative"}]','[{"name": "CDC - Laboratory Testing for Epstein-Barr Virus (EBV)", "url": "https://www.cdc.gov/epstein-barr/php/laboratories/index.html", "accessed": "2026-07-14"}, {"name": "Mayo Clinic Laboratories - Epstein-Barr Virus Antibody Profile, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/621373", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]',NULL,NULL,'Does this confirm I currently have mononucleosis, or is this from a past infection? How long am I likely to be contagious or symptomatic? Do I need any activity restrictions (like avoiding contact sports)?','A pattern consistent with acute infection is usually managed with supportive care (rest, fluids) and, if you have an enlarged spleen, temporary avoidance of contact sports or heavy lifting until it''s resolved, given the small risk of splenic rupture.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (120,'hla-b27','HLA-B27 Testing','','HLA-B27, Human Leukocyte Antigen B27','Immunoassay / Inflammation Markers','Supports the diagnosis of ankylosing spondylitis, reactive arthritis, and related spondyloarthropathies in patients with compatible clinical/radiographic findings (inflammatory back pain, sacroiliitis, recurrent acute anterior uveitis).',NULL,'Venous whole blood, EDTA tube (lavender top)','No fasting required. Specimen should reach the testing lab within the stated stability window (commonly 96 hours) since the test requires viable cells for flow cytometry-based methods, or DNA for genotyping-based methods.',NULL,'Flow cytometry (detecting the HLA-B27 antigen on lymphocytes) or PCR-based genotyping (detecting the HLA-B*27 allele); genotyping is generally more specific and can further subtype the allele.',NULL,'[{"parameter": "HLA-B27", "population": "Result categories", "range": "Positive (P) or Negative (N) -- a qualitative genetic marker, not a numeric value"}]',1,'HLA-B27 is present in roughly 80-90% of patients with ankylosing spondylitis compared to only about 5-10% of the general population, making it a strong supportive marker when combined with compatible clinical and imaging findings -- but it is not diagnostic on its own, since roughly 10% of the general healthy population carries the allele without ever developing disease, and this test should not be used as a standalone screening tool. It is less strongly associated with reactive arthritis, psoriatic arthritis, and inflammatory bowel disease-associated arthritis, where a substantial proportion of affected patients test negative. A negative result does not rule out these conditions when clinical suspicion is high.',NULL,'[{"condition": "Ankylosing spondylitis", "direction": "positive in ~80-90% of patients"}, {"condition": "Reactive arthritis / acute anterior uveitis", "direction": "positive, with lower sensitivity than for AS"}, {"condition": "Psoriatic arthritis / IBD-associated arthritis", "direction": "positive in a minority of patients"}]','[{"name": "StatPearls / NCBI Bookshelf - HLA-B27 Syndromes", "url": "https://www.ncbi.nlm.nih.gov/books/NBK551523/", "accessed": "2026-07-14"}, {"name": "ARUP Consult - Ankylosing Spondylitis (HLA-B27) Genotyping", "url": "https://arupconsult.com/ati/ankylosing-spondylitis-hla-b27-genotyping", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]',NULL,NULL,'Given my symptoms, does this result support a specific diagnosis? Does a positive result mean I will definitely develop this condition? Do I need further imaging or rheumatology referral?','A positive result in someone with compatible symptoms (like inflammatory back pain) supports referral to rheumatology for further evaluation, including imaging; a positive result alone in someone without symptoms is not itself actionable, since many people with this marker never develop disease.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (121,'nse','Neuron-Specific Enolase (NSE), Serum','','NSE','Immunoassay / Tumor Markers','Tumor marker for neuroendocrine tumors, most notably small cell lung cancer (SCLC), used to support diagnosis, monitor treatment response, and detect relapse; also used as a prognostic marker after cardiac arrest/hypoxic brain injury and in neuroblastoma.',NULL,'Venous serum (avoid hemolysis)','Sample must be processed to separate serum promptly and avoid hemolysis, since red blood cells and platelets contain enolase and hemolysis causes marked false elevation -- this is the single most important preanalytical consideration for this test.',NULL,'Chemiluminescent or enzyme immunoassay on automated immunoassay analyzers; results can vary significantly between different assay platforms, so serial monitoring should use the same assay.',NULL,'[{"parameter": "NSE", "population": "Healthy adult", "range": "Approximately <13-16 ng/mL", "notes": "Cutoffs vary meaningfully by assay/laboratory and study; always use the reporting lab''s own reference range"}]',1,'Elevated NSE at diagnosis is seen in up to 70% of small cell lung cancer patients, with higher levels generally correlating with more extensive disease stage and worse prognosis; serial NSE tracks treatment response and can signal relapse before it is clinically apparent. Other neuroendocrine tumors (carcinoid, neuroblastoma, pheochromocytoma, medullary thyroid carcinoma) can also elevate NSE. In post-cardiac-arrest care, markedly elevated NSE at 48-72 hours is one of several markers used (alongside clinical exam, EEG, and imaging) to help predict poor neurological outcome, though it should never be used as the sole basis for that prediction. Hemolysis, seizures, brain injury/stroke, and proton pump inhibitor use can all cause false elevation unrelated to tumor burden.',NULL,'[{"condition": "Small cell lung cancer (diagnosis, staging, monitoring)", "direction": "high, correlates with disease extent"}, {"condition": "Other neuroendocrine tumors (carcinoid, neuroblastoma, pheochromocytoma)", "direction": "high"}, {"condition": "Poor neurological outcome after cardiac arrest (prognostic marker)", "direction": "markedly high at 48-72h post-arrest"}]','[{"name": "Mayo Clinic Laboratories - Neuron-Specific Enolase, Serum (test catalog)", "url": "https://oncology.testcatalog.org/show/NSE", "accessed": "2026-07-14"}, {"name": "British Journal of Cancer (PMC) - Neurone specific enolase (NSE) in small cell lung cancer: a tumour marker of prognostic significance", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC1971357/", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]',NULL,'Hemolysis is the most common and significant cause of falsely elevated results, since red cells and platelets are rich in enolase -- any hemolyzed sample should be recollected before an elevated NSE is acted upon. Proton pump inhibitor use, hemolytic anemia, liver failure, and kidney failure can also cause artifactual elevation; when used for neurological prognostication, recent seizure, brain injury, stroke, or encephalitis can independently raise NSE unrelated to tumor status.','Was my sample checked for hemolysis, since that''s a common cause of a falsely high result? How does this level fit with my staging/imaging findings? If being followed serially, is the same laboratory/assay being used each time for a valid comparison? If used for prognosis after a brain injury, how is this being combined with other predictors rather than used alone?','An elevated result in the context of a known or suspected neuroendocrine tumor typically prompts imaging correlation and, if not already done, tissue diagnosis; serial levels help track treatment response. In neurologic prognostication after cardiac arrest, results are interpreted together with clinical examination, EEG, and imaging findings by the treating team, following recommended timing (commonly 48-72 hours post-arrest) rather than acted on in isolation.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (122,'varicella-zoster-igg-igm','Varicella-Zoster Virus (VZV) IgG/IgM','','VZV Serology, Chickenpox Immunity Test, Varicella Antibody','Immunoassay / Infectious Disease Serology','Determines immune status to varicella-zoster virus (chickenpox/shingles), used for prenatal screening, pre-employment screening in healthcare workers, and to help diagnose acute VZV infection or reactivation (e.g., in suspected Ramsay Hunt syndrome or disseminated zoster).',NULL,'Venous serum or plasma','No fasting required. IgM testing should be reserved for patients with a clinically compatible presentation, since interpretation outside that context is limited. IgG may reflect blood product transfusion in the preceding months rather than true immunity/infection, which should be considered in the history.',NULL,'Enzyme immunoassay or chemiluminescent immunoassay, reported as an index/antibody value with a categorical interpretation (negative/equivocal/positive).',NULL,'[{"parameter": "VZV IgG and IgM", "population": "Result categories", "range": "Negative, Equivocal, or Positive -- reported via an index value against an assay-specific cutoff, not a single universal number"}]',1,'A positive IgG with negative IgM indicates prior infection or vaccination and protective immunity against reinfection. A positive IgG together with a positive IgM suggests recent/acute infection or reactivation, though this pattern should be interpreted alongside the clinical presentation rather than in isolation. A negative IgG and IgM indicates no prior exposure and susceptibility to infection, but does not rule out very early infection before antibodies have developed -- repeat testing 2-3 weeks later is recommended if early infection is still suspected clinically.',NULL,'[{"condition": "Immunity from past infection or vaccination", "direction": "positive IgG, negative IgM"}, {"condition": "Acute varicella infection or zoster reactivation", "direction": "positive IgG and IgM (interpret with clinical context)"}, {"condition": "Susceptibility to primary infection", "direction": "negative IgG and IgM"}]','[{"name": "Mayo Clinic Laboratories - Varicella-Zoster Antibody, IgM and IgG, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/61856", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]',NULL,NULL,'Am I immune, or susceptible to infection? If I''m pregnant and non-immune, what precautions should I take if exposed? Do I need vaccination, and when would that be safe?','A non-immune result generally leads to vaccination recommendations (timed appropriately if you''re pregnant, since it''s a live vaccine); if there''s been a recent exposure and you''re non-immune, your clinician may discuss post-exposure options depending on your risk factors.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (123,'ionized-calcium','Ionized Calcium, Serum','','iCa, Free Calcium, Ionized Calcium','Clinical Chemistry','Measures the physiologically active (unbound) fraction of calcium directly, avoiding the confounding effect of albumin that affects total calcium interpretation; used in critically ill patients, during large-volume transfusion (citrate can bind calcium), and when total calcium and albumin don''t provide a clear picture.',NULL,'Venous or arterial whole blood, collected anaerobically (without air exposure) in a heparinized syringe or tube','Must be collected and analyzed anaerobically, since exposure to air causes CO2 loss, raising pH and artifactually lowering ionized calcium -- this is the most important preanalytical factor. Results are typically corrected/reported at a standardized pH (7.40) to remove this variability. Point-of-care blood gas analyzers are commonly used given the need for rapid, careful handling.',NULL,'Ion-selective electrode (ISE) method, typically on a point-of-care blood gas/electrolyte analyzer.',NULL,'[{"parameter": "Ionized calcium", "population": "Adult", "range": "~4.60-5.40 mg/dL (1.15-1.35 mmol/L)", "notes": "Reference range varies modestly by lab/analyzer"}]',1,'Ionized calcium is considered the more physiologically accurate measure of calcium status compared to total calcium, since it directly reflects the biologically active fraction without needing correction for albumin. Low ionized calcium (true hypocalcemia) can cause neuromuscular irritability, tetany, and cardiac arrhythmias, and is common in critically ill patients (sepsis, pancreatitis, massive transfusion with citrate-containing blood products, and after parathyroid/thyroid surgery). High ionized calcium (true hypercalcemia) reflects the same underlying causes as elevated total calcium (hyperparathyroidism, malignancy) but confirms that the elevation is truly in the active fraction rather than an artifact of high albumin/protein binding. In-hospital ionized calcium derangements (both high and low) have been associated with increased mortality risk in observational studies.',NULL,'[{"condition": "Critical illness-associated hypocalcemia (sepsis, pancreatitis, massive transfusion)", "direction": "low"}, {"condition": "Primary hyperparathyroidism / malignancy-associated hypercalcemia", "direction": "high"}, {"condition": "Post-thyroidectomy/parathyroidectomy hypocalcemia", "direction": "low"}]','[{"name": "PMC - Hospital-Acquired Serum Ionized Calcium Derangements and Their Associations with In-Hospital Mortality", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7699179/", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]','In-hospital ionized calcium levels outside the 4.60-5.40 mg/dL range are associated with increased mortality risk in critically ill patients per observational data; markedly abnormal values in a critically ill patient warrant urgent clinical correlation and, for severe hypocalcemia, prompt correction.','Exposure of the sample to air causes CO2 loss and a rise in pH, which artifactually lowers the measured ionized calcium -- anaerobic collection and prompt analysis are essential. Prolonged tourniquet time can also affect results by causing local pH shifts.','Does this change how my total calcium result should be interpreted? Is this related to my critical illness or a specific medication? How urgently does this need to be corrected?','Since this reflects the true active calcium level, results directly guide treatment decisions (calcium replacement for low levels, or investigation of the cause for high levels) more reliably than total calcium alone, especially in critically ill patients.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (124,'hepatitis-a-igm','Hepatitis A Virus IgM Antibody','','Anti-HAV IgM, HAV IgM, Hepatitis A Acute Antibody','Immunoassay / Infectious Disease Serology','Diagnoses acute or recent hepatitis A virus (HAV) infection in a symptomatic patient; the standard test for confirming acute hepatitis A, as distinct from total anti-HAV (IgG+IgM), which only indicates immunity and cannot confirm active infection.',NULL,'Venous serum or plasma','No fasting required. Should only be ordered in patients with a clinically compatible presentation (jaundice, elevated liver enzymes, GI symptoms with recent relevant exposure), since testing asymptomatic/low-risk individuals increases the chance of a false-positive result relative to true disease prevalence.',NULL,'Chemiluminescent immunoassay (CIA) or enzyme immunoassay (EIA) detecting HAV-specific IgM antibody.',NULL,'[{"parameter": "Anti-HAV IgM", "population": "Result categories", "range": "Negative or Positive (reactive) -- reported by signal-to-cutoff ratio, not a numeric concentration; equivocal results may occur early in acute infection"}]',1,'A positive (reactive) result indicates acute or recent (generally within the past 6 months) hepatitis A infection -- IgM becomes detectable about 4 weeks after infection, persists at elevated levels for roughly 2 months, then declines to undetectable by about 6 months (rarely persisting beyond 12 months). A negative result in a patient tested very early in illness may reflect an inadequate or delayed IgM response rather than true absence of infection, and retesting in 2-4 weeks (alongside total anti-HAV) is recommended if suspicion remains. Positive results are reportable to public health authorities in most jurisdictions given the outbreak potential of hepatitis A.',NULL,'[{"condition": "Acute hepatitis A infection", "direction": "positive/reactive"}, {"condition": "Recent infection (within past several months, waning)", "direction": "positive but declining, may need serial testing"}]','[{"name": "Mayo Clinic Laboratories - Hepatitis A Virus IgM Antibody, Serum (test catalog)", "url": "https://microbiology.testcatalog.org/show/HAIGM", "accessed": "2026-07-14"}, {"name": "CDC - Clinical Screening and Diagnosis for Hepatitis A", "url": "https://www.cdc.gov/hepatitis-a/hcp/diagnosis-testing/index.html", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]',NULL,NULL,'Does this confirm my symptoms are from hepatitis A? How long am I likely to be contagious to others? Do my close contacts need post-exposure treatment?','A positive result confirms acute infection, and public health notification is typically required; close contacts may be offered post-exposure vaccination or immune globulin depending on timing, and you''ll be advised on hygiene precautions to prevent spreading it to others.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (125,'ch50','Total Complement Activity (CH50)','','CH50, Complement Total, Total Hemolytic Complement','Immunoassay / Inflammation Markers','Functional screening test for the overall integrity of the classical complement pathway (C1 through C9); used to investigate suspected complement deficiency (recurrent infections, especially with encapsulated bacteria or Neisseria species) and to help monitor autoimmune conditions like SLE.',NULL,'Venous serum, requiring careful handling','Complement activity is very labile -- the specimen must clot properly, be separated promptly, and be frozen for transport, since delayed processing, prolonged storage at room temperature, or use of plasma instead of serum can all falsely lower results.',NULL,'Functional hemolytic assay measuring the dilution of serum required to lyse 50% of antibody-coated sheep red blood cells; assesses the combined function of the classical complement pathway components (C1-C9) rather than measuring any individual protein level.',NULL,'[{"parameter": "CH50", "population": "Adult", "range": "Approximately 30-75 U/mL (assay-dependent; some labs report 31-60 U/mL with an upper reporting limit of ''>60'')", "notes": "Reference range and units vary considerably by laboratory/method -- always use the reporting lab''s own range"}]',1,'A markedly low or absent CH50 suggests a deficiency in one or more of the classical pathway components (C1-C9) and warrants measurement of individual complement components (C3, C4, and others) to localize the defect -- hereditary complement deficiencies increase susceptibility to recurrent bacterial infections, particularly Neisseria (meningococcal/gonococcal), and are also associated with autoimmune disease (notably lupus-like syndromes with deficiencies of early classical pathway components). Low CH50 can also reflect acquired complement consumption from active autoimmune disease (e.g., active SLE) or severe infection/sepsis, where it has been associated with worse outcomes in some studies. A normal CH50 confirms the presence of all pathway components but does not exclude a partial reduction in an individual component (e.g., C3 or C4 reduced by 50-80%), since normal serum contains these in excess of what''s needed for a normal CH50 result -- individual complement levels are needed if a partial deficiency is specifically suspected.',NULL,'[{"condition": "Hereditary complement deficiency (recurrent Neisseria infections)", "direction": "very low/absent"}, {"condition": "Active systemic lupus erythematosus (complement consumption)", "direction": "low, alongside low C3/C4"}, {"condition": "Severe sepsis/DIC (complement consumption)", "direction": "low, associated with worse prognosis in some studies"}]','[{"name": "Labcorp - Complement, Total (CH50) test description", "url": "https://www.labcorp.com/tests/001941/complement-total-ch50", "accessed": "2026-07-14"}, {"name": "PMC - Reduced hemolytic complement activity in the classical pathway (CH50) is a risk factor for poor clinical outcomes of patients with infections", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC12176544/", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]',NULL,'Improper sample handling -- delayed serum separation, insufficient clotting time, prolonged room-temperature storage, or use of plasma instead of serum -- can all cause falsely low results due to in-vitro complement degradation, independent of the patient''s true in-vivo complement status.','If my CH50 is low, do I need testing of individual complement components (C3, C4) to identify which part of the pathway is affected? Could my recurrent infections be explained by a complement deficiency, and if so, are there vaccinations or precautions I should take? If I have an autoimmune condition, is my complement level being used to track disease activity?','A low CH50 typically leads to measurement of individual complement components (C3, C4, and sometimes others) to localize the deficiency, and may prompt referral to immunology, particularly if recurrent bacterial infections (especially Neisseria species) are part of the clinical picture -- vaccination against encapsulated organisms is often recommended in confirmed complement deficiency.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (126,'total-ige','Total IgE, Serum','','Total IgE, Immunoglobulin E','Immunoassay / Inflammation Markers','Screens for atopic (allergic) disease and helps evaluate suspected allergic bronchopulmonary aspergillosis and hyper-IgE syndrome; a modestly useful adjunct in allergy/asthma workup, though allergen-specific IgE testing is more directly informative for identifying specific triggers.',NULL,'Venous serum or plasma','No fasting required.',NULL,'Fluoroenzyme immunoassay or chemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "Total IgE", "population": "Adult", "range": "Approximately <100-120 kU/L (upper limit of normal)", "notes": "Reference ranges vary by lab/population and rise somewhat with age in childhood before stabilizing in adulthood; geometric mean in non-atopic adults is roughly 13-14 kU/L"}]',1,'Elevated total IgE supports (but does not confirm) atopic disease such as allergic rhinitis, asthma, and atopic dermatitis, and is also elevated in parasitic infections, allergic bronchopulmonary aspergillosis (often markedly elevated), and rare primary immunodeficiencies like hyper-IgE (Job) syndrome. The test has only moderate sensitivity and high specificity for atopy at commonly used cutoffs (roughly 100 kU/L), meaning a normal total IgE does not exclude allergic disease, and many non-allergic people can also have mildly elevated levels -- allergen-specific IgE testing or skin prick testing is generally more useful for identifying specific triggers once atopic disease is suspected.',NULL,'[{"condition": "Atopic disease (allergic rhinitis, asthma, atopic dermatitis)", "direction": "high (moderate sensitivity, high specificity)"}, {"condition": "Allergic bronchopulmonary aspergillosis", "direction": "markedly high"}, {"condition": "Parasitic infection", "direction": "high"}, {"condition": "Hyper-IgE (Job) syndrome (rare primary immunodeficiency)", "direction": "very high"}]','[{"name": "PMC - Reference values of serum total IgE in Uppsala \u2013 comparison over four decades", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC10710850/", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]',NULL,NULL,'Does this support an allergic condition as the cause of my symptoms? Do I need allergen-specific testing to identify triggers? Could a non-allergic cause (like a parasitic infection) explain this?','An elevated result supportive of atopic disease often leads to allergen-specific IgE testing or skin prick testing to identify your specific triggers, since total IgE alone doesn''t tell you what you''re reacting to.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (127,'copper','Copper, Serum','','Serum Copper, Cu','Clinical Chemistry','Evaluates suspected copper deficiency or excess; used alongside ceruloplasmin in the workup of Wilson disease (where free/non-ceruloplasmin-bound copper is elevated despite low total copper) and to investigate unexplained cytopenias, neuropathy, or malabsorption where copper deficiency is suspected.',NULL,'Venous serum, collected in a trace-element (copper-free) tube','Requires specialized trace-element collection tubes to avoid contamination, similar to zinc testing.',NULL,'Inductively coupled plasma mass spectrometry (ICP-MS) or atomic absorption spectrophotometry.',NULL,'[{"parameter": "Serum copper", "population": "Adult (\u226518 years)", "range": "77-206 mcg/dL", "notes": "Reference ranges vary meaningfully by lab/method (some cite 70-140 or 80-155 mcg/dL) -- always confirm against the reporting lab''s range"}]',1,'Low serum copper (with low ceruloplasmin, since most serum copper is ceruloplasmin-bound) suggests copper deficiency, which can cause anemia, neutropenia, and peripheral neuropathy -- causes include malabsorption (e.g., after bariatric surgery, celiac disease), excess zinc intake/supplementation (which blocks copper absorption), or rarely Menkes disease (a genetic copper transport disorder in infants). In Wilson disease, total serum copper is typically low (because ceruloplasmin, the major copper carrier, is reduced) despite copper accumulation in tissues -- the free/non-ceruloplasmin-bound copper fraction is actually elevated, which is why total copper alone can be misleading and is always interpreted alongside ceruloplasmin. High serum copper is seen in cholestatic liver disease (primary biliary cholangitis, primary sclerosing cholangitis), pregnancy, estrogen therapy, and as a nonspecific acute-phase reactant response.',NULL,'[{"condition": "Copper deficiency (malabsorption, excess zinc, Menkes disease)", "direction": "low, with low ceruloplasmin"}, {"condition": "Wilson disease", "direction": "low total copper despite tissue accumulation -- interpret with ceruloplasmin and free copper"}, {"condition": "Cholestatic liver disease (primary biliary cholangitis, PSC)", "direction": "high"}, {"condition": "Pregnancy / estrogen therapy (physiologic)", "direction": "high"}]','[{"name": "Mayo Clinic Laboratories - Copper, Serum (test catalog, via Billings Clinic)", "url": "https://billingscliniclaboratory.testcatalog.org/show/Billings-Clinic-8890-Mayo-CUS1", "accessed": "2026-07-14"}]',1,'2026-07-15 05:52:16','2026-07-15 05:52:16','[]',NULL,NULL,'Does this reflect true copper deficiency or excess, or could Wilson disease or another condition better explain this? Should this be interpreted alongside ceruloplasmin? Do I need supplementation or dietary changes?','Results are interpreted together with ceruloplasmin to distinguish true deficiency/excess from Wilson disease, and treatment (supplementation for deficiency, chelation for confirmed overload) depends on that combined picture.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (128,'procalcitonin','Procalcitonin (PCT), Serum','','PCT, Procalcitonin','Immunoassay / Inflammation Markers','Helps distinguish bacterial from non-bacterial causes of infection/inflammation and supports decisions about starting or stopping antibiotics, particularly in sepsis, lower respiratory tract infection, and febrile neutropenia.',NULL,'Venous serum or plasma','No fasting required. Often ordered serially (e.g., daily) to track trend during antibiotic treatment, since the trajectory is often more clinically useful than a single value.',NULL,'Chemiluminescent or immunofluorescent immunoassay on automated immunoassay analyzers or point-of-care platforms.',NULL,'[{"parameter": "Procalcitonin", "population": "Adult/child \u226572 hours old", "range": "\u22640.15 ng/mL", "notes": "Neonates <72 hours have markedly different, higher physiologic reference ranges"}]',1,'Procalcitonin rises specifically in response to bacterial infection (via bacterial endotoxin-driven cytokine release) more than in viral infection or non-infectious inflammation, making it useful for distinguishing bacterial sepsis from other causes of systemic inflammatory response and for guiding antibiotic initiation/discontinuation protocols. Higher levels generally correlate with greater severity and risk of progression to septic shock; a level that fails to fall (or rises) despite treatment suggests inadequate source control or ongoing/secondary infection. Levels also vary by the causative organism, tending to be higher with gram-negative than gram-positive or fungal infections in some studies, though this is not reliable enough to guide organism-specific therapy on its own.',NULL,'[{"condition": "Bacterial sepsis/septic shock", "direction": "high, correlates with severity"}, {"condition": "Viral infection / non-infectious inflammation", "direction": "typically low/normal, helping distinguish from bacterial cause"}, {"condition": "Response to antibiotic therapy (monitoring)", "direction": "declining trend indicates response; persistent/rising suggests treatment failure"}]','[{"name": "Medscape/eMedicine - Procalcitonin (PCT): Reference Range, Interpretation of Procalcitonin Levels", "url": "https://emedicine.medscape.com/article/2096589-overview", "accessed": "2026-07-15"}]',1,'2026-07-15 05:59:29','2026-07-15 05:59:29','[]',NULL,'Non-infectious causes of marked systemic inflammation (major trauma, surgery, burns, cardiogenic shock, severe pancreatitis) can also elevate procalcitonin independent of bacterial infection, so results must be interpreted alongside the full clinical picture rather than as a standalone rule-in/rule-out test.','Does this level support starting or continuing antibiotics, or could it support stopping them? How does today''s level compare to previous days, and what does that trend mean for my treatment plan? Could a non-infectious cause (recent surgery, trauma) be contributing to this result?','Procalcitonin results are typically used alongside clinical assessment, cultures, and other inflammatory markers (like CRP) to guide antibiotic decisions -- many hospitals use protocol-driven algorithms where a low or declining procalcitonin supports antibiotic discontinuation, while a rising or persistently high level prompts reassessment for ongoing infection or source control failure.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (129,'creatine-kinase-total','Creatine Kinase (CK), Total','','CK, CPK, Creatine Phosphokinase','Clinical Chemistry','Screens for and monitors muscle injury (skeletal or cardiac); used to diagnose and follow rhabdomyolysis, myositis/myopathy, and to distinguish myoglobinuria from hemoglobinuria; historically used for MI diagnosis before troponin became standard.',NULL,'Venous serum or plasma','Avoid strenuous exercise immediately before the draw and note any recent intramuscular injections, surgery, or muscle trauma, all of which can transiently raise results.',NULL,'Enzymatic kinetic assay on automated chemistry analyzers.',NULL,'[{"parameter": "CK, total", "population": "Adult male (Caucasian/Asian)", "range": "~227-440 U/L (upper limit varies by population)", "notes": "Black individuals have significantly higher normal upper limits (~520-810 U/L); values are non-Gaussian distributed and vary by lab/method"}, {"parameter": "CK, total", "population": "Adult female", "range": "~135-248 U/L (upper limit varies by population)", "notes": "Higher upper limits reported in Black women (~up to 354 U/L)"}]',1,'Markedly elevated CK (often 5-10x the upper limit or more) supports rhabdomyolysis, with the degree of elevation correlating with risk of acute kidney injury in observational data (risk of dialysis/renal failure increases progressively above roughly 1,000-5,000 U/L and higher). Milder elevations are common after strenuous exercise, intramuscular injections, surgery, or seizures, and are not necessarily pathologic. CK is also used with LD to distinguish myoglobinuria (CK markedly elevated, LD mildly elevated) from hemoglobinuria/hemolysis (CK normal, LD/LD1 elevated). Statin-associated myopathy is another common cause of mild-to-moderate elevation.',NULL,'[{"condition": "Rhabdomyolysis", "direction": "markedly high, often several-fold above upper limit"}, {"condition": "Statin-associated myopathy", "direction": "mild-moderate high"}, {"condition": "Inflammatory myopathy (polymyositis/dermatomyositis)", "direction": "high"}, {"condition": "Recent exercise, IM injection, or surgery (benign cause)", "direction": "mild-moderate high"}]','[{"name": "PMC - What Are the Normal Serum Creatine Kinase Values for Skeletal Muscle? A Worldwide Systematic Review", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC12163646/", "accessed": "2026-07-15"}, {"name": "PMC - Creatine Kinase Elevations and Risk of Renal Failure and Dialysis in Patients With Rhabdomyolysis", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC12282552/", "accessed": "2026-07-15"}]',1,'2026-07-15 05:59:29','2026-07-15 05:59:29','[]','CK levels ≥1,000 U/L are associated with progressively increasing risk of acute kidney injury and need for dialysis in rhabdomyolysis per observational cohort data; markedly elevated CK in a symptomatic patient (muscle pain, dark urine) warrants urgent evaluation for rhabdomyolysis and its renal complications.','Strenuous exercise, intramuscular injections, recent surgery involving muscle incision, and seizures can all transiently raise CK independent of significant underlying pathology -- timing and history around the draw are important for interpretation.','Is this level of elevation consistent with a benign cause (recent exercise, injection) or does it suggest rhabdomyolysis requiring urgent evaluation? Do I need kidney function monitoring given this result? If I''m on a statin, could this be medication-related, and does my statin need adjustment?','Markedly elevated CK, especially with symptoms (muscle pain, weakness, dark urine), typically prompts urgent evaluation of kidney function, aggressive IV fluid hydration to prevent kidney injury, and investigation of the underlying cause (exertional, traumatic, toxic/drug-induced, or inflammatory myopathy). Mild elevations without symptoms are often simply repeated or monitored.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (130,'ttg-iga','Tissue Transglutaminase IgA Antibody (tTG-IgA)','','tTG-IgA, Anti-tTG, Celiac Antibody Screen','Immunoassay / Inflammation Markers','First-line serologic screening test for celiac disease in patients with compatible symptoms (chronic diarrhea, malabsorption, unexplained iron deficiency) or at increased risk (first-degree relatives, type 1 diabetes, autoimmune thyroid disease).',NULL,'Venous serum or plasma','Must be tested while the patient is still consuming gluten -- starting a gluten-free diet before testing can cause a false-negative result. A total IgA level should be checked alongside, since IgA-deficient patients (about 2-3% of celiac patients) will have a falsely low/negative tTG-IgA and need tTG-IgG testing instead.',NULL,'Enzyme immunoassay (EIA) or chemiluminescent immunoassay (CLIA) detecting IgA antibodies against tissue transglutaminase.',NULL,'[{"parameter": "tTG-IgA", "population": "Negative", "range": "Assay-dependent cutoff, commonly <4 to <20 U/mL depending on the platform", "notes": "Different manufacturers/labs use different units and cutoffs -- always use the reporting lab''s own reference range"}]',1,'A tTG-IgA titer ≥10 times the assay''s upper limit of normal has a high positive predictive value (around 95% in adults) for celiac disease, and some pediatric guidelines allow a biopsy-free diagnosis when combined with a positive endomysial antibody on a separate sample and compatible symptoms. Lower-titer positive results are less specific and generally warrant duodenal biopsy for confirmation, since tTG-IgA can also be mildly elevated in other autoimmune or liver conditions. A negative result in a patient with normal total IgA makes celiac disease unlikely but does not completely exclude it, particularly in patients already reducing gluten intake or with very mild disease.',NULL,'[{"condition": "Celiac disease", "direction": "high, especially \u226510x upper limit of normal"}, {"condition": "IgA deficiency (false-negative tTG-IgA)", "direction": "falsely low despite possible celiac disease -- check total IgA"}]','[{"name": "Mayo Clinic Laboratories - Tissue Transglutaminase Antibodies, IgA and IgG Profile, Serum (test catalog)", "url": "https://neurology.testcatalog.org/show/TSTGP", "accessed": "2026-07-15"}]',1,'2026-07-15 05:59:29','2026-07-15 05:59:29','[]',NULL,NULL,'Given this result and my total IgA, is celiac disease likely? Do I need a biopsy to confirm? Should I continue eating gluten until further testing is done?','A significantly elevated result typically leads to referral for endoscopic biopsy to confirm the diagnosis before starting a gluten-free diet, since starting the diet early can make later testing less accurate -- it''s important not to eliminate gluten before all testing is complete.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (131,'fecal-calprotectin','Fecal Calprotectin','','Calprotectin, Stool Calprotectin','Clinical Chemistry / Point of Care','Non-invasive marker of intestinal mucosal inflammation, used to distinguish inflammatory bowel disease (Crohn''s disease, ulcerative colitis) from irritable bowel syndrome, and to monitor IBD disease activity and response to treatment without repeated colonoscopy.',NULL,'Stool sample, collected by the patient in a specimen container','A random stool sample is generally sufficient (no special preparation required); recent NSAID/aspirin use should be noted, as it can cause a false-positive elevation unrelated to IBD.',NULL,'Enzyme immunoassay (ELISA) or lateral-flow point-of-care immunoassay detecting the calprotectin protein, which is released by neutrophils during intestinal inflammation.',NULL,'[{"parameter": "Fecal calprotectin", "population": "Not suggestive of active inflammation", "range": "<50 \u00b5g/g"}, {"parameter": "Fecal calprotectin", "population": "Borderline/mild inflammation", "range": "50-120 \u00b5g/g", "notes": "May warrant retesting in 4-6 weeks"}, {"parameter": "Fecal calprotectin", "population": "Suggestive of active inflammation", "range": ">120 \u00b5g/g", "notes": "Cutoffs vary somewhat between labs (commonly cited thresholds range from 50-250 \u00b5g/g depending on clinical use)"}]',1,'A normal fecal calprotectin (<50 µg/g) has high sensitivity and negative predictive value for excluding IBD in adults and children, meaning colonoscopy can often be safely deferred in patients with IBS-like symptoms and a normal result. Elevated levels support active mucosal inflammation but are not specific to IBD -- infectious enteritis, colorectal cancer, celiac disease, and NSAID use can also raise it, so results must be interpreted alongside the clinical picture. In established IBD, serial calprotectin is used to monitor disease activity and treatment response, often targeting levels below roughly 250 µg/g as part of tight-control treatment strategies, since it correlates with mucosal healing better than symptoms alone.',NULL,'[{"condition": "Inflammatory bowel disease (Crohn''s disease, ulcerative colitis)", "direction": "high, correlates with mucosal inflammation"}, {"condition": "Irritable bowel syndrome (functional, non-inflammatory)", "direction": "normal/low in the vast majority of cases"}, {"condition": "Infectious enteritis / NSAID-induced enteropathy", "direction": "high, non-IBD cause"}]','[{"name": "American Family Physician (AAFP) - Fecal Calprotectin for the Evaluation of Inflammatory Bowel Disease", "url": "https://www.aafp.org/pubs/afp/issues/2021/0900/p303.html", "accessed": "2026-07-15"}, {"name": "Mayo Clinic Laboratories - Calprotectin, Feces (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/Overview/63016", "accessed": "2026-07-15"}]',1,'2026-07-15 05:59:29','2026-07-15 05:59:29','[]',NULL,'NSAID and aspirin use can cause mucosal inflammation independent of IBD, leading to false-positive elevation. Children under 4-5 years and adults over 65 have physiologically higher baseline levels, requiring age-adjusted interpretation.','Given my result, is colonoscopy still needed, or can it reasonably be deferred? If I have known IBD, does this level suggest my current treatment is controlling inflammation adequately? Could a medication I''m taking (like NSAIDs) be affecting this result? Should this be repeated, and if so, when?','A normal result in a patient with IBS-like symptoms generally supports a non-inflammatory diagnosis and colonoscopy can often be deferred with clinical monitoring. An elevated result typically prompts further workup (colonoscopy, stool studies for infection) to identify the cause. In established IBD, serial levels guide treatment adjustments as part of a tight-control monitoring strategy.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (132,'myoglobin','Myoglobin, Serum','','Myoglobin','Clinical Chemistry / Cardiac Biomarkers','Early, sensitive but non-specific marker of muscle injury, historically used as an early marker for myocardial infarction (rises faster than troponin) and now mainly used to diagnose and assess severity of rhabdomyolysis.',NULL,'Venous serum or plasma','No fasting required. Often ordered serially in the early hours after suspected muscle injury given its rapid rise and fall kinetics.',NULL,'Chemiluminescent or turbidimetric immunoassay on automated analyzers.',NULL,'[{"parameter": "Myoglobin", "population": "Adult male", "range": "0-72 ng/mL"}, {"parameter": "Myoglobin", "population": "Adult female", "range": "0-58 ng/mL"}]',1,'Myoglobin rises within 1-2 hours of muscle injury (faster than CK or troponin), making it useful as an early, sensitive marker, but it lacks specificity since it rises with any skeletal or cardiac muscle injury and is also elevated in renal failure due to reduced clearance. A level above roughly 150-170 ng/mL is often cited as supportive of rhabdomyolysis, with some sources using higher thresholds (around 600 ng/mL) as more specifically concerning, though CK trend and clinical context remain central to the diagnosis. Because of its low specificity, myoglobin has been largely superseded by troponin for cardiac diagnosis and is now used mainly in rhabdomyolysis assessment alongside CK.',NULL,'[{"condition": "Rhabdomyolysis", "direction": "high, often markedly, with elevated CK"}, {"condition": "Acute myocardial infarction (early marker, historical use)", "direction": "high, rises before troponin but less specific"}, {"condition": "Renal failure (reduced clearance)", "direction": "high, independent of new muscle injury"}]','[{"name": "MedlinePlus (NIH/NLM) - Myoglobin blood test", "url": "https://medlineplus.gov/ency/article/003663.htm", "accessed": "2026-07-15"}, {"name": "droracle.ai - Diagnostic serum myoglobin level for rhabdomyolysis (clinical synthesis)", "url": "https://www.droracle.ai/articles/301838/what-is-the-diagnostic-serum-myoglobin-myoglobin-level-for", "accessed": "2026-07-15"}]',1,'2026-07-15 05:59:29','2026-07-15 05:59:29','[]',NULL,NULL,'Does this support rhabdomyolysis as the cause of my symptoms? How does this compare with my CK level? Is my kidney function being monitored given this result?','An elevated result alongside elevated CK and compatible symptoms (muscle pain, dark urine) supports rhabdomyolysis, prompting aggressive IV hydration and monitoring of kidney function to prevent complications.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (133,'il-6','Interleukin-6 (IL-6), Serum','','IL-6, Interleukin-6','Immunoassay / Inflammation Markers','Pro-inflammatory cytokine marker used to assess severity and prognosis in sepsis/critical illness (including COVID-19), evaluate suspected cytokine release syndrome, and as a research/adjunct marker in some inflammatory and autoimmune conditions.',NULL,'Venous serum or plasma','No fasting required. Plasma is preferred over serum by some laboratories -- confirm the specimen type required by the specific assay.',NULL,'Enzyme-linked immunosorbent assay (ELISA) or chemiluminescent immunoassay.',NULL,'[{"parameter": "IL-6", "population": "Healthy adult", "range": "Approximately <12.5 to <17.4 pg/mL", "notes": "Reference values are derived from limited healthy populations and are not formal diagnostic thresholds; cutoffs vary meaningfully by assay platform"}]',1,'Elevated IL-6 is a marker of active systemic inflammation and has been studied as a prognostic marker in sepsis and critical illness, with higher and rising levels associated with greater disease severity and, in some studies (including COVID-19 cohorts), higher risk of mortality or need for escalated care. It is also used to help identify cytokine release syndrome (e.g., after CAR-T cell therapy or severe infection) and can guide use of IL-6 receptor-blocking therapies (e.g., tocilizumab) in specific clinical contexts. As a research-oriented and less standardized assay compared to CRP, results should be interpreted with awareness of assay-specific reference ranges and in the context of the broader clinical picture rather than as an isolated diagnostic threshold.',NULL,'[{"condition": "Severe sepsis / septic shock (prognostic marker)", "direction": "high, correlates with severity"}, {"condition": "Cytokine release syndrome", "direction": "markedly high"}, {"condition": "Severe COVID-19 / other severe systemic inflammatory states", "direction": "high, associated with worse outcomes in some studies"}]','[{"name": "MLabs (University of Michigan) - Interleukin 6 (IL-6), Serum (test catalog)", "url": "https://mlabs.umich.edu/tests/interleukin-6-il-6-serum", "accessed": "2026-07-15"}]',1,'2026-07-15 05:59:29','2026-07-15 05:59:29','[]',NULL,NULL,'Does this level help predict how sick I am or how I might respond to treatment? Is this being used to guide a specific medication decision? How does this compare to my other inflammatory markers?','In critical illness, this result is used alongside clinical assessment and other markers to help gauge severity and, in specific situations (like cytokine release syndrome), may guide use of targeted anti-inflammatory therapy.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (134,'anti-xa-assay','Anti-Xa (Heparin) Assay','','Anti-Factor Xa, Anti-Xa, Heparin Level, UFH Anti-Xa, LMWH Anti-Xa','Hematology / Coagulation','Monitors anticoagulation with unfractionated heparin (UFH) and low-molecular-weight heparin (LMWH), particularly when aPTT is unreliable (e.g., baseline prolonged aPTT, lupus anticoagulant, heparin resistance) or when monitoring LMWH, which does not reliably affect aPTT.',NULL,'Venous whole blood, sodium citrate tube (light blue top)','Timing relative to the dose is critical: for LMWH, blood is typically drawn 3-4 hours after subcutaneous injection (peak level) unless a trough level is specifically needed; for continuous UFH infusion, timing follows institutional protocol (commonly every 6 hours after a rate change). Avoid drawing from a line containing heparin.',NULL,'Chromogenic anti-Xa assay measuring the degree of inhibition of activated factor X by heparin-antithrombin complexes.',NULL,'[{"parameter": "Anti-Xa, unfractionated heparin (UFH) therapeutic range", "population": "Adult, for venous thromboembolism treatment", "range": "0.3-0.7 IU/mL", "notes": "Lower-intensity ranges (e.g., 0.10-0.32 IU/mL, aligned with aPTT 50-70 sec) are used for some indications"}, {"parameter": "Anti-Xa, LMWH therapeutic range", "population": "Adult", "range": "Assay/indication-dependent, commonly around 0.5-1.0 IU/mL for treatment dosing (peak level)", "notes": "Target ranges vary by specific LMWH product and indication"}]',1,'A result below the therapeutic range suggests under-anticoagulation and increased clotting/thrombosis risk, prompting a dose increase per institutional heparin nomogram. A result above the therapeutic range (a critical value is commonly set around >1.0 IU/mL) suggests over-anticoagulation and increased bleeding risk, prompting a dose reduction or hold. In renal impairment, LMWH clearance is reduced, so anti-Xa levels can rise unexpectedly even without a dose change, making monitoring especially important in that population.',NULL,'[{"condition": "Sub-therapeutic anticoagulation (thrombosis risk)", "direction": "below target range"}, {"condition": "Supra-therapeutic anticoagulation (bleeding risk)", "direction": "above target range, especially >1.0 IU/mL"}, {"condition": "LMWH accumulation in renal impairment", "direction": "unexpectedly high despite stable dosing"}]','[{"name": "Medscape/eMedicine - Anti-Xa Assay (Heparin Assay): Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2085000-overview", "accessed": "2026-07-15"}, {"name": "MLabs (University of Michigan) - UFH Anti-Xa (test catalog)", "url": "https://mlabs.umich.edu/tests/ufh-anti-xa", "accessed": "2026-07-15"}]',1,'2026-07-15 05:59:29','2026-07-15 05:59:29','[]','A UFH anti-Xa level >1.0 IU/mL is commonly used as a critical value indicating significant over-anticoagulation and bleeding risk, warranting prompt dose reduction/hold and clinical reassessment.','Sample contamination from a heparin-containing IV line falsely raises results. Delayed separation of plasma from cells, incorrect draw timing relative to the dose, and under-filled citrate tubes (wrong blood-to-anticoagulant ratio) can all affect accuracy.','Is my current heparin dose in the therapeutic range, and if not, how will it be adjusted? Given my kidney function, do I need more frequent monitoring if I''m on LMWH? If my aPTT and anti-Xa results don''t agree, which one is guiding my dose adjustments and why?','Results are used directly with an institutional heparin dosing nomogram to adjust the infusion rate or next LMWH dose; levels are typically rechecked after each dose adjustment (commonly every 6 hours for UFH) until therapeutic, then monitored periodically or with any change in renal function or bleeding/clotting symptoms.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (135,'semen-fructose','Semen Fructose (Qualitative/Quantitative)','','Seminal Fructose, Fructose Test (Semen)','Andrology','Assesses seminal vesicle function and helps establish the cause of azoospermia or very low-volume ejaculate -- fructose is produced by the seminal vesicles, so its presence or absence helps localize an obstruction or developmental absence within the male reproductive tract.',NULL,'Semen sample (same collection as a standard semen analysis)','Collected as part of, or as a reflex test from, a semen analysis, particularly when the initial analysis shows azoospermia or low ejaculate volume with low/absent pH.',NULL,'Qualitative colorimetric test (resorcinol-based color reaction) for a positive/negative result, or quantitative spectrophotometric measurement when a precise concentration is needed.',NULL,'[{"parameter": "Semen fructose", "population": "Normal", "range": "Positive (present); quantitatively often cited as >13 mmol/L in seminal plasma", "notes": "Qualitative testing (positive/negative) is most commonly used clinically; quantitative cutoffs vary by method/lab"}]',1,'Absent fructose in an azoospermic, low-volume, acidic (low pH) semen sample strongly suggests bilateral congenital absence of the vas deferens (CBAVD), ejaculatory duct obstruction, or seminal vesicle agenesis/hypoplasia -- since the seminal vesicles are the source of seminal fructose, and their secretions are absent when they are missing, obstructed, or not connected to the ejaculate. Normal (present) fructose with azoospermia and normal semen volume/pH instead points toward an obstruction distal to the seminal vesicles or a testicular/spermatogenesis problem (non-obstructive azoospermia) rather than an ejaculatory duct or seminal vesicle problem, helping direct further workup (e.g., transrectal ultrasound, testicular biopsy, or genetic testing for CFTR mutations in suspected CBAVD).',NULL,'[{"condition": "Congenital bilateral absence of the vas deferens (CBAVD)", "direction": "absent, with azoospermia, low volume, low pH"}, {"condition": "Ejaculatory duct obstruction / seminal vesicle agenesis", "direction": "absent"}, {"condition": "Non-obstructive azoospermia (testicular cause)", "direction": "present, with normal volume/pH despite azoospermia"}]','[{"name": "Mayo Clinic Laboratories - Fructose, Qualitative, Semen (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/92187", "accessed": "2026-07-15"}, {"name": "Male Infertility Guide - Azoospermia and Male Infertility (clinical reference)", "url": "https://www.maleinfertilityguide.com/azoospermia", "accessed": "2026-07-15"}]',1,'2026-07-15 13:08:19','2026-07-15 13:08:19','["semen-analysis", "total-testosterone"]',NULL,NULL,'Given the absence of fructose, does this point to an obstruction or a developmental absence of the seminal vesicles/vas deferens? Do I need genetic testing (e.g., for CFTR mutations) as part of this workup? What imaging or further tests are needed to pinpoint the exact location of the problem? Does this change my options for fertility treatment (e.g., surgical sperm retrieval)?','Absent fructose with azoospermia typically prompts further evaluation with transrectal ultrasound (to assess the seminal vesicles and ejaculatory ducts), CFTR genetic testing if CBAVD is suspected (since it''s strongly associated with cystic fibrosis gene mutations), and consultation with a reproductive urologist to discuss surgical sperm retrieval options for fertility treatment, since sperm production in the testes may still be normal even when transport is obstructed.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (136,'antisperm-antibodies','Antisperm Antibodies (ASA)','','ASA, Anti-Sperm Antibodies, MAR Test, Immunobead Test','Andrology','Investigates suspected immunologic male infertility, particularly when semen analysis shows sperm agglutination (clumping) or unexplained reduced motility, and in men with a history of testicular trauma, infection, surgery (including vasectomy reversal), or obstructive azoospermia where the blood-testis barrier may have been breached.',NULL,'Semen sample (direct testing, most clinically relevant) or venous serum (indirect testing, for circulating antibodies)','Direct testing on semen (mixed agglutination reaction/MAR test or immunobead test) evaluates antibodies actually bound to the sperm surface and is more clinically informative than indirect serum testing, which only detects circulating antibodies that may not reflect what''s happening at the sperm surface.',NULL,'Mixed agglutination reaction (MAR) test or direct immunobead binding test, both of which detect IgG or IgA antibodies bound directly to motile sperm.',NULL,'[{"parameter": "Antisperm antibodies (direct, % sperm bound)", "population": "Normal", "range": "Generally <10% of motile sperm with bound antibody considered a negative/non-significant result", "notes": "Cutoffs for clinical significance vary by lab and test method; some use a >50% threshold as clearly significant"}]',1,'A significant percentage of antibody-bound sperm can impair fertility by interfering with sperm motility, cervical mucus penetration, and sperm-egg binding/fusion, contributing to unexplained infertility even when standard semen parameters appear otherwise normal. Roughly 70% of men whose azoospermia is due to a physical obstruction test positive for antisperm antibodies on indirect (blood) testing (since obstruction allows sperm antigens to leak and trigger an immune response), whereas men with non-obstructive azoospermia (a primary production problem) are not expected to have these antibodies -- making indirect ASA testing occasionally useful to help distinguish obstructive from non-obstructive causes of azoospermia in specific clinical scenarios (normal FSH, normal testicular size, no clear cause for obstruction).',NULL,'[{"condition": "Immunologic male infertility", "direction": "high % antibody-bound sperm, with agglutination on semen analysis"}, {"condition": "Obstructive azoospermia (supportive indirect finding)", "direction": "positive indirect (serum) ASA in ~70% of cases"}, {"condition": "Post-vasectomy or vasectomy reversal infertility", "direction": "positive, from breach of the blood-testis barrier"}]','[{"name": "Male Infertility Guide - Antisperm Antibodies (clinical reference)", "url": "https://www.maleinfertilityguide.com/antisperm-antibodies", "accessed": "2026-07-15"}, {"name": "PMC - Prevalence and impact of antisperm antibodies on semen quality and male reproductive health aspects: A 10-years retrospective study", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3003948/", "accessed": "2026-07-15"}]',1,'2026-07-15 13:08:19','2026-07-15 13:08:19','["semen-analysis", "total-testosterone"]',NULL,NULL,'Given a positive result, how significant is the antibody level for my fertility, and does it explain my infertility findings? What treatment options are available (e.g., sperm washing with IUI, corticosteroids, IVF/ICSI) and which is recommended for my situation? If this followed a vasectomy reversal, does it affect the likelihood of natural conception versus needing assisted reproduction?','A clinically significant result often leads to a discussion of assisted reproductive techniques that can bypass the antibody effect, most reliably intracytoplasmic sperm injection (ICSI) as part of IVF, since it circumvents the natural barriers antibodies interfere with; sperm washing combined with intrauterine insemination (IUI) is sometimes tried first in less severe cases, and corticosteroid therapy is occasionally used though with variable evidence and known side effects.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (137,'igf-1','Insulin-Like Growth Factor 1 (IGF-1), Serum','','IGF-1, Somatomedin C','Immunoassay / Endocrinology','Primary screening and monitoring test for growth hormone (GH) status -- used to evaluate suspected adult or pediatric GH deficiency, support diagnosis of acromegaly/gigantism (GH excess), and monitor GH replacement therapy or treatment response in acromegaly.',NULL,'Venous serum or plasma','No fasting required. Recent resistance exercise or a high-protein meal can transiently raise levels; acute illness, stress, or prolonged fasting (>24 hours) can transiently lower levels -- ideally tested in a stable, non-acute state.',NULL,'Chemiluminescent immunoassay (CLIA) on automated immunoassay analyzers, standardized against international reference preparations; results are typically reported alongside an age- and sex-adjusted Z-score, since IGF-1 varies substantially across the lifespan (rising through childhood/puberty, peaking in young adulthood, then steadily declining with age).',NULL,'[{"parameter": "IGF-1", "population": "Adult", "range": "Age- and sex-specific reference ranges apply; a Z-score of -2.0 to +2.0 is generally considered normal", "notes": "IGF-1 declines steadily with age -- there is no single adult-wide numeric range; the reporting lab''s age/sex-matched reference interval and Z-score should be used"}]',1,'IGF-1 reflects average growth hormone secretion over time (unlike GH itself, which is secreted in pulses and is hard to interpret from a single random sample) and is considered the primary screening test for GH axis disorders. A level below the 2.5th percentile (Z-score below -2) for age is consistent with GH deficiency or severe GH resistance, though dynamic GH stimulation testing is often needed for definitive diagnosis, especially when IGF-1 is borderline. Elevated IGF-1 supports a diagnosis of acromegaly (in adults) or gigantism (in children with open growth plates) when combined with compatible clinical findings, and is also used to monitor treatment response in confirmed acromegaly, with a goal of normalizing IGF-1 into the age-adjusted reference range.',NULL,'[{"condition": "Adult or pediatric growth hormone deficiency", "direction": "low, Z-score below -2"}, {"condition": "Acromegaly / gigantism (GH excess)", "direction": "high, with compatible clinical findings"}, {"condition": "Chronic illness, malnutrition, or liver disease (non-GH-axis cause of low IGF-1)", "direction": "low, independent of true GH status"}]','[{"name": "Mayo Clinic Laboratories - Insulin-Like Growth Factor 1, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/Overview/623571", "accessed": "2026-07-15"}, {"name": "PMC - Reference ranges for serum insulin-like growth factor I (IGF-I) in healthy Chinese adults (peer-reviewed age-dependence study)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5627923/", "accessed": "2026-07-15"}]',1,'2026-07-15 13:08:19','2026-07-15 13:08:19','["total-testosterone", "prolactin", "acth"]',NULL,NULL,'Given my age and sex, is my result truly abnormal, or within the expected range for someone my age? Do I need dynamic GH stimulation testing to confirm a diagnosis before starting treatment? If I''m on GH replacement therapy, is my current dose achieving the target IGF-1 range? Could a non-hormonal cause (illness, nutrition, liver function) be affecting this result?','A low result consistent with possible GH deficiency typically leads to a GH stimulation test (such as insulin tolerance testing or GHRH-arginine testing) performed under endocrinology supervision to confirm the diagnosis before starting GH replacement therapy. An elevated result suggestive of acromegaly leads to pituitary imaging (MRI) and, often, an oral glucose tolerance test with GH suppression testing to confirm the diagnosis.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (138,'spep','Serum Protein Electrophoresis (SPEP)','','SPEP, Protein Electrophoresis, M-Spike','Clinical Chemistry','Screens for monoclonal gammopathies (multiple myeloma, MGUS, Waldenstrom macroglobulinemia, AL amyloidosis) and evaluates unexplained findings such as anemia, hypercalcemia, renal impairment, bone pain, or elevated total protein/globulin gap.',NULL,'Venous serum or plasma','No fasting required. If a monoclonal band (M-spike) is detected, reflex immunofixation electrophoresis (IFE) is typically performed to identify the specific immunoglobulin class and light chain type.',NULL,'Gel or capillary zone electrophoresis separates serum proteins by charge into fractions (albumin, alpha-1, alpha-2, beta, gamma), producing a densitometric tracing; a discrete narrow spike (M-spike), usually in the gamma or beta region, indicates a monoclonal protein.',NULL,'[{"parameter": "SPEP", "population": "Normal", "range": "No monoclonal (M) protein band detected; polyclonal gamma fraction pattern", "notes": "Individual fraction reference ranges (albumin, globulins) vary by lab"}]',1,'A monoclonal (M-spike) band indicates clonal proliferation of a single plasma cell or lymphocyte line producing identical immunoglobulin, seen across a spectrum from monoclonal gammopathy of undetermined significance (MGUS, the most common finding, often incidental and non-progressive) to smoldering or active multiple myeloma, Waldenstrom macroglobulinemia, and AL amyloidosis. SPEP is used per International Myeloma Working Group guidelines for baseline diagnosis and disease monitoring when the M-protein is measurable (≥1 g/dL); when not measurable, serum free light chain testing is used instead. SPEP alone cannot identify the specific immunoglobulin type -- immunofixation electrophoresis is required for that.',NULL,'[{"condition": "Monoclonal gammopathy of undetermined significance (MGUS)", "direction": "small M-spike, no other myeloma-defining features"}, {"condition": "Multiple myeloma", "direction": "M-spike, often with anemia, hypercalcemia, renal impairment, bone lesions"}, {"condition": "Waldenstrom macroglobulinemia / AL amyloidosis", "direction": "M-spike, with disease-specific features"}]','[{"name": "Inciteful Med - Myeloma Lab Results: M-Spike & Light Chains Guide", "url": "https://incitefulmed.com/resources/guides/multiple-myeloma-patient-guide/multiple-myeloma-lab-results/", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'If a band was found, do I need immunofixation to identify exactly what it is? Does this explain my symptoms (like bone pain, anemia, or kidney issues)? Do I need a hematology referral?','A detected monoclonal band leads to immunofixation electrophoresis to identify the specific protein type, along with free light chain testing and, depending on findings, hematology referral to determine whether this represents MGUS or a disease requiring treatment.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (139,'serum-free-light-chains','Serum Free Light Chains (Kappa/Lambda Ratio)','','sFLC, Free Kappa, Free Lambda, FLC Ratio','Clinical Chemistry / Tumor Markers','Ordered alongside SPEP in the workup of suspected monoclonal gammopathy; particularly valuable for oligosecretory or non-secretory myeloma, light chain-only myeloma, and AL amyloidosis, where SPEP alone may be falsely negative.',NULL,'Venous serum or plasma','No fasting required. Renal impairment can elevate both free light chains and shift the ratio, so results should be interpreted with kidney function in mind.',NULL,'Immunonephelometric or immunoturbidimetric assay using antisera specific to free (unbound) kappa and lambda light chains, distinct from the light chains bound within intact immunoglobulins.',NULL,'[{"parameter": "Free kappa light chain", "population": "Adult", "range": "~0.33-1.94 mg/dL"}, {"parameter": "Free lambda light chain", "population": "Adult", "range": "~0.57-2.63 mg/dL"}, {"parameter": "Kappa/lambda ratio", "population": "Adult, normal renal function", "range": "0.26-1.65", "notes": "Widened reference range (approximately 0.37-3.1) is used in patients with renal failure, since reduced clearance raises both light chains"}]',1,'An abnormal kappa/lambda ratio with one light chain elevated out of proportion to the other supports a monoclonal free light chain-producing process and, combined with SPEP/IFE, supports diagnosis of a plasma cell disorder. When both free light chains are elevated but the ratio stays normal or only mildly increased, this more often reflects polyclonal elevation from renal impairment or chronic inflammation rather than a monoclonal process. The involved light chain and the sFLC ratio are used by the International Myeloma Working Group for diagnosis, risk stratification, and response assessment (a normalized ratio is required to document a stringent complete response), and sFLC monitoring is the preferred method for light chain-only or non-secretory disease.',NULL,'[{"condition": "Light chain multiple myeloma / oligosecretory or non-secretory myeloma", "direction": "abnormal kappa/lambda ratio, disproportionate elevation of one light chain"}, {"condition": "AL amyloidosis", "direction": "abnormal ratio, often with a modestly elevated involved light chain"}, {"condition": "Renal impairment / chronic inflammation (polyclonal elevation)", "direction": "both light chains elevated, ratio normal or only mildly increased"}]','[{"name": "ARUP Consult - Kappa/Lambda Quantitative Free Light Chain With Ratio, Serum", "url": "https://arupconsult.com/ati/kappalambda-quantitative-free-light-chain-ratio-serum", "accessed": "2026-07-15"}, {"name": "myADLM - Serum Free Light Chains (Optimal Testing Guide)", "url": "https://myadlm.org/advocacy-and-outreach/optimal-testing-guide-to-lab-test-utilization/g-s/serum-free-light-chains", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'Does this abnormal ratio point toward a specific plasma cell disorder? Could my kidney function be affecting this result? Do I need this combined with SPEP and imaging for a full picture?','An abnormal ratio typically leads to further testing (SPEP, immunofixation, sometimes bone marrow biopsy and imaging) to determine the specific diagnosis and whether treatment is needed, guided by hematology.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (140,'metanephrines-plasma-free','Metanephrines, Fractionated, Plasma Free','','Plasma Free Metanephrines, Metanephrine, Normetanephrine','Immunoassay / Endocrinology','First-line screening test for pheochromocytoma and paraganglioma (catecholamine-secreting tumors), used in patients with suggestive symptoms (episodic headache, palpitations, sweating, hypertension) or an incidentally found adrenal mass.',NULL,'Venous plasma, drawn after the patient has been supine/resting for at least 20-30 minutes','Blood should be drawn from a seated or, preferably, supine patient after a period of rest, since upright posture and stress/anxiety during the draw can cause false-positive elevations; many interfering medications (tricyclic antidepressants, some psychiatric drugs) should be discussed with the ordering clinician beforehand when possible.',NULL,'Liquid chromatography-tandem mass spectrometry (LC-MS/MS), the preferred modern method for specificity, or immunoassay/HPLC with electrochemical detection.',NULL,'[{"parameter": "Normetanephrine and metanephrine", "population": "Adult, supine sample", "range": "Age-adjusted upper cutoffs (normetanephrine cutoff rises from ~0.47 nmol/L in children to ~1.05 nmol/L in adults over 60)", "notes": "Reference intervals are method- and age-specific; always use the reporting lab''s own cutoffs"}]',1,'Normal plasma free metanephrines (in a properly collected supine sample) have very high negative predictive value, essentially ruling out a catecholamine-secreting tumor. An elevation three-fold or more above the upper cutoff is rarely a false positive and should prompt imaging to localize the tumor; borderline elevations (less than three-fold) are more often false positives from stress, posture, or medication interference, and are typically followed up with a repeat supine sample, 24-hour urinary fractionated metanephrines, or a clonidine suppression test before proceeding to imaging.',NULL,'[{"condition": "Pheochromocytoma / paraganglioma", "direction": "high, especially \u22653x upper cutoff"}, {"condition": "False-positive elevation from posture, stress, or interfering medications", "direction": "mildly high, typically <3x upper cutoff"}]','[{"name": "Labcorp - Metanephrines, Fractionated, Plasma Free (test description)", "url": "https://www.labcorp.com/tests/121806/metanephrines-fractionated-plasma-free", "accessed": "2026-07-15"}, {"name": "PMC - Reference intervals for plasma free metanephrines with an age adjustment for normetanephrine", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC4714582/", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'Was my sample drawn in the correct (supine/resting) position, since that affects accuracy? If borderline, do I need repeat testing or a confirmatory test before imaging? Are any of my current medications known to interfere with this test?','A markedly elevated result (typically ≥3x the upper cutoff) prompts imaging (CT or MRI of the adrenal glands/abdomen, sometimes functional imaging) to localize the tumor. A borderline result is usually repeated under optimal (supine, rested) conditions, or confirmed with 24-hour urinary fractionated metanephrines or a clonidine suppression test, before imaging is pursued.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (141,'chromogranin-a','Chromogranin A, Plasma/Serum','','CgA, Chromogranin A','Immunoassay / Tumor Markers','General marker for neuroendocrine tumors, used as a complementary test to plasma metanephrines in pheochromocytoma/paraganglioma workup, and as a marker for carcinoid tumors, gastroenteropancreatic neuroendocrine tumors, and to monitor treatment response.',NULL,'Venous plasma or serum, per assay requirements','Proton pump inhibitors (PPIs) can significantly raise chromogranin A independent of tumor activity by causing reactive hypergastrinemia -- ideally stopped for 1-2 weeks before testing when feasible, per assay-specific guidance.',NULL,'Immunoradiometric assay (IRMA) or enzyme-linked immunoassay.',NULL,'[{"parameter": "Chromogranin A", "population": "Normal (assay-dependent)", "range": "Commonly cited cutoff around 150 \u00b5g/L in one validated assay", "notes": "Reference ranges vary substantially between assay platforms -- always use the reporting lab''s own cutoff"}]',1,'Elevated chromogranin A supports the presence of a neuroendocrine tumor (pheochromocytoma, paraganglioma, carcinoid, gastroenteropancreatic neuroendocrine tumors, some pituitary tumors), with sensitivity around 82-90% depending on tumor type in published series, and can be the only abnormal circulating marker in a minority of cases where metanephrines/catecholamines are normal. It has lower specificity than plasma metanephrines for pheochromocytoma specifically, since PPI use, atrophic gastritis, renal impairment, and other conditions with increased adrenergic activity can also raise it -- making it most useful as a complementary follow-up test rather than a first-line screen for catecholamine-secreting tumors.',NULL,'[{"condition": "Neuroendocrine tumors (pheochromocytoma, paraganglioma, carcinoid, GEP-NETs)", "direction": "high"}, {"condition": "PPI use / atrophic gastritis / renal impairment (non-tumor cause of elevation)", "direction": "high, non-specific"}]','[{"name": "PMC - Chromogranin A in the Laboratory Diagnosis of Pheochromocytoma and Paraganglioma", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6521298/", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'Could a medication I''m taking (like a PPI) be raising this result rather than a tumor? Does this need to be combined with other tests (like metanephrines) for a clearer picture? Do I need imaging?','Given how many non-tumor causes can raise this result, your clinician will consider stopping interfering medications if possible before repeat testing, and an elevated result typically prompts imaging to look for a neuroendocrine tumor.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (142,'gastrin','Fasting Serum Gastrin','','Gastrin, Fasting Gastrin','Immunoassay / Tumor Markers','Primary screening test for Zollinger-Ellison syndrome (gastrinoma), evaluated in patients with refractory or recurrent peptic ulcer disease, unexplained chronic diarrhea, or multiple endocrine neoplasia type 1 (MEN1).',NULL,'Venous serum, fasting (at least 8-12 hours)','Proton pump inhibitors and H2 blockers must be stopped before testing (commonly 6 days for PPIs, 1 day for H2 blockers, per institutional protocol) since they cause reactive hypergastrinemia that can mimic or mask true gastrinoma; the sample should be drawn fasting and processed/frozen promptly.',NULL,'Chemiluminescent or radioimmunoassay.',NULL,'[{"parameter": "Fasting serum gastrin", "population": "Normal", "range": "Approximately 15-100 pg/mL (commonly cited upper limit up to 150 pg/mL)", "notes": "Reference range varies by lab/assay"}]',1,'A fasting gastrin above 10 times the upper limit of normal (roughly >1,000 pg/mL) in a patient with gastric acid hypersecretion is considered virtually diagnostic of Zollinger-Ellison syndrome without further testing. However, two-thirds of confirmed gastrinoma patients have levels less than 10-fold the upper limit, which overlaps considerably with more common causes of hypergastrinemia -- most importantly proton pump inhibitor use, but also H. pylori infection, atrophic gastritis, pernicious anemia, renal failure, and prior gastric surgery -- so a secretin stimulation test is often needed to confirm the diagnosis when gastrin is only modestly elevated.',NULL,'[{"condition": "Zollinger-Ellison syndrome (gastrinoma)", "direction": "high, especially >1,000 pg/mL with acid hypersecretion"}, {"condition": "Proton pump inhibitor use / H. pylori infection / atrophic gastritis (non-tumor causes)", "direction": "mild-moderate high, overlapping with mild gastrinoma elevations"}]','[{"name": "Medscape/eMedicine - Gastrinoma Workup: Laboratory Studies", "url": "https://emedicine.medscape.com/article/184332-workup", "accessed": "2026-07-15"}, {"name": "Labcorp - Gastrin (test description)", "url": "https://www.labcorp.com/tests/004390/gastrin", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'Was I properly off acid-reducing medications before this test? Does this level need a stimulation test to confirm a diagnosis? What symptoms should I watch for?','A markedly elevated result with acid hypersecretion strongly supports Zollinger-Ellison syndrome; a more modestly elevated result often leads to a secretin stimulation test to confirm the diagnosis before treatment decisions are made.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (143,'5-hiaa','5-Hydroxyindoleacetic Acid (5-HIAA)','','5-HIAA, Urine 5-HIAA, Serotonin Metabolite','Clinical Chemistry / Tumor Markers','Confirms carcinoid syndrome in patients with a neuroendocrine tumor and compatible symptoms (flushing, diarrhea, wheezing), and can be used to monitor disease activity and treatment response.',NULL,'24-hour urine collection (traditional standard) or venous serum (newer alternative)','For urine testing, dietary restriction of serotonin-rich foods (bananas, tomatoes, avocados, walnuts, pineapple) and certain medications for 2-3 days before and during collection is traditionally recommended to avoid false elevation, though this requirement is being reconsidered with modern mass spectrometry methods; serum 5-HIAA avoids the need for a 24-hour collection and dietary restriction.',NULL,'High-performance liquid chromatography (HPLC) or liquid chromatography-tandem mass spectrometry (LC-MS/MS).',NULL,'[{"parameter": "Serum 5-HIAA", "population": "Optimal cutoff (peer-reviewed study)", "range": "139.4 nmol/L (sensitivity 96.3%, specificity 87.6% for carcinoid syndrome in SSA-naive patients)", "notes": "24-hour urine 5-HIAA reference ranges and units differ by lab; serum and urine results correlate well (r=0.892) but are not directly interchangeable"}]',1,'Elevated 5-HIAA, a breakdown product of serotonin, supports carcinoid syndrome in a patient with a known or suspected neuroendocrine tumor, and correlates with the presence of flushing, diarrhea, and carcinoid heart disease -- each 100 nmol/L rise in serum 5-HIAA is associated with modestly increased odds of these symptoms. Serial 5-HIAA is used to monitor disease activity and response to somatostatin analog therapy. False elevation can occur from dietary serotonin intake (in urine testing) or certain medications, so results should be interpreted alongside diet/medication history.',NULL,'[{"condition": "Carcinoid syndrome (from a serotonin-secreting neuroendocrine tumor)", "direction": "high, correlates with flushing/diarrhea/carcinoid heart disease"}]','[{"name": "PMC - Serum 5-Hydroxyindoleacetic Acid Measurements for the Diagnosis and Follow-up of Carcinoid Syndrome", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC12623023/", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'Does this confirm carcinoid syndrome as the cause of my symptoms (like flushing or diarrhea)? Do I need imaging to locate the tumor? Will this be used to track how my treatment is working?','An elevated result in someone with a known or suspected neuroendocrine tumor supports the diagnosis of carcinoid syndrome and is often followed serially to monitor disease activity and response to treatment (such as somatostatin analog therapy).');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (144,'ena-panel','Extractable Nuclear Antigen (ENA) Antibody Panel','','ENA Panel, Anti-Ro/SSA, Anti-La/SSB, Anti-Sm, Anti-RNP','Immunoassay / Inflammation Markers','Reflex panel ordered after a positive ANA to identify specific autoantibodies that help diagnose and subtype connective tissue diseases -- Sjogren''s syndrome (Anti-Ro/SSA, Anti-La/SSB), systemic lupus erythematosus (Anti-Sm, Anti-Ro/SSA), and mixed connective tissue disease (Anti-RNP).',NULL,'Venous serum or plasma','Typically ordered as a reflex panel after a positive ANA screen with a compatible clinical picture, rather than as an isolated first-line test.',NULL,'Solid-phase immunoassay (chemiluminescent or ELISA) or multiplex bead-based assay, detecting IgG antibodies against specific nuclear/cytoplasmic antigens (Ro/SSA, La/SSB, Sm, RNP, Scl-70, Jo-1, and others depending on the panel).',NULL,'[{"parameter": "ENA panel components (Ro/SSA, La/SSB, Sm, RNP)", "population": "Result categories", "range": "Negative or Positive, commonly reported with a titer/unit value against an assay-specific cutoff (e.g., >10 U/mL positive on some platforms)"}]',1,'Anti-Ro/SSA and Anti-La/SSB antibodies are found in roughly 60-75% of primary Sjogren''s syndrome cases and about 50% (Ro) of SLE cases, and Anti-Ro/SSA is specifically associated with photosensitivity, subacute cutaneous lupus, neonatal lupus, and congenital heart block risk in pregnancy. Anti-Sm antibodies are highly specific for SLE (found in only 5-30% of cases but rarely in other conditions), making a positive result strong supportive evidence when clinical suspicion exists, though titer does not correlate with disease activity. Anti-RNP antibodies are the defining serologic feature of mixed connective tissue disease (found in the large majority of cases) and are also seen in a minority of SLE cases. Isolated Anti-La/SSB without Anti-Ro/SSA has low positive predictive value for Sjogren''s syndrome on its own.',NULL,'[{"condition": "Sjogren''s syndrome", "direction": "positive Anti-Ro/SSA and/or Anti-La/SSB"}, {"condition": "Systemic lupus erythematosus", "direction": "positive Anti-Sm (highly specific) and/or Anti-Ro/SSA"}, {"condition": "Mixed connective tissue disease", "direction": "positive Anti-RNP, often high titer"}, {"condition": "Neonatal lupus / congenital heart block risk (maternal Anti-Ro/SSA)", "direction": "positive Anti-Ro/SSA in a pregnant patient"}]','[{"name": "Medscape/eMedicine - Anti-Ro Antibody: Reference Range, Interpretation", "url": "https://emedicine.medscape.com/article/2086660-overview", "accessed": "2026-07-15"}, {"name": "The Rheumatologist - Know Your Labs (ACR-referenced antibody prevalence data)", "url": "https://www.the-rheumatologist.org/article/know-your-labs/?singlepage=1", "accessed": "2026-07-15"}, {"name": "Mayo Clinic Laboratories - SS-A and SS-B Antibodies, IgG, Serum (test catalog)", "url": "https://neurology.testcatalog.org/show/SSAB", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'Which specific antibody was positive, and what condition does that point to? Does this change my diagnosis or treatment plan? If I''m pregnant, does a positive Anti-Ro/SSA affect monitoring for my baby?','The specific antibody pattern (Ro/SSA, La/SSB, Sm, or RNP) helps confirm a specific diagnosis (Sjogren''s, lupus, or mixed connective tissue disease) and guides your rheumatologist''s management plan; a positive Anti-Ro/SSA in pregnancy prompts additional fetal heart monitoring.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (145,'cold-agglutinin-titer','Cold Agglutinin Titer','','Cold Agglutinins, CA Titer','Hematology','Diagnoses cold agglutinin disease and investigates cold-related hemolytic anemia; also relevant preoperatively before planned intraoperative hypothermia, since clinically significant cold agglutinins can cause dangerous red cell agglutination during cooling.',NULL,'Venous whole blood, drawn into a pre-warmed tube and kept warm (37°C) until the serum is separated','The specimen must be kept warm from collection through serum separation, since cold agglutinins can bind to red cells and be lost from the serum (falsely lowering the titer) if the sample is allowed to cool before processing -- a critical and unique preanalytical requirement for this test.',NULL,'Serial dilutions of patient serum are mixed with reagent red cells and tested for agglutination at 4°C (and often also at 30°C and 37°C to assess thermal amplitude); the titer is the reciprocal of the highest dilution still showing agglutination.',NULL,'[{"parameter": "Cold agglutinin titer at 4\u00b0C", "population": "Normal/non-pathogenic", "range": "<1:64", "notes": "Low-titer, low-thermal-amplitude cold agglutinins occur in a small percentage of the healthy population without hemolysis"}]',1,'A titer ≥1:64 at 4°C is considered abnormal, and cold agglutinin disease is typically associated with much higher titers (often >1:10,000) with a thermal amplitude reaching up to 30-32°C or higher, meaning the antibody remains active closer to body temperature and can cause clinically significant hemolysis and cold-induced symptoms (acrocyanosis, Raynaud-like phenomena). Thermal amplitude, not titer alone, best predicts clinical significance -- a high-titer cold agglutinin that only reacts at very low temperatures (4°C) may be less clinically relevant than a lower-titer one that reacts up to near-body temperature. Causes include primary cold agglutinin disease, Mycoplasma pneumoniae or EBV infection (typically transient, lower titer), and lymphoproliferative disorders (e.g., Waldenstrom macroglobulinemia, CLL).',NULL,'[{"condition": "Primary cold agglutinin disease", "direction": "very high titer (often >1:10,000), high thermal amplitude"}, {"condition": "Mycoplasma pneumoniae or EBV infection (secondary, usually transient)", "direction": "moderately elevated titer"}, {"condition": "Lymphoproliferative disorders (Waldenstrom macroglobulinemia, CLL)", "direction": "elevated titer, often monoclonal IgM"}]','[{"name": "Medscape/eMedicine - Cold Agglutinin Disease Workup", "url": "https://emedicine.medscape.com/article/135327-workup", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'Does this explain my cold-related symptoms or anemia? Do I need to avoid cold exposure? If I need surgery, does this affect how it''s planned?','A significant titer prompts avoidance of cold exposure where possible and, if surgery is planned, special precautions (like keeping the operating room warm) to prevent complications from red cell agglutination during cooling.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (146,'cryoglobulins','Cryoglobulins','','Cryoglobulin Screen','Immunoassay / Inflammation Markers','Investigates suspected cryoglobulinemia in patients with purpura, arthralgia, peripheral neuropathy, or glomerulonephritis, particularly in the context of hepatitis C infection, lymphoproliferative disorders, or autoimmune disease (e.g., Sjogren''s syndrome).',NULL,'Venous whole blood, drawn into a pre-warmed tube and kept at 37°C during transport and clotting, then refrigerated at 4°C to allow cryoprecipitation','Strict temperature control is essential and easily gets this test wrong: the sample must be kept warm (37°C) from the moment of collection through clot formation and serum separation, since cryoglobulins will precipitate prematurely at room or cold temperature and be lost from the serum before ever reaching the cold incubation step used to detect them.',NULL,'Serum is incubated at 4°C for up to 7 days and observed for precipitate (cryoprecipitate) formation; if present, the precipitate is redissolved by warming and characterized by immunofixation to classify the cryoglobulin type (Type I monoclonal, Type II mixed monoclonal-polyclonal, Type III mixed polyclonal).',NULL,'[{"parameter": "Cryoglobulins", "population": "Normal", "range": "Negative (no cryoprecipitate) or Not detected", "notes": "When present in low concentration, cryoglobulins exist alongside vastly larger concentrations of normal serum proteins, making the test technically demanding"}]',1,'Type I cryoglobulinemia (a single monoclonal immunoglobulin) is associated with lymphoproliferative disorders such as Waldenstrom macroglobulinemia and multiple myeloma. Type II and III (mixed cryoglobulinemia, involving both monoclonal and/or polyclonal components with rheumatoid factor activity) are most strongly associated with chronic hepatitis C infection, and also occur in autoimmune diseases (Sjogren''s syndrome, SLE) and some lymphoproliferative disorders. Clinical manifestations of mixed cryoglobulinemia include palpable purpura, arthralgia, peripheral neuropathy, and membranoproliferative glomerulonephritis, resulting from immune complex deposition in small vessels.',NULL,'[{"condition": "Chronic hepatitis C infection (mixed cryoglobulinemia)", "direction": "positive, Type II/III"}, {"condition": "Waldenstrom macroglobulinemia / multiple myeloma", "direction": "positive, Type I (monoclonal)"}, {"condition": "Sjogren''s syndrome / SLE (secondary mixed cryoglobulinemia)", "direction": "positive, Type II/III"}]','[{"name": "Annals of Clinical & Laboratory Science - Cryoglobulins: An Important but Neglected Clinical Test", "url": "https://www.annclinlabsci.org/content/36/4/395.full", "accessed": "2026-07-15"}]',1,'2026-07-15 13:24:50','2026-07-15 13:24:50','[]',NULL,NULL,'Does this explain my skin, joint, or kidney symptoms? Could this be related to a hepatitis C infection or another underlying condition? What further testing or treatment do I need?','A positive result prompts investigation for the underlying cause -- most commonly hepatitis C, but also autoimmune disease or a blood cancer -- since treatment is directed at that underlying condition rather than the cryoglobulins themselves.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (147,'rh-phenotype-extended','Extended Rh Phenotype (C/c/E/e Antigen Typing)','','Rh Phenotype, Rh Antigen Typing, CcEe Typing','Blood Bank / Immunohematology','Determines the full Rh antigen profile (C, c, E, e, in addition to D) of a patient''s or donor''s red cells; used for antigen-matched transfusion in chronically transfused patients (e.g., sickle cell disease, thalassemia) to reduce alloimmunization risk, and to help resolve or predict specific Rh antibody identifications.',NULL,'Venous whole blood, EDTA tube (lavender top)','Recent transfusion introduces donor red cells that can cause a mixed-field or inaccurate phenotype result -- testing is ideally done on a pre-transfusion sample, or DNA-based genotyping is used instead when a recent transfusion makes serologic phenotyping unreliable.',NULL,'Hemagglutination technique using monoclonal antisera specific to each antigen (anti-C, anti-c, anti-E, anti-e), performed by tube, gel-card, or automated solid-phase methods; molecular (RHCE genotyping) methods are used when serologic results are ambiguous or the patient has been recently transfused.',NULL,'[{"parameter": "Rh phenotype (C/c/E/e)", "population": "Result categories", "range": "Each antigen reported as present or absent, combined into a phenotype designation (e.g., DCCee, DCcee, DccEe)", "notes": "Population frequencies vary by ethnicity -- e.g., one hospital donor study found DCCee (~46%) and DCcee (~30%) as the most common phenotypes, with e (~97%) and D (~99%) the most prevalent individual antigens and E (~21%) the least"}]',1,'After D, the C/c/E/e antigens are among the most clinically significant in transfusion medicine because of their immunogenicity and the clinical severity of antibodies formed against them (e.g., anti-c and anti-E can cause both hemolytic transfusion reactions and hemolytic disease of the fetus/newborn). Extended phenotype matching (beyond ABO/D alone) is standard of care for patients requiring chronic transfusion support, most notably sickle cell disease and thalassemia patients, since it substantially reduces the rate of alloimmunization compared to D-only matching. Certain antigen combinations are also population-dependent -- for example, the C-c+E-e+ phenotype is typically associated with Rh-positive haplotypes in patients of African ancestry but Rh-negative haplotypes in Caucasian patients, which is relevant when predicting likely genotype from phenotype.',NULL,'[{"condition": "Sickle cell disease / thalassemia requiring chronic transfusion", "direction": "guides extended antigen-matched unit selection"}, {"condition": "Alloimmunization to non-D Rh antigens (anti-C, anti-c, anti-E, anti-e)", "direction": "phenotype used to select antigen-negative units"}, {"condition": "Hemolytic disease of the fetus/newborn risk (non-D Rh antibodies)", "direction": "maternal phenotype/antibody correlation in prenatal care"}]','[{"name": "PMC - Distribution and frequency of principal Rh blood group antigens (D, C, c, E, and e) in blood donors", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC9855209/", "accessed": "2026-07-15"}, {"name": "ScienceDirect Topics - Rh Blood Group System", "url": "https://www.sciencedirect.com/topics/immunology-and-microbiology/rh-blood-group-system", "accessed": "2026-07-15"}]',1,'2026-07-16 06:31:20','2026-07-16 06:31:20','["abo-rh-typing", "antibody-screen", "antibody-identification", "kleihauer-betke"]',NULL,NULL,'Does this affect what type of blood I should receive in future transfusions? If I''ve had a transfusion reaction before, does this help explain why? Should this be documented for my future care?','This result is typically recorded in your record to guide antigen-matched blood selection for any future transfusions, particularly important if you''re likely to need chronic transfusion support or have a history of transfusion reactions.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (148,'weak-d-testing','Weak D Testing','','Weak D, Du Testing, Partial D Testing','Blood Bank / Immunohematology','Resolves an ambiguous or discrepant RhD typing result by detecting weak expression of the D antigen using an indirect antiglobulin (AHG) enhancement step; historically also used more broadly, though current practice reserves it for specific discrepancy/ambiguity scenarios rather than routine typing.',NULL,'Venous whole blood, EDTA tube (lavender top)','Performed as a reflex test when initial RhD typing is negative or gives a weak/ambiguous reaction (commonly ≤2+ agglutination), or when there is a discrepancy with a patient''s historical Rh type on record.',NULL,'An indirect antiglobulin test (IAT): red cells are incubated with anti-D reagent, then antihuman globulin (AHG) is added to enhance and detect otherwise weak or undetectable agglutination; a positive result after AHG addition indicates weak or partial D antigen expression. When serology remains ambiguous, RHD molecular genotyping is used to definitively classify the specific weak D type.',NULL,'[{"parameter": "Weak D test", "population": "Result categories", "range": "Negative (true RhD-negative) or Positive (weak/partial D detected) -- approximately 0.2-1.0% of routine RhD typings in Caucasian populations result in a serologic weak D phenotype"}]',1,'How a weak D result is managed differs sharply depending on the clinical role of the person tested. Blood donors with a serologic weak D phenotype are conventionally managed as RhD-positive for donation purposes. Transfusion recipients and pregnant women, by contrast, have traditionally been managed as RhD-negative out of caution, since some weak D variants (though not the common weak D types 1, 2, and 3) carry a real risk of forming anti-D antibodies if given RhD-positive blood or exposed to RhD-positive fetal cells. Molecular RHD genotyping can now distinguish weak D types 1, 2, and 3 (which can safely be managed as RhD-positive, avoiding unnecessary Rh immune globulin and preserving the RhD-negative blood supply) from other weak D types and partial D variants that still carry alloimmunization risk and should continue to be managed as RhD-negative.',NULL,'[{"condition": "Weak D phenotype (blood donor)", "direction": "positive -- generally managed as RhD-positive for donation"}, {"condition": "Weak D phenotype (transfusion recipient or pregnant patient)", "direction": "positive -- traditionally managed as RhD-negative unless RHD genotyping confirms a low-risk weak D type"}, {"condition": "Partial D phenotype (alloimmunization risk if given RhD-positive blood)", "direction": "positive on weak D screen, requires genotyping to distinguish from benign weak D types"}]','[{"name": "StatPearls / NCBI Bookshelf - Rh Blood Group System", "url": "https://www.ncbi.nlm.nih.gov/books/NBK594252/", "accessed": "2026-07-15"}, {"name": "PMC - Serological weak D phenotypes: A review and guidance for interpreting the RhD blood type using the RHD genotype", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC5612847/", "accessed": "2026-07-15"}, {"name": "Medscape/eMedicine - Rh Typing: Overview, Clinical Indications/Applications, Test Performance and Limitations", "url": "https://emedicine.medscape.com/article/1731214-overview", "accessed": "2026-07-15"}]',1,'2026-07-16 06:31:20','2026-07-16 06:31:20','["abo-rh-typing", "antibody-screen", "antibody-identification", "kleihauer-betke"]',NULL,NULL,'Given this result, am I considered Rh-positive or Rh-negative for transfusion and pregnancy purposes? Do I need genetic testing to clarify further? Does this affect whether I need Rh immune globulin during pregnancy?','How this result is used depends on your role -- if you''re a blood donor, a weak D result is generally treated as Rh-positive; if you''re a transfusion recipient or pregnant, it''s typically treated as Rh-negative unless RHD genotyping specifically confirms a benign weak D type, which your care team will discuss with you.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (149,'digoxin-level','Digoxin, Serum (Therapeutic Drug Monitoring)','','Digoxin Level, Digitalis Level','Clinical Chemistry / Therapeutic Drug Monitoring','Monitors digoxin therapy in heart failure and atrial fibrillation, confirms medication adherence, and investigates suspected digoxin toxicity, given its narrow therapeutic index.',NULL,'Venous serum or plasma','Blood should be drawn at least 6-8 hours after the last oral dose (trough level, just before the next dose) -- levels drawn earlier will be falsely elevated due to the drug''s distribution pattern, since blood levels don''t yet reflect tissue equilibration.',NULL,'Chemiluminescent or fluorescence polarization immunoassay on automated analyzers.',NULL,'[{"parameter": "Digoxin", "population": "Conventional therapeutic range", "range": "0.8-2.0 ng/mL", "notes": "Contemporary evidence and updated recommendations increasingly favor a lower target of 0.5-1.0 ng/mL for heart failure, since higher levels within the older ''therapeutic'' range are associated with increased morbidity and mortality without added benefit -- many labs and references have not yet fully adopted this lower target"}]',1,'Digoxin has a narrow therapeutic index, and current evidence supports targeting the lower end of the traditional range (roughly 0.5-0.9 ng/mL) for heart failure, since higher levels have been associated with increased mortality without added benefit in major trials, while a somewhat higher range has traditionally been used for rate control in atrial fibrillation. Toxicity can occur even within or near the traditional therapeutic range, particularly with hypokalemia, hypomagnesemia, hypoxia, hypothyroidism, or renal impairment (digoxin is renally cleared), and classically presents with nausea, visual disturbances (yellow-green halos), confusion, and characteristic cardiac arrhythmias (including bidirectional ventricular tachycardia). Because digoxin distributes slowly into tissue, a level drawn too soon after a dose (within about 6-8 hours) can be falsely high and does not reflect true steady-state exposure.',NULL,'[{"condition": "Digoxin toxicity (nausea, visual disturbance, arrhythmia)", "direction": "high, or even low-normal with hypokalemia/renal impairment/hypothyroidism"}, {"condition": "Subtherapeutic digoxin (inadequate rate control or heart failure benefit)", "direction": "low"}]','[{"name": "Medscape/eMedicine - Digoxin Level: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2089975-overview", "accessed": "2026-07-15"}, {"name": "PMC - Failure of current digoxin monitoring for toxicity: new monitoring recommendations", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC10350506/", "accessed": "2026-07-15"}]',1,'2026-07-16 06:55:23','2026-07-20 05:50:41','[]','A level >2.4 ng/mL is generally considered toxic, though roughly 10% of patients can show toxicity symptoms even below 2.0 ng/mL, particularly in the presence of hypokalemia, hypomagnesemia, hypoxia, underlying heart disease, or hypercalcemia -- toxicity should be assessed clinically, not by level alone.','Drawing the sample too soon after a dose (before 6-8 hours) falsely elevates the result, since digoxin has not yet fully distributed from blood into tissue. Low potassium, low magnesium, and impaired kidney function (which reduces digoxin clearance) all increase the risk of toxicity at a given level.','Was this sample drawn at the correct time relative to my last dose? Given contemporary evidence, should my target level be lower than the traditional range? Are my kidney function and electrolytes being checked alongside this, since they affect my risk of toxicity?','A subtherapeutic level may prompt a dose increase (after checking for adherence and correct timing of the draw); a level above target, especially with symptoms of toxicity (nausea, visual changes, arrhythmias), prompts dose reduction or holding the medication, correction of contributing electrolyte abnormalities, and in severe toxicity, digoxin-specific antibody fragments (Fab).');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (150,'lithium-level','Lithium, Serum (Therapeutic Drug Monitoring)','','Lithium Level','Clinical Chemistry / Therapeutic Drug Monitoring','Monitors lithium therapy for bipolar disorder to maintain therapeutic efficacy while avoiding toxicity, given its narrow therapeutic index; also used to investigate suspected toxicity.',NULL,'Venous serum or plasma','Blood should be drawn approximately 12 hours after the last dose (trough level, typically a morning draw after an evening dose) for standardized, comparable results between visits.',NULL,'Ion-selective electrode or atomic absorption spectrophotometry on automated analyzers.',NULL,'[{"parameter": "Lithium", "population": "Maintenance therapeutic range", "range": "Approximately 0.6-1.2 mEq/L", "notes": "Target range varies by clinical indication and prescriber''s treatment plan -- follow local/institutional guidance"}]',1,'Lithium has a narrow therapeutic index, and levels must be interpreted alongside clinical response and side effects rather than as an isolated target -- a level within range does not exclude toxicity in a vulnerable patient, and a level slightly above range may be tolerated in some. Toxicity risk rises substantially above the therapeutic range and presents with a spectrum from mild tremor and GI upset to confusion, ataxia, and, at severe levels, seizures, arrhythmias, and coma; renal impairment, dehydration, and drug interactions (notably NSAIDs, ACE inhibitors/ARBs, and thiazide diuretics, all of which reduce lithium clearance) can precipitate toxicity even without a dose change. Because lithium excretion tracks closely with sodium and water balance, any condition causing volume depletion (vomiting, diarrhea, reduced intake, hot weather) can unexpectedly raise levels and requires closer monitoring or temporary dose adjustment.',NULL,'[{"condition": "Lithium toxicity (tremor, GI upset progressing to confusion, ataxia, seizures)", "direction": "high, or unexpectedly high with dehydration/renal impairment/interacting drugs"}, {"condition": "Subtherapeutic lithium (inadequate mood stabilization)", "direction": "low"}]','[{"name": "GoodNurse - Therapeutic Drug Levels: Vancomycin, Digoxin, Lithium - Monitoring, Toxicity", "url": "https://goodnurse.com/article/208/therapeutic-drug-levels-2026-vancomycin-digoxin-lithium-monitoring-toxicity-teaching", "accessed": "2026-07-15"}, {"name": "PMC - Overview of Therapeutic Drug Monitoring", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC2687654/", "accessed": "2026-07-15"}]',1,'2026-07-16 06:55:23','2026-07-20 05:50:41','[]','Toxicity risk rises substantially above the therapeutic range, and levels can rise unexpectedly due to dehydration or low sodium (lithium excretion tracks with sodium/water balance) even without a dose change -- any signs of toxicity (tremor, confusion, ataxia, vomiting) warrant urgent level checking regardless of the last known result.','Dehydration, low-sodium diets, and certain medications (thiazide diuretics, NSAIDs, ACE inhibitors) can raise lithium levels by reducing renal excretion, sometimes causing toxicity even without a dose increase. Drawing the sample too soon after a dose (before reaching steady state or before the appropriate trough timing) can give a misleading result.','Was this drawn at the right time (about 12 hours post-dose)? Could dehydration, a new medication, or my kidney function be affecting this level? How often should this be monitored going forward, and is my thyroid and kidney function also being checked periodically?','A subtherapeutic level with inadequate response may prompt a dose increase; a level above the therapeutic range prompts dose reduction and review of factors that may have raised it. Since lithium can affect the kidneys and thyroid over time, periodic monitoring of both is typically done alongside lithium levels.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (151,'factor-v-leiden','Factor V Leiden Mutation Testing','','Factor V Leiden, FVL, Activated Protein C Resistance','Hematology / Coagulation','Identifies the most common inherited thrombophilia, evaluated in patients with unprovoked or recurrent venous thromboembolism, VTE at a young age, VTE with a strong family history, or recurrent pregnancy loss.',NULL,'Venous whole blood, EDTA tube (lavender top)','Can be tested at any time, including during acute thrombosis or while on anticoagulation, since this is a DNA-based test and not affected by current clotting status (unlike protein C, protein S, or antithrombin levels).',NULL,'PCR-based DNA testing detects the specific G1691A mutation in the factor V gene; a functional activated protein C (APC) resistance assay can be used as an initial screen, with genetic testing to confirm.',NULL,'[{"parameter": "Factor V Leiden mutation", "population": "Result categories", "range": "Not detected (wild-type), Heterozygous, or Homozygous -- a genetic result, not a numeric value; prevalence varies substantially by ethnicity (e.g., ~4-7% in Northern/Southern Europeans, 7.5% in some Middle Eastern populations, rare in East Asian and African populations)"}]',1,'Heterozygous Factor V Leiden increases venous thromboembolism risk roughly 3-8 fold; homozygous carriers have a substantially higher risk (estimates vary, often cited around 20-fold or more). The mutation causes resistance to inactivation by activated protein C, leading to a hypercoagulable state. Risk is further amplified by additional factors such as estrogen-containing contraceptives, pregnancy, surgery, and immobility. It is also associated with certain obstetric complications (recurrent miscarriage, preeclampsia) though the strength of this association remains debated in the literature.',NULL,'[{"condition": "Venous thromboembolism (DVT/PE) risk", "direction": "positive, heterozygous or homozygous"}, {"condition": "Recurrent pregnancy loss / preeclampsia (debated association)", "direction": "positive"}]','[{"name": "PMC - Factor V Leiden G1691A and Prothrombin Gene G20210A Mutations on Pregnancy Outcome (prevalence data)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8439407/", "accessed": "2026-07-15"}, {"name": "Testing.com - Factor 5 Leiden Mutation Test: Purpose and Results", "url": "https://www.testing.com/tests/factor-v-leiden-mutation-and-pt-20210-mutation/", "accessed": "2026-07-15"}]',1,'2026-07-16 06:55:23','2026-07-16 06:55:23','["antithrombin-iii", "d-dimer", "protein-c", "protein-s", "prothrombin-g20210a"]',NULL,NULL,'Given this result, what precautions should I take during pregnancy, surgery, or long flights? Does this affect my choice of contraception or hormone therapy? Do family members need to be tested?','A positive result leads to a discussion of risk-reduction strategies (avoiding estrogen-containing contraceptives, prophylactic anticoagulation around high-risk situations like surgery or pregnancy) rather than routine long-term anticoagulation in someone who hasn''t had a clot, and family testing may be offered given the hereditary nature of this mutation.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (152,'prothrombin-g20210a','Prothrombin G20210A Mutation Testing','','Prothrombin Gene Mutation, Factor II Mutation','Hematology / Coagulation','Identifies the second most common inherited thrombophilia after Factor V Leiden, evaluated as part of the same thrombophilia workup for unprovoked or recurrent venous thromboembolism, especially at a young age or with a family history.',NULL,'Venous whole blood, EDTA tube (lavender top)','Can be tested at any time, including during acute thrombosis or while on anticoagulation, since this is a DNA-based test unaffected by current clotting status.',NULL,'PCR-based DNA testing detects the specific G20210A mutation in the prothrombin (factor II) gene, which increases prothrombin production and clotting activity.',NULL,'[{"parameter": "Prothrombin G20210A mutation", "population": "Result categories", "range": "Not detected (wild-type), Heterozygous, or Homozygous -- a genetic result; overall population prevalence is approximately 2%, higher in some European populations"}]',1,'This gain-of-function mutation increases thrombin and fibrin generation, raising venous thromboembolism risk (heterozygous carriers have an estimated 2-3 fold increased risk, similar in magnitude to Factor V Leiden). It is often tested alongside Factor V Leiden as part of a standard thrombophilia panel, and the combination of both mutations together (or with other risk factors) substantially increases risk beyond either alone.',NULL,'[{"condition": "Venous thromboembolism (DVT/PE) risk", "direction": "positive, heterozygous or homozygous"}, {"condition": "Combined thrombophilia (with Factor V Leiden or other risk factors)", "direction": "positive, compounding risk"}]','[{"name": "World Thrombosis Day - Thrombophilia Testing and MTHFR", "url": "https://www.worldthrombosisday.org/thrombophilia-testing-and-mthfr/", "accessed": "2026-07-15"}, {"name": "PubMed - Testing for Factor V Leiden (FVL) and Prothrombin G20210A Genetic Variants", "url": "https://pubmed.ncbi.nlm.nih.gov/37204714/", "accessed": "2026-07-15"}]',1,'2026-07-16 06:55:23','2026-07-16 06:55:23','["antithrombin-iii", "factor-v-leiden", "protein-c", "protein-s"]',NULL,NULL,'Does this change my risk during pregnancy, surgery, or with hormone-based contraception? Should I be on prophylactic blood thinners in high-risk situations even without a prior clot? Do my family members need testing?','As with Factor V Leiden, a positive result leads to counseling on situational risk reduction (avoiding estrogen-based contraceptives, prophylactic anticoagulation around surgery/pregnancy) rather than automatic long-term anticoagulation without a prior clot, guided by hematology.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (153,'adamts13-activity','ADAMTS13 Activity','','ADAMTS13, vWF-Cleaving Protease Activity','Hematology / Coagulation','Confirms or excludes thrombotic thrombocytopenic purpura (TTP) in patients presenting with microangiopathic hemolytic anemia and thrombocytopenia, distinguishing TTP from other thrombotic microangiopathies (like hemolytic uremic syndrome) that require different treatment.',NULL,'Venous whole blood, sodium citrate tube (light blue top) -- EDTA tubes are not acceptable, as EDTA strongly inhibits ADAMTS13 function','Should be drawn before starting plasma exchange therapy whenever possible, since plasma exchange will alter results; specimens must not be hemolyzed, clotted, or heparin-contaminated.',NULL,'Functional activity assay (e.g., FRET-based cleavage of a synthetic vWF substrate), often combined with antigen level and inhibitor (autoantibody) testing when activity is low.',NULL,'[{"parameter": "ADAMTS13 activity", "population": "Normal", "range": "Approximately 60-130 IU/dL (methods vary)"}]',1,'Severely reduced ADAMTS13 activity (typically <10 IU/dL) in a patient with microangiopathic hemolytic anemia and thrombocytopenia is considered diagnostic of thrombotic thrombocytopenic purpura (TTP) in the appropriate clinical context, distinguishing it from other thrombotic microangiopathies such as hemolytic uremic syndrome, which have a normal or only mildly reduced ADAMTS13 and require different treatment. Acquired TTP (the more common form) results from an autoantibody inhibiting ADAMTS13, identified by adding an inhibitor/antibody assay when activity is low; congenital TTP (Upshaw-Schulman syndrome) instead reflects an inherited enzyme deficiency present from birth without an inhibitory antibody. Because untreated TTP can be rapidly fatal, plasma exchange therapy is often started empirically based on strong clinical suspicion (using a validated clinical prediction score) before the ADAMTS13 result is even back, with the result confirming the diagnosis and guiding continued management.',NULL,'[{"condition": "Thrombotic thrombocytopenic purpura (TTP)", "direction": "severely low, typically <10 IU/dL"}, {"condition": "Congenital TTP (Upshaw-Schulman syndrome)", "direction": "severely low from birth, without inhibitory antibody"}]','[{"name": "Practical Haemostasis - ADAMTS13 Assays", "url": "https://practical-haemostasis.com/Miscellaneous/adamts13_assays.html", "accessed": "2026-07-15"}, {"name": "MLabs (University of Michigan) - ADAMTS-13 Activity (test catalog)", "url": "https://mlabs.umich.edu/tests/adamts-13-activity", "accessed": "2026-07-15"}, {"name": "myADLM - The Role of ADAMTS13 Testing in the Work up of Suspected TTP", "url": "https://myadlm.org/cln/articles/2016/april/the-role-of-adamts13-testing-in-the-work-up-of-suspected-thrombotic-thrombocytopenic-purpura", "accessed": "2026-07-15"}]',1,'2026-07-16 06:55:23','2026-07-20 05:50:41','["cbc", "haptoglobin", "ldh", "von-willebrand-factor"]','Severe deficiency (<10 IU/dL, some labs use <10%) is considered diagnostic of TTP in the appropriate clinical context and is treated as a critical, actionable result requiring urgent plasma exchange therapy.','High bilirubin (>15-30 mg/dL depending on the assay), significant hemolysis (free hemoglobin >2 g/dL), hyperlipidemia, and high endogenous von Willebrand factor can all interfere with the activity assay -- results should be interpreted with awareness of these confounders, particularly in critically ill patients with multiple abnormalities.','Does this confirm TTP as the cause of my low platelets and anemia, or point to a different cause (like HUS or DIC)? If severely deficient, is this from an autoantibody or a genetic cause? How quickly does treatment need to start?','A severely deficient result in a compatible clinical picture confirms TTP and prompts urgent plasma exchange therapy, typically started even before the result is finalized if clinical suspicion is high, given how quickly untreated TTP can become life-threatening. A normal or only mildly reduced result makes TTP less likely and prompts investigation of other causes.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (154,'vitamin-k','Vitamin K1 (Phylloquinone), Serum','','Vitamin K, Phylloquinone','Clinical Chemistry','Evaluates suspected vitamin K deficiency, particularly in patients with unexplained bleeding/bruising, malabsorption (e.g., cystic fibrosis, cholestatic liver disease), or prolonged PT/INR not explained by warfarin use.',NULL,'Venous serum or plasma','Fasting sample is generally preferred, since recent dietary intake of vitamin K-rich foods (leafy greens, certain oils) can transiently raise levels.',NULL,'High-performance liquid chromatography (HPLC) or LC-MS/MS, given the very low circulating concentrations involved.',NULL,'[{"parameter": "Vitamin K1 (phylloquinone)", "population": "Adult, general reference", "range": "Approximately 0.2-3.0 ng/mL", "notes": "Reference ranges vary meaningfully by population, age, and laboratory method -- functional markers (like PIVKA-II or PT) are often used alongside or instead of direct vitamin K level measurement, since direct testing is not widely standardized"}]',1,'Low vitamin K impairs the liver''s ability to produce functional clotting factors II, VII, IX, and X, leading to a prolonged PT/INR and bleeding risk -- this is why vitamin K deficiency is a key differential when PT/INR is elevated in someone not on warfarin. Causes include malabsorption syndromes (celiac disease, cystic fibrosis, cholestatic liver disease), prolonged antibiotic use (which reduces gut bacterial vitamin K production), and inadequate dietary intake. In practice, functional testing (PT/INR response to vitamin K administration, or PIVKA-II) is often used to assess vitamin K status rather than direct serum level measurement, since direct assays are less standardized and widely available.',NULL,'[{"condition": "Malabsorption syndromes (celiac disease, cystic fibrosis, cholestatic liver disease)", "direction": "low"}, {"condition": "Prolonged broad-spectrum antibiotic use", "direction": "low, from reduced gut bacterial synthesis"}, {"condition": "Unexplained bleeding / prolonged PT-INR (not on warfarin)", "direction": "low, contributing cause"}]','[{"name": "PMC - Reference Range of Vitamin K Evaluating Indicators in Chinese Childbearing Women", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC10143736/", "accessed": "2026-07-15"}, {"name": "PMC - Preliminary study on the reference intervals of vitamin K in a normal physical examination population (Beijing)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC11811856/", "accessed": "2026-07-15"}]',1,'2026-07-16 06:55:23','2026-07-20 05:50:41','[]',NULL,NULL,'Could a medication I''m taking (like long-term antibiotics) or a digestive condition be causing this deficiency? Do I need vitamin K supplementation, and how quickly will my clotting times normalize?','Confirmed deficiency is treated with vitamin K supplementation (oral or, if malabsorption is significant or urgent correction of bleeding risk is needed, parenteral), with a repeat PT/INR after treatment to confirm correction and investigation of the underlying cause (malabsorption, antibiotic use, dietary intake) addressed where possible.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (155,'stool-culture','Stool Culture','','Stool C&S, Enteric Pathogen Culture','Microbiology','Identifies bacterial pathogens causing infectious diarrhea/gastroenteritis (e.g., Salmonella, Shigella, Campylobacter, pathogenic E. coli), used in patients with severe, bloody, or persistent diarrhea, or during suspected outbreaks.',NULL,'Fresh stool sample, collected in a sterile container (or rectal swab in some settings)','Sample should be transported and processed promptly, or placed in appropriate transport media, since some enteric pathogens are fragile and can die off or be overgrown by normal flora if the sample is delayed.',NULL,'Selective and differential culture media targeting specific enteric pathogens, since normal stool flora (anaerobes, gram-negative enterics, Enterococcus) is abundant and would otherwise overwhelm a non-selective culture; molecular (PCR panel) methods are increasingly used alongside or instead of culture for faster, broader pathogen detection.',NULL,'[{"parameter": "Stool culture", "population": "Normal", "range": "No pathogenic organisms isolated (normal flora only) -- growth of a specific enteric pathogen (Salmonella, Shigella, Campylobacter, etc.) is a positive/reportable result"}]',1,'Identification of a specific enteric pathogen guides targeted antibiotic therapy (when indicated -- many bacterial gastroenteritis cases are self-limited and don''t require antibiotics) and, for reportable organisms like Salmonella and Shigella, triggers public health reporting to monitor for outbreaks. A negative culture in someone with persistent symptoms may prompt additional testing (stool PCR panel, ova and parasites, C. difficile toxin testing) since culture alone doesn''t detect all causes of infectious diarrhea (viruses, parasites, and some bacteria are not reliably identified by standard culture).',NULL,'[{"condition": "Bacterial gastroenteritis (Salmonella, Shigella, Campylobacter, pathogenic E. coli)", "direction": "positive, specific pathogen identified"}, {"condition": "Traveler''s diarrhea", "direction": "positive, commonly enterotoxigenic E. coli in many regions"}]','[{"name": "Medscape/eMedicine - Stool Culture: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2107038-overview", "accessed": "2026-07-15"}]',1,'2026-07-16 06:55:23','2026-07-16 06:55:23','["gram-stain", "h-pylori-testing"]',NULL,NULL,'Does this identify what''s causing my symptoms? Do I need antibiotics, or will this resolve on its own? Is this a reportable infection, and do I need to take precautions to avoid spreading it to others?','A positive result for a specific pathogen guides whether antibiotics are needed (many cases don''t require them) and any public health reporting/isolation precautions required for that organism. A negative result with ongoing symptoms often leads to additional testing (PCR panel, parasite testing, or C. difficile testing depending on your history).');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (156,'sweat-chloride','Sweat Chloride Test','','Sweat Test, Pilocarpine Iontophoresis Sweat Test','Clinical Chemistry','Gold-standard diagnostic test for cystic fibrosis (CF), used to confirm the diagnosis in infants with a positive newborn screen or in patients with clinical features suggestive of CF (chronic respiratory infections, growth failure, malabsorption).',NULL,'Sweat, collected via pilocarpine iontophoresis (a small electrical current stimulates local sweat production, which is then collected and analyzed)','Requires an adequate sweat volume for a valid result; testing is ideally performed at an accredited CF center given the technical precision required, and repeated if the initial sample volume is insufficient.',NULL,'Chloride concentration in the collected sweat is measured by coulometric titration or ion-selective electrode.',NULL,'[{"parameter": "Sweat chloride", "population": "Normal", "range": "<40 mEq/L (mmol/L)"}, {"parameter": "Sweat chloride", "population": "Intermediate (requires further evaluation)", "range": "30-59 mEq/L (age-dependent cutoffs vary)"}, {"parameter": "Sweat chloride", "population": "Consistent with CF", "range": "\u226560 mEq/L"}]',1,'A sweat chloride ≥60 mEq/L on two separate occasions is considered diagnostic of cystic fibrosis in the appropriate clinical context. Intermediate results require CFTR genetic mutation analysis to clarify the diagnosis, since some patients with CFTR-related disease can have borderline sweat chloride values. A normal sweat chloride makes classic CF unlikely but does not completely exclude rare CFTR-related disorders in patients with a strongly suggestive clinical picture.',NULL,'[{"condition": "Cystic fibrosis", "direction": "high, \u226560 mEq/L"}, {"condition": "CFTR-related disorder (borderline phenotype)", "direction": "intermediate, 30-59 mEq/L"}]','[{"name": "droracle.ai - Cystic Fibrosis Diagnosis and Management (CDC/AAP-referenced sweat chloride and fecal elastase cutoffs)", "url": "https://www.droracle.ai/guidelines/2c50bd2d-9911-426c-909b-ab6b2bd9c198?z=673774", "accessed": "2026-07-15"}]',1,'2026-07-16 06:58:35','2026-07-16 06:58:35','[]',NULL,NULL,'If the result is intermediate, do I need CFTR genetic testing to clarify the diagnosis? What does this mean for my child''s long-term care plan? Do other family members need to be tested?','A diagnostic result leads to referral to a CF care center for comprehensive management planning (pulmonary, nutritional, and genetic counseling). An intermediate result prompts CFTR genetic mutation analysis, and the test may be repeated to confirm an adequate, valid sweat sample was obtained.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (157,'fecal-elastase','Fecal Elastase-1','','Fecal Elastase, Pancreatic Elastase','Clinical Chemistry','Non-invasive screening test for exocrine pancreatic insufficiency (EPI), used in patients with cystic fibrosis, chronic pancreatitis, or unexplained malabsorption/steatorrhea.',NULL,'Random stool sample (formed, not liquid, for accurate results)','A formed stool sample is needed for accurate results, since liquid/watery stool can dilute the elastase concentration and cause a falsely low result unrelated to true pancreatic function. Pancreatic enzyme replacement therapy does not need to be stopped before testing, since the assay detects human elastase specifically and does not cross-react with supplemental enzymes.',NULL,'Enzyme-linked immunosorbent assay (ELISA) using antibodies specific to human pancreatic elastase-1.',NULL,'[{"parameter": "Fecal elastase-1", "population": "Normal pancreatic function", "range": ">200 \u00b5g/g (some sources cite >184-480 \u00b5g/g as the normal cutoff, varying by study/population)"}, {"parameter": "Fecal elastase-1", "population": "Exocrine pancreatic insufficiency", "range": "<100 \u00b5g/g"}, {"parameter": "Fecal elastase-1", "population": "Severe exocrine pancreatic insufficiency", "range": "<50 \u00b5g/g", "notes": "Per American Academy of Pediatrics guidance for cystic fibrosis"}]',1,'A low result supports exocrine pancreatic insufficiency and, in patients with cystic fibrosis or chronic pancreatitis, guides the decision to start or adjust pancreatic enzyme replacement therapy (PERT). It is a sensitive and specific indirect marker, though borderline results (roughly 100-200 µg/g) may need clinical correlation or a repeat test, since dilutional effects from liquid stool can lower the result independent of true pancreatic function.',NULL,'[{"condition": "Cystic fibrosis with pancreatic insufficiency", "direction": "low, often severely (<50 \u00b5g/g)"}, {"condition": "Chronic pancreatitis", "direction": "low"}, {"condition": "Malabsorption / steatorrhea from exocrine pancreatic insufficiency", "direction": "low"}]','[{"name": "ScienceDirect - Fecal elastase-1 cut-off levels in the assessment of exocrine pancreatic function in cystic fibrosis", "url": "https://www.sciencedirect.com/science/article/pii/S1569199302000966", "accessed": "2026-07-15"}, {"name": "droracle.ai - Cystic Fibrosis Diagnosis and Management (AAP fecal elastase cutoffs)", "url": "https://www.droracle.ai/guidelines/2c50bd2d-9911-426c-909b-ab6b2bd9c198?z=673774", "accessed": "2026-07-15"}]',1,'2026-07-16 06:58:35','2026-07-16 06:58:35','[]',NULL,NULL,'Does this confirm my malabsorption symptoms are from pancreatic insufficiency? Do I need to start (or adjust) pancreatic enzyme replacement therapy? Should this be rechecked periodically to monitor my pancreatic function?','A low result in someone with malabsorption symptoms typically leads to pancreatic enzyme replacement therapy (PERT), with fat-soluble vitamin (A, D, E, K) levels also checked given the associated malabsorption risk, and nutritional status monitored over time.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (158,'cystatin-c','Cystatin C, Serum','','Cystatin C','Clinical Chemistry','Alternative/complementary marker of kidney function to creatinine, used to estimate GFR, particularly valuable when creatinine-based estimates may be unreliable (e.g., very muscular, frail/sarcopenic, or malnourished patients) or to confirm early kidney function decline.',NULL,'Venous serum or plasma','No fasting required. Unlike creatinine, cystatin C production is not significantly affected by muscle mass, diet, or sex, making it useful when these factors are expected to distort creatinine-based estimates.',NULL,'Immunoturbidimetric or immunonephelometric assay on automated chemistry analyzers.',NULL,'[{"parameter": "Cystatin C", "population": "Adult", "range": "Approximately 0.6-1.0 mg/L", "notes": "Reference range varies modestly by lab/assay"}]',1,'Elevated cystatin C suggests reduced kidney filtration, and current KDIGO guidance recommends using the combined creatinine-cystatin C eGFR equation (CKD-EPI 2021) for improved accuracy, particularly in elderly, cancer, or hospitalized patients, and in situations where creatinine-based eGFR results (60-75 mL/min/1.73m²) need clarification -- distinguishing true kidney function decline from a muscle-mass effect on creatinine. Cystatin C has also been studied as a stronger predictor of cardiovascular events than creatinine-based eGFR in some large cohort studies, though it should be used alongside, not instead of, standard cardiovascular risk assessment. Clinical decisions should rely on validated combined eGFR equations rather than an isolated cystatin C value.',NULL,'[{"condition": "Chronic kidney disease (early or masked by low muscle mass)", "direction": "high"}, {"condition": "Reduced GFR in elderly, frail, or highly muscular patients where creatinine is unreliable", "direction": "high, clarifies true kidney function"}]','[{"name": "Cleveland Clinic Journal of Medicine - The role of cystatin C in estimating glomerular filtration rate and guiding medication dosing", "url": "https://www.ccjm.org/content/92/9/546", "accessed": "2026-07-15"}]',1,'2026-07-16 06:58:35','2026-07-16 06:58:35','["creatinine", "bun"]',NULL,NULL,'Why was this test added to my creatinine-based kidney function assessment? Does this change my calculated eGFR and kidney disease stage? Does this affect any medication dosing decisions?','Results are used together with creatinine in a combined eGFR equation (per current KDIGO guidance) rather than interpreted alone, and a combined eGFR significantly different from the creatinine-only estimate may prompt adjustment of medication dosing or kidney disease staging.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (159,'pivka-ii','PIVKA-II (Des-Gamma-Carboxy Prothrombin, DCP)','','PIVKA-II, DCP, Des-Gamma-Carboxy Prothrombin','Immunoassay / Tumor Markers','Tumor marker used alongside AFP for hepatocellular carcinoma (HCC) surveillance and diagnosis in high-risk patients (cirrhosis, chronic hepatitis B/C), particularly useful for detecting AFP-negative HCC.',NULL,'Venous serum or plasma','Vitamin K deficiency or warfarin use can independently raise PIVKA-II (since it reflects an abnormal, undercarboxylated prothrombin produced when vitamin K-dependent carboxylation is impaired) unrelated to HCC -- this history should be reviewed when interpreting an elevated result.',NULL,'Chemiluminescent or electrochemiluminescent immunoassay on automated immunoassay analyzers.',NULL,'[{"parameter": "PIVKA-II", "population": "Normal", "range": "Commonly cited cutoffs for HCC detection range from ~37-58 mAU/mL depending on the study/population", "notes": "Cutoffs vary by assay and population; always use the reporting lab''s own reference range"}]',1,'Elevated PIVKA-II supports a diagnosis of hepatocellular carcinoma, with several studies showing it performs comparably to or better than AFP alone for HCC detection, and the combination of both markers together improves diagnostic accuracy over either alone. Higher levels are also associated with larger tumor size, vascular invasion, and worse prognosis in confirmed HCC. As with AFP, PIVKA-II is used for surveillance in high-risk patients (cirrhosis, chronic hepatitis) and to help monitor treatment response, but a mildly elevated result should be interpreted alongside vitamin K/warfarin status, since that is a well-recognized non-cancer cause of elevation.',NULL,'[{"condition": "Hepatocellular carcinoma (diagnosis, surveillance, prognosis)", "direction": "high, correlates with tumor size and vascular invasion"}, {"condition": "Vitamin K deficiency / warfarin therapy (non-cancer cause)", "direction": "high, unrelated to malignancy"}]','[{"name": "PMC - Value of AFP and PIVKA-II in diagnosis of HBV-related hepatocellular carcinoma", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7684907/", "accessed": "2026-07-15"}, {"name": "PMC - Utility of PIVKA-II and AFP in Differentiating Hepatocellular Carcinoma from Non-Malignant High-Risk Patients", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9416286/", "accessed": "2026-07-15"}]',1,'2026-07-16 06:58:35','2026-07-16 06:58:35','["afp"]',NULL,NULL,'Does this, combined with my AFP result, suggest liver cancer? Could my warfarin use or vitamin K status be contributing to this result? Do I need imaging to look for a liver mass?','An elevated result, especially combined with an elevated AFP, typically prompts liver imaging (ultrasound, CT, or MRI) to look for a mass; if you''re on warfarin or have vitamin K deficiency, this is factored into interpretation before further workup is pursued.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (160,'jak2-v617f','JAK2 V617F Mutation Analysis','','JAK2 Mutation, JAK2 V617F','Hematology / Molecular','Key diagnostic test for BCR-ABL1-negative myeloproliferative neoplasms (polycythemia vera, essential thrombocythemia, primary myelofibrosis), used to evaluate unexplained sustained elevation of red cell or platelet counts, splenomegaly, or bone marrow fibrosis of undetermined cause.',NULL,'Venous whole blood or bone marrow, EDTA tube','No special preparation required. Can be performed on peripheral blood in most cases, avoiding the need for a bone marrow sample specifically for this test.',NULL,'Allele-specific PCR (ARMS-PCR) or quantitative real-time PCR (qPCR) detecting the specific c.1849G>T (p.Val617Phe) point mutation in the JAK2 gene; quantitative methods also report the mutant allele burden as a percentage.',NULL,'[{"parameter": "JAK2 V617F", "population": "Result categories", "range": "Not detected (negative) or Detected/Positive (with mutant allele burden % if quantitative testing is used)"}]',1,'The JAK2 V617F mutation is detected in approximately 95-98% of polycythemia vera cases, and 50-60% of essential thrombocythemia and primary myelofibrosis cases, making it a highly useful diagnostic marker when positive. A negative result does not rule out any of these myeloproliferative neoplasms, since a meaningful proportion of ET and PMF cases are JAK2-negative but may carry a CALR or MPL mutation instead (these three mutations are essentially mutually exclusive). The mutation is not seen in reactive causes of elevated blood counts or in BCR-ABL1-positive chronic myeloid leukemia, helping distinguish true myeloproliferative neoplasms from secondary/reactive processes. Rising allele burden over time, or transition from heterozygous to homozygous status, has been associated with disease progression in some studies.',NULL,'[{"condition": "Polycythemia vera", "direction": "positive in ~95-98% of cases"}, {"condition": "Essential thrombocythemia", "direction": "positive in ~50-60% of cases"}, {"condition": "Primary myelofibrosis", "direction": "positive in ~50-65% of cases"}]','[{"name": "Mayo Clinic Laboratories - JAK2 V617F Mutation Detection, Blood (test catalog)", "url": "https://hematology.testcatalog.org/show/JAK2B", "accessed": "2026-07-19"}, {"name": "MLabs (University of Michigan) - JAK2 V617F Mutation (test catalog)", "url": "https://mlabs.umich.edu/tests/jak2-v617f-mutation", "accessed": "2026-07-19"}]',1,'2026-07-19 08:44:16','2026-07-19 08:44:16','["cbc"]',NULL,NULL,'Does a positive result confirm my diagnosis, or do I need bone marrow examination too? What does my specific allele burden mean for my prognosis? If negative, do I need testing for CALR or MPL mutations instead?','A positive result, combined with your blood counts and bone marrow findings, generally confirms the diagnosis of a JAK2-mutated myeloproliferative neoplasm and guides risk stratification and treatment planning with hematology. A negative result in someone still suspected of having an MPN typically leads to CALR and MPL mutation testing before the diagnosis is reconsidered.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (161,'bcr-abl1-quantitative','BCR-ABL1 Quantitative PCR (International Scale)','','BCR-ABL1, Philadelphia Chromosome PCR, CML Molecular Monitoring','Hematology / Molecular','Diagnoses and monitors chronic myeloid leukemia (CML) and Philadelphia chromosome-positive acute lymphoblastic leukemia by detecting and quantifying the BCR-ABL1 fusion transcript, and is the standard test for monitoring molecular response to tyrosine kinase inhibitor (TKI) therapy.',NULL,'Venous whole blood or bone marrow (peripheral blood is standard for routine monitoring)','Typically collected in an RNA-stabilizing tube per the testing laboratory''s requirements, since RNA is less stable than DNA and results depend on adequate transcript preservation during transport.',NULL,'Real-time quantitative reverse-transcriptase PCR (RT-qPCR) detecting the BCR-ABL1 fusion transcript (most commonly e13a2/e14a2, ''major'' breakpoint) relative to a control gene (ABL1), with results standardized to the International Scale (IS) to allow comparison across laboratories.',NULL,'[{"parameter": "BCR-ABL1 (International Scale)", "population": "Major molecular response (MMR)", "range": "\u22640.1% IS (a 3-log reduction from a standardized baseline)"}, {"parameter": "BCR-ABL1 (International Scale)", "population": "Deep molecular response (MR4)", "range": "\u22640.01% IS"}, {"parameter": "BCR-ABL1 (International Scale)", "population": "Deep molecular response (MR4.5)", "range": "\u22640.0032% IS"}]',1,'In newly diagnosed CML, the baseline BCR-ABL1 level (before treatment) is used as the reference point for tracking log-reduction in response to TKI therapy (imatinib, nilotinib, dasatinib, and others). Achieving a major molecular response (BCR-ABL1 ≤0.1% IS) by 12 months of treatment is a key treatment milestone associated with excellent long-term outcomes, while failure to reach expected milestones prompts consideration of treatment adherence issues, resistance mutations, or a change in therapy. Deeper molecular responses (MR4, MR4.5) are increasingly used to identify patients who may be candidates for treatment-free remission (stopping TKI therapy under close monitoring) in appropriate clinical trials or protocols.',NULL,'[{"condition": "Chronic myeloid leukemia (diagnosis and monitoring)", "direction": "detectable at diagnosis, tracked serially during treatment"}, {"condition": "Philadelphia chromosome-positive acute lymphoblastic leukemia", "direction": "detectable, monitored similarly"}, {"condition": "Treatment failure / TKI resistance", "direction": "failure to achieve expected log-reduction milestones, or rising level after a response"}]','[{"name": "ScienceDirect - BCR-ABL1 RT-qPCR for Monitoring the Molecular Response to Tyrosine Kinase Inhibitors in Chronic Myeloid Leukemia", "url": "https://www.sciencedirect.com/science/article/pii/S1525157813001001", "accessed": "2026-07-19"}, {"name": "PMC - A new highly sensitive real-time quantitative-PCR method for detection of BCR-ABL1 to monitor minimal residual disease in chronic myeloid leukemia (International Scale / MMR definitions)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6400442/", "accessed": "2026-07-19"}, {"name": "Labcorp - BCR-ABL1 Transcript Detection for CML and ALL, Quantitative (test description)", "url": "https://www.labcorp.com/tests/480481/bcr-abl1-transcript-detection-for-chronic-myelogenous-leukemia-cml-and-acute-lymphocytic-leukemia-all-quantitative", "accessed": "2026-07-19"}]',1,'2026-07-19 08:44:16','2026-07-19 08:44:16','["cbc"]',NULL,NULL,'Am I on track to meet my expected molecular response milestones for this stage of treatment? Does this result mean my current TKI is working, or should we consider a change? Could this level make me eligible for treatment-free remission in the future?','Results are tracked serially against established treatment milestones (typically at 3, 6, and 12 months after starting therapy); failure to meet expected milestones prompts assessment of medication adherence, mutation testing for TKI resistance, and consideration of switching to a different tyrosine kinase inhibitor.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (162,'aldolase','Aldolase, Serum','','Aldolase','Clinical Chemistry','Marker of muscle and liver cell damage, used to investigate suspected inflammatory myopathy (polymyositis, dermatomyositis) particularly when creatine kinase (CK) is normal, and to help distinguish muscular from neurological causes of weakness.',NULL,'Venous serum, collected in a red-top (no additive) tube','No fasting required. Recent strenuous exercise or intramuscular injections can transiently raise levels, similar to CK.',NULL,'Enzymatic (ultraviolet or coupled enzymatic) assay on automated chemistry analyzers; not offered as a routine test by all laboratories.',NULL,'[{"parameter": "Aldolase", "population": "Adult", "range": "Approximately 1.0-7.5 U/L (some sources cite up to 8.2 U/L)", "notes": "Newborns and children have higher reference ranges (up to ~4x and ~2x the adult value respectively); reference range varies by lab/method"}]',1,'Elevated aldolase supports muscle damage or an inflammatory myopathy (polymyositis, dermatomyositis, inclusion body myositis), and is particularly useful when CK is normal despite clinical suspicion of myopathy -- a pattern (isolated aldolase elevation with normal CK) seen in a meaningful subset of dermatomyositis patients, who in one Mayo Clinic cohort had less cutaneous involvement but more perifascicular mitochondrial pathology than those with elevated CK. Aldolase does not rise in weakness caused by neurological (rather than muscular) disease, making it useful for that distinction. It is nonspecific, however, and also elevated in liver disease, myocardial infarction, and some hemolytic anemias, so results are interpreted alongside CK, clinical exam, and other muscle/liver markers.',NULL,'[{"condition": "Polymyositis / dermatomyositis (especially with normal CK)", "direction": "high"}, {"condition": "Muscular dystrophy / other myopathies", "direction": "high"}, {"condition": "Liver disease (nonspecific elevation)", "direction": "high"}]','[{"name": "Medscape/eMedicine - Aldolase: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2087158-overview", "accessed": "2026-07-19"}, {"name": "PMC - Disease spectrum of myopathies with elevated aldolase and normal creatine kinase (Mayo Clinic cohort study)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC11235866/", "accessed": "2026-07-19"}]',1,'2026-07-19 08:44:16','2026-07-19 08:44:16','["creatine-kinase-total", "myoglobin"]',NULL,NULL,'Given my CK is normal, does this elevated aldolase still support a muscle disease diagnosis? Do I need a muscle biopsy to confirm? Could this be related to my liver instead of my muscles?','An elevated aldolase with clinical weakness, especially when CK is normal, typically prompts further myositis workup (autoantibody panel, EMG, muscle biopsy) with rheumatology or neurology, since this pattern can represent a distinct and treatable subset of inflammatory myopathy.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (163,'mthfr-mutation','MTHFR Mutation Testing (C677T / A1298C)','','MTHFR, MTHFR Gene Mutation','Hematology / Molecular','Detects the two most common variants (C677T and A1298C) in the MTHFR gene, which affect folate metabolism and homocysteine processing; historically ordered as part of thrombophilia panels, though current major medical society guidance does not recommend routine testing for this purpose.',NULL,'Venous whole blood, EDTA tube (lavender top)','No fasting or special preparation required; this is a DNA-based test unaffected by current physiological state.',NULL,'PCR-based genotyping detecting the specific C677T (rs1801133) and A1298C (rs1801131) single nucleotide variants.',NULL,'[{"parameter": "MTHFR C677T and A1298C", "population": "Result categories", "range": "Homozygous wild-type, heterozygous, or homozygous variant for each of the two positions -- a genetic result, not a numeric value; C677T heterozygosity occurs in ~30-40% and homozygosity in ~10-15% of White European/Hispanic populations, with substantial variation by ethnicity"}]',1,'The C677T variant reduces MTHFR enzyme activity and, particularly in the homozygous (TT) state combined with low folate status, can raise homocysteine levels. However, major medical organizations including the American College of Medical Genetics and the American Heart Association do not recommend routine MTHFR genotyping for the general population, including for most thrombophilia workups, since homocysteine level itself (rather than the genotype) is the more clinically actionable measurement -- many people with an MTHFR variant never develop elevated homocysteine, and the CDC states that finding an MTHFR mutation generally ''has no clinical implications for the patient.'' The A1298C variant alone is generally considered to have minimal clinical significance. When relevant, an elevated homocysteine (rather than the MTHFR genotype itself) is what typically prompts folate/B12/B6 supplementation.',NULL,'[{"condition": "Mildly elevated homocysteine (in homozygous C677T with low folate status)", "direction": "positive genotype, only relevant if homocysteine is also elevated"}, {"condition": "Generally minimal independent clinical significance", "direction": "positive genotype without elevated homocysteine"}]','[{"name": "World Thrombosis Day - Thrombophilia Testing and MTHFR", "url": "https://www.worldthrombosisday.org/thrombophilia-testing-and-mthfr/", "accessed": "2026-07-19"}, {"name": "AskMyDNA - MTHFR Gene Mutation Complete Guide (citing CDC and ACMG/AHA guidance)", "url": "https://www.askmydna.com/en/blog/mthfr-gene-mutation-complete-guide", "accessed": "2026-07-19"}]',1,'2026-07-19 08:44:16','2026-07-19 08:44:16','["homocysteine", "folate", "vitamin-b12"]',NULL,NULL,'Given current guidelines don''t recommend routine MTHFR testing, why was this ordered, and does the result actually change my management? Should my homocysteine level be checked directly instead of relying on this genotype result? Does this affect anything about a current or future pregnancy?','In most cases, an MTHFR result by itself does not lead to specific treatment -- your clinician will likely check (or already have checked) a homocysteine level, since that is the measurement that actually guides whether folate/B-vitamin supplementation or further workup is warranted, rather than the genotype alone.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (164,'antiphospholipid-panel','Antiphospholipid Antibody Panel (Lupus Anticoagulant, Anticardiolipin, Anti-β2-Glycoprotein I)','','APS Panel, Lupus Anticoagulant, Anticardiolipin Antibodies, Anti-B2GPI, aPL Panel','Hematology / Coagulation','Diagnoses antiphospholipid syndrome (APS), evaluated in patients with unprovoked venous or arterial thrombosis, recurrent pregnancy loss or other specific pregnancy morbidity, or an unexplained prolonged aPTT, particularly in the context of SLE or other autoimmune disease.',NULL,'Venous whole blood, sodium citrate tube (for lupus anticoagulant) plus serum (for anticardiolipin and anti-β2GPI antibodies)','Testing should ideally be done while off anticoagulation when possible, since anticoagulants can interfere with lupus anticoagulant testing; any positive result must be confirmed on a repeat sample at least 12 weeks later before a diagnosis of APS is made, since transient positivity (e.g., from acute infection) is common and not diagnostic.',NULL,'Lupus anticoagulant is detected via phospholipid-dependent clotting assays (commonly dilute Russell viper venom time [dRVVT] and a sensitive aPTT), which show prolonged clotting that doesn''t correct with a mixing study but does correct with excess phospholipid. Anticardiolipin and anti-β2-glycoprotein I antibodies (IgG, IgM, and sometimes IgA) are measured by enzyme-linked immunosorbent assay (ELISA).',NULL,'[{"parameter": "Lupus anticoagulant", "population": "Result categories", "range": "Negative or Positive -- based on a prolonged phospholipid-dependent clotting time (e.g., aPTT \u226546 sec or dRVVT \u226540 sec on some assay platforms) that fails to correct with mixing but corrects with excess phospholipid"}, {"parameter": "Anticardiolipin antibody (aCL)", "population": "Negative", "range": "IgG <19.3 U/mL, IgM <15.7 U/mL, IgA <8.2 U/mL (assay-dependent cutoffs)"}, {"parameter": "Anti-\u03b22-glycoprotein I antibody", "population": "Negative", "range": "IgG, IgM, and IgA each <20 U/mL (assay-dependent cutoffs)"}]',1,'Per the revised (Sapporo) classification criteria, a diagnosis of antiphospholipid syndrome requires at least one clinical criterion (vascular thrombosis or specific pregnancy morbidity) plus at least one of these three laboratory criteria (lupus anticoagulant, anticardiolipin IgG/IgM at medium-high titer, or anti-β2-glycoprotein I IgG/IgM), confirmed on two occasions at least 12 weeks apart. All three tests carry equal diagnostic weight, but lupus anticoagulant has been shown in multiple studies to correlate most strongly with thrombosis risk, and β2-glycoprotein I-dependent lupus anticoagulant in particular is a strong predictor. Triple positivity (all three tests positive) carries the highest risk of thrombosis and pregnancy complications. A single positive result without confirmatory repeat testing, or a low-titer result, is not sufficient for diagnosis given the risk of transient positivity from unrelated causes (infection, certain medications).',NULL,'[{"condition": "Antiphospholipid syndrome (primary or secondary to SLE)", "direction": "positive on \u22651 criterion, confirmed 12+ weeks apart"}, {"condition": "Recurrent pregnancy loss / pre-eclampsia / placental insufficiency", "direction": "positive, associated with obstetric morbidity"}, {"condition": "Unprovoked venous or arterial thrombosis", "direction": "positive, especially with triple positivity"}]','[{"name": "Mayo Clinic Laboratories - Beta-2 Glycoprotein 1 Antibodies, IgG and IgM, Serum (test catalog, 2023 ACR/EULAR criteria)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/62926", "accessed": "2026-07-19"}, {"name": "PMC - IgA Anti-\u03b22-Glycoprotein I Autoantibodies Are Associated with an Increased Risk of Thromboembolic Events in SLE (assay cutoffs)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2924386/", "accessed": "2026-07-19"}, {"name": "Blood (American Society of Hematology) - \u03b22-glycoprotein I-dependent lupus anticoagulant highly correlates with thrombosis in the antiphospholipid syndrome", "url": "https://ashpublications.org/blood/article/104/12/3598/89073/2-glycoprotein-I-dependent-lupus-anticoagulant", "accessed": "2026-07-19"}]',1,'2026-07-19 11:36:48','2026-07-19 11:36:48','["pt-inr", "aptt", "ana", "anti-dsdna", "factor-v-leiden"]',NULL,NULL,'Which of the three tests came back positive, and does that affect my risk level? Does this need to be repeated before a diagnosis is confirmed? If confirmed, do I need long-term blood thinners, and does this change how any future pregnancy would be managed?','Any positive result requires confirmatory repeat testing at least 12 weeks later before antiphospholipid syndrome can be diagnosed. A confirmed diagnosis typically leads to hematology or rheumatology-guided long-term anticoagulation planning (for those with a prior thrombosis) and, for women of childbearing age, a specific management plan for future pregnancies given the associated risks.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (165,'gad65-antibody','Glutamic Acid Decarboxylase (GAD65) Antibody','','GAD65, GAD Antibody, Anti-GAD','Immunoassay / Endocrinology','Most sensitive of the islet autoantibodies for confirming autoimmune (type 1) diabetes and distinguishing it from type 2 diabetes, including in adults with new-onset diabetes where the type is unclear (latent autoimmune diabetes of adulthood, LADA); also the recommended first-line test for suspected stiff-person syndrome and related autoimmune neurologic disorders.',NULL,'Venous serum or plasma','No fasting required. Often ordered alongside other islet autoantibodies (insulin autoantibody, IA-2 antibody, ZnT8 antibody) for a complete assessment of beta-cell autoimmunity, since no single antibody has complete sensitivity.',NULL,'Radioimmunoassay (RIA) or enzyme-linked immunosorbent assay (ELISA) detecting IgG antibodies against the 65-kDa isoform of glutamic acid decarboxylase.',NULL,'[{"parameter": "GAD65 antibody", "population": "Normal (type 1 diabetes unlikely)", "range": "\u22640.02 nmol/L"}, {"parameter": "GAD65 antibody", "population": "Positive, low titer (consistent with type 1 diabetes susceptibility)", "range": "0.03-19.9 nmol/L"}, {"parameter": "GAD65 antibody", "population": "High titer (seen in stiff-person syndrome)", "range": "\u226520.0 nmol/L"}]',1,'GAD65 antibodies are present in approximately 80% of type 1 diabetes patients at clinical presentation, the highest individual sensitivity among the islet autoantibodies (compared to roughly 54-75% for IA-2 antibody and lower for insulin autoantibody), and in less than 5% of type 2 diabetes patients, making it useful for distinguishing autoimmune from non-autoimmune diabetes, particularly in adults with an ambiguous presentation (LADA). Testing multiple islet autoantibodies together substantially increases sensitivity (up to ~96%) and helps predict future progression to type 1 diabetes in at-risk relatives -- the five-year risk of developing diabetes rises from about 17% with one positive antibody to about 70% with three. GAD65 antibodies also mark susceptibility to other autoimmune endocrine conditions that cluster with type 1 diabetes (autoimmune thyroid disease, pernicious anemia, Addison disease, premature ovarian failure), and at high titer (≥20 nmol/L) are strongly associated with stiff-person syndrome and related autoimmune neurologic disorders, a distinct clinical use for this same antibody.',NULL,'[{"condition": "Type 1 diabetes mellitus / LADA", "direction": "positive, low-moderate titer"}, {"condition": "Autoimmune polyendocrine susceptibility (thyroid disease, pernicious anemia, Addison disease)", "direction": "positive, marker of associated risk"}, {"condition": "Stiff-person syndrome / related autoimmune neurologic disorders", "direction": "high titer, \u226520 nmol/L"}]','[{"name": "Mayo Clinic Laboratories - Glutamic Acid Decarboxylase (GAD65) Antibody Assay, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/81596", "accessed": "2026-07-19"}, {"name": "ClinLab Navigator - Islet Cell Antibodies (combined sensitivity data)", "url": "https://www.clinlabnavigator.com/test-interpretations/test-interpretations-1/islet-cell-antibodies.html", "accessed": "2026-07-19"}, {"name": "Johns Hopkins Diabetes Guide - Autoantibodies in Type 1 Diabetes", "url": "https://www.hopkinsguides.com/hopkins/view/Johns_Hopkins_Diabetes_Guide/547013/all/Autoantibodies_in_Type_1_Diabetes", "accessed": "2026-07-19"}]',1,'2026-07-19 11:38:36','2026-07-19 11:38:36','["fasting-glucose", "hba1c", "c-peptide", "insulin", "anti-tpo"]',NULL,NULL,'Does this result mean I have type 1 diabetes rather than type 2? Do I need additional islet autoantibody testing (IA-2, insulin, ZnT8) for a complete picture? If I''m a relative of someone with type 1 diabetes, what does a positive result mean for my own future risk?','A positive result in someone with new-onset diabetes supports a type 1 (or LADA) diagnosis and typically changes management toward insulin therapy sooner rather than oral diabetes medications alone. In an at-risk relative without diabetes, a positive result (especially with multiple positive antibodies) prompts closer monitoring for progression, since risk rises substantially with each additional positive antibody.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (166,'c1-esterase-inhibitor','C1 Esterase Inhibitor (Quantitative and Functional)','','C1-INH, C1 Inhibitor, HAE Panel','Immunoassay / Inflammation Markers','Diagnoses hereditary or acquired angioedema (C1 esterase inhibitor deficiency), evaluated in patients with recurrent, non-itching episodes of swelling (skin, GI tract, or upper airway) without urticaria, especially with a family history or attacks unresponsive to antihistamines/steroids.',NULL,'Venous serum or plasma','Sample should be processed promptly; functional C1 inhibitor activity can be falsely reduced by transit delay, so a result down to about 40% may still be considered normal if the accompanying C4 level is also normal. Testing is ideally done between attacks for baseline assessment, though it can be checked during an acute episode if diagnosis is urgent.',NULL,'C1 esterase inhibitor antigen (protein quantity) is measured by nephelometric or turbidimetric immunoassay; C1 esterase inhibitor functional activity (how well the protein actually works) is measured by a separate chromogenic functional assay, since roughly 15% of hereditary angioedema patients have a normal or even elevated antigen level but a non-functional protein (detectable only by the functional assay).',NULL,'[{"parameter": "C1 esterase inhibitor, quantitative (antigen)", "population": "Normal", "range": "Assay-specific reference range; patients with hereditary angioedema type I typically have levels at 5-30% of normal"}, {"parameter": "C1 esterase inhibitor, functional", "population": "Normal", "range": "Assay-specific reference range; reduced in both type I and type II HAE despite a normal antigen level in type II"}]',1,'Low C1 esterase inhibitor antigen with low functional activity supports type I hereditary angioedema (about 85% of hereditary cases), caused by reduced protein production. Normal or elevated antigen with low functional activity supports type II hereditary angioedema (about 15% of cases), where the protein is present but doesn''t work -- this is why both the antigen and functional tests are needed together, since testing only the antigen level would miss type II cases. A low C1q level helps distinguish acquired angioedema (low C1q, often associated with a lymphoproliferative disorder or autoantibody) from the hereditary form (normal C1q). C4 is typically low in both hereditary and acquired forms and is often used as an accessible screening test, with C1 inhibitor testing used to confirm the diagnosis and determine the type.',NULL,'[{"condition": "Hereditary angioedema type I (low antigen and function)", "direction": "low both, ~85% of hereditary cases"}, {"condition": "Hereditary angioedema type II (normal/high antigen, low function)", "direction": "normal/high antigen, low functional activity, ~15% of hereditary cases"}, {"condition": "Acquired angioedema (associated with lymphoproliferative disease or autoantibody)", "direction": "low antigen/function with additionally low C1q"}]','[{"name": "Mayo Clinic Laboratories - C1 Esterase Inhibitor Antigen, Serum (test catalog)", "url": "https://www.mayocliniclabs.com/test-catalog/overview/8198", "accessed": "2026-07-19"}, {"name": "The Pathology Centre - C1 Esterase Inhibitor (Quantitation and Functional Level)", "url": "https://www.thepathologycentre.org/test/c1-esterase-inhibitor-quantitation-and-functional-level/", "accessed": "2026-07-19"}, {"name": "PMC - Hereditary angioedema with C1 inhibitor (C1-INH) deficit: the strength of recognition (51 cases)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6247277/", "accessed": "2026-07-19"}]',1,'2026-07-19 12:05:39','2026-07-19 12:05:39','["complement-c3", "complement-c4", "ch50"]',NULL,NULL,'Which type of angioedema does this confirm, and does that affect my treatment options? Do I need C1q testing too, to distinguish hereditary from acquired disease? Should my family members be tested, given this is often hereditary? What should I do if I have an acute attack, especially if it affects my airway?','A confirmed diagnosis leads to a personalized treatment plan that typically includes on-demand therapy for acute attacks (C1 inhibitor concentrate or other targeted therapies), consideration of long-term prophylactic medication depending on attack frequency and severity, an emergency action plan (especially for airway involvement), and often genetic counseling and testing of at-risk family members.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (167,'calcitonin','Calcitonin, Serum','','Calcitonin, CT','Immunoassay / Tumor Markers','Primary tumor marker for medullary thyroid carcinoma (MTC), used to help evaluate a thyroid nodule when MTC is suspected, and to monitor for residual or recurrent disease after thyroidectomy.',NULL,'Venous serum or plasma','No fasting required for most assays. Levels are affected by sex (higher in men) and can be falsely low in early childhood; some centers use a pentagastrin or calcium stimulation test to increase sensitivity in equivocal cases, though pentagastrin is not available in all countries.',NULL,'Chemiluminescent or immunoradiometric assay (IRMA) on automated immunoassay analyzers; assays are not fully standardized between manufacturers, so results and cutoffs can vary meaningfully by platform.',NULL,'[{"parameter": "Calcitonin", "population": "Normal", "range": "<10 pg/mL (assay-dependent; some report separate male/female cutoffs)"}, {"parameter": "Calcitonin", "population": "Suspicious for MTC (per American Thyroid Association)", "range": ">100 pg/mL"}, {"parameter": "Calcitonin", "population": "Suggests nodal metastases", "range": "~10-40 pg/mL, with tumor present"}, {"parameter": "Calcitonin", "population": "Suggests distant metastases", "range": ">150 pg/mL, often >1,000 pg/mL"}]',1,'Elevated calcitonin is produced by the parafollicular (C) cells of the thyroid and is a sensitive and fairly specific marker for medullary thyroid carcinoma, with preoperative levels correlating with tumor size, nodal involvement, and distant metastasis. A cutoff around 10 pg/mL gives high sensitivity (~91-96% in various studies) and specificity (~92-99%) for MTC in patients being evaluated for a thyroid nodule, though benign causes of mild elevation exist (C-cell hyperplasia, renal failure, some neuroendocrine tumors, proton pump inhibitor use, and hypergastrinemia). After thyroidectomy for confirmed MTC, calcitonin is used serially to monitor for residual disease or recurrence -- normalization suggests no residual disease outside the thyroid, while a persistently detectable or rising level after surgery suggests residual or recurrent tumor.',NULL,'[{"condition": "Medullary thyroid carcinoma (diagnosis, staging, and postoperative monitoring)", "direction": "high, correlates with tumor burden"}, {"condition": "C-cell hyperplasia / benign causes (renal failure, hypergastrinemia, PPI use)", "direction": "mild elevation, non-malignant cause"}]','[{"name": "PMC - Current Understanding and Management of Medullary Thyroid Cancer", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC3805151/", "accessed": "2026-07-19"}, {"name": "American Thyroid Association - Calcitonin for Patients (Vol 12 Issue 8)", "url": "https://www.thyroid.org/patient-thyroid-information/ct-for-patients/august-2019/vol-12-issue-8-p-9-10/", "accessed": "2026-07-19"}]',1,'2026-07-19 12:14:38','2026-07-19 12:14:38','["tsh", "free-t4", "cea"]',NULL,NULL,'Given this level, how likely is it that I have medullary thyroid cancer, and do I need further testing (like a stimulation test or imaging)? If I''ve already had surgery for MTC, does this result mean I still have residual disease? Should my family be screened for MEN2, given that MTC can be hereditary?','A markedly elevated result in someone with a thyroid nodule typically leads to fine-needle aspiration biopsy (with calcitonin washout testing if needed) and, if MTC is confirmed, genetic testing for RET proto-oncogene mutations, since about 20% of MTC is hereditary (part of MEN2 syndrome) and family screening may be needed. After surgery, persistently elevated or rising calcitonin prompts further imaging to locate residual or recurrent disease.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (168,'anti-mitochondrial-antibody','Anti-Mitochondrial Antibody (AMA)','','AMA, Anti-Mitochondrial Antibody','Immunoassay / Inflammation Markers','Serologic hallmark of primary biliary cholangitis (PBC, formerly primary biliary cirrhosis), used to investigate unexplained cholestatic liver enzyme elevation (particularly a disproportionately high alkaline phosphatase), especially in middle-aged women with fatigue or itching.',NULL,'Venous serum or plasma','No fasting required. Usually ordered alongside a full liver panel and, if AMA is negative but suspicion remains high, PBC-specific antinuclear antibodies (anti-sp100, anti-gp210).',NULL,'Indirect immunofluorescence assay (IFA) on rodent tissue sections (the traditional reference method) or solid-phase immunoassays (ELISA) targeting the M2 mitochondrial antigen (AMA-M2), which is the clinically relevant subtype in PBC.',NULL,'[{"parameter": "AMA", "population": "Result categories", "range": "Negative or Positive (with titer if using immunofluorescence) -- a qualitative/semi-quantitative result, not a single numeric value"}]',1,'AMA is detected in approximately 90-95% of patients with primary biliary cholangitis and is uncommon in other conditions, making it highly useful diagnostically -- per current diagnostic criteria, PBC can be diagnosed with a compatible cholestatic liver enzyme pattern (elevated ALP) plus a positive AMA, without requiring liver biopsy in typical cases. Roughly 5-15% of patients with clinical, biochemical, and histologic features of PBC are AMA-negative; in this group, testing for PBC-specific antinuclear antibodies (anti-sp100, anti-gp210) can help confirm the diagnosis, since these are highly specific (though less sensitive) alternatives. AMA-negative PBC appears clinically similar to AMA-positive disease in most respects, though some studies suggest a potentially more severe course.',NULL,'[{"condition": "Primary biliary cholangitis", "direction": "positive in ~90-95% of cases"}, {"condition": "AMA-negative PBC (requires anti-sp100/anti-gp210 or biopsy to confirm)", "direction": "negative despite compatible clinical/biochemical/histologic picture"}]','[{"name": "PMC - Antimitochondrial Antibody-Negative Primary Biliary Cholangitis: A Retrospective Diagnosis", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC10106268/", "accessed": "2026-07-19"}, {"name": "PMC - Anti-mitochondrial autoantibodies-milestone or byway to primary biliary cholangitis?", "url": "https://pmc.ncbi.nlm.nih.gov/articles/PMC5326641/", "accessed": "2026-07-19"}]',1,'2026-07-19 12:14:38','2026-07-19 12:14:38','["alkaline-phosphatase", "ggt", "alt-ast", "total-bilirubin"]',NULL,NULL,'Does this confirm a diagnosis of PBC, or do I need a liver biopsy as well? If negative but my liver tests still suggest PBC, do I need the additional antibody tests (anti-sp100, anti-gp210)? What treatment is recommended, and how will my response be monitored?','A positive AMA with a compatible cholestatic liver enzyme pattern generally confirms the diagnosis and leads to starting ursodeoxycholic acid (UDCA), the standard first-line treatment, with periodic monitoring of liver tests to assess response. A negative AMA with strong clinical suspicion leads to further antibody testing or liver biopsy before treatment is started.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (169,'anti-smooth-muscle-antibody','Anti-Smooth Muscle Antibody (ASMA)','','ASMA, SMA, Anti-Smooth Muscle Antibody','Immunoassay / Inflammation Markers','Supports the diagnosis of autoimmune hepatitis (particularly type 1), used to investigate unexplained elevated liver enzymes with a hepatocellular (rather than cholestatic) pattern, especially in young to middle-aged women.',NULL,'Venous serum or plasma','No fasting required. Typically ordered alongside ANA, immunoglobulin levels (especially IgG), and a full liver panel as part of the autoimmune hepatitis diagnostic score.',NULL,'Indirect immunofluorescence assay on rodent tissue sections, looking for staining of actin filaments in smooth muscle; anti-actin antibody testing (a more specific ELISA-based test for the F-actin target) is sometimes used as a follow-up or alternative.',NULL,'[{"parameter": "ASMA", "population": "Result categories", "range": "Negative or Positive (with titer if using immunofluorescence) -- a qualitative/semi-quantitative result"}]',1,'A positive ASMA, together with elevated IgG, a hepatocellular pattern of liver enzyme elevation, and compatible histology, supports a diagnosis of type 1 autoimmune hepatitis (the most common form) -- ASMA is often positive alongside or instead of ANA in this condition, and the two are frequently tested together as part of a validated diagnostic scoring system. ASMA is not specific to autoimmune hepatitis alone and can be seen at low titer in other liver diseases and some infections, so it is interpreted alongside the full clinical, biochemical, and (when needed) histologic picture rather than used as a standalone diagnostic test.',NULL,'[{"condition": "Type 1 autoimmune hepatitis", "direction": "positive, especially at higher titer with elevated IgG"}, {"condition": "Other liver diseases / infections (lower-titer, less specific finding)", "direction": "positive, low titer, non-diagnostic alone"}]','[{"name": "Karger - Distinction between Mitochondrial Antibody-Positive and -Negative Primary Biliary Cholangitis (ASMA testing context)", "url": "https://karger.com/crg/article/17/1/14/832394/Distinction-between-Mitochondrial-Antibody", "accessed": "2026-07-19"}, {"name": "Rare Disease Advisor - Primary Biliary Cholangitis Types (diagnostic criteria referencing ASMA)", "url": "https://www.rarediseaseadvisor.com/hcp-resource/primary-biliary-cholangitis-types/", "accessed": "2026-07-19"}]',1,'2026-07-19 12:14:38','2026-07-19 12:14:38','["alt-ast", "ana", "alkaline-phosphatase"]',NULL,NULL,'Does this, combined with my liver enzyme pattern and IgG level, support autoimmune hepatitis? Do I need a liver biopsy to confirm before starting treatment? What treatment (and how long) is typically needed for this condition?','A positive result with a compatible clinical and biochemical picture typically leads to liver biopsy to confirm the diagnosis and assess severity before starting immunosuppressive treatment (commonly corticosteroids with or without azathioprine), which is usually needed long-term with periodic monitoring of liver enzymes and immunoglobulin levels.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (170,'vitamin-b6','Vitamin B6 (Pyridoxal 5''-Phosphate, PLP)','','Vitamin B6, PLP, Pyridoxine','Clinical Chemistry','Evaluates suspected vitamin B6 deficiency, evaluated in patients with peripheral neuropathy, certain anemias, or seizures (especially pyridoxine-dependent seizures in infants), and used to guide supplementation dosing.',NULL,'Venous plasma (EDTA) or serum','Sample should be protected from light and processed/frozen promptly, since PLP degrades at room temperature and with light exposure; low albumin states can also affect the result since PLP binds tightly to albumin.',NULL,'High-performance liquid chromatography (HPLC) with fluorescence detection, or HPLC coupled to tandem mass spectrometry.',NULL,'[{"parameter": "Plasma PLP", "population": "Normal", "range": "20-200 nmol/L, with adequate status generally defined as >30 nmol/L"}]',1,'Low PLP indicates vitamin B6 deficiency, which can cause peripheral neuropathy, seizures (notably pyridoxine-dependent epilepsy in infants, a rare but treatable cause of neonatal seizures), sideroblastic anemia, and dermatitis; common causes include poor dietary intake, alcohol use disorder, certain medications (isoniazid, some anticonvulsants, penicillamine), and malabsorption. Results can be confounded by low albumin, elevated alkaline phosphatase, inflammation, and pregnancy, all of which can lower plasma PLP independent of true vitamin B6 status -- red cell PLP or functional enzyme activity assays are sometimes used to clarify borderline results in these situations.',NULL,'[{"condition": "Vitamin B6 deficiency (dietary, alcohol use, malabsorption, certain medications)", "direction": "low"}, {"condition": "Pyridoxine-dependent seizures (infants)", "direction": "responds to B6 supplementation; PLP level itself may be normal, since the disorder is in PLP-dependent enzyme function"}]','[{"name": "droracle.ai - Which laboratory test best assesses pyridoxine (vitamin B6) status (clinical synthesis)", "url": "https://www.droracle.ai/articles/887154/which-laboratory-test-best-assesses-pyridoxine-vitamin-b6-status", "accessed": "2026-07-19"}, {"name": "Medscape/eMedicine - Vitamin B6: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2088627-overview", "accessed": "2026-07-19"}]',1,'2026-07-19 12:14:38','2026-07-19 12:14:38','["vitamin-b12", "folate", "homocysteine"]',NULL,NULL,'Could a medication I''m taking (like isoniazid) be causing this deficiency? Do I need supplementation, and for how long? Could my low albumin or another condition be affecting the accuracy of this result?','Confirmed deficiency is treated with oral pyridoxine supplementation, with attention to the underlying cause (medication review, alcohol use, dietary intake) and, in some cases, a repeat level after a period of supplementation to confirm response.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (171,'vitamin-a','Vitamin A (Retinol), Serum','','Vitamin A, Retinol','Clinical Chemistry','Evaluates suspected vitamin A deficiency (a leading cause of preventable blindness worldwide) or, less commonly, suspected toxicity from excessive supplementation; relevant in malabsorption syndromes, chronic liver disease, and unexplained night blindness or dry eyes.',NULL,'Venous serum or plasma, protected from light','Sample should be protected from light and processed promptly, since retinol degrades on light exposure; fasting is generally preferred.',NULL,'High-performance liquid chromatography (HPLC).',NULL,'[{"parameter": "Serum retinol", "population": "Moderate deficiency", "range": "\u226420 mcg/dL (\u22640.70 \u00b5mol/L)"}, {"parameter": "Serum retinol", "population": "Severe deficiency", "range": "\u226410 mcg/dL (\u22640.35 \u00b5mol/L)"}]',1,'Low serum retinol supports vitamin A deficiency, which classically causes night blindness progressing to xerophthalmia and, if untreated, irreversible blindness, along with impaired immune function; common causes in adults include fat malabsorption (celiac disease, cystic fibrosis, chronic pancreatitis, bariatric surgery), chronic liver disease, and severely restricted diets. Serum retinol is tightly homeostatically regulated by the liver until stores are substantially depleted, so a normal level does not fully exclude early or mild deficiency, and it can also be falsely lowered by acute inflammation (as a negative acute-phase reactant) independent of true vitamin A status. Excess vitamin A (from high-dose supplementation) can cause toxicity (headache, bone pain, liver injury, and birth defects if taken in excess during pregnancy), which is a different clinical concern from deficiency and generally requires assessing supplement/dietary intake rather than serum retinol alone, since retinol doesn''t rise proportionally with intake once stores are replete.',NULL,'[{"condition": "Vitamin A deficiency (dietary, malabsorption, chronic liver disease)", "direction": "low"}, {"condition": "Night blindness / xerophthalmia", "direction": "low, with compatible symptoms"}, {"condition": "Vitamin A toxicity (excessive supplementation)", "direction": "assessed via intake history more than serum level alone"}]','[{"name": "NIH Office of Dietary Supplements - Vitamin A and Carotenoids: Health Professional Fact Sheet", "url": "https://ods.od.nih.gov/factsheets/VitaminA-HealthProfessional/", "accessed": "2026-07-19"}]',1,'2026-07-19 12:14:38','2026-07-19 12:14:38','["vitamin-d", "vitamin-k", "zinc"]',NULL,NULL,'Does this level explain my eye or skin symptoms? Do I need supplementation, and at what dose, given the risk of toxicity with excessive intake? Could inflammation or another condition be affecting this result independent of my true vitamin A status?','Confirmed deficiency is treated with vitamin A supplementation at a dose tailored to severity, with monitoring given the narrow margin between adequate replacement and toxicity, and investigation of the underlying cause (malabsorption, liver disease, dietary intake) addressed where possible.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (172,'vancomycin-level','Vancomycin, Serum/Plasma (Therapeutic Drug Monitoring)','','Vancomycin Trough, Vancomycin Level, TDM Vancomycin','Clinical Chemistry / Therapeutic Drug Monitoring','Guides dosing of IV vancomycin in patients being treated for serious gram-positive infections (including MRSA), balancing adequate antibacterial exposure against the risk of nephrotoxicity.',NULL,'Venous serum or plasma (trough, drawn 0-1 hour before the next dose at steady state, usually before the 4th dose)','Trough sampling timing relative to the dose is critical to interpretation; many centers are shifting to AUC-guided dosing (24-hour area under the curve divided by minimum inhibitory concentration, target AUC/MIC 400-600) rather than trough alone, per 2020 consensus guidelines, which requires two timed levels rather than a single trough.',NULL,'Immunoassay (e.g., particle-enhanced turbidimetric inhibition immunoassay or chemiluminescent microparticle immunoassay) on automated chemistry/immunoassay analyzers.',NULL,'[{"parameter": "Trough (standard target, most infections)", "population": "Adult", "range": "10-15 mcg/mL"}, {"parameter": "Trough (target for MIC \u22651, complicated infections e.g. endocarditis, osteomyelitis, meningitis)", "population": "Adult", "range": "15-20 mcg/mL"}, {"parameter": "Peak (rarely used for dosing decisions)", "population": "Adult", "range": "20-40 mcg/mL"}]',1,'Troughs below about 10 mcg/mL are associated with inadequate therapy and a higher risk of selecting for resistant organisms, while troughs at or above roughly 15-20 mcg/mL (or an AUC/MIC below the 400-600 target) are associated with a materially higher risk of vancomycin-induced nephrotoxicity, especially with concurrent nephrotoxins such as aminoglycosides or prolonged courses. Because trough concentration correlates imperfectly with total drug exposure (AUC), many hospital pharmacies now use AUC-guided (Bayesian) dosing software with two timed levels per course, reserving trough-only monitoring for simpler regimens or where AUC software is unavailable.',NULL,'[{"condition": "Subtherapeutic exposure / risk of treatment failure or resistance", "direction": "trough or AUC below target"}, {"condition": "Vancomycin-induced nephrotoxicity risk", "direction": "trough >15-20 mcg/mL or AUC/MIC persistently >600, especially with other nephrotoxins"}]','[{"name": "Medscape/eMedicine - Vancomycin Level: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2090484-overview", "accessed": "2026-07-20"}, {"name": "PMC - Evaluation of Therapeutic Vancomycin Monitoring (AUC/MIC vs trough)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9045330/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["serum-creatinine", "blood-urea-nitrogen", "complete-blood-count"]',NULL,NULL,'Is my current dose achieving the AUC/MIC target, or only a trough target? How is my kidney function being monitored while on this drug, and how often will levels be rechecked?','Levels outside target prompt a dose or interval adjustment by the treating team or clinical pharmacist, with a repeat level after the new dose reaches steady state (typically after 3-5 doses, sooner in renal impairment); renal function (creatinine, BUN) is monitored in parallel throughout therapy.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (173,'phenytoin-level','Phenytoin, Total and Free, Serum (Therapeutic Drug Monitoring)','','Phenytoin Level, Dilantin Level, TDM Phenytoin','Clinical Chemistry / Therapeutic Drug Monitoring','Guides dosing of phenytoin in patients treated for seizure disorders, confirms adherence, and investigates suspected toxicity or breakthrough seizures.',NULL,'Venous serum or plasma (trough, just before the next dose)','Total phenytoin is affected by protein binding; free (unbound) phenytoin should be measured directly in patients with hypoalbuminemia, renal failure, pregnancy, or concurrent highly protein-bound drugs (e.g., valproic acid) since total levels can be misleading in these situations.',NULL,'Immunoassay on automated analyzers, or HPLC for free-fraction measurement after ultrafiltration.',NULL,'[{"parameter": "Total phenytoin", "population": "Adult, steady state", "range": "10-20 mcg/mL"}, {"parameter": "Free phenytoin", "population": "Adult, steady state", "range": "1.0-2.0 mcg/mL (8-14% of total)"}, {"parameter": "Total phenytoin, toxic", "population": "Adult", "range": ">30 mcg/mL associated with clinical toxicity"}]',1,'Levels below 10 mcg/mL are frequently associated with inadequate seizure control, while levels above 20 mcg/mL (total) increasingly carry a risk of dose-related toxicity, classically nystagmus, ataxia, and sedation at higher levels, progressing to encephalopathy at very high concentrations. Because phenytoin follows non-linear (zero-order, saturable) kinetics near the therapeutic range, small dose increases can cause disproportionately large rises in serum level, which is why frequent monitoring is used during dose titration.',NULL,'[{"condition": "Subtherapeutic phenytoin (breakthrough seizures, non-adherence)", "direction": "low"}, {"condition": "Phenytoin toxicity (nystagmus, ataxia, sedation, encephalopathy at extreme levels)", "direction": "high, especially free fraction"}]','[{"name": "StatPearls / NCBI Bookshelf - Phenytoin", "url": "https://www.ncbi.nlm.nih.gov/books/NBK551520/", "accessed": "2026-07-20"}, {"name": "Mayo Clinic Laboratories Therapeutics Catalog - Phenytoin, Total and Free, Serum", "url": "https://therapeutics.testcatalog.org/show/PNTFT", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["albumin-serum", "valproic-acid-level"]',NULL,NULL,'Should my free phenytoin level be checked given my albumin/kidney function, rather than relying on the total level alone? Could an interacting drug (like valproic acid) be affecting this result?','Dose adjustments are typically small given the non-linear kinetics near the therapeutic range, with a repeat level after roughly 1-2 weeks (steady state) to confirm the new dose is appropriate; free-level testing is pursued when the clinical picture and total level disagree.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (174,'valproic-acid-level','Valproic Acid, Serum (Therapeutic Drug Monitoring)','','Valproate Level, VPA Level, Depakote Level','Clinical Chemistry / Therapeutic Drug Monitoring','Guides dosing of valproic acid used for seizure disorders, bipolar disorder, and migraine prophylaxis, and investigates suspected toxicity, non-adherence, or breakthrough symptoms.',NULL,'Venous serum or plasma (trough, just before the next dose)','Free (unbound) valproic acid is preferred over total level in hypoalbuminemia, renal failure, pregnancy, or with interacting highly protein-bound drugs (e.g., phenytoin, aspirin), since valproic acid is heavily protein bound (~90%) and its free fraction rises disproportionately as albumin falls.',NULL,'Immunoassay on automated analyzers.',NULL,'[{"parameter": "Total valproic acid", "population": "Adult, steady state", "range": "50-100 mcg/mL"}, {"parameter": "Free valproic acid", "population": "Adult, steady state", "range": "2.5-20 mcg/mL (unbound fraction rises with hypoalbuminemia)"}, {"parameter": "Total valproic acid, toxic", "population": "Adult", "range": ">100-150 mcg/mL associated with toxicity"}]',1,'Subtherapeutic levels are associated with inadequate seizure or mood control, while levels above roughly 100-150 mcg/mL are increasingly associated with sedation, tremor, thrombocytopenia, hyperammonemic encephalopathy, and (rarely) fatal hepatotoxicity or pancreatitis; the drug also carries significant teratogenic risk, so it is generally avoided in women of childbearing potential when alternatives exist. Because total level can be misleading when albumin is low, the free fraction is the more reliable indicator of drug exposure in critically ill, elderly, pregnant, or hypoalbuminemic patients.',NULL,'[{"condition": "Subtherapeutic valproic acid (breakthrough seizures/mood symptoms, non-adherence)", "direction": "low"}, {"condition": "Valproic acid toxicity (sedation, tremor, thrombocytopenia, hyperammonemia, hepatotoxicity)", "direction": "high, especially free fraction"}]','[{"name": "PMC - TDM of Phenytoin and Valproic Acid in Critically Ill Patients", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9350491/", "accessed": "2026-07-20"}, {"name": "MedlinePlus Medical Encyclopedia - Therapeutic Drug Levels", "url": "https://medlineplus.gov/ency/article/003430.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["albumin-serum", "phenytoin-level", "ammonia-blood"]',NULL,NULL,'Given my albumin level, should the free valproic acid level be checked instead of relying on total? Should my liver enzymes, platelet count, and ammonia be monitored alongside this?','Confirmed subtherapeutic or toxic levels lead to dose adjustment with a repeat level once steady state is reached (about 3-4 days); periodic liver function tests, platelet counts, and ammonia are typically monitored alongside long-term therapy.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (175,'carbamazepine-level','Carbamazepine, Serum (Therapeutic Drug Monitoring)','','Carbamazepine Level, Tegretol Level, TDM Carbamazepine','Clinical Chemistry / Therapeutic Drug Monitoring','Guides dosing of carbamazepine used for seizure disorders, trigeminal neuralgia, and bipolar disorder, confirms adherence, and investigates suspected toxicity.',NULL,'Venous serum or plasma (trough, just before the next dose)','Carbamazepine induces its own hepatic metabolism (autoinduction) over the first several weeks of therapy, so levels typically fall after initial dosing and require re-checking once autoinduction is complete (usually 2-4 weeks).',NULL,'Immunoassay on automated analyzers.',NULL,'[{"parameter": "Carbamazepine, trough", "population": "Adult, steady state", "range": "4-12 mcg/mL"}, {"parameter": "Carbamazepine, toxic", "population": "Adult", "range": ">15 mcg/mL associated with toxicity in most patients"}]',1,'Levels below 4 mcg/mL are often associated with inadequate seizure control, while levels above roughly 12-15 mcg/mL are increasingly associated with dose-related toxicity: diplopia, ataxia, dizziness, and sedation, progressing to more severe neurotoxicity at higher levels. Carbamazepine also carries idiosyncratic risks unrelated to serum level, including hyponatremia (SIADH-like effect), agranulocytosis/aplastic anemia, and severe cutaneous reactions (Stevens-Johnson syndrome/toxic epidermal necrolysis), the last of which is strongly linked to the HLA-B*15:02 allele in patients of Southeast and East Asian ancestry, for whom genetic screening is recommended before starting the drug.',NULL,'[{"condition": "Subtherapeutic carbamazepine (breakthrough seizures, autoinduction-related fall in level)", "direction": "low"}, {"condition": "Carbamazepine toxicity (diplopia, ataxia, sedation)", "direction": "high"}, {"condition": "Idiosyncratic reactions (hyponatremia, blood dyscrasias, severe skin reactions)", "direction": "not level-dependent; monitored separately"}]','[{"name": "MedlinePlus Medical Encyclopedia - Therapeutic Drug Levels", "url": "https://medlineplus.gov/ency/article/003430.htm", "accessed": "2026-07-20"}, {"name": "GGC Medicines - Therapeutic Drug Monitoring Target Concentration Ranges", "url": "https://handbook.ggcmedicines.org.uk/guidelines/appendices/appendix-3-therapeutic-drug-monitoring-target-concentration-ranges/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["sodium-na", "complete-blood-count", "alt-ast"]',NULL,NULL,'Since this drug can lower its own level over time through autoinduction, when should this be rechecked after starting or changing my dose? Do I need HLA-B*15:02 screening or monitoring of my sodium and blood counts?','A subtherapeutic level in the first weeks of treatment is often expected due to autoinduction and re-checked after 2-4 weeks; sodium, complete blood count, and liver enzymes are typically monitored periodically during long-term therapy independent of the drug level itself.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (176,'tacrolimus-level','Tacrolimus, Whole Blood (Therapeutic Drug Monitoring)','','Tacrolimus Trough, FK506 Level, TDM Tacrolimus','Clinical Chemistry / Therapeutic Drug Monitoring','Guides dosing of tacrolimus, a calcineurin-inhibitor immunosuppressant used after solid organ transplantation, balancing prevention of graft rejection against nephrotoxicity and infection risk.',NULL,'Whole blood (EDTA), trough, drawn immediately before the next dose','Target trough ranges differ substantially by transplanted organ, time since transplant, and concurrent immunosuppressants, so results must be interpreted against the specific center''s protocol rather than a single universal range; generic-to-brand or between-generic switches can also meaningfully change levels.',NULL,'Chemiluminescent microparticle immunoassay (CMIA) or liquid chromatography-tandem mass spectrometry (LC-MS/MS, the more specific reference method).',NULL,'[{"parameter": "Trough, early post-transplant (first 1-3 months, varies by organ/protocol)", "population": "Adult", "range": "commonly 8-15 ng/mL"}, {"parameter": "Trough, maintenance phase (varies by organ/protocol)", "population": "Adult", "range": "commonly 5-10 ng/mL, sometimes lower with combination therapy"}]',1,'Subtherapeutic tacrolimus increases the risk of acute or chronic graft rejection, while excessive levels increase the risk of nephrotoxicity, neurotoxicity (tremor, headache, posterior reversible encephalopathy syndrome in severe cases), new-onset diabetes after transplant, and opportunistic infection from over-immunosuppression. Because the therapeutic window is narrow and levels are affected by numerous drug interactions (notably CYP3A4 inhibitors like azole antifungals and inducers like rifampin) and by food (grapefruit), close, protocol-driven trough monitoring is standard throughout the life of the transplant.',NULL,'[{"condition": "Acute or chronic graft rejection risk", "direction": "trough below target range"}, {"condition": "Tacrolimus toxicity (nephrotoxicity, tremor, new-onset diabetes, opportunistic infection)", "direction": "trough above target range"}]','[{"name": "PMC - Identification of Critical Values in Therapeutic Drug Monitoring (tacrolimus trough context)", "url": "https://www.nature.com/articles/s41598-024-62402-7", "accessed": "2026-07-20"}, {"name": "MedlinePlus Medical Encyclopedia - Therapeutic Drug Levels", "url": "https://medlineplus.gov/ency/article/003430.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["serum-creatinine", "fasting-plasma-glucose"]',NULL,NULL,'What is my specific target trough range at this point post-transplant? Could a medication I recently started or stopped be interacting with this drug and affecting my level?','Levels outside the center''s target range prompt a dose adjustment by the transplant team, with a repeat trough after steady state (roughly 2-3 days given the drug''s half-life), alongside monitoring of kidney function, glucose, and, when relevant, a biopsy if rejection is suspected despite adequate levels.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (177,'cyclosporine-level','Cyclosporine, Whole Blood (Therapeutic Drug Monitoring)','','Cyclosporine Trough, Ciclosporin Level, TDM Cyclosporine','Clinical Chemistry / Therapeutic Drug Monitoring','Guides dosing of cyclosporine, a calcineurin-inhibitor immunosuppressant used after solid organ or bone marrow transplantation and in some autoimmune conditions, balancing efficacy against nephrotoxicity.',NULL,'Whole blood (EDTA), trough (C0) or 2-hour post-dose (C2) depending on protocol','Some transplant centers use C2 (2-hour post-dose) monitoring rather than trough, since it correlates better with total drug exposure (AUC) for cyclosporine specifically; sample timing must match the protocol being used for the result to be interpretable.',NULL,'Chemiluminescent microparticle immunoassay (CMIA) or LC-MS/MS (reference method).',NULL,'[{"parameter": "Trough (C0), varies by organ/protocol and time post-transplant", "population": "Adult", "range": "commonly 100-400 ng/mL depending on phase of treatment"}, {"parameter": "2-hour post-dose (C2), where used", "population": "Adult", "range": "protocol-specific, generally higher than trough targets"}]',1,'As with tacrolimus, subtherapeutic cyclosporine raises rejection risk while excessive levels raise the risk of nephrotoxicity, hypertension, hirsutism, gingival hyperplasia, and neurotoxicity; the therapeutic window is narrow and levels are sensitive to the same major drug and food interactions (CYP3A4 inhibitors/inducers, grapefruit) as tacrolimus. Target ranges are set by the transplant center''s protocol and vary by organ transplanted, time since transplant, and whether the center uses trough or C2 monitoring, so results should be interpreted against that specific protocol.',NULL,'[{"condition": "Acute or chronic graft rejection risk", "direction": "level below target range"}, {"condition": "Cyclosporine toxicity (nephrotoxicity, hypertension, hirsutism, gingival hyperplasia)", "direction": "level above target range"}]','[{"name": "MedlinePlus Medical Encyclopedia - Therapeutic Drug Levels", "url": "https://medlineplus.gov/ency/article/003430.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["serum-creatinine", "lipid-panel"]',NULL,NULL,'Is my center using trough or 2-hour post-dose monitoring, and what is my current target range? Could a new medication be interacting with my cyclosporine dose?','Levels outside target prompt dose adjustment with a repeat level at steady state, alongside monitoring of kidney function, blood pressure, and lipid profile as part of routine post-transplant follow-up.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (178,'gentamicin-level','Gentamicin, Serum (Therapeutic Drug Monitoring)','','Gentamicin Peak and Trough, TDM Gentamicin','Clinical Chemistry / Therapeutic Drug Monitoring','Guides dosing of the aminoglycoside antibiotic gentamicin, balancing adequate antibacterial exposure (peak-dependent killing) against dose-related nephrotoxicity and ototoxicity (trough-dependent accumulation).',NULL,'Venous serum, both peak (30-60 minutes after infusion ends) and trough (just before the next dose) depending on dosing strategy used','With extended-interval (once-daily) dosing, which is now standard for most indications, a single random level plotted on a nomogram (e.g., Hartford nomogram) is often used instead of separate peak/trough sampling; traditional multiple-daily dosing still uses paired peak and trough levels.',NULL,'Immunoassay on automated analyzers.',NULL,'[{"parameter": "Peak, traditional multiple-daily dosing", "population": "Adult", "range": "5-10 mcg/mL (higher, e.g. 8-10, for serious infections)"}, {"parameter": "Trough, traditional multiple-daily dosing", "population": "Adult", "range": "<2 mcg/mL"}]',1,'Inadequate peak concentrations risk undertreatment, since aminoglycosides exhibit concentration-dependent bacterial killing, while elevated troughs (drug accumulation between doses) are the main driver of nephrotoxicity and irreversible ototoxicity/vestibulotoxicity. Extended-interval (once-daily) dosing was developed specifically to maximize the peak-dependent killing effect while allowing a longer drug-free interval that reduces accumulation-related toxicity compared with older multiple-daily-dose regimens.',NULL,'[{"condition": "Subtherapeutic peak (risk of inadequate antibacterial effect)", "direction": "low peak"}, {"condition": "Aminoglycoside nephrotoxicity / ototoxicity risk", "direction": "elevated trough or cumulative exposure, especially with prolonged courses or other nephrotoxins"}]','[{"name": "MedlinePlus Medical Encyclopedia - Therapeutic Drug Levels", "url": "https://medlineplus.gov/ency/article/003430.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["serum-creatinine", "blood-urea-nitrogen"]',NULL,NULL,'Am I on extended-interval or traditional dosing, and how does that affect when my levels are drawn? How is my kidney function and hearing being monitored during this course?','Levels outside target prompt dose or interval adjustment, with renal function monitored throughout the course; therapy exceeding about 5-7 days generally warrants closer monitoring given cumulative toxicity risk.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (179,'theophylline-level','Theophylline, Serum (Therapeutic Drug Monitoring)','','Theophylline Level, TDM Theophylline','Clinical Chemistry / Therapeutic Drug Monitoring','Guides dosing of theophylline, occasionally used for chronic obstructive pulmonary disease or asthma when other therapies are insufficient, given its narrow therapeutic index.',NULL,'Venous serum or plasma, timing depends on formulation (trough for sustained-release oral dosing, timed level for IV infusion)','Theophylline clearance is affected by numerous factors including smoking (increases clearance), liver disease and heart failure (decrease clearance), and many drug interactions (e.g., certain macrolides and fluoroquinolones raise levels), all of which affect how a given dose translates to serum concentration.',NULL,'Immunoassay on automated analyzers.',NULL,'[{"parameter": "Theophylline, therapeutic", "population": "Adult", "range": "8-20 mcg/mL (narrower target of 10-15 often used to reduce toxicity risk)"}, {"parameter": "Theophylline, toxic", "population": "Adult", "range": ">20 mcg/mL associated with increasing risk of toxicity"}]',1,'Levels below the therapeutic range are associated with inadequate bronchodilator effect, while levels above roughly 20 mcg/mL are associated with a graded risk of toxicity: nausea, tremor, and tachycardia at moderately elevated levels, progressing to arrhythmias and seizures at higher levels, which can occur even without milder warning symptoms first. Given the narrow therapeutic index and the many factors that alter its clearance, theophylline has been largely superseded by other bronchodilators and inhaled corticosteroids in most patients, and is now reserved for select cases where monitoring is feasible.',NULL,'[{"condition": "Subtherapeutic theophylline (inadequate bronchodilation)", "direction": "low"}, {"condition": "Theophylline toxicity (nausea, tremor, tachyarrhythmia, seizures at high levels)", "direction": "high, particularly >20 mcg/mL"}]','[{"name": "MedlinePlus Medical Encyclopedia - Therapeutic Drug Levels", "url": "https://medlineplus.gov/ency/article/003430.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["complete-blood-count"]',NULL,NULL,'Could smoking status, my other medications, or my liver/heart function be changing how my body clears this drug? What symptoms of toxicity should prompt me to seek care before my next scheduled level?','Levels outside target prompt a dose adjustment and repeat level at steady state; new symptoms suggestive of toxicity (persistent vomiting, palpitations, tremor) warrant urgent evaluation rather than waiting for a scheduled level.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (180,'methotrexate-level','Methotrexate, Serum (Therapeutic Drug Monitoring, High-Dose)','','Methotrexate Level, MTX Level, TDM Methotrexate','Clinical Chemistry / Therapeutic Drug Monitoring','Monitors clearance of high-dose intravenous methotrexate given for certain cancers (e.g., osteosarcoma, some leukemias/lymphomas), timing and dosing of the rescue agent leucovorin (folinic acid), and identifying patients at risk for delayed methotrexate elimination and toxicity.',NULL,'Venous serum or plasma, drawn at specified timepoints after the infusion (e.g., 24, 48, and 72 hours post-dose per institutional protocol)','This test is specific to high-dose methotrexate protocols with leucovorin rescue; it is not used to monitor the much lower weekly doses used for rheumatoid arthritis or psoriasis, where clinical response and standard toxicity labs (CBC, liver enzymes, renal function) are used instead.',NULL,'Immunoassay (e.g., fluorescence polarization immunoassay or enzyme immunoassay) on automated analyzers; some centers use HPLC for greater specificity, particularly to avoid cross-reactivity with the DAMPA metabolite formed during glucarpidase rescue therapy.',NULL,'[{"parameter": "24 hours post-infusion, expected clearance", "population": "Per institutional protocol", "range": "typically <10 micromol/L"}, {"parameter": "48 hours post-infusion, expected clearance", "population": "Per institutional protocol", "range": "typically <1 micromol/L"}, {"parameter": "72 hours post-infusion, expected clearance", "population": "Per institutional protocol", "range": "typically <0.1 micromol/L"}]',1,'Methotrexate levels above the expected clearance curve at any monitoring timepoint indicate delayed elimination, which sharply increases the risk of severe, potentially fatal toxicity: myelosuppression, mucositis, hepatotoxicity, and nephrotoxicity from precipitation of methotrexate and its metabolites in the renal tubules. Delayed clearance most often reflects renal impairment (methotrexate is cleared primarily by the kidneys), third-spacing of fluid (ascites, pleural effusion), or drug interactions, and prompts intensified leucovorin rescue, aggressive hydration and urinary alkalinization, and in severe cases the enzyme glucarpidase to rapidly inactivate circulating methotrexate.',NULL,'[{"condition": "Delayed methotrexate elimination (renal impairment, third-spacing, drug interaction)", "direction": "level above expected clearance curve"}, {"condition": "High-dose methotrexate toxicity (myelosuppression, mucositis, hepatotoxicity, nephrotoxicity)", "direction": "correlates with degree and duration of delayed clearance"}]','[{"name": "MedlinePlus Medical Encyclopedia - Therapeutic Drug Levels", "url": "https://medlineplus.gov/ency/article/003430.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:26:09','2026-07-20 05:26:09','["serum-creatinine", "alt-ast", "complete-blood-count"]',NULL,NULL,'Is my level following the expected clearance curve for this protocol? Do I need adjusted leucovorin dosing, extra IV fluids, or urine alkalinization based on this result?','A level above the expected curve at any checkpoint leads to intensified leucovorin rescue and continued frequent monitoring until the level clears to a safe threshold, with aggressive hydration/alkalinization and, in severe delayed-clearance cases, glucarpidase administration.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (181,'ethanol-blood-alcohol','Ethanol, Blood (Blood Alcohol Level)','','Blood Alcohol Concentration, BAC, Ethanol Level','Clinical Chemistry / Toxicology','Confirms and quantifies acute alcohol intoxication in the emergency or clinical setting, helps evaluate altered mental status, and is used for legal/forensic and workplace testing purposes.',NULL,'Venous serum or plasma for clinical use; whole blood for forensic/legal specimens collected under chain-of-custody','The site must be cleaned with a non-alcohol-based antiseptic to avoid contaminating the sample. Serum/plasma levels run roughly 12-18% higher than whole blood levels for the same true blood alcohol concentration, which matters when comparing a clinical lab result to legal whole-blood limits.',NULL,'Enzymatic (alcohol dehydrogenase) assay on automated chemistry analyzers, or headspace gas chromatography for forensic-grade specimens.',NULL,'[{"parameter": "Ethanol", "population": "Non-drinking individual", "range": "Undetectable / <10 mg/dL"}, {"parameter": "Ethanol", "population": "Legal driving limit (varies by jurisdiction)", "range": "commonly 50-80 mg/dL (0.05-0.08%) in many countries; Saudi Arabia prohibits alcohol consumption entirely"}, {"parameter": "Ethanol", "population": "Significant clinical intoxication", "range": ">150-300 mg/dL, with marked impairment in most non-tolerant individuals"}, {"parameter": "Ethanol", "population": "Potentially lethal (non-tolerant adult)", "range": ">400 mg/dL"}]',1,'The clinical effect of a given blood alcohol level varies considerably with an individual''s tolerance -- a chronic heavy drinker may appear only mildly impaired at a level that would cause severe intoxication or respiratory depression in a naive drinker, so the level is interpreted alongside the clinical exam rather than in isolation. In the emergency setting, a level is often used to determine whether altered mental status is fully explained by alcohol or whether other causes (head injury, other intoxicants, metabolic derangement) need to be actively excluded, particularly if the exam doesn''t improve as expected with clearance of alcohol over time.',NULL,'[{"condition": "Acute alcohol intoxication", "direction": "elevated, correlating imprecisely with clinical impairment"}, {"condition": "Altered mental status of uncertain cause", "direction": "used to determine how much of the presentation is explained by alcohol alone"}]','[{"name": "MedlinePlus Medical Encyclopedia - Alcohol Level", "url": "https://medlineplus.gov/ency/article/003611.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:27:36','2026-07-20 05:27:36','["osmolality-serum", "urine-drug-screen"]',NULL,NULL,'Does my level fully explain my symptoms, or are other causes being investigated as well? Is repeat monitoring planned to make sure my mental status is clearing as expected as the alcohol is metabolized?','Management is primarily supportive (airway protection, monitoring, IV fluids as needed) with attention to co-ingestants and underlying causes of altered mental status; mental status that fails to improve as blood alcohol clears prompts further workup (imaging, other toxicology, metabolic panel) rather than being attributed to alcohol alone.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (182,'acetaminophen-level','Acetaminophen (Paracetamol), Serum','','Paracetamol Level, APAP Level, Tylenol Level','Clinical Chemistry / Toxicology','Evaluates suspected acetaminophen overdose (accidental or intentional) to predict the risk of hepatotoxicity and guide the need for N-acetylcysteine (NAC) antidote therapy, using the Rumack-Matthew nomogram.',NULL,'Venous serum or plasma, drawn at a known, documented time after a single acute ingestion','The Rumack-Matthew nomogram is only valid starting 4 hours after a single, acute ingestion (to allow complete absorption) and does not apply to staggered/chronic supratherapeutic ingestion, which is assessed differently using total dose ingested, symptoms, and liver enzymes rather than the nomogram.',NULL,'Enzymatic or immunoassay methods on automated chemistry analyzers.',NULL,'[{"parameter": "Acetaminophen, therapeutic use", "population": "General", "range": "Undetectable to low single-digit mcg/mL, dose-dependent"}, {"parameter": "Acetaminophen, possible hepatotoxicity risk (nomogram treatment line, US)", "population": "4 hours post-single acute ingestion", "range": "\u2265150 mcg/mL"}, {"parameter": "Acetaminophen, high-risk ingestion", "population": "Above the ''300-line'' on the nomogram", "range": "significantly higher; may require an adjusted NAC regimen"}]',1,'A level plotted on the Rumack-Matthew nomogram at or above the treatment line (150 mcg/mL at 4 hours in the commonly used US line, extrapolated forward in time) indicates a meaningful risk of hepatotoxicity and is an indication to start N-acetylcysteine, which is highly effective at preventing liver injury when started early but becomes progressively less effective the longer it is delayed after ingestion. The nomogram is not valid for chronic or staggered ingestions, ingestions of unknown timing, or extended-release formulations, all of which require a different assessment approach (empiric NAC, serial levels, and liver function monitoring) since a single timed level cannot be reliably interpreted in these scenarios.',NULL,'[{"condition": "Acetaminophen-induced hepatotoxicity risk (acute overdose)", "direction": "level above the relevant nomogram treatment line"}, {"condition": "Chronic/staggered overdose (nomogram not applicable)", "direction": "assessed by dose history, symptoms, and liver enzymes rather than a single level"}]','[{"name": "Wikipedia - Rumack-Matthew Nomogram (overview and treatment lines)", "url": "https://en.wikipedia.org/wiki/Rumack%E2%80%93Matthew_nomogram", "accessed": "2026-07-20"}, {"name": "Medscape/eMedicine - Acetaminophen Toxicity Workup", "url": "https://emedicine.medscape.com/article/820200-workup", "accessed": "2026-07-20"}]',1,'2026-07-20 05:27:36','2026-07-20 05:27:36','["alt-ast", "total-bilirubin", "prothrombin-time-inr"]',NULL,NULL,'Is my ingestion timing well-established enough for the nomogram to apply, or will I be treated empirically instead? Will my liver function be monitored during and after treatment?','A level above the treatment line, or any staggered/unclear-timing ingestion with a potentially toxic total dose, leads to N-acetylcysteine therapy along with monitoring of liver enzymes, INR, and renal function; a level below the treatment line at an appropriate post-ingestion time generally does not require antidote therapy.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (183,'salicylate-level','Salicylate, Serum','','Aspirin Level, Salicylate Level, ASA Level','Clinical Chemistry / Toxicology','Evaluates suspected salicylate (aspirin) overdose or chronic salicylate toxicity, and monitors levels during high-dose aspirin therapy.',NULL,'Venous serum or plasma','A single level can underestimate severity in acute overdose because absorption can be delayed (enteric-coated tablets, bezoar formation), so serial levels every 2 hours until a clear downward trend is established are standard practice in significant ingestions, rather than relying on one result.',NULL,'Colorimetric (Trinder) or enzymatic assay on automated chemistry analyzers.',NULL,'[{"parameter": "Salicylate, therapeutic (anti-inflammatory dosing)", "population": "Adult", "range": "15-30 mg/dL"}, {"parameter": "Salicylate, mild-moderate toxicity", "population": "Adult", "range": "30-50 mg/dL, with symptoms typically present"}, {"parameter": "Salicylate, severe toxicity", "population": "Adult", "range": ">50-100 mg/dL, life-threatening"}]',1,'Salicylate toxicity classically produces a mixed acid-base picture (early respiratory alkalosis from direct respiratory center stimulation, followed by an anion-gap metabolic acidosis), tinnitus, hyperthermia, and altered mental status, with severity correlating imperfectly with a single serum level -- clinical status, pH, and the trend of serial levels matter more than one absolute number, particularly in chronic toxicity where levels can be misleadingly lower than the degree of illness. Chronic salicylate toxicity (seen especially in elderly patients on long-term high-dose aspirin) is often more dangerous than it appears because of subtler presentation and can occur at lower serum levels than acute single-dose overdose.',NULL,'[{"condition": "Acute salicylate overdose", "direction": "elevated, trending on serial measurement"}, {"condition": "Chronic salicylate toxicity (often under-recognized, especially in elderly patients)", "direction": "may be only modestly elevated relative to severity of illness"}]','[{"name": "Medscape/eMedicine - Acetaminophen Toxicity Workup (context on co-ingestant salicylate testing)", "url": "https://emedicine.medscape.com/article/820200-workup", "accessed": "2026-07-20"}]',1,'2026-07-20 05:27:36','2026-07-20 05:27:36','["arterial-blood-gas", "bicarbonate-co2-total-carbon-dioxide"]',NULL,NULL,'Since a single level can underestimate the severity of this kind of overdose, will levels be repeated to check the trend? Is urine alkalinization being considered to help my body eliminate the drug?','Significant toxicity is managed with IV fluids, urinary alkalinization (sodium bicarbonate, which enhances renal elimination of salicylate) and, in severe cases, hemodialysis; serial levels and arterial blood gas monitoring guide the intensity and duration of treatment.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (184,'carboxyhemoglobin','Carboxyhemoglobin (Carbon Monoxide, Blood)','','COHb, Carbon Monoxide Level, CO-Hemoglobin','Clinical Chemistry / Toxicology','Confirms and quantifies carbon monoxide poisoning in patients with suspected exposure (smoke inhalation, faulty heating/generators, industrial exposure) and guides the intensity of treatment, including the decision for hyperbaric oxygen.',NULL,'Arterial or venous whole blood (venous is generally acceptable for this specific measurement, unlike most blood gas parameters)','Standard pulse oximetry cannot distinguish carboxyhemoglobin from oxyhemoglobin and will read falsely normal or near-normal oxygen saturation in CO poisoning; a co-oximeter (or laboratory blood gas analyzer with co-oximetry) is required to measure carboxyhemoglobin directly.',NULL,'Co-oximetry, typically performed on the same blood gas analyzer used for arterial blood gas testing.',NULL,'[{"parameter": "Carboxyhemoglobin", "population": "Non-smoker", "range": "<3%"}, {"parameter": "Carboxyhemoglobin", "population": "Smoker", "range": "up to 10-15% depending on smoking intensity"}, {"parameter": "Carboxyhemoglobin", "population": "Symptomatic poisoning (headache, nausea, confusion)", "range": "generally >20-25%"}, {"parameter": "Carboxyhemoglobin", "population": "Severe/life-threatening poisoning", "range": ">40-50%, risk of coma, cardiac ischemia, death"}]',1,'Carbon monoxide binds hemoglobin with roughly 200-250 times the affinity of oxygen, displacing oxygen delivery to tissues and causing symptoms that correlate imperfectly with the measured level -- a level obtained after the patient has already received supplemental oxygen (which accelerates CO elimination) may substantially underestimate the peak exposure, so the level is interpreted alongside symptoms, exposure history, and any loss of consciousness rather than in isolation. Delayed neurological sequelae (cognitive changes, parkinsonism-like symptoms) can occur days to weeks after apparent recovery from significant poisoning, which is part of why more severe exposures are treated aggressively even after the acute level has come down.',NULL,'[{"condition": "Carbon monoxide poisoning (smoke inhalation, faulty heating, industrial exposure)", "direction": "elevated, though level alone doesn''t fully predict severity or delayed sequelae"}]','[{"name": "MedlinePlus Medical Encyclopedia - Carboxyhemoglobin", "url": "https://medlineplus.gov/ency/article/003643.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:27:36','2026-07-20 05:27:36','["arterial-blood-gas", "lactate-blood"]',NULL,NULL,'Since this level may already be falling because of the oxygen I''ve been given, does it fully reflect how severe my exposure was? Am I a candidate for hyperbaric oxygen therapy, and what does that involve?','Confirmed poisoning is treated with high-flow 100% oxygen (which accelerates CO elimination compared to room air) and, for severe exposures (very high levels, loss of consciousness, pregnancy, cardiac ischemia, or neurological symptoms), hyperbaric oxygen therapy is considered to reduce the risk of delayed neurological sequelae.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (185,'urine-drug-screen','Urine Drug Screen (Multi-Panel Toxicology)','','UDS, Urine Toxicology Screen, Drug of Abuse Panel','Clinical Chemistry / Toxicology','Screens for recent use of common drugs of abuse in the emergency, clinical, workplace, forensic, or substance-use-treatment setting; commonly panels include opiates, cocaine metabolite, amphetamines/methamphetamine, cannabinoids (THC), benzodiazepines, barbiturates, and PCP, with panel composition varying by protocol.',NULL,'Random urine specimen; observed collection with chain-of-custody documentation is required for forensic/legal or employment testing','Immunoassay screens are prone to both false positives (cross-reactivity with certain prescription or over-the-counter medications, e.g. some cold medications causing false-positive amphetamine results, poppy seeds causing false-positive opiate results) and false negatives (many synthetic opioids like fentanyl and newer synthetic drugs are not detected by standard opiate immunoassays and require specific separate testing).',NULL,'Immunoassay screening (point-of-care or laboratory-based), with presumptive positive results generally confirmed by gas chromatography-mass spectrometry (GC-MS) or liquid chromatography-tandem mass spectrometry (LC-MS/MS) when the result has clinical, legal, or employment consequences.',NULL,'[{"parameter": "Result categories", "population": "Per substance tested", "range": "Negative or Presumptive Positive (screening); confirmatory testing required for a legally or clinically definitive positive result"}]',1,'A screening immunoassay result indicates presumptive, not definitive, presence of a substance class and reflects recent use over a variable detection window (hours for some substances to weeks for chronic heavy cannabis use), not impairment at the time of testing or the exact substance/dose used -- interpretation requires knowing which specific panel was run and its known cross-reactivities. Because standard opiate immunoassays often do not detect synthetic opioids (fentanyl, and many novel psychoactive substances), a negative standard panel does not rule out these exposures in a clinical toxicology context, and specific fentanyl testing or broader confirmatory panels should be requested when suspicion is high despite a negative screen.',NULL,'[{"condition": "Recent use of screened substance class (presumptive)", "direction": "positive screen, pending confirmation if clinically or legally significant"}, {"condition": "Fentanyl/novel synthetic opioid exposure (often missed by standard opiate panels)", "direction": "requires specific testing beyond the standard panel"}]','[{"name": "MedlinePlus Medical Encyclopedia - Drug Screen (Comprehensive)", "url": "https://medlineplus.gov/ency/article/003578.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:27:36','2026-07-20 05:27:36','["ethanol-blood-alcohol"]',NULL,NULL,'Which specific substances were included in this panel, and were any results confirmed with a more specific method? Could a medication I''m taking explain a positive result on this screen?','A presumptive positive result with clinical, legal, or employment implications should be sent for confirmatory testing (GC-MS or LC-MS/MS) before being acted upon as definitive; in the acute clinical setting, management is guided primarily by the patient''s symptoms and vital signs rather than waiting for a screen result.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (186,'lead-blood','Lead, Blood','','Blood Lead Level, BLL, Lead Level','Clinical Chemistry / Toxicology','Screens for and quantifies lead exposure, particularly in young children (developmental risk) and in adults with occupational or environmental exposure (battery manufacturing, smelting, some traditional cosmetics/remedies, renovation of older housing with lead paint).',NULL,'Venous whole blood (EDTA); capillary (finger-stick) samples may be used for initial screening but a positive capillary result should be confirmed with a venous sample','Strict attention to lead-free collection technique is required, since skin contamination or inadequately cleaned equipment can falsely elevate capillary results; venous confirmation of any elevated capillary result is standard practice.',NULL,'Graphite furnace atomic absorption spectrometry or inductively coupled plasma mass spectrometry (ICP-MS).',NULL,'[{"parameter": "Blood lead reference value (CDC, children 1-5 years, 97.5th percentile)", "population": "Children", "range": "\u22653.5 \u00b5g/dL identifies levels higher than most children''s"}, {"parameter": "Occupational threshold prompting workplace investigation (OSHA, general industry)", "population": "Adult, occupational", "range": "\u226525 \u00b5g/dL considered actionable"}, {"parameter": "Medical removal threshold (occupational, various guidelines)", "population": "Adult, occupational", "range": ">30 \u00b5g/dL"}]',1,'There is no known safe threshold for lead exposure in children, since even low-level exposure has been associated with measurable, largely irreversible effects on cognitive development and behavior; the CDC''s blood lead reference value (lowered to 3.5 µg/dL in 2021) is used to identify children in the top 2.5% of exposure for prompt investigation of the source and follow-up, not as a ''safe'' cutoff. In adults, lead toxicity affects the hematologic (microcytic anemia, basophilic stippling), neurologic (peripheral neuropathy, encephalopathy at high levels), renal, and reproductive systems, with occupational exposure being the dominant cause; regulatory action levels exist to trigger workplace exposure controls and, at higher levels, medical removal from the lead-exposed task.',NULL,'[{"condition": "Childhood lead exposure (developmental/cognitive risk, no safe threshold)", "direction": "any detectable elevation above reference value prompts evaluation"}, {"condition": "Occupational or environmental lead poisoning in adults (anemia, neuropathy, encephalopathy at high levels)", "direction": "elevated, severity correlating with level and duration of exposure"}]','[{"name": "CDC - Blood Lead Reference Value Update", "url": "https://www.cdc.gov/lead-prevention/php/news-features/updates-blood-lead-reference-value.html", "accessed": "2026-07-20"}, {"name": "CDC/NIOSH - Blood Lead Level Guidance for Adults", "url": "https://www.cdc.gov/niosh/lead/bll-reference/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:27:36','2026-07-20 05:27:36','["complete-blood-count", "zinc-serum"]',NULL,NULL,'What is the likely source of this exposure, and how can it be reduced or eliminated? For a child, what follow-up testing and developmental monitoring is recommended at this level?','Any confirmed elevation in a child prompts investigation of the exposure source (commonly old paint, contaminated soil, or certain imported products) and periodic repeat testing; higher levels in children or adults may warrant chelation therapy per current guidelines, always alongside source identification and removal, since chelation without addressing ongoing exposure has limited benefit.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (187,'sars-cov-2-rt-pcr','SARS-CoV-2 RT-PCR (COVID-19 Molecular Test)','','COVID-19 PCR, SARS-CoV-2 NAAT, Coronavirus PCR','Molecular Diagnostics / Infectious Disease','Detects current SARS-CoV-2 infection with high sensitivity, used for diagnosis in symptomatic patients, pre-procedure/admission screening, and outbreak investigation.',NULL,'Nasopharyngeal or mid-turbinate nasal swab; saliva accepted by some assay platforms','Proper swab technique and adequate sample collection depth in the nasopharynx materially affect sensitivity; timing relative to symptom onset also matters, since viral load rises and falls over the course of infection.',NULL,'Real-time reverse transcription polymerase chain reaction (RT-PCR), targeting one or more SARS-CoV-2 gene regions (e.g., N, ORF1ab, S genes).',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Detected (Positive) or Not Detected (Negative); some platforms report a cycle threshold (Ct) value, which correlates inversely with viral load but is not standardized for cross-platform comparison"}]',1,'RT-PCR remains the reference-standard method for detecting current SARS-CoV-2 infection due to its high analytical sensitivity, and a positive result in a symptomatic patient is highly reliable, though the test can remain positive for a period after infectiousness has resolved since it detects viral RNA rather than live, transmissible virus. A negative result does not fully exclude infection, particularly very early in the course of illness before viral load rises to detectable levels or with a poorly collected specimen, so repeat testing or an alternative specimen may be considered when clinical suspicion remains high despite an initial negative result.',NULL,'[{"condition": "Active SARS-CoV-2 infection", "direction": "detected/positive"}, {"condition": "Early infection or inadequate specimen (false-negative risk)", "direction": "not detected despite ongoing clinical suspicion"}]','[{"name": "CDC - COVID-19 Testing Overview and Guidance", "url": "https://www.cdc.gov/covid/testing/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["influenza-a-b", "rsv-antigen-pcr", "c-reactive-protein-hs-crp"]',NULL,NULL,'Given my symptoms and exposure history, does a negative result here rule out COVID-19, or should I be retested? How long should I isolate based on this result and current guidance?','A positive result guides isolation precautions and, in higher-risk patients, consideration of antiviral therapy per current clinical guidelines; a negative result with ongoing strong clinical suspicion may prompt repeat testing 24-48 hours later or consideration of alternative diagnoses.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (188,'influenza-a-b','Influenza A/B (Rapid Antigen and Molecular Testing)','','Flu Test, Influenza PCR, Rapid Flu Antigen','Molecular Diagnostics / Infectious Disease','Diagnoses influenza A or B infection to guide antiviral treatment decisions, infection control precautions, and, in outbreak settings, epidemiologic surveillance.',NULL,'Nasopharyngeal or nasal swab','Rapid antigen tests have notably lower sensitivity than molecular (PCR) methods, particularly in adults and later in the illness course, so a negative rapid antigen result in a symptomatic patient during flu season does not reliably exclude infection and may warrant confirmatory PCR testing.',NULL,'Rapid immunoassay (lateral flow antigen detection) for point-of-care use, or real-time RT-PCR (often as part of a multiplex respiratory panel with RSV and SARS-CoV-2) for higher sensitivity.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Detected (Positive, with type A or B specified) or Not Detected (Negative)"}]',1,'A positive result in a patient with compatible symptoms confirms influenza and, in patients at higher risk of complications or presenting early in illness, supports starting antiviral therapy (e.g., oseltamivir), which is most effective when started within 48 hours of symptom onset. Distinguishing influenza from other respiratory viruses (including SARS-CoV-2 and RSV, which can present nearly identically) matters for both treatment (antivirals differ by pathogen) and infection control precautions, which is why multiplex PCR panels testing for several respiratory viruses simultaneously are increasingly used in hospital settings.',NULL,'[{"condition": "Influenza A or B infection", "direction": "detected/positive"}, {"condition": "Other respiratory viral infection (clinically similar presentation)", "direction": "influenza negative; consider multiplex respiratory panel if available"}]','[{"name": "CDC - Information for Clinicians on Influenza Virus Testing", "url": "https://www.cdc.gov/flu/hcp/testing/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["sars-cov-2-rt-pcr", "rsv-antigen-pcr", "procalcitonin-pct-serum"]',NULL,NULL,'Given my symptom duration, am I still within the window where antiviral treatment would be most effective? If this rapid test is negative but I''m still very symptomatic, should a more sensitive PCR test be done?','A positive result in a higher-risk or early-presenting patient generally leads to antiviral therapy and appropriate isolation/infection control measures; a negative rapid antigen result with ongoing strong clinical suspicion, especially during a high-prevalence period, is often followed by PCR confirmation.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (189,'rsv-antigen-pcr','Respiratory Syncytial Virus (RSV) Antigen/PCR','','RSV Test, RSV Antigen, RSV PCR','Molecular Diagnostics / Infectious Disease','Diagnoses RSV infection, particularly important in infants and young children with bronchiolitis, and in older or immunocompromised adults with severe respiratory illness, to guide clinical management and infection control (RSV spreads readily in hospital and daycare settings).',NULL,'Nasopharyngeal or nasal swab/aspirate','Rapid antigen testing performs best in young children, who tend to have higher viral loads, and less reliably in adults, where PCR is preferred given its greater sensitivity.',NULL,'Rapid immunoassay (antigen detection) for point-of-care use in pediatric patients, or real-time RT-PCR (often as part of a multiplex respiratory panel) for higher sensitivity.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Detected (Positive) or Not Detected (Negative)"}]',1,'A positive result in an infant with bronchiolitis symptoms (wheezing, increased work of breathing, following a viral prodrome) confirms the diagnosis and supports cohorting/isolation precautions to limit nosocomial spread, since RSV is highly contagious in healthcare settings; management remains largely supportive (oxygen, hydration, suctioning) regardless of confirmation, as there is no widely used specific antiviral for most patients. In adults, particularly the elderly or those with chronic cardiopulmonary disease, RSV can cause severe lower respiratory tract disease that clinically resembles influenza or COVID-19, so confirming the specific pathogen (often via multiplex panel) helps guide isolation decisions and, where relevant, eligibility discussions for RSV-specific preventive vaccines in future seasons.',NULL,'[{"condition": "RSV bronchiolitis (infants/young children)", "direction": "detected/positive"}, {"condition": "RSV lower respiratory tract infection (older adults, immunocompromised)", "direction": "detected/positive"}]','[{"name": "CDC - RSV Clinical Overview", "url": "https://www.cdc.gov/rsv/hcp/clinical-overview/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["influenza-a-b", "sars-cov-2-rt-pcr"]',NULL,NULL,'Does this result change the treatment plan, or is supportive care the main approach either way? What precautions should be taken to avoid spreading this to other children or vulnerable family members?','Management for most patients is supportive regardless of confirmation; hospitalized patients with a positive result are placed on appropriate contact/droplet precautions, and severe cases in high-risk patients may prompt closer monitoring for respiratory decompensation.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (190,'tb-igra-quantiferon','Tuberculosis Interferon-Gamma Release Assay (IGRA, e.g. QuantiFERON-TB Gold)','','IGRA, QuantiFERON-TB, TB Gold, T-SPOT.TB','Immunoassay / Infectious Disease Serology','Detects immune sensitization to Mycobacterium tuberculosis antigens to diagnose latent TB infection (LTBI), and is used as an alternative to the tuberculin skin test (TST), particularly in patients previously vaccinated with BCG (which can cause false-positive TST results).',NULL,'Venous whole blood collected into specialized antigen tubes (must be incubated per manufacturer protocol within a defined time window after draw)','Strict adherence to blood volume, incubation temperature, and incubation timing is required for a valid result; samples that sit too long before incubation or are under/over-filled can produce indeterminate results.',NULL,'Interferon-gamma release assay: whole blood is incubated with TB-specific antigen peptides, and the interferon-gamma released by sensitized T-cells is measured, most commonly by ELISA (QuantiFERON) or ELISPOT (T-SPOT.TB).',NULL,'[{"parameter": "Result categories (QuantiFERON-TB Gold, standard cutoff)", "population": "General", "range": "Negative (<0.35 IU/mL TB-antigen minus nil response, meeting negative criteria) or Positive (\u22650.35 IU/mL and \u226525% of nil)"}, {"parameter": "Borderline/equivocal zone (used by some laboratories)", "population": "General", "range": "approximately 0.20-0.99 IU/mL; some laboratories recommend retesting results in this range"}]',1,'A positive IGRA indicates immune sensitization consistent with TB infection (latent or active) but, like the tuberculin skin test, cannot on its own distinguish latent infection from active disease -- a positive result in a patient without symptoms and a normal chest X-ray supports latent TB infection, warranting consideration of preventive treatment, while a positive result with compatible symptoms or imaging findings prompts full evaluation for active disease (sputum studies, imaging). Unlike the tuberculin skin test, IGRA results are not affected by prior BCG vaccination, making it the preferred test in BCG-vaccinated populations, though results near the assay cutoff can show meaningful inter-run and inter-laboratory variability and are sometimes retested before being acted upon.',NULL,'[{"condition": "Latent tuberculosis infection", "direction": "positive, with normal chest imaging and no symptoms"}, {"condition": "Active tuberculosis (requires additional testing to confirm)", "direction": "positive, with compatible symptoms/imaging prompting further workup"}]','[{"name": "PMC - Refining the Diagnostic Approach to Latent TB with QuantiFERON Gold Plus (cutoffs and borderline zone)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC12416684/", "accessed": "2026-07-20"}, {"name": "PMC - A Borderline Range for QuantiFERON Gold In-Tube Results", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5667766/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["complete-blood-count"]',NULL,NULL,'Does this result mean I have latent infection, active disease, or could it be a borderline result that should be repeated? If latent infection is confirmed, what does preventive treatment involve?','A positive result without symptoms or radiographic abnormality typically leads to a chest X-ray to exclude active disease, followed by consideration of latent TB preventive treatment; a positive result with symptoms or imaging findings leads to sputum studies (smear, culture, and/or molecular testing) to evaluate for active tuberculosis.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (191,'c-difficile-toxin','Clostridioides difficile Toxin (Stool)','','C. diff Toxin, CDAD Testing, C. difficile PCR/GDH/Toxin','Microbiology','Diagnoses Clostridioides difficile infection in patients with diarrhea, most often following antibiotic use, healthcare exposure, or advanced age, and distinguishes true infection from asymptomatic colonization.',NULL,'Unformed (liquid or soft) stool specimen; formed stool should not be tested since it usually reflects colonization rather than infection','Testing should only be performed on patients with clinically significant diarrhea (typically ≥3 unformed stools in 24 hours) without another obvious cause; testing formed stool or asymptomatic patients is discouraged because C. difficile PCR can detect colonization without true infection, leading to overdiagnosis and unnecessary treatment.',NULL,'Multi-step algorithm commonly used: glutamate dehydrogenase (GDH) antigen screen plus toxin A/B enzyme immunoassay, with nucleic acid amplification testing (NAAT/PCR) for the toxin gene used to resolve discordant results or as a standalone highly sensitive molecular test.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Negative or Positive; algorithm-dependent (GDH+/Toxin+, GDH+/Toxin-/NAAT+, etc.) interpretation may require correlation with clinical presentation"}]',1,'A positive toxin EIA result, reflecting active toxin production, correlates best with clinically significant disease, while a positive NAAT/PCR alone (detecting the toxin gene without confirmed toxin production) can reflect either true infection or asymptomatic carriage/colonization, which is why many laboratories use a two- or three-step algorithm rather than PCR alone to reduce overdiagnosis and unnecessary antibiotic treatment in colonized but asymptomatic patients. Risk factors include recent antibiotic use (especially broad-spectrum agents), hospitalization, advanced age, and proton pump inhibitor use; recurrence after treatment is common and a topic of ongoing clinical management (repeat treatment, fecal microbiota transplantation for recurrent cases).',NULL,'[{"condition": "Clostridioides difficile infection (symptomatic)", "direction": "positive toxin (with or without positive GDH/NAAT), correlating with clinical diarrhea"}, {"condition": "Asymptomatic colonization (NAAT-positive, toxin-negative, no diarrhea)", "direction": "generally not treated as active infection"}]','[{"name": "CDC - Clostridioides difficile Infection Clinical Guidance", "url": "https://www.cdc.gov/c-diff/hcp/clinical-guidance/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["stool-culture", "fecal-calprotectin"]',NULL,NULL,'Which specific test(s) in the algorithm came back positive, and does that combination indicate active infection rather than colonization? Should any antibiotics I''m currently taking be reviewed given this result?','Confirmed infection is treated with a specific oral antibiotic regimen (commonly vancomycin or fidaxomicin) and discontinuation of the inciting antibiotic where possible; recurrent episodes may prompt extended or alternative regimens, or referral for fecal microbiota transplantation in select cases.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (192,'chlamydia-gonorrhea-naat','Chlamydia trachomatis / Neisseria gonorrhoeae NAAT','','CT/NG NAAT, Chlamydia and Gonorrhea PCR, STI Molecular Panel','Molecular Diagnostics / Infectious Disease','Diagnoses genital, rectal, or pharyngeal chlamydia and gonorrhea infection; used for symptomatic evaluation, routine screening in sexually active individuals per risk-based guidelines, and test-of-cure in specific situations (notably pharyngeal gonorrhea or in pregnancy).',NULL,'Depends on exposure site and symptoms: first-catch urine, vaginal swab (self- or clinician-collected), endocervical swab, or extragenital (rectal/pharyngeal) swab','Vaginal swabs (including self-collected) generally perform as well as or better than urine for detecting infection in women and are preferred by many guidelines; extragenital site testing should be based on actual reported exposure sites, since infections at these sites are frequently asymptomatic and missed if only genital testing is performed.',NULL,'Nucleic acid amplification testing (NAAT), the current reference-standard method given its high sensitivity and specificity compared with older culture or antigen methods.',NULL,'[{"parameter": "Result categories", "population": "Per organism and site tested", "range": "Detected (Positive) or Not Detected (Negative)"}]',1,'Both infections are frequently asymptomatic, particularly in women and at extragenital sites, which is why risk-based screening (not just symptom-triggered testing) is recommended in sexually active individuals under 25 and others with risk factors, since untreated infection can lead to pelvic inflammatory disease, infertility, ectopic pregnancy, and facilitates HIV transmission. Because NAAT detects genetic material rather than viable organism, a test-of-cure (repeat testing) at an appropriate interval after treatment, rather than immediately, is recommended specifically for pharyngeal gonorrhea and in pregnancy, since a repeat test too soon after treatment can show a false positive from residual non-viable organism DNA.',NULL,'[{"condition": "Chlamydia trachomatis infection", "direction": "detected/positive"}, {"condition": "Neisseria gonorrhoeae infection", "direction": "detected/positive"}, {"condition": "Pelvic inflammatory disease / infertility risk (untreated infection)", "direction": "associated with delayed or missed diagnosis"}]','[{"name": "CDC - STI Treatment Guidelines: Chlamydia and Gonorrhea", "url": "https://www.cdc.gov/std/treatment-guidelines/default.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["hiv-antigen-antibody-combination-screen", "syphilis-screening-rpr-vdrl-with-treponemal-confirmation"]',NULL,NULL,'Should my partner(s) also be tested and treated to prevent reinfection? Given the site(s) of my exposure, was testing done at all relevant sites (not just genital)?','A positive result is treated with the current recommended antibiotic regimen, with partner notification and treatment strongly encouraged to prevent reinfection and further transmission; abstinence from sexual activity is generally advised until treatment is completed and, where recommended, until a test-of-cure at the appropriate interval.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (193,'hsv-1-2-igg','Herpes Simplex Virus (HSV) Type-Specific IgG (HSV-1/HSV-2)','','HSV IgG, Herpes Type-Specific Serology, HSV-1/2 Antibody','Immunoassay / Infectious Disease Serology','Determines prior HSV-1 or HSV-2 infection status using type-specific serology, useful for confirming a clinical diagnosis of genital herpes when lesion-based testing (PCR/culture) isn''t available, evaluating an asymptomatic partner of someone with known genital herpes, and in pregnancy risk assessment for neonatal herpes.',NULL,'Venous serum','Only type-specific glycoprotein G (gG)-based assays reliably distinguish HSV-1 from HSV-2; older non-type-specific HSV antibody tests should not be used for this purpose since they cannot differentiate the two types, and antibodies may take several weeks after initial infection to become detectable (seroconversion window).',NULL,'Type-specific enzyme immunoassay (EIA) targeting glycoprotein G1 (HSV-1) and glycoprotein G2 (HSV-2).',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Negative, Positive, or Equivocal, reported separately for HSV-1 IgG and HSV-2 IgG"}]',1,'A positive HSV-2 IgG indicates prior genital herpes infection in most cases (HSV-2 is predominantly a genital infection), while a positive HSV-1 IgG is common in the general population and does not distinguish oral from genital infection, since HSV-1 increasingly causes genital disease as well -- this limits the usefulness of HSV-1 serology alone in confirming genital involvement without a corresponding lesion-based test. Serologic testing detects prior exposure, not necessarily active shedding or lesion status, so a positive result in an asymptomatic person indicates infection has occurred (with implications for counseling on transmission risk and, in pregnancy, monitoring), while it cannot confirm whether a current lesion is due to HSV without direct lesion testing (PCR or culture).',NULL,'[{"condition": "Prior HSV-2 infection (predominantly genital)", "direction": "positive"}, {"condition": "Prior HSV-1 infection (oral and/or genital)", "direction": "positive, site not distinguished by serology alone"}]','[{"name": "CDC - STI Treatment Guidelines: Genital HSV Infections (serologic testing section)", "url": "https://www.cdc.gov/std/treatment-guidelines/herpes.htm", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["varicella-zoster-virus-vzv-igg-igm"]',NULL,NULL,'What does this result mean for transmission risk to a current or future partner? If I''m pregnant, does this affect the delivery plan or need for suppressive therapy near term?','A positive result prompts counseling on transmission risk, safer-sex practices, and, for genital HSV-2, discussion of suppressive antiviral therapy options; in pregnancy, a known history (or a new diagnosis) informs monitoring and delivery planning to reduce the risk of neonatal transmission.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (194,'measles-igg','Measles IgG (Immunity Status)','','Measles Antibody, Rubeola IgG, Measles Immunity Screen','Immunoassay / Infectious Disease Serology','Confirms immune status to measles (rubeola), used for healthcare worker immunity documentation, outbreak/exposure investigation, and in patients with uncertain vaccination history.',NULL,'Venous serum','For outbreak investigation or suspected acute infection (rather than immunity screening), IgM serology and/or molecular testing (RT-PCR from a throat/nasopharyngeal swab or urine) is used instead, since IgG mainly reflects past infection or vaccination rather than acute illness.',NULL,'Enzyme immunoassay (EIA) on automated immunoassay analyzers.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Non-immune (negative/equivocal) or Immune (positive), with some assays reporting a quantitative index value alongside the qualitative interpretation"}]',1,'A positive (immune) result indicates protective antibody from prior infection or vaccination and generally requires no further action; a negative or equivocal result in a healthcare worker, traveler, or other individual at risk of exposure prompts a recommendation for MMR vaccination (unless contraindicated), since measles is highly contagious and can cause serious complications including pneumonia and encephalitis, with additional risk to unvaccinated infants and immunocompromised contacts. Following documented significant exposure in a non-immune individual, post-exposure prophylaxis (MMR vaccine or immune globulin, depending on timing and the individual''s risk factors) may be indicated rather than relying on serology alone, given the short window in which post-exposure measures are effective.',NULL,'[{"condition": "Measles immunity (from prior infection or vaccination)", "direction": "positive"}, {"condition": "Susceptibility to measles infection", "direction": "negative or equivocal, especially relevant after a known exposure"}]','[{"name": "CDC - Measles (Rubeola) Clinical Overview and Immunity Assessment", "url": "https://www.cdc.gov/measles/hcp/clinical-overview/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["rubella-igg-immunity-status", "varicella-zoster-virus-vzv-igg-igm"]',NULL,NULL,'If I''m not immune, is there still time for post-exposure prophylaxis to be effective given when I was exposed? Do I need a booster MMR vaccine, or is my vaccination history sufficient going forward?','A negative or equivocal result generally leads to a recommendation for MMR vaccination (two doses if no prior documented vaccination); a documented significant exposure in a non-immune person may warrant urgent evaluation for post-exposure prophylaxis rather than waiting on routine vaccination scheduling.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (195,'hepatitis-b-core-antibody-total','Hepatitis B Core Antibody, Total (Anti-HBc)','','Anti-HBc Total, HBcAb, Hepatitis B Core Antibody','Immunoassay / Infectious Disease Serology','Detects prior or current hepatitis B infection as part of a complete hepatitis B panel (alongside HBsAg and anti-HBs), used to distinguish natural infection (past or present) from vaccine-induced immunity, and to identify occult or resolved infection before immunosuppressive therapy.',NULL,'Venous serum','Interpretation requires the full panel (HBsAg, anti-HBc total, anti-HBs) together, since anti-HBc alone cannot distinguish current from past infection; IgM anti-HBc specifically indicates recent/acute infection and is ordered separately when acute hepatitis B is suspected.',NULL,'Chemiluminescent immunoassay or enzyme immunoassay on automated analyzers.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Non-reactive or Reactive; interpreted alongside HBsAg and anti-HBs (e.g., anti-HBc reactive with anti-HBs reactive and HBsAg non-reactive indicates resolved past infection with natural immunity, distinct from vaccine-induced immunity which is anti-HBc non-reactive with anti-HBs reactive)"}]',1,'Because anti-HBc becomes positive with any hepatitis B infection (acute, chronic, or resolved) but is not produced by vaccination alone, its pattern relative to HBsAg and anti-HBs distinguishes resolved natural infection (anti-HBc+/anti-HBs+/HBsAg-) from vaccine immunity (anti-HBc-/anti-HBs+/HBsAg-) and from chronic active infection (anti-HBc+/HBsAg+). Isolated anti-HBc positivity (with negative HBsAg and negative or low anti-HBs) can represent a window period of acute infection, a false positive, or -- importantly -- occult hepatitis B infection with the potential for reactivation if the patient later receives immunosuppressive or biologic therapy, which is why anti-HBc is included in pre-treatment screening panels for such therapies.',NULL,'[{"condition": "Resolved past hepatitis B infection (natural immunity)", "direction": "anti-HBc reactive with anti-HBs reactive, HBsAg non-reactive"}, {"condition": "Chronic hepatitis B infection", "direction": "anti-HBc reactive with HBsAg reactive"}, {"condition": "Occult hepatitis B infection / reactivation risk before immunosuppression", "direction": "isolated anti-HBc reactivity"}]','[{"name": "CDC - Hepatitis B Serology Interpretation Table", "url": "https://www.cdc.gov/hepatitis-b/hcp/diagnosis-testing/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:29:32','2026-07-20 05:29:32','["hepatitis-b-surface-antigen-hbsag", "hepatitis-b-surface-antibody-anti-hbs"]',NULL,NULL,'Given my full hepatitis B panel results, do I have natural immunity, vaccine-induced immunity, or an active infection? If I''m starting immunosuppressive or biologic therapy, does this result mean I need antiviral prophylaxis to prevent reactivation?','The pattern of results across the full panel determines next steps: reactive HBsAg leads to further evaluation for chronic hepatitis B (viral load, liver assessment); isolated anti-HBc positivity before planned immunosuppressive therapy generally prompts hepatitis B DNA testing and consideration of prophylactic antiviral therapy to prevent reactivation.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (196,'growth-hormone','Growth Hormone (GH), Serum','','GH, Somatotropin, Human Growth Hormone','Immunoassay / Endocrinology','Evaluates suspected growth hormone excess (acromegaly/gigantism) or deficiency; a single random level has limited diagnostic value on its own and dynamic (stimulation or suppression) testing is usually required to confirm either condition.',NULL,'Venous serum','GH is secreted in a pulsatile pattern and is strongly affected by sleep, exercise, stress, and fasting status, so a single random level is difficult to interpret in isolation; suspected excess is confirmed with an oral glucose suppression test, and suspected deficiency with a stimulation test (e.g., insulin tolerance test, glucagon stimulation), typically alongside IGF-1 measurement.',NULL,'Chemiluminescent immunoassay on automated analyzers.',NULL,'[{"parameter": "Random GH, adult", "population": "General adult", "range": "Highly variable due to pulsatile secretion; a low or undetectable random level does not exclude normal GH function, and a normal or mildly elevated level does not confirm excess"}, {"parameter": "GH after oral glucose suppression (used to diagnose excess)", "population": "Adult", "range": "Normal suppression to <1.0 ng/mL (assay-dependent); failure to suppress supports acromegaly"}]',1,'Failure of GH to suppress appropriately after an oral glucose load, together with an elevated IGF-1 (which better reflects average GH exposure since it doesn''t fluctuate pulsatile-ly), supports a diagnosis of GH excess (acromegaly in adults, gigantism if onset is before growth plate closure), most often due to a pituitary somatotroph adenoma. In suspected GH deficiency (short stature in children, or specific adult GH deficiency syndromes, often from pituitary disease or prior pituitary surgery/radiation), a stimulation test showing an inadequate GH rise, together with a low IGF-1 and compatible clinical context, supports the diagnosis; a low random GH level alone is not sufficient given normal fluctuation throughout the day.',NULL,'[{"condition": "Acromegaly / gigantism (GH excess)", "direction": "failure to suppress with oral glucose, elevated IGF-1"}, {"condition": "Growth hormone deficiency", "direction": "inadequate rise on stimulation testing, low IGF-1"}]','[{"name": "Medscape/eMedicine - Growth Hormone: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2089136-overview", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["insulin-like-growth-factor-1-igf-1-serum"]',NULL,NULL,'Since a single random level isn''t usually enough to diagnose either condition, what dynamic testing (suppression or stimulation) is planned, and how should I prepare for it? Will my IGF-1 level be checked alongside this?','Suspected excess proceeds to an oral glucose suppression test and pituitary imaging (MRI) if confirmed; suspected deficiency proceeds to a formal stimulation test, with treatment (GH replacement or, for excess, surgery/medical therapy) guided by the confirmed diagnosis and underlying cause.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (197,'plasma-renin-activity','Plasma Renin Activity (PRA)','','Renin Activity, PRA, Renin Level','Immunoassay / Endocrinology','Evaluated together with aldosterone (as the aldosterone-to-renin ratio) to screen for primary aldosteronism in resistant or early-onset hypertension, and used in the broader workup of secondary hypertension and unexplained hypokalemia.',NULL,'Venous plasma (EDTA), collected in a chilled tube and processed under cold conditions per protocol','Posture (supine vs. seated/upright) and time of day significantly affect results and must match the reference range being used; many antihypertensive medications (especially spironolactone, other diuretics, and beta-blockers) interfere with interpretation and should be discontinued for a specified period (often 2-6 weeks depending on the drug) before testing whenever clinically safe to do so.',NULL,'Radioimmunoassay or enzyme immunoassay measuring the rate of angiotensin I generation (activity-based assay), distinct from direct renin concentration assays which some laboratories use instead.',NULL,'[{"parameter": "Plasma renin activity, supine", "population": "Adult", "range": "0.15-2.33 ng/mL/hour"}, {"parameter": "Plasma renin activity, upright/seated", "population": "Adult", "range": "1.3-4.0 ng/mL/hour"}]',1,'A suppressed renin (often below assay detection) together with an elevated aldosterone and a high aldosterone-to-renin ratio is the standard first-step screen for primary aldosteronism, a common and often under-recognized cause of secondary hypertension that is important to identify since it is potentially curable (unilateral adenoma) or specifically treatable (mineralocorticoid receptor antagonists for bilateral disease). Elevated renin, by contrast, points toward renin-mediated causes of hypertension or hypokalemia such as renal artery stenosis, renin-secreting tumors (rare), or diuretic-induced volume depletion, and a low aldosterone-to-renin ratio in this setting argues against primary aldosteronism.',NULL,'[{"condition": "Primary aldosteronism", "direction": "low/suppressed renin with elevated aldosterone (high aldosterone-renin ratio)"}, {"condition": "Renovascular hypertension / renin-secreting tumor", "direction": "elevated renin"}, {"condition": "Secondary hyperaldosteronism (volume depletion, diuretic use, renal artery stenosis)", "direction": "elevated renin with elevated aldosterone"}]','[{"name": "Mayo Clinic Laboratories Endocrinology Catalog - Renin Activity, Plasma", "url": "https://endocrinology.testcatalog.org/show/PRA", "accessed": "2026-07-20"}, {"name": "PMC - Paraneoplastic Secondary Hypertension Due to Renin-Secreting Tumor (reference ranges cited)", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4186556/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["aldosterone-and-renin-aldosterone-renin-ratio", "sodium-na", "potassium-k"]',NULL,NULL,'Were my blood pressure medications adjusted appropriately before this test, since some can interfere with the result? If this points toward primary aldosteronism, what confirmatory testing and imaging are next?','A high aldosterone-to-renin ratio prompts a confirmatory test (e.g., oral or IV saline loading) and, if confirmed, adrenal CT imaging with adrenal vein sampling in appropriate candidates to distinguish unilateral from bilateral disease and guide surgical versus medical management.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (198,'adh-vasopressin','Antidiuretic Hormone (ADH / Arginine Vasopressin), Plasma','','ADH, Vasopressin, AVP','Immunoassay / Endocrinology','Helps evaluate disorders of water balance, particularly distinguishing central diabetes insipidus (inadequate ADH secretion) from nephrogenic diabetes insipidus (inadequate renal response to normal/high ADH) and from primary polydipsia, in a patient with polyuria and dilute urine.',NULL,'Venous plasma (EDTA), collected on ice and processed promptly per protocol, since ADH is unstable at room temperature','ADH assays are technically demanding and increasingly being supplemented or replaced by copeptin (a more stable surrogate marker co-secreted with ADH) in some laboratories; interpretation requires simultaneous measurement of plasma osmolality, since ADH should be interpreted relative to the osmotic stimulus present at the time of sampling, often as part of a formal water deprivation test.',NULL,'Radioimmunoassay or enzyme immunoassay.',NULL,'[{"parameter": "ADH, random (normally hydrated)", "population": "Adult", "range": "approximately 1-5 pg/mL, interpreted relative to simultaneous plasma osmolality rather than as an isolated number"}]',1,'In a patient with polyuria and dilute urine, an inappropriately low ADH despite elevated plasma osmolality (during a water deprivation test) supports central diabetes insipidus, while a normal or elevated ADH with persistently dilute urine despite osmotic stimulation supports nephrogenic diabetes insipidus (renal resistance to ADH); primary polydipsia, by contrast, shows an appropriately low ADH in the setting of low-normal osmolality from excess fluid intake. Inappropriately elevated ADH relative to a low plasma osmolality is the hallmark of the syndrome of inappropriate antidiuretic hormone secretion (SIADH), a common cause of euvolemic hyponatremia from causes including certain cancers, CNS disease, pulmonary disease, and many medications.',NULL,'[{"condition": "Central diabetes insipidus", "direction": "inappropriately low relative to elevated osmolality"}, {"condition": "Nephrogenic diabetes insipidus", "direction": "normal or elevated, but with persistent renal resistance (dilute urine despite ADH presence)"}, {"condition": "SIADH (euvolemic hyponatremia)", "direction": "inappropriately elevated relative to low plasma osmolality"}]','[{"name": "StatPearls / NCBI Bookshelf - Physiology, Vasopressin", "url": "https://www.ncbi.nlm.nih.gov/books/NBK526069/", "accessed": "2026-07-20"}, {"name": "StatPearls / NCBI Bookshelf - Arginine Vasopressin Disorder (Diabetes Insipidus)", "url": "https://www.ncbi.nlm.nih.gov/books/NBK470458/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["osmolality-serum", "sodium-na", "urine-osmolality"]',NULL,NULL,'Is a formal water deprivation test planned to properly interpret this result alongside my osmolality? Could any of my current medications be contributing to inappropriate ADH secretion?','Confirmed central diabetes insipidus is treated with desmopressin (a synthetic ADH analog); nephrogenic diabetes insipidus is managed by addressing the underlying cause (including reviewing causative medications like lithium) plus supportive measures; SIADH is managed with fluid restriction and treatment of the underlying cause, with careful correction of sodium to avoid overly rapid correction.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (199,'thyroglobulin','Thyroglobulin, Serum','','Tg, Thyroglobulin Tumor Marker','Immunoassay / Endocrinology','Used primarily as a tumor marker after treatment (thyroidectomy with or without radioactive iodine ablation) for differentiated thyroid cancer (papillary or follicular), to monitor for residual disease or recurrence; not useful for initial diagnosis since it does not distinguish benign from malignant thyroid tissue.',NULL,'Venous serum','Must always be measured together with thyroglobulin antibody (TgAb), since even low-level TgAb can artifactually suppress measured thyroglobulin in immunoassay methods, causing a falsely low or undetectable result that could mask actual disease; a rising TgAb trend itself can be used as an imperfect surrogate marker of disease when TgAb interferes with direct Tg measurement.',NULL,'Immunoassay (chemiluminescent or enzyme immunoassay) on automated analyzers; TSH-stimulated thyroglobulin testing (after recombinant TSH or during hypothyroid withdrawal) provides higher sensitivity for detecting small amounts of residual disease than a suppressed (on-therapy) level alone.',NULL,'[{"parameter": "Thyroglobulin, euthyroid individual with intact thyroid, TgAb-negative", "population": "General adult", "range": "approximately 3-40 ng/mL (assay-dependent, not standardized between manufacturers)"}, {"parameter": "Thyroglobulin, post-thyroidectomy + radioiodine ablation, TSH-stimulated (per American Thyroid Association)", "population": "Post-treatment thyroid cancer", "range": "<1.0 ng/mL associated with high probability of remission"}]',1,'After total thyroidectomy and radioactive iodine ablation for differentiated thyroid cancer, thyroglobulin should fall to a very low or undetectable level, since it is produced only by thyroid tissue (normal or cancerous); a persistently detectable or rising level over serial measurements suggests residual or recurrent disease and prompts further imaging, while an undetectable, TgAb-negative, TSH-stimulated level is reassuring for remission. Because assay methods and cutoffs are not standardized across manufacturers, serial monitoring in an individual patient should ideally use the same laboratory/assay over time for meaningful trend comparison.',NULL,'[{"condition": "Residual or recurrent differentiated thyroid cancer (post-treatment)", "direction": "persistently detectable or rising level on serial measurement"}, {"condition": "Successful ablation / remission", "direction": "undetectable, TgAb-negative, TSH-stimulated level"}]','[{"name": "Medscape/eMedicine - Thyroglobulin: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2089532-overview", "accessed": "2026-07-20"}, {"name": "PMC - Serum Thyroglobulin Reference Intervals in Regions with Adequate Iodine Intake", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5134814/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["thyroid-antibodies-tpoab-and-tgab", "thyroid-stimulating-hormone"]',NULL,NULL,'Was my thyroglobulin antibody checked alongside this result, since a positive antibody could make this level unreliable? Should this be repeated using TSH stimulation for the most sensitive assessment?','A rising or persistently detectable level prompts neck ultrasound and, depending on the clinical scenario, further imaging (whole-body radioiodine scan, cross-sectional imaging) to localize possible residual or recurrent disease; TgAb-positive patients are followed using the antibody trend as a surrogate marker when direct Tg measurement is unreliable.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (200,'androstenedione','Androstenedione, Serum','','Androstenedione, A4','Immunoassay / Endocrinology','Evaluates suspected androgen excess in women (hirsutism, acne, irregular cycles), part of the workup for polycystic ovary syndrome and congenital adrenal hyperplasia, and used in the evaluation of ambiguous genitalia and precocious puberty in children.',NULL,'Venous serum, morning collection preferred given diurnal variation similar to other adrenal androgens','Typically ordered alongside total and free testosterone, DHEA-S, and 17-hydroxyprogesterone as part of a full androgen/adrenal panel, since no single marker reliably localizes the source (ovarian vs. adrenal) of androgen excess on its own.',NULL,'Chemiluminescent immunoassay or, increasingly preferred for accuracy at low concentrations, liquid chromatography-tandem mass spectrometry (LC-MS/MS).',NULL,'[{"parameter": "Androstenedione", "population": "Adult women", "range": "approximately 30-200 ng/dL (assay-dependent)"}, {"parameter": "Androstenedione", "population": "Adult men", "range": "approximately 40-150 ng/dL (assay-dependent)"}]',1,'Elevated androstenedione, an intermediate androgen produced by both the ovaries/testes and the adrenal glands (and a direct precursor to testosterone and estrone), is seen in polycystic ovary syndrome, congenital adrenal hyperplasia (particularly non-classic 21-hydroxylase deficiency, where it''s often used alongside 17-hydroxyprogesterone), and, less commonly, androgen-secreting adrenal or ovarian tumors, which should be considered when elevation is marked or accompanied by rapidly progressive virilization. Because it is produced by both glands, an isolated androstenedione elevation doesn''t localize the source, and additional markers (DHEA-S favoring adrenal origin, LH/FSH ratio and pelvic ultrasound favoring ovarian origin) are used together to narrow the differential.',NULL,'[{"condition": "Polycystic ovary syndrome", "direction": "mildly to moderately elevated"}, {"condition": "Non-classic congenital adrenal hyperplasia", "direction": "elevated, alongside elevated 17-hydroxyprogesterone"}, {"condition": "Androgen-secreting tumor (adrenal or ovarian)", "direction": "markedly elevated, especially with rapid virilization"}]','[{"name": "Mayo Clinic Laboratories Endocrinology Catalog - Renin Activity context and general endocrine reference approach", "url": "https://endocrinology.testcatalog.org/show/PRA", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["testosterone-total-serum", "dehydroepiandrosterone-sulfate-dhea-s-serum", "17-hydroxyprogesterone-17-ohp-serum"]',NULL,NULL,'Given my full androgen panel, does this look more consistent with PCOS, an adrenal source, or something that needs imaging to exclude a tumor? How rapidly did my symptoms develop, since that affects how urgently this needs to be worked up?','Mild to moderate elevation with a compatible clinical picture and gradual symptom onset is generally worked up as PCOS or non-classic CAH with the relevant additional tests; marked elevation or rapidly progressive virilizing symptoms warrant prompt imaging (pelvic ultrasound, adrenal CT/MRI) to exclude a hormone-secreting tumor.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (201,'vitamin-b1-thiamine','Vitamin B1 (Thiamine), Whole Blood','','Thiamine, Vitamin B1, Thiamine Pyrophosphate','Clinical Chemistry','Evaluates suspected thiamine deficiency, relevant in alcohol use disorder, malnutrition/refeeding syndrome, bariatric surgery, hyperemesis gravidarum, and unexplained encephalopathy (Wernicke''s encephalopathy) or heart failure (wet beriberi).',NULL,'Whole blood (EDTA), protected from light','In suspected Wernicke''s encephalopathy, treatment with thiamine should never be delayed while awaiting laboratory confirmation, since the condition is a medical emergency and the risk of untreated deficiency (permanent Korsakoff amnestic syndrome) far outweighs the low risk of empiric thiamine administration.',NULL,'High-performance liquid chromatography (HPLC), measuring thiamine pyrophosphate (the active cofactor form) in whole blood or erythrocytes.',NULL,'[{"parameter": "Whole blood thiamine (thiamine pyrophosphate)", "population": "Adult", "range": "approximately 70-180 nmol/L (assay-dependent; deficiency generally reflected by levels below the local reference range)"}]',1,'Low thiamine supports a diagnosis of deficiency, which classically causes Wernicke''s encephalopathy (the triad of confusion, ataxia, and eye movement abnormalities, though all three are present in only a minority of cases) and, if untreated, can progress to irreversible Korsakoff syndrome; it also causes dry beriberi (peripheral neuropathy) and wet beriberi (high-output heart failure). Common risk factors include chronic alcohol use (impaired absorption and intake), malnutrition, prolonged vomiting (including hyperemesis gravidarum), bariatric surgery, and refeeding after prolonged starvation, where thiamine should be given before or with any glucose-containing fluids to avoid precipitating acute deficiency symptoms.',NULL,'[{"condition": "Wernicke''s encephalopathy / Korsakoff syndrome", "direction": "low, in a patient with compatible risk factors and symptoms"}, {"condition": "Beriberi (dry: peripheral neuropathy; wet: high-output heart failure)", "direction": "low"}]','[{"name": "PMC/StatPearls-style clinical toxicology reference used for TDM and micronutrient testing context", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9350491/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["folate-folic-acid-serum", "vitamin-b12-cobalamin-serum"]',NULL,NULL,'Given my risk factors, was thiamine started empirically without waiting for this result, given how time-sensitive untreated deficiency can be? Do I need ongoing supplementation, and for how long?','Confirmed or strongly suspected deficiency is treated with thiamine repletion (parenteral in acute or severe cases, particularly suspected Wernicke''s encephalopathy, given uncertain oral absorption), given before glucose administration in at-risk patients, with attention to the underlying cause (alcohol use, malnutrition, ongoing GI losses).');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (202,'vitamin-e-tocopherol','Vitamin E (Alpha-Tocopherol), Serum','','Vitamin E, Alpha-Tocopherol','Clinical Chemistry','Evaluates suspected vitamin E deficiency, most often related to fat malabsorption syndromes (cystic fibrosis, cholestatic liver disease, chronic pancreatitis, short bowel syndrome) or rare genetic disorders of vitamin E transport, presenting with peripheral neuropathy, ataxia, or retinopathy.',NULL,'Venous serum, protected from light','Because vitamin E is transported in blood bound to lipoproteins, serum levels should be interpreted relative to total serum lipids (or expressed as a vitamin E-to-lipid ratio) in patients with significant hyperlipidemia, since an elevated lipid level can falsely raise the absolute vitamin E concentration without reflecting true tissue sufficiency.',NULL,'High-performance liquid chromatography (HPLC).',NULL,'[{"parameter": "Serum alpha-tocopherol", "population": "Adult", "range": "approximately 5.5-17 mg/L (or corrected as a ratio to total serum lipids in patients with abnormal lipid levels)"}]',1,'Low vitamin E supports deficiency, which principally affects the nervous system (peripheral neuropathy, ataxia, areflexia, and in children, potential impact on neurodevelopment) and the retina (pigmentary retinopathy), reflecting vitamin E''s role as a major lipid-soluble antioxidant protecting cell membranes, particularly in neural tissue, from oxidative damage. Because absorption depends on adequate fat digestion and lipoprotein transport, most acquired deficiency in adults occurs in the setting of chronic fat malabsorption rather than dietary insufficiency alone, so identifying and addressing the underlying malabsorptive condition is as important as direct supplementation.',NULL,'[{"condition": "Vitamin E deficiency (fat malabsorption, cystic fibrosis, cholestatic liver disease)", "direction": "low"}, {"condition": "Ataxia with vitamin E deficiency (rare genetic disorder of vitamin E transport)", "direction": "low, with neurologic symptoms out of proportion to any dietary/malabsorptive cause"}]','[{"name": "NIH Office of Dietary Supplements - Vitamin A and Carotenoids Fact Sheet (general fat-soluble vitamin testing context)", "url": "https://ods.od.nih.gov/factsheets/VitaminA-HealthProfessional/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["vitamin-a-retinol-serum", "vitamin-k1-phylloquinone-serum", "lipid-panel"]',NULL,NULL,'Since this level should be interpreted relative to my lipid levels, was that correction applied? Is there an underlying malabsorption condition that needs its own evaluation and treatment alongside supplementation?','Confirmed deficiency is treated with oral vitamin E supplementation (dosing adjusted for the severity of malabsorption, which may require much higher doses than typical dietary supplementation) alongside management of the underlying cause; neurologic symptoms are monitored for improvement, recognizing that some deficits may only partially reverse if deficiency has been prolonged.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (203,'urine-protein-24-hour','Urine Protein, 24-Hour Collection (Quantitative)','','24-Hour Urine Protein, Proteinuria Quantification','Clinical Chemistry / Urinalysis','Quantifies total daily protein loss in the urine, used to confirm and grade significant proteinuria found on screening urinalysis or urine albumin-to-creatinine ratio, characterize nephrotic-range proteinuria, and monitor kidney disease over time.',NULL,'Complete 24-hour urine collection (all urine passed over a full 24-hour period, in an appropriate preservative-containing container if instructed by the laboratory)','Incomplete collection is the most common source of error and materially affects accuracy; concurrent measurement of urine creatinine in the same collection can help verify collection adequacy (based on expected creatinine excretion for the patient''s muscle mass), and a spot urine protein-to-creatinine ratio is often used as a more practical, reasonably well-correlated alternative when a full 24-hour collection is impractical.',NULL,'Automated turbidimetric or colorimetric (e.g., pyrogallol red) protein assay on a chemistry analyzer.',NULL,'[{"parameter": "Total urine protein, 24-hour", "population": "Adult", "range": "<150 mg/24 hours"}, {"parameter": "Nephrotic-range proteinuria", "population": "Adult", "range": "\u22653.5 g/24 hours"}]',1,'Proteinuria above the normal range indicates glomerular or tubular kidney injury, with the degree of proteinuria helping characterize the pattern and severity of disease -- nephrotic-range proteinuria (≥3.5 g/24h), often accompanied by hypoalbuminemia, edema, and hyperlipidemia, points toward primary glomerular diseases (minimal change disease, membranous nephropathy, focal segmental glomerulosclerosis) or systemic diseases affecting the glomerulus (diabetic nephropathy, lupus nephritis, amyloidosis), while lesser degrees of proteinuria are seen across a broader range of kidney conditions. Serial 24-hour urine protein measurements are also used to track disease progression or response to treatment (e.g., ACE inhibitor/ARB therapy, immunosuppression for glomerulonephritis) over time.',NULL,'[{"condition": "Nephrotic syndrome (minimal change disease, membranous nephropathy, FSGS)", "direction": "high, \u22653.5 g/24h with hypoalbuminemia"}, {"condition": "Diabetic nephropathy / other glomerular disease", "direction": "elevated, variable degree"}]','[{"name": "Mayo Clinic Laboratories Endocrinology Catalog - reference approach used for quantitative chemistry testing context", "url": "https://endocrinology.testcatalog.org/show/PRA", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["urine-albumin-to-creatinine-ratio-acr-microalbumin", "serum-creatinine"]',NULL,NULL,'Was the collection likely complete and accurate based on the creatinine content? Given this level of protein loss, do I need a kidney biopsy or specific treatment to reduce proteinuria and protect kidney function?','Significant proteinuria prompts further workup for the underlying cause, which may include a kidney biopsy (particularly for nephrotic-range proteinuria without an obvious cause like long-standing diabetes), and treatment aimed at reducing proteinuria (ACE inhibitors/ARBs, disease-specific immunosuppression) alongside monitoring of kidney function over time.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (204,'urine-osmolality','Urine Osmolality','','Urine Osm, Osmolality Urine','Clinical Chemistry / Urinalysis','Assesses the kidney''s urine-concentrating ability, used in the workup of polyuria, hyponatremia, and hypernatremia, and to help distinguish diabetes insipidus from primary polydipsia and from SIADH in combination with serum osmolality and ADH.',NULL,'Random or timed urine specimen, depending on the clinical question','Interpretation always requires simultaneous serum/plasma osmolality for context, since a urine osmolality value is only meaningful relative to the concurrent plasma osmolality and clinical volume status; formal water deprivation testing with serial measurements is used when diabetes insipidus is suspected.',NULL,'Freezing-point depression osmometry.',NULL,'[{"parameter": "Random urine osmolality", "population": "Adult, normally hydrated", "range": "approximately 300-900 mOsm/kg, highly dependent on fluid intake"}, {"parameter": "Maximally concentrated urine (after water deprivation)", "population": "Adult with normal concentrating ability", "range": ">800 mOsm/kg, generally exceeding simultaneous plasma osmolality substantially"}, {"parameter": "Inappropriately dilute urine, suggestive of diabetes insipidus", "population": "Adult with polyuria", "range": "<300 mOsm/kg despite elevated plasma osmolality/dehydration"}]',1,'In a patient with polyuria, urine that remains inappropriately dilute (low osmolality) despite water deprivation and rising plasma osmolality indicates a defect in urinary concentrating ability, seen in both central and nephrogenic diabetes insipidus (distinguished by response to administered desmopressin) and, in milder degree, in primary polydipsia after prolonged excess fluid intake. In the hyponatremia workup, an inappropriately concentrated urine (osmolality above roughly 100 mOsm/kg) despite low serum sodium/osmolality points toward ADH-mediated water retention (SIADH or another cause of inappropriate ADH activity) rather than primary polydipsia, where urine is typically maximally dilute.',NULL,'[{"condition": "Diabetes insipidus (central or nephrogenic)", "direction": "inappropriately low despite water deprivation/hypertonicity"}, {"condition": "SIADH", "direction": "inappropriately concentrated relative to low serum osmolality"}, {"condition": "Primary polydipsia", "direction": "appropriately dilute, reflecting excess fluid intake"}]','[{"name": "StatPearls / NCBI Bookshelf - Arginine Vasopressin Disorder (Diabetes Insipidus)", "url": "https://www.ncbi.nlm.nih.gov/books/NBK470458/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["osmolality-serum", "adh-vasopressin", "sodium-na"]',NULL,NULL,'Was my serum osmolality checked at the same time, since this result can''t be interpreted alone? Is a formal water deprivation test needed to distinguish between the possible causes?','Results suggesting diabetes insipidus lead to a formal water deprivation test with desmopressin challenge to distinguish central from nephrogenic causes; results suggesting SIADH lead to investigation of the underlying cause (medications, pulmonary or CNS disease, malignancy) and fluid restriction as initial management.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (205,'urinary-free-cortisol-24-hour','Urinary Free Cortisol, 24-Hour Collection','','UFC, 24-Hour Urine Cortisol, Free Cortisol Urine','Immunoassay / Endocrinology','One of several first-line screening tests for Cushing''s syndrome (endogenous cortisol excess), reflecting integrated cortisol production over a full day rather than a single timepoint.',NULL,'Complete 24-hour urine collection','As with other 24-hour collections, incomplete collection is the main source of error; multiple collections (at least two) are generally recommended given day-to-day variability in cortisol production, and the test should not be used as a stand-alone diagnostic test but interpreted alongside other screening tests (late-night salivary cortisol, low-dose dexamethasone suppression test).',NULL,'Chemiluminescent immunoassay or, for greater specificity (avoiding cross-reactivity with cortisol metabolites and certain medications), liquid chromatography-tandem mass spectrometry (LC-MS/MS).',NULL,'[{"parameter": "Urinary free cortisol, 24-hour", "population": "Adult", "range": "approximately 10-100 mcg/24 hours (assay-dependent; values several-fold above the upper reference limit are considered strongly supportive of Cushing''s syndrome)"}]',1,'An elevated urinary free cortisol, especially when more than 3-4 times the upper limit of normal and reproduced on repeat collection, is strongly supportive of Cushing''s syndrome, though mild elevations can also occur in states of physiologic stress, depression, alcohol use disorder, obesity, and poorly controlled diabetes (''pseudo-Cushing'' states), which is why the diagnosis relies on a combination of tests rather than this result alone. A normal result on a single collection does not fully exclude Cushing''s syndrome, particularly in mild or cyclical disease, which is part of why current guidelines recommend at least two abnormal screening tests (from different test types) before proceeding to further localization workup.',NULL,'[{"condition": "Cushing''s syndrome (endogenous cortisol excess)", "direction": "elevated, especially markedly and reproducibly"}, {"condition": "Pseudo-Cushing states (obesity, depression, alcohol use, poorly controlled diabetes)", "direction": "mildly elevated without true autonomous cortisol excess"}]','[{"name": "PMC - Syndrome of Inappropriate ADH context referencing cortisol/endocrine screening workflow", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC10731729/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["cortisol-serum-am", "adrenocorticotropic-hormone-acth-plasma"]',NULL,NULL,'Given the possibility of day-to-day variation, will this collection be repeated, and are other screening tests (like late-night salivary cortisol or dexamethasone suppression) also planned? Could any of my current health conditions be causing a ''pseudo-Cushing'' pattern rather than true Cushing''s syndrome?','A clearly elevated, reproducible result supports proceeding to determine the cause (ACTH level to distinguish ACTH-dependent from ACTH-independent disease, followed by pituitary or adrenal imaging as indicated); borderline or single-abnormal results are usually confirmed with a second, different type of screening test before further workup.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (206,'beta-hydroxybutyrate','Beta-Hydroxybutyrate (Ketones), Blood','','BOHB, Blood Ketones, Beta-Hydroxybutyrate','Clinical Chemistry','Confirms and quantifies ketosis/ketoacidosis, most importantly diabetic ketoacidosis (DKA), and is used to monitor response to treatment; also relevant in alcoholic ketoacidosis and prolonged fasting/starvation ketosis.',NULL,'Venous or capillary (fingerstick) whole blood, or venous serum/plasma','Blood beta-hydroxybutyrate has replaced urine ketone testing as the preferred method in most acute-care settings, since it directly measures the predominant ketone body in DKA and is not subject to the false positives/negatives seen with urine nitroprusside-based ketone strips (which primarily detect acetoacetate, not beta-hydroxybutyrate).',NULL,'Enzymatic assay on a point-of-care ketone meter or automated chemistry analyzer.',NULL,'[{"parameter": "Normal", "population": "General", "range": "<0.6 mmol/L"}, {"parameter": "Mild ketosis", "population": "General", "range": "0.6-1.0 mmol/L"}, {"parameter": "Moderate ketosis, medical evaluation warranted", "population": "General", "range": "1.0-3.0 mmol/L"}, {"parameter": "Consistent with diabetic ketoacidosis", "population": "General, with compatible clinical/acid-base picture", "range": ">3.0 mmol/L"}]',1,'In a patient with hyperglycemia and metabolic acidosis, a beta-hydroxybutyrate level above approximately 3.0 mmol/L supports a diagnosis of diabetic ketoacidosis, and the level is also used to track treatment response, with resolution of DKA generally corresponding to the level falling below about 1.0 mmol/L alongside normalization of the anion gap and pH. Elevated levels can also reflect alcoholic ketoacidosis (in the setting of chronic alcohol use, poor intake, and recent heavy drinking, typically with normal or low glucose) or prolonged starvation ketosis, both of which are distinguished from diabetic ketoacidosis by the clinical context and glucose level rather than the ketone level alone.',NULL,'[{"condition": "Diabetic ketoacidosis", "direction": "elevated, typically >3.0 mmol/L, with hyperglycemia and acidosis"}, {"condition": "Alcoholic ketoacidosis", "direction": "elevated, typically with normal/low glucose and history of heavy alcohol use with poor intake"}, {"condition": "Starvation ketosis", "direction": "mild-moderate elevation, with a compatible history of prolonged fasting"}]','[{"name": "Medscape/eMedicine - Beta-Hydroxybutyrate: Reference Range, Interpretation, Collection and Panels", "url": "https://emedicine.medscape.com/article/2087381-overview", "accessed": "2026-07-20"}, {"name": "Medscape/eMedicine - Diabetic Ketoacidosis (DKA) Workup", "url": "https://emedicine.medscape.com/article/118361-workup", "accessed": "2026-07-20"}]',1,'2026-07-20 05:32:38','2026-07-20 05:32:38','["arterial-blood-gas", "fasting-plasma-glucose", "bicarbonate-co2-total-carbon-dioxide"]',NULL,NULL,'Is this level being used to help decide the intensity of my treatment (fluids, insulin) as well as to confirm the diagnosis? How often will it be rechecked to track my response to treatment?','A level supporting DKA leads to standard treatment (IV fluids, insulin infusion, electrolyte repletion, particularly potassium) with serial rechecking of the level (or the anion gap if ketone testing isn''t readily available) to guide the pace of treatment and confirm resolution before transitioning off IV insulin.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (207,'osmotic-fragility-test','Osmotic Fragility Test','','Red Cell Osmotic Fragility, OFT','Hematology','Evaluates suspected hereditary spherocytosis and other conditions causing abnormally shaped or fragile red blood cells, by measuring how readily red cells hemolyze when exposed to progressively hypotonic saline solutions.',NULL,'Venous whole blood (heparin or EDTA, per laboratory protocol)','Largely superseded in many reference laboratories by more specific, standardized tests (eosin-5-maleimide binding by flow cytometry, or genetic testing) for confirming hereditary spherocytosis, since osmotic fragility has notable overlap with normal in mild cases and can be falsely normal shortly after a transfusion or in the presence of reticulocytosis.',NULL,'Red cells are incubated in a series of saline solutions of decreasing concentration, and the percentage of hemolysis at each concentration is measured and compared to a normal curve; an incubated (24-hour) version increases sensitivity for mild cases.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Normal curve, or a left-shifted curve (increased fragility, hemolysis occurring at higher/less-hypotonic saline concentrations than normal)"}]',1,'Increased osmotic fragility (a left-shifted curve, meaning hemolysis occurs at less dilute saline than normal) is characteristic of hereditary spherocytosis, in which red cells lose surface area relative to volume due to a membrane protein defect, making them less able to withstand osmotic stress; it can also be seen with autoimmune hemolytic anemia and some other membrane disorders. Decreased osmotic fragility (a right-shifted curve, more resistant to hemolysis than normal) is seen with conditions producing thin or flattened red cells with increased surface-to-volume ratio, such as thalassemia, iron deficiency anemia, and other states with target cells or reticulocytosis.',NULL,'[{"condition": "Hereditary spherocytosis", "direction": "increased fragility (left-shifted curve)"}, {"condition": "Thalassemia / iron deficiency anemia (target cells)", "direction": "decreased fragility (right-shifted curve)"}]','[{"name": "PMC - reference used for red cell membrane/hemolytic anemia testing context", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9350491/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["complete-blood-count", "hemoglobin-electrophoresis-hemoglobinopathy-evaluation"]',NULL,NULL,'Given the overlap with normal in mild cases, would a more specific test (like eosin-5-maleimide binding or genetic testing) help confirm this diagnosis? Does a family history of anemia or gallstones support this diagnosis alongside the test result?','A result consistent with hereditary spherocytosis, especially with a compatible family history, splenomegaly, and jaundice/gallstones, generally leads to further confirmatory testing (eosin-5-maleimide flow cytometry) and evaluation for possible splenectomy in more severe cases; unexplained decreased fragility prompts hemoglobin electrophoresis and iron studies to evaluate for thalassemia or iron deficiency.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (208,'peripheral-blood-smear','Peripheral Blood Smear (Manual Review)','','PBS, Blood Film, Peripheral Smear','Hematology','Direct microscopic examination of red cells, white cells, and platelets on a stained blood film, used to evaluate abnormal complete blood count results, characterize anemias, identify blood parasites (e.g., malaria), and detect abnormal or immature cells suggestive of leukemia or other hematologic disease.',NULL,'Venous whole blood (EDTA), made into a thin film and stained (typically Wright-Giemsa stain)','A smear should be reviewed promptly after collection, since red cell morphology and some parasites (notably some malaria species) can be affected by prolonged EDTA exposure; a smear is often triggered automatically by an automated hematology analyzer''s flagging of an abnormal or unclassifiable result, in addition to being ordered directly.',NULL,'Light microscopy of a stained blood film by a trained laboratory professional, evaluating red cell morphology (size, shape, color, inclusions), white cell differential and morphology, and platelet number/morphology.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Normal morphology across all three cell lines, or a descriptive report of specific abnormalities (e.g., schistocytes, spherocytes, blasts, hypersegmented neutrophils) with an interpretive comment"}]',1,'Specific red cell morphologic findings point toward particular diagnoses: schistocytes (fragmented cells) suggest microangiopathic hemolytic anemia (TTP, HUS, DIC, mechanical heart valve), spherocytes suggest hereditary spherocytosis or autoimmune hemolysis, target cells suggest thalassemia or liver disease, and sickle cells confirm sickle cell disease. On the white cell side, blasts (immature precursor cells) in the peripheral blood are a critical finding requiring urgent evaluation for acute leukemia, while other findings (toxic granulation, left shift, atypical lymphocytes) support infection or reactive processes; platelet clumping can cause a falsely low automated platelet count that the smear can identify as an artifact.',NULL,'[{"condition": "Microangiopathic hemolytic anemia (TTP, HUS, DIC)", "direction": "schistocytes present"}, {"condition": "Acute leukemia", "direction": "circulating blasts present"}, {"condition": "Malaria and other blood parasites", "direction": "intracellular/extracellular parasites identified on the smear"}]','[{"name": "PMC - reference used for hematologic morphology and anemia workup context", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9045330/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["complete-blood-count", "reticulocyte-count", "malaria-smear-rdt"]',NULL,NULL,'What specific abnormality was seen on the smear, and what does it mean for my diagnosis? Does this finding require urgent further testing (like a bone marrow biopsy or specific hemolysis workup)?','Findings suggestive of a serious process (blasts, schistocytes with thrombocytopenia, malaria parasites) prompt urgent further evaluation and, where relevant, urgent treatment; more indolent findings guide targeted follow-up testing (hemolysis labs, hemoglobin electrophoresis, iron studies) based on the specific morphologic pattern seen.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (209,'bleeding-time','Bleeding Time (Ivy Method)','','Bleeding Time, Ivy Bleeding Time','Hematology / Coagulation','Historically used to assess primary hemostasis (platelet number/function and blood vessel wall interaction), largely replaced in current practice by platelet function analyzers (e.g., PFA-100) and specific platelet aggregation studies due to poor standardization and reproducibility.',NULL,'In vivo test performed directly on the patient''s forearm (not a blood sample sent to the laboratory)','This test has largely fallen out of routine clinical use due to significant inter-operator variability, lack of standardization, and poor correlation with actual surgical bleeding risk; it is included here for reference completeness and historical/comparative context, as some centers or contexts (including certain resource-limited settings) may still use it.',NULL,'A standardized small incision is made on the volar forearm under a blood pressure cuff maintained at a set pressure, and the time to cessation of bleeding is measured (Ivy method) or, in the older Duke method, a fingertip/earlobe incision is used.',NULL,'[{"parameter": "Bleeding time (Ivy method)", "population": "Adult", "range": "approximately 2-9 minutes (method- and device-dependent)"}]',1,'A prolonged bleeding time historically suggested a disorder of primary hemostasis -- thrombocytopenia, qualitative platelet dysfunction (including from aspirin/antiplatelet medications), von Willebrand disease, or vascular disorders -- but the test''s poor reproducibility, operator dependence, and limited predictive value for actual surgical or clinical bleeding risk have led most laboratories and clinical guidelines to replace it with platelet function analyzer testing (PFA-100/200) and, where indicated, specific platelet aggregation studies or von Willebrand panel testing. A normal bleeding time does not reliably exclude a mild bleeding disorder, and the test is not recommended as a general pre-operative screening tool given its limited value for predicting surgical bleeding.',NULL,'[{"condition": "Thrombocytopenia or qualitative platelet dysfunction", "direction": "prolonged (historically; low diagnostic reliability)"}, {"condition": "von Willebrand disease", "direction": "prolonged (historically; specific vWF testing now preferred)"}]','[{"name": "PMC - hemostasis testing standardization context", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9045330/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["platelet-function-analyzer-pfa-100", "complete-blood-count"]',NULL,NULL,'Given this test''s known limitations, would a platelet function analyzer test or specific von Willebrand panel give more reliable information about my bleeding risk?','In current practice, an abnormal or clinically concerning bleeding history is generally worked up with a platelet count, PFA-100/200 platelet function testing, and a von Willebrand disease panel rather than relying on bleeding time; results feed into decisions about perioperative management or specific hematologic treatment as needed.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (210,'platelet-function-analyzer-pfa-100','Platelet Function Analyzer (PFA-100/PFA-200)','','PFA-100, PFA-200, Platelet Function Assay, Closure Time','Hematology / Coagulation','Screens for qualitative platelet dysfunction and von Willebrand disease under high-shear flow conditions that mimic in vivo platelet plug formation, used in the workup of a mucocutaneous bleeding history and to help evaluate suspected antiplatelet medication effect.',NULL,'Venous whole blood (citrate), tested promptly after collection','Results are affected by hematocrit and platelet count, so significant anemia or thrombocytopenia can prolong closure time independent of true platelet dysfunction and should be accounted for when interpreting the result; recent aspirin or other antiplatelet medication use is a common and important cause of a prolonged result that should be documented at the time of testing.',NULL,'A citrated whole blood sample is aspirated through a small aperture coated with collagen and either epinephrine or ADP under high shear stress, and the time to platelet plug formation and aperture closure is measured.',NULL,'[{"parameter": "Closure time, collagen/epinephrine cartridge", "population": "Adult, normal hematocrit and platelet count", "range": "approximately 82-150 seconds (device/reagent lot-dependent)"}, {"parameter": "Closure time, collagen/ADP cartridge", "population": "Adult, normal hematocrit and platelet count", "range": "approximately 62-100 seconds (device/reagent lot-dependent)"}]',1,'Prolonged closure time on both cartridges, in the absence of significant anemia or thrombocytopenia, suggests either von Willebrand disease or an intrinsic platelet function disorder, and typically prompts specific von Willebrand studies (antigen, activity) and, if those are normal, formal platelet aggregation studies to characterize a suspected platelet function defect. A prolonged collagen/epinephrine closure time with a normal collagen/ADP closure time is a classic (though not entirely specific) pattern associated with aspirin effect, since ADP-pathway activation partially bypasses the cyclooxygenase pathway that aspirin inhibits.',NULL,'[{"condition": "von Willebrand disease", "direction": "prolonged on both cartridges"}, {"condition": "Qualitative platelet function disorder", "direction": "prolonged on both cartridges, vWF studies normal"}, {"condition": "Aspirin/antiplatelet medication effect", "direction": "prolonged collagen/epinephrine with relatively preserved collagen/ADP"}]','[{"name": "PMC - hemostasis and coagulation testing standardization context", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9045330/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["von-willebrand-factor-antigen-ristocetin-cofactor-activity", "complete-blood-count"]',NULL,NULL,'Could my hematocrit, platelet count, or a medication I''m taking be affecting this result independent of a true platelet disorder? What follow-up testing is planned if this result is abnormal?','An abnormal result prompts specific von Willebrand disease testing and, if that is unrevealing, referral for formal platelet aggregation studies; a clearly medication-related pattern (recent aspirin use) may simply be noted and the test repeated after an appropriate washout period if clinically needed.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (211,'coagulation-mixing-study','Coagulation Mixing Study (PT/aPTT Correction Study)','','Mixing Study, 1:1 Mix, PTT Correction Study','Hematology / Coagulation','Investigates a prolonged PT and/or aPTT of unclear cause, distinguishing a true factor deficiency (which corrects with mixing) from the presence of an inhibitor such as a lupus anticoagulant or a specific factor inhibitor (which does not fully correct).',NULL,'Venous plasma (citrate), from both the patient and pooled normal plasma','The patient''s plasma is mixed 1:1 with pooled normal plasma, and the PT and/or aPTT is repeated immediately and, for aPTT, often again after a period of incubation at 37°C (since some inhibitors, notably factor VIII inhibitors, are time- and temperature-dependent and may only become apparent on the incubated mix).',NULL,'Clot-based coagulation assay (PT and/or aPTT) performed on the 1:1 mixture of patient and normal pooled plasma, compared against the original patient result and the normal reference range.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Correction (mixed result falls within or close to the normal reference range) supports factor deficiency; failure to correct (mixed result remains significantly prolonged) supports an inhibitor"}]',1,'If the prolonged clotting time corrects with mixing, it indicates the patient is simply missing sufficient clotting factor (which is supplied by the normal plasma in the mix), pointing toward an inherited or acquired factor deficiency (e.g., hemophilia, liver disease, vitamin K deficiency, warfarin effect) and prompting specific factor level testing to identify which factor is deficient. If the clotting time fails to correct (remains prolonged), it indicates the presence of an inhibitor -- most commonly a lupus anticoagulant (part of the antiphospholipid antibody syndrome workup) causing aPTT prolongation without a true bleeding tendency, or less commonly a specific factor inhibitor (such as an acquired factor VIII inhibitor), which does carry a significant bleeding risk and requires urgent hematology involvement.',NULL,'[{"condition": "Factor deficiency (hemophilia, liver disease, vitamin K deficiency, anticoagulant effect)", "direction": "mixing study corrects"}, {"condition": "Lupus anticoagulant", "direction": "mixing study does not correct; aPTT prolonged without bleeding tendency"}, {"condition": "Acquired factor inhibitor (e.g., factor VIII inhibitor)", "direction": "mixing study does not correct, especially after incubation; associated with significant bleeding risk"}]','[{"name": "PMC - coagulation abnormality workup context", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9045330/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["prothrombin-time-inr", "activated-partial-thromboplastin-time-aptt", "factor-ix-activity"]',NULL,NULL,'Based on whether this corrected or not, what specific follow-up testing (factor levels, lupus anticoagulant panel) is being ordered next? If an inhibitor is suspected, does this affect my bleeding risk for any upcoming procedures?','A correcting result leads to specific factor level testing to identify and quantify the deficiency; a non-correcting result leads to a lupus anticoagulant panel (if aPTT-based, with no bleeding history) or specific factor inhibitor (Bethesda) assay testing (especially if there is an active bleeding history), with urgent hematology consultation for suspected acquired factor inhibitors.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (212,'factor-ix-activity','Coagulation Factor IX Activity Assay','','Factor IX, FIX Activity, Hemophilia B Testing','Hematology / Coagulation','Diagnoses and classifies severity of hemophilia B (factor IX deficiency), and is used to guide factor replacement dosing in known patients before procedures or during bleeding episodes.',NULL,'Venous plasma (citrate)','Should be drawn before administration of any factor replacement product or, in patients on certain non-factor hemophilia therapies, coordinated with the hematology team since some newer agents can interfere with standard clotting-based factor assays.',NULL,'One-stage clotting assay measuring the degree of aPTT correction of factor IX-deficient plasma by dilutions of the patient''s plasma, compared to a standard curve.',NULL,'[{"parameter": "Factor IX activity, normal", "population": "General", "range": "50-150% of normal (assay-dependent)"}, {"parameter": "Hemophilia B, severe", "population": "General", "range": "<1%"}, {"parameter": "Hemophilia B, moderate", "population": "General", "range": "1-5%"}, {"parameter": "Hemophilia B, mild", "population": "General", "range": ">5% and <40%"}]',1,'Factor IX activity level correlates closely with clinical bleeding severity in hemophilia B: severe deficiency (<1%) causes frequent spontaneous joint and muscle bleeding, moderate deficiency causes bleeding with minor trauma, and mild deficiency typically causes bleeding only with significant trauma or surgery. Hemophilia B is X-linked recessive and much less common than hemophilia A (factor VIII deficiency), which it clinically resembles; distinguishing between the two requires specific factor assays since they are managed with different replacement products.',NULL,'[{"condition": "Hemophilia B (congenital factor IX deficiency)", "direction": "low, severity graded by percentage activity"}, {"condition": "Acquired factor IX deficiency (severe liver disease, vitamin K deficiency, warfarin effect)", "direction": "low, typically alongside deficiency of other vitamin K-dependent factors"}]','[{"name": "PMC - inherited coagulation factor deficiency and TDM/coagulation testing reference context", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9045330/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["activated-partial-thromboplastin-time-aptt", "coagulation-factor-viii-activity-assay"]',NULL,NULL,'Given my activity level and bleeding severity category, what does my factor replacement or prophylaxis plan look like? Do family members need to be tested given the inherited nature of this condition?','Confirmed hemophilia B is managed with a personalized care plan by a hematologist, including factor IX replacement or newer non-factor therapies for bleeding episodes and surgical prophylaxis, with genetic counseling offered given the X-linked inheritance pattern and implications for family members.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (213,'factor-xi-activity','Coagulation Factor XI Activity Assay','','Factor XI, FXI Activity, Hemophilia C Testing','Hematology / Coagulation','Diagnoses factor XI deficiency (hemophilia C), a generally milder bleeding disorder with unpredictable correlation between factor level and bleeding tendency, notably more common in individuals of Ashkenazi Jewish descent.',NULL,'Venous plasma (citrate)','Should be drawn as an isolated prolonged aPTT workup test when a mixing study has confirmed a correcting pattern (suggesting factor deficiency) and factor VIII/IX have been excluded or when the specific clinical/ethnic context raises suspicion for factor XI deficiency.',NULL,'One-stage clotting assay measuring the degree of aPTT correction of factor XI-deficient plasma by dilutions of the patient''s plasma, compared to a standard curve.',NULL,'[{"parameter": "Factor XI activity, normal", "population": "General", "range": "50-150% of normal (assay-dependent); deficiency defined as below this range, with severe deficiency generally <15-20%"}]',1,'Unlike hemophilia A and B, bleeding tendency in factor XI deficiency correlates poorly with the measured factor level -- some patients with severely low levels have minimal bleeding, while others with partial deficiency experience significant bleeding, particularly with surgery or trauma involving tissues rich in fibrinolytic activity (e.g., oral/dental surgery, urologic procedures). Factor XI deficiency is inherited in an autosomal pattern (unlike the X-linked hemophilias A and B) and is notably more prevalent in individuals of Ashkenazi Jewish descent, where population carrier rates are substantially higher than in the general population.',NULL,'[{"condition": "Factor XI deficiency (hemophilia C)", "direction": "low, though bleeding severity correlates poorly with the level itself"}]','[{"name": "PMC - inherited coagulation factor deficiency reference context", "url": "https://www.ncbi.nlm.nih.gov/pmc/articles/PMC9045330/", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["activated-partial-thromboplastin-time-aptt", "coagulation-mixing-study"]',NULL,NULL,'Given that bleeding risk doesn''t correlate well with my factor level, has my personal or family bleeding history been taken into account in planning for any upcoming surgery? What precautions are recommended for procedures given this diagnosis?','Management is individualized based on personal/family bleeding history rather than factor level alone, with fresh frozen plasma, factor XI concentrate (where available), or antifibrinolytic agents used around high-risk procedures as determined by a hematologist; genetic counseling may be offered given the hereditary nature of the condition.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (214,'sputum-culture','Sputum Culture','','Sputum C&S, Respiratory Culture','Microbiology','Identifies bacterial pathogens causing lower respiratory tract infection (pneumonia, bronchitis exacerbation) and provides antimicrobial susceptibility testing to guide targeted antibiotic therapy.',NULL,'Expectorated sputum (deep cough sample) or, where obtainable, a more reliable lower-respiratory sample such as a bronchoalveolar lavage','Specimen quality is critical: a sample heavily contaminated with saliva/upper airway flora (assessed by the laboratory via Gram stain screening -- low squamous epithelial cells, high neutrophils indicates a good-quality sample) may yield misleading results reflecting oral flora rather than the true lower respiratory pathogen, and poor-quality specimens are often rejected or reported with a caveat.',NULL,'Aerobic culture on selective and non-selective media, with organism identification (often by MALDI-TOF mass spectrometry in modern laboratories) and antimicrobial susceptibility testing performed on significant isolates.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "No growth / normal respiratory flora, or growth of a specific pathogen with quantitative or semi-quantitative growth level and susceptibility results"}]',1,'Growth of a recognized respiratory pathogen (e.g., Streptococcus pneumoniae, Haemophilus influenzae, Staphylococcus aureus including MRSA, or gram-negative organisms like Klebsiella pneumoniae or Pseudomonas aeruginosa in healthcare-associated or complicated pneumonia) in a good-quality specimen supports the diagnosis and, importantly, allows antibiotic therapy to be narrowed from broad empiric coverage to a pathogen-directed regimen based on susceptibility results. Because sputum inevitably passes through the upper airway, results must always be interpreted alongside specimen quality indicators and the overall clinical picture, since growth of typical oral flora or a low-quality specimen does not reliably indicate the causative lower respiratory pathogen.',NULL,'[{"condition": "Bacterial pneumonia", "direction": "growth of a recognized respiratory pathogen in a good-quality specimen"}, {"condition": "Poor-quality/contaminated specimen (limits interpretability)", "direction": "growth of predominantly upper airway flora"}]','[{"name": "CDC - Guidance on respiratory specimen collection and pneumonia diagnostics (general microbiology reference)", "url": "https://www.cdc.gov/c-diff/hcp/clinical-guidance/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["blood-culture", "gram-stain", "c-reactive-protein-hs-crp"]',NULL,NULL,'Was this a good-quality lower respiratory sample based on the lab''s quality screening? Based on the susceptibility results, can my antibiotic be switched to a more targeted option?','A significant, susceptibility-tested pathogen guides narrowing of antibiotic therapy from broad empiric coverage; a poor-quality or equivocal result may prompt repeat sampling or a more invasive sampling method (bronchoscopy with bronchoalveolar lavage) if the clinical picture requires a more definitive answer.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (215,'csf-analysis-culture','Cerebrospinal Fluid (CSF) Analysis and Culture','','CSF Studies, Lumbar Puncture Analysis, Spinal Fluid Culture','Microbiology','Diagnoses central nervous system infection (bacterial, viral, fungal, or tuberculous meningitis/encephalitis), subarachnoid hemorrhage, and various inflammatory/autoimmune and malignant CNS conditions, obtained via lumbar puncture.',NULL,'Cerebrospinal fluid obtained by lumbar puncture, typically collected into multiple sequential tubes for different tests (cell count/differential, protein and glucose, Gram stain and culture, and additional studies such as PCR panels as clinically indicated)','Antibiotics should not be delayed for lumbar puncture in suspected bacterial meningitis with signs of severe illness or contraindications to immediate LP (e.g., suspected raised intracranial pressure requiring imaging first); blood cultures and, when feasible, the LP itself should be obtained as soon as safely possible, ideally before or with the first antibiotic dose.',NULL,'Cell count and differential (manual or automated), chemistry analysis (protein, glucose, often compared to a simultaneous serum glucose), Gram stain, and aerobic/fungal/AFB culture as indicated; molecular multiplex PCR panels for common meningitis/encephalitis pathogens are increasingly used alongside traditional culture for faster results.',NULL,'[{"parameter": "CSF white blood cell count", "population": "Adult, normal", "range": "\u22645/\u00b5L (predominantly lymphocytes)"}, {"parameter": "CSF protein", "population": "Adult, normal", "range": "15-45 mg/dL"}, {"parameter": "CSF glucose", "population": "Adult, normal", "range": "typically \u226560% of a simultaneous serum glucose"}]',1,'Bacterial meningitis classically shows a markedly elevated neutrophil-predominant white cell count, high protein, and low glucose (reflecting bacterial glucose consumption), while viral meningitis/encephalitis typically shows a more modest lymphocyte-predominant pleocytosis with normal or mildly elevated protein and normal glucose; these patterns overlap, especially early in bacterial infection or in partially treated cases, so culture and/or PCR results are essential for definitive pathogen identification. Tuberculous and fungal meningitis often show a lymphocyte-predominant pleocytosis with notably low glucose and high protein, and typically require specific stains/cultures (AFB smear and culture, fungal culture, cryptococcal antigen) beyond the standard bacterial workup, given their more indolent, subacute presentation.',NULL,'[{"condition": "Bacterial meningitis", "direction": "neutrophil-predominant pleocytosis, high protein, low glucose, organism identified on Gram stain/culture"}, {"condition": "Viral meningitis/encephalitis", "direction": "lymphocyte-predominant pleocytosis, normal or mildly elevated protein, normal glucose"}, {"condition": "Tuberculous or fungal meningitis", "direction": "lymphocyte-predominant pleocytosis, markedly low glucose, high protein"}]','[{"name": "CDC - Bacterial Meningitis Clinical Overview (general CSF interpretation reference)", "url": "https://www.cdc.gov/meningitis/hcp/clinical-overview/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["gram-stain", "blood-culture"]',NULL,NULL,'Given these results, is antibiotic/antiviral therapy being adjusted while final culture results are pending? Are additional studies (like PCR panels or cryptococcal antigen) being sent given the specific pattern seen here?','Findings consistent with bacterial meningitis lead to continuation or escalation of empiric antibiotics pending culture and susceptibility results, with de-escalation once a specific organism and susceptibility are identified; findings suggesting a viral, tuberculous, or fungal process guide the addition of specific antiviral/antifungal/antituberculous therapy and further targeted testing as appropriate.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (216,'throat-culture-strep','Throat Culture (Group A Streptococcus)','','Throat Culture, Strep Culture, GAS Culture','Microbiology','Confirms Group A Streptococcus (Streptococcus pyogenes) pharyngitis, most often used to follow up a negative rapid antigen detection test in children and adolescents (where the consequence of missing GAS pharyngitis -- rheumatic fever -- is more clinically significant), since culture is more sensitive than rapid antigen testing.',NULL,'Throat swab, vigorously swabbing both tonsils/tonsillar fossae and the posterior pharynx','Adequate swab technique (touching both tonsillar areas and the posterior pharyngeal wall, avoiding the tongue and buccal mucosa) is essential for sensitivity; culture takes 24-48 hours to result, unlike the rapid antigen test, which is why culture is typically used as a backup/confirmatory test rather than the primary initial test in most clinical settings.',NULL,'Culture on blood agar with identification of beta-hemolytic colonies confirmed as Group A Streptococcus by latex agglutination or other specific methods.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "No growth of Group A Streptococcus, or Group A Streptococcus isolated"}]',1,'A positive throat culture for Group A Streptococcus in a patient with compatible symptoms (sore throat, fever, tonsillar exudate, absence of cough/rhinorrhea suggesting a viral cause) confirms the need for antibiotic treatment, primarily to prevent acute rheumatic fever (a serious but now uncommon complication in most high-resource settings, though still clinically relevant, particularly in some regions) and to reduce symptom duration and transmission. Because Group A Streptococcus can also be carried asymptomatically in the throat without causing active infection, a positive result is interpreted alongside clinical symptoms rather than treated as diagnostic in isolation, particularly in a patient tested primarily due to contact exposure rather than symptoms.',NULL,'[{"condition": "Group A Streptococcal pharyngitis", "direction": "positive culture with compatible symptoms"}, {"condition": "Asymptomatic Group A Streptococcus carriage", "direction": "positive culture without acute symptoms; generally not treated"}]','[{"name": "CDC - Group A Streptococcal (GAS) Pharyngitis Clinical Guidance", "url": "https://www.cdc.gov/group-a-strep/hcp/clinical-guidance/pharyngitis.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["gram-stain"]',NULL,NULL,'Given my symptoms, does this result mean I have an active infection that needs antibiotics, or could this reflect asymptomatic carriage? How long until I''m no longer contagious once treatment starts?','A positive result with compatible symptoms leads to a course of an appropriate antibiotic (typically penicillin or amoxicillin, given continued universal susceptibility of Group A Streptococcus to these agents), with symptoms and contagiousness typically improving substantially within 24 hours of starting treatment.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (217,'afb-smear-culture','Acid-Fast Bacilli (AFB) Smear and Culture','','AFB Smear, TB Culture, Mycobacterial Culture','Microbiology','Diagnoses active tuberculosis and other mycobacterial infections (including nontuberculous mycobacteria), assesses infectiousness (smear positivity correlates with higher transmission risk), and, via culture, provides definitive species identification and drug susceptibility testing.',NULL,'Sputum (typically three separate specimens collected on different occasions, at least one being an early-morning sample), or other specimen type depending on suspected site of disease (e.g., urine, tissue, CSF)','Molecular testing (nucleic acid amplification testing, e.g. Xpert MTB/RIF) is increasingly used alongside or instead of smear microscopy for faster, more sensitive detection and rapid rifampin resistance screening, but culture remains essential for definitive diagnosis, full drug susceptibility testing, and monitoring treatment response, since it can take several weeks to result given the slow growth of Mycobacterium tuberculosis.',NULL,'Smear: Ziehl-Neelsen or auramine-rhodamine fluorescent staining for microscopy. Culture: liquid culture media (e.g., MGIT) for faster growth detection, with solid media (Lowenstein-Jensen) also commonly used; species identification (M. tuberculosis complex versus nontuberculous mycobacteria) and drug susceptibility testing performed on positive cultures.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "Smear: No AFB seen, or AFB seen (with quantitative grading, e.g. 1+ to 4+). Culture: No growth, or Mycobacterium species isolated and identified, generally reported over 2-6 weeks"}]',1,'A positive AFB smear indicates a high bacillary burden and correlates with higher infectiousness, prompting immediate airborne isolation precautions while awaiting further confirmation, though smear alone cannot distinguish Mycobacterium tuberculosis from nontuberculous mycobacteria (which requires culture identification or molecular testing). A positive culture provides definitive diagnosis and, critically, allows drug susceptibility testing to guide appropriate therapy, which is essential given the global concern about multidrug-resistant tuberculosis; a negative smear does not exclude tuberculosis, since sensitivity is lower than culture, and multiple specimens plus molecular/culture testing are used together to maximize diagnostic yield.',NULL,'[{"condition": "Active pulmonary tuberculosis", "direction": "AFB seen on smear and/or Mycobacterium tuberculosis complex isolated on culture"}, {"condition": "Nontuberculous mycobacterial infection", "direction": "AFB seen, with culture identifying a species other than M. tuberculosis complex"}]','[{"name": "CDC - Tuberculosis Diagnostic Testing Overview", "url": "https://www.cdc.gov/tb/hcp/testing-diagnosis/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["tb-igra-quantiferon"]',NULL,NULL,'Given this smear result, what isolation precautions are needed, and for how long? Will drug susceptibility results be available before or after I start treatment, and how might that change my regimen?','A positive smear leads to airborne isolation precautions and typically empiric multidrug anti-tuberculous therapy pending culture/susceptibility confirmation; culture and drug susceptibility results, once available, guide any needed adjustment of the treatment regimen, particularly if drug resistance is identified.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (218,'wound-culture','Wound Culture','','Wound C&S, Skin/Soft Tissue Culture','Microbiology','Identifies the causative organism(s) in a clinically infected wound (surgical site infection, diabetic foot ulcer, traumatic wound, abscess) and provides susceptibility testing to guide targeted antibiotic therapy.',NULL,'Tissue biopsy or deep wound swab/aspirate, ideally obtained after cleaning/debriding the wound surface to reduce contamination with surface colonizing flora','Superficial swabs of a wound that hasn''t been cleaned/debrided first frequently grow colonizing organisms rather than true pathogens, which can lead to unnecessary antibiotic treatment of colonization; tissue biopsy or curettage from the wound base, or aspiration of purulent material, generally provides more clinically meaningful results than a surface swab, especially in chronic wounds like diabetic foot ulcers.',NULL,'Aerobic and, when clinically indicated (deep or necrotic wounds, suspected anaerobic infection), anaerobic culture, with organism identification and susceptibility testing on significant isolates.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "No growth, growth of normal skin flora (interpreted with caution regarding clinical significance), or growth of a specific pathogen with susceptibility results"}]',1,'Growth of a recognized wound pathogen (Staphylococcus aureus including MRSA, Streptococcus pyogenes, Pseudomonas aeruginosa, or, in polymicrobial chronic wounds like diabetic foot ulcers, a mix of aerobes and anaerobes) alongside clinical signs of infection (increasing redness, warmth, purulent drainage, systemic signs) supports targeted antibiotic therapy, while growth from a wound without clinical signs of infection often represents colonization that does not require treatment. Distinguishing true infection from colonization is a common clinical challenge, particularly in chronic wounds, which is why culture results are always interpreted alongside the clinical examination rather than treated as automatically requiring antibiotics.',NULL,'[{"condition": "Surgical site or traumatic wound infection", "direction": "growth of a pathogen with compatible clinical signs of infection"}, {"condition": "Wound colonization (no active infection)", "direction": "growth without clinical signs of infection; generally not treated"}]','[{"name": "CDC - Surgical Site Infection Prevention and Management Guidance (general wound infection reference)", "url": "https://www.cdc.gov/hai/prevent/ssi.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["gram-stain", "blood-culture"]',NULL,NULL,'Was this specimen collected from deep tissue/after debridement, or a surface swab, since that affects how reliable the result is? Do my clinical signs support treating this as a true infection rather than colonization?','Confirmed infection with a compatible clinical picture is treated with targeted antibiotic therapy based on susceptibility results, alongside appropriate wound care (debridement, drainage of any abscess); growth without clinical infection signs generally does not warrant antibiotic treatment, to avoid promoting antibiotic resistance.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (219,'fungal-culture','Fungal Culture','','Mycology Culture, Fungal C&S','Microbiology','Identifies invasive or superficial fungal pathogens from blood, tissue, respiratory, or skin/nail specimens, particularly important in immunocompromised patients at risk for invasive fungal infection (candidiasis, aspergillosis, and others) and in suspected dermatophyte or other superficial fungal infections.',NULL,'Depends on suspected site: blood, tissue biopsy, respiratory specimen (sputum, bronchoalveolar lavage), or skin/nail/hair scrapings for superficial infections','Fungal cultures can take substantially longer to result than bacterial cultures -- days for yeasts like Candida, but often 1-4 weeks or longer for molds like Aspergillus -- so in suspected invasive fungal infection, complementary rapid tests (beta-D-glucan, galactomannan antigen, and molecular PCR-based assays) are often used alongside culture to guide earlier treatment decisions.',NULL,'Culture on fungal-selective media (e.g., Sabouraud dextrose agar) with incubation times tailored to the suspected organism; identification by colony/microscopic morphology or, increasingly, MALDI-TOF mass spectrometry or molecular sequencing for definitive species identification.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "No growth, or growth of a specific fungal organism, reported with turnaround time depending on the organism''s growth rate"}]',1,'Growth of a pathogenic fungus from a normally sterile site (blood, deep tissue, CSF) is generally clinically significant and prompts antifungal therapy, while growth from a non-sterile site (sputum, skin) requires more careful clinical correlation, since some fungi (including some Candida species and molds like Aspergillus) can be colonizers or environmental contaminants rather than true invasive pathogens in a given clinical context. Invasive fungal infections are a particular concern in immunocompromised patients (transplant recipients, patients with hematologic malignancy or prolonged neutropenia, advanced HIV/AIDS), where the threshold for aggressive diagnostic workup and empiric or pre-emptive antifungal therapy is generally lower given the high mortality of delayed treatment in this population.',NULL,'[{"condition": "Invasive fungal infection (candidiasis, aspergillosis, and others) in immunocompromised patients", "direction": "growth from a sterile site, or from a non-sterile site with strong supporting clinical/radiographic evidence"}, {"condition": "Superficial fungal infection (dermatophytosis, onychomycosis)", "direction": "growth of a dermatophyte from skin/nail/hair specimen"}]','[{"name": "CDC - Invasive Candidiasis and Fungal Disease Clinical Guidance", "url": "https://www.cdc.gov/fungal/hcp/clinical-guidance/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["blood-culture", "gram-stain"]',NULL,NULL,'Given how long fungal cultures can take, are faster complementary tests (like beta-D-glucan or galactomannan) also being used to guide treatment in the meantime? Does this organism represent true infection or possible colonization/contamination given where it was found?','Growth from a sterile site or with strong clinical correlation leads to targeted antifungal therapy based on the organism identified and, where performed, susceptibility results; growth that likely represents colonization or contamination is interpreted in the full clinical context and may not require treatment.');
INSERT INTO lab_tests (id,slug,name_en,name_ar,aliases,category,purpose_en,purpose_ar,specimen_type,collection_notes_en,collection_notes_ar,methodology_en,methodology_ar,reference_ranges_json,reference_ranges_verified,clinical_significance_en,clinical_significance_ar,associated_conditions_json,sources_json,is_published,created_at,updated_at,related_tests_json,critical_values_en,interfering_factors_en,questions_to_ask_en,next_steps_en) VALUES (220,'malaria-smear-rdt','Malaria Smear (Thick/Thin Film) and Rapid Diagnostic Test','','Malaria Smear, Malaria RDT, Blood Parasite Smear','Microbiology','Diagnoses malaria in a patient with fever and relevant travel/exposure history, identifies the infecting Plasmodium species, and quantifies parasitemia (percentage of infected red cells) to help assess severity and guide treatment urgency.',NULL,'Venous whole blood (EDTA), used to prepare thick and thin blood films and, where available, a rapid antigen test','A single negative smear does not exclude malaria, since parasitemia can fluctuate; current guidelines recommend repeating smears (typically every 12-24 hours for a total of up to 3 sets) if clinical suspicion remains high, given the potential severity of untreated Plasmodium falciparum infection.',NULL,'Thick film (concentrates parasites for more sensitive detection) and thin film (allows species identification and precise parasitemia quantification) examined by light microscopy after Giemsa staining; rapid diagnostic tests (immunochromatographic antigen detection, e.g. for histidine-rich protein 2 or lactate dehydrogenase) provide faster results and are especially useful where expert microscopy isn''t readily available, though they cannot reliably quantify parasitemia and may have reduced sensitivity for non-falciparum species.',NULL,'[{"parameter": "Result categories", "population": "General", "range": "No parasites seen, or Plasmodium species identified (P. falciparum, P. vivax, P. ovale, P. malariae, or P. knowlesi) with parasitemia percentage reported for confirmed cases"}]',1,'Identification of Plasmodium falciparum, particularly with high parasitemia (commonly considered severe above roughly 5%, though clinical severity criteria matter as much as the percentage alone), signs of organ dysfunction, or in a non-immune traveler, constitutes a medical emergency requiring urgent treatment given the risk of rapid progression to severe/complicated malaria (cerebral malaria, severe anemia, acute kidney injury, respiratory distress) and death if treatment is delayed. Identifying the specific species also matters for treatment choice, since P. vivax and P. ovale require additional therapy (primaquine or tafenoxin) to eradicate dormant liver-stage parasites (hypnozoites) and prevent relapse, which is not needed for P. falciparum or P. malariae.',NULL,'[{"condition": "Plasmodium falciparum malaria (highest risk of severe/complicated disease)", "direction": "parasites identified, with parasitemia percentage guiding severity assessment"}, {"condition": "Plasmodium vivax / P. ovale malaria (relapse risk from liver hypnozoites)", "direction": "parasites identified; requires additional liver-stage treatment to prevent relapse"}]','[{"name": "CDC - Malaria Diagnosis and Treatment Guidance for Clinicians", "url": "https://www.cdc.gov/malaria/hcp/diagnosis-testing/index.html", "accessed": "2026-07-20"}]',1,'2026-07-20 05:35:44','2026-07-20 05:35:44','["complete-blood-count", "peripheral-blood-smear"]',NULL,NULL,'Given my travel history and this result, how urgently does treatment need to start, and is this considered severe malaria requiring closer monitoring or IV therapy? If this is P. vivax or P. ovale, do I need additional medication to prevent relapse?','A positive result, especially P. falciparum or any case with severity features, leads to prompt initiation of appropriate antimalarial therapy (with IV therapy and closer monitoring for severe disease) and, for P. vivax/P. ovale, additional treatment to eradicate liver-stage parasites after screening for G6PD deficiency (since the relevant medications can cause hemolysis in G6PD-deficient patients); a negative smear with ongoing suspicion prompts repeat testing.');
INSERT INTO order_sets (id,slug,name_en,description_en,category,test_slugs_json,is_published,created_at) VALUES (1,'anemia-workup','Anemia Workup Panel','Core panel for the initial evaluation of unexplained anemia -- assesses cell counts, iron stores, and the two most common nutritional causes of macrocytic anemia.','Hematology','["cbc", "ferritin", "serum-iron", "tibc-transferrin-saturation", "vitamin-b12", "folate", "reticulocyte-count"]',1,'2026-07-16 07:08:43');
