INSERT INTO order_sets (id,slug,name_en,description_en,category,test_slugs_json,is_published,created_at) VALUES (8,'thrombophilia-workup','Thrombophilia Workup Panel','Panel for investigating a hereditary or acquired clotting tendency after unprovoked or recurrent venous thromboembolism.','Hematology / Coagulation','["factor-v-leiden", "prothrombin-g20210a", "protein-c", "protein-s", "antithrombin-iii", "d-dimer"]',1,'2026-07-16 07:08:43');
INSERT INTO order_sets (id,slug,name_en,description_en,category,test_slugs_json,is_published,created_at) VALUES (9,'sepsis-workup-panel','Sepsis / Severe Infection Workup Panel','Core panel for evaluating suspected sepsis or severe systemic infection in the emergency or critical care setting.','Critical Care','["cbc", "procalcitonin", "lactate", "crp", "blood-culture", "creatinine", "bun"]',1,'2026-07-16 07:08:43');
